SET session_replication_role = replica;

INSERT INTO public.questions VALUES ('df276f6e-5a7f-4135-99bd-668f5df9a186', 'f2fb4447-a526-4152-adff-c533d6a2e336', 'matrix', 'Questions 11–15', '', '<p>Label the map below. </p>
<p>Choose the correct letter,<strong> A-H</strong>, next to questions 11-15.</p>
<p><img src="data:image/png;base64," width="587" height="549"></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "seating area", "correctCategoryLetter": "C"}, {"itemText": "cushions", "correctCategoryLetter": "F"}, {"itemText": "computer bench", "correctCategoryLetter": "D"}, {"itemText": "café bar", "correctCategoryLetter": "A"}, {"itemText": "newspapers", "correctCategoryLetter": "H"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 2: BIBLIOSTACK BOOKSHOP</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Manager:</strong> Good morning everyone and a big welcome to Bibliostack. Firstly, I''ll explain the plan of the store to you. The building is on 7 floors and is circular, as you can see, and we''re here on the ground floor in its entrance hall.</p>\n<p data-path-to-node=\"4\">Right in the center of this floor, but behind the bookshelf—so you can''t see it very well from here—is our <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"107\">(Q11) main seating area (G)</strong></span>, where people are encouraged to sit and read for as long as they like. But they''re under no pressure to buy what they''re reading; that''s not how we operate.</p>\n<p data-path-to-node=\"5\">And if you look to your immediate left, past the first double row of shelves, you''ll see piles of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"98\">(Q12) coloured cushions (B)</strong></span> in front of the window there. We provide those so that people can sit wherever they want. Lots of people like to sit close to the bookshelves, and if they want to sit on the floor there, we want them to be as comfortable as possible.</p>\n<p data-path-to-node=\"6\">On your right, between the two larger bookshelves, you''ll see the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"66\">(Q13) computer bench (C)</strong></span> where our visitors can search through our entire catalogue. We pride ourselves in being the largest bookshop in the country, so our sales assistants can''t possibly know all the available titles.</p>\n<p data-path-to-node=\"7\">Although the room in front of you is dominated by the bookshelves, at the far end, just in front of the lift, you''ll see that we provide a small <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"145\">(Q14) cafe bar (A)</strong></span> here too.</p>\n<p data-path-to-node=\"8\">And just to your right, there''s a door to the cloakroom where people can leave their coats. Then after that, there''s a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"119\">(Q15) stand (E)</strong></span> where we keep a selection of local and national <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"183\">newspapers</strong></span>. Customers are welcome to browse through them, and we also have some for sale. We really want people to feel as though they''re browsing through books in the comfort of their own home.</p>\n<hr data-path-to-node=\"9\">\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">STORE OPERATIONS (Questions 16–20)</strong></h3>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Manager:</strong> Right now, I suggest we walk slowly up through the building and I''ll give you more information as we go. We''re open 12 hours a day. We don''t mind if people spend the whole day here but leave without buying anything. Of course we hope they''ll buy something, but <strong data-path-to-node=\"11\" data-index-in-node=\"270\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q16) our purpose is to draw people in, to provide the kind of environment which makes them want to stay and read</span>.</strong> Look at how busy each floor is, but how quiet. You may be wondering whether there are any children in the building. We debated about locating children''s books on the ground floor or halfway up the building, like the third or fourth floor, but in the end, <strong data-path-to-node=\"11\" data-index-in-node=\"640\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q17) we decided to put them on the very top level</span>.</strong> And I can assure you, it''s not the least bit quiet up there!</p>\n<p data-path-to-node=\"12\">Of course, many parents would prefer to spend time on other floors and so we provide a supervised area for children under 2 in the basement. So parents can wander around the shop for a few hours and not worry. But they do have to pay for this service because although we thought about using some of our own assistants, <strong data-path-to-node=\"12\" data-index-in-node=\"319\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q18) we decided to employ qualified nursery staff for parents'' complete peace of mind</span>.</strong> Now we''re just passing the fiction section, and you''ve probably noticed a small crowd of people beginning to gather. That''s because a well-known author is going to read from her latest novel. We try to hold events like this at least once or twice a week, and as you can imagine they''re very popular. We don''t make a charge for people to attend, but <strong data-path-to-node=\"12\" data-index-in-node=\"756\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q19) we obviously hope that some of them will want to purchase the book after listening to part of it being read aloud</span>.</strong> Other events which are proving to be very popular are our workshops. Last week we held a poetry workshop and people came along with poems that they''d written. One of the country''s best-known poets ran the workshop and <strong data-path-to-node=\"12\" data-index-in-node=\"1095\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q20) the participants read their poems aloud to him</span>.</strong> He was kind and encouraging and many people felt inspired by his advice.</p>\n<p data-path-to-node=\"13\">It''s extremely difficult to earn your living as a professional poet, and even published poets have other jobs. Now we''re going to take a look at our section on audio books...</p>"}]', 0);
INSERT INTO public.questions VALUES ('4c32771d-6d01-4b9f-a1a0-e6ae381e0e48', '7c69aed1-b61c-48bf-8434-fca30ae4a00d', 'radio', 'Questions 27-32', '', '<p>Choose the correct letter, A, B, C, or D.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "Computer scientists are rarely represented at the Oscars."}, {"option_text": "Film-industry awards hold little interest for computer scientists."}, {"option_text": "The USA rewards film actors more than computer scientists."}, {"option_text": "Computer scientists are becoming a vital part of the film industry."}], "question": "What is the writer’s main point in the first paragraph?"}, {"correct": 0, "options": [{"option_text": "CGI looks best from a distance."}, {"option_text": "CGI interferes with actors’ facial expressions."}, {"option_text": "Audiences expect too much of CGI."}, {"option_text": "The scientists had hoped for more convincing results."}], "question": "When describing the way computer-generated imagery changes actors’ appearance, what does the writer suggest?"}, {"correct": 0, "options": [{"option_text": "They were motivated to get as near to reality as possible."}, {"option_text": "They were interested in gaining recognition for their work."}, {"option_text": "They thought it could have medical applications."}, {"option_text": "They hoped to receive further funding for their research."}], "question": "What does the writer suggest about the scientists’ attitude to their work in the fourth paragraph?"}, {"correct": 1, "options": [{"option_text": "It has only recently been used by doctors."}, {"option_text": "It is similar to X-rays in the way it works."}, {"option_text": "Filmmakers have used it for many years for special lighting effects."}, {"option_text": "It can be administered using traditional radiography machines."}], "question": "What are we told about computerised tomography?"}, {"correct": 1, "options": [{"option_text": "It is most effective when used to create images of skin."}, {"option_text": "It can make a few people seem like a crowd."}, {"option_text": "It allows clothes designers to create new designs."}, {"option_text": "It is practical because of the time it takes."}], "question": "Which of these advantages does the writer attribute to the current use of computerised tomography?"}, {"correct": 3, "options": [{"option_text": "comment on the success of CGI in commercial contexts."}, {"option_text": "highlight the link between CGI and photography."}, {"option_text": "show that Marschner’s team are uncertain about the future of CGI."}, {"option_text": "demonstrate a use for CGI outside the film industry."}], "question": "The writer mentions Kavita Bala in order to"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">Questions 27–32: Multiple Choice</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. What is the writer’s main point in the first paragraph?</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: D</strong> (Computer scientists are becoming a vital part of the film industry.)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…computer scientists that has become <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"51\">fundamental</strong> to moviemaking.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh rằng các nhà khoa học máy tính đang trở thành một phần thiết yếu/nền tảng (fundamental = vital part) của ngành làm phim.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. When describing the way CGI changes actors’ appearance, what does the writer suggest?</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: A</strong> (CGI looks best from a distance.)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it is possible if the altered actors are <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"56\">not filmed too closely</strong>. This is because… the effect is <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"113\">less convincing when seen close up</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết nói rằng kỹ xảo CGI sẽ kém thuyết phục khi nhìn gần, nghĩa là nó trông tốt nhất khi nhìn từ một khoảng cách nhất định (not filmed too closely).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. What does the writer suggest about the scientists’ attitude to their work in the fourth paragraph?</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: A</strong> (They were motivated to get as near to reality as possible.)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…continued their <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"31\">search for perfection</strong>, as they still did not feel that they had yet satisfactorily recreated the <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"128\">subtle ways light is reflected</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “search for perfection” (tìm kiếm sự hoàn hảo) và việc chưa hài lòng với kết quả hiện tại cho thấy họ muốn đạt tới mức độ thực tế nhất có thể.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. What are we told about computerised tomography?</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: B</strong> (It is similar to X-rays in the way it works.)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"12\">Like classical radiology, it uses X-rays</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết khẳng định kỹ thuật chụp cắt lớp vi tính (CT) cũng sử dụng tia X giống như phương pháp chụp X-quang truyền thống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. Which of these advantages does the writer attribute to the current use of computerised tomography?</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: B</strong> (It can make a few people seem like a crowd.)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…in the same way that a <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"38\">small group of actors</strong> can be made to look like <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"85\">hundreds of people</strong> gathered together.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả so sánh việc ghép các mảnh vải CGI với việc biến một nhóm nhỏ diễn viên trông như hàng trăm người (đám đông).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">32. The writer mentions Kavita Bala in order to</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: D</strong> (demonstrate a use for CGI outside the film industry.)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the technology might have an <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"44\">application in online retailing</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc nhắc đến Kavita Bala là để chỉ ra một ứng dụng tiềm năng của công nghệ này trong ngành bán lẻ trực tuyến, vốn nằm ngoài lĩnh vực điện ảnh.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('5436d8af-6709-4a19-addc-1ec3e46be67c', '7c69aed1-b61c-48bf-8434-fca30ae4a00d', 'radio', 'Questions 33-36', '', '<p>Choose <strong data-path-to-node="18,0,0" data-index-in-node="0">YES</strong> if the statement agrees with the views of the writer, <strong data-path-to-node="18,1,0" data-index-in-node="0">NO</strong> if the statement contradicts the views of the writer, <strong data-path-to-node="18,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "It used to be unusual for university researchers to receive a cinematography award."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "CGI is popular among ageing actors."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The scientists’ success in generating images of complete CGI garments has won them many awards."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "It will be a long time before computerised tomographic imaging of fabric is used by filmmakers."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. It used to be unusual for university researchers to receive a cinematography award.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In 2004 a <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"22\">notable event</strong> took place: the <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"52\">academic world met the cinematographic world</strong> when researchers from Stanford University… were awarded an Oscar.”</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc gọi sự kiện năm 2004 là “notable event” (sự kiện đáng chú ý/hiếm thấy) khi giới học thuật gặp giới điện ảnh cho thấy trước đó điều này là không thường xuyên (unusual).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. CGI is popular among ageing actors.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Films have shown that it is possible to use CGI to <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"63\">make actors look younger</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói CGI có thể làm diễn viên trông trẻ hơn, nhưng <strong data-path-to-node=\"20,2,0\" data-index-in-node=\"74\">không hề đề cập</strong> đến việc nó có “phổ biến” (popular) trong nhóm diễn viên đang già đi hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. The scientists’ success in generating images of complete CGI garments has won them many awards.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc nhắc đến giải Oscar cho việc mô phỏng độ xuyên thấu của da (subsurface scattering), nhưng <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"109\">không nói</strong> việc tạo ra trang phục (garments) hoàn chỉnh có mang về cho họ “nhiều giải thưởng” (many awards) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">36. It will be a long time before computerised tomographic imaging of fabric is used by filmmakers.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…for the <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"23\">moment</strong> the movement of a <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"48\">virtual cloak</strong> or the lifting of a <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"82\">computerized hat</strong> should look far more realistic.”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,2,0\"><strong data-path-to-node=\"24,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết nói rằng kỹ thuật này <strong data-path-to-node=\"24,2,0\" data-index-in-node=\"43\">hiện tại</strong> (for the moment) đã có thể giúp các vật dụng bằng vải như áo choàng hay mũ trông thực tế hơn, trái ngược với ý kiến “phải chờ đợi lâu” (long time).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('1808905d-c107-4712-8fdf-c6d6701b2a42', '12ce4f88-e9e8-40aa-bcdb-71f446533e80', 'matrix', 'Questions 21-23', NULL, '<p>Match each statement with the correct historical period</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "A wide variety of people achieve a brief period of fame.", "correctCategoryLetter": "D"}, {"itemText": "Stories are invented about celebrities'' lives.", "correctCategoryLetter": "A"}, {"itemText": "The fame of rulers is starting to diminish.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Ancient times", "categoryLetter": "A"}, {"categoryText": "Dark Ages", "categoryLetter": "B"}, {"categoryText": "Renaissance", "categoryLetter": "C"}, {"categoryText": "Modern era", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">21. A wide variety of people achieve a brief period of fame.</strong></p>\n<p data-path-to-node=\"3\">(Nhiều nhóm người khác nhau đạt được một khoảng thời gian nổi tiếng ngắn ngủi.)</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: D. Modern era (Kỷ nguyên hiện đại)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The emergence of reality television shows in the late 1990s allowed <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"80\">all kinds of people</strong> with little ability to enjoy a <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"131\">short burst of fame</strong> on the television screen.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “all kinds of people” tương ứng với “a wide variety of people”, và “short burst of fame” tương ứng với “brief period of fame”. Hiện tượng này gắn liền với truyền hình thực tế trong kỷ nguyên hiện đại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. Stories are invented about celebrities’ lives.</strong></p>\n<p data-path-to-node=\"7\">(Các câu chuyện được thêu dệt/sáng tạo ra về cuộc đời của những người nổi tiếng.)</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: A. Ancient times (Thời cổ đại)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This need to know led to the <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"41\">creation of myths</strong>, which personalized the gods and involved them in ancient celebrity scandals…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Creation of myths” (sáng tạo ra các huyền thoại/thần thoại) chính là việc thêu dệt nên các câu chuyện. Trong thời cổ đại, các vị thần được coi là người nổi tiếng và người dân đã tạo ra các thần thoại để tìm hiểu về đời tư của họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">23. The fame of rulers is starting to diminish.</strong></p>\n<p data-path-to-node=\"11\">(Sự nổi tiếng của các nhà cầm quyền bắt đầu suy giảm.)</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: C. Renaissance (Thời kỳ Phục hưng)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “During the period 1300-1600 AD, or the <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"51\">Renaissance</strong> period as it is known, <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"86\">interest in ruling figures faded</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “interest in ruling figures faded” (sự quan tâm đến các nhân vật cầm quyền phai nhạt dần) đồng nghĩa với việc sự nổi tiếng của các nhà cầm quyền đang bắt đầu suy giảm (starting to diminish).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('80ddefd8-6e33-4e0e-8d6a-8c77529e2eef', 'baed8df8-804e-4c5f-8e49-36dfa2cf11af', 'fillup', 'Questions 1-10', '<p><span style="font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</span><strong><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;"> </span></strong></p>
<p><strong><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Wedding arrangements – Clarence House Hotel</span></strong></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Available date: 1st June</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">The Oxford Suite has:</span></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l2 level1 lfo1; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">a dining room with a good view of the {city}</span></span></li>
</ul>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l1 level1 lfo2; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">a private garden for {photos} </span></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">and for the wedding ceremony</span></li>
</ul>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l5 level1 lfo3; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">an area suitable for dancing</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">The wedding package includes:</span></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l3 level1 lfo4; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">use of the Oxford Suite</span></li>
</ul>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l4 level1 lfo5; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">a three-course meal</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">+ room arranged with {round} </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">tables</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">+ table {decorations} </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">included</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">+ white tablecloths and chairs</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">+ personalised printed {menu}</span></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 150%; mso-list: l0 level1 lfo6; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;"><span style="color: #15191e;">a late-evening buffet with a choice of {sandwiches} </span></span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;">and hot drinks</span></li>
</ul>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Music: hotel will organise a band (not included in price)</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Total cost of package: £ {5995}</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Can also recommend a {cake} </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">supplier (new company)</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Wedding coordinator Sarah {Izard}</span></p>
<p><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">Date arranged for visit: {15th October | 15 October} </span><span style="font-size: 12.0pt; line-height: 150%; mso-ascii-font-family: Calibri; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: ''Times New Roman''; mso-hansi-font-family: Calibri; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin; color: #15191e;">at 11.30 a.m</span></p>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p><strong>Narrator:</strong> You will hear a telephone conversation between a hotel manager and a woman who is inquiring about wedding arrangements. First you have some time to look at questions 1 to five. Now listen carefully and answer questions 1 to five.</p>\n<p><strong>Hotel Manager:</strong> Hello, Clarence House.</p>\n<p><strong>Woman:</strong> Oh, hello. Um, I’m getting married next year, and I understand you’re licensed to hold weddings at the hotel.</p>\n<p><strong>Hotel Manager:</strong> Yes, we are. Can I ask what date you were thinking of?</p>\n<p><strong>Woman:</strong> Either the 1st or the 7th of June.</p>\n<p><strong>Hotel Manager:</strong> Right, let me see. Oh, I’m afraid we already have a booking for the 7th, but we still have availability on <strong>June the first</strong>.</p>\n<p><strong>Woman:</strong> That would be fine.</p>\n<p><strong>Hotel Manager:</strong> So, how many guests are you going to be inviting?</p>\n<p><strong>Woman:</strong> About 80.</p>\n<p><strong>Hotel Manager:</strong> So, for that number, we’d recommend the Oxford Suite. I don’t know if you’ve been to the hotel?</p>\n<p><strong>Woman:</strong> Yes, in fact, I went to a wedding there a few years ago and I was really impressed.</p>\n<p><strong>Hotel Manager:</strong> Very good. I think we’re in the Oxford Suite then. Um, the room where we were eating had big windows with really good views. You could see right across the <strong>(1) city</strong>.</p>\n<p><strong>Hotel Manager:</strong> That’s it. And you’d have exclusive access to the garden. It’ll be at its best in June, so we could have the <strong>(2) photos</strong> there.</p>\n<p><strong>Woman:</strong> Sure.</p>\n<p><strong>Hotel Manager:</strong> In fact, you can even have the ceremony there if you want. It makes a lovely background.</p>\n<p><strong>Woman:</strong> Oh, I hadn’t thought of that. Yes, that’s certainly an idea. And is there somewhere for dancing?</p>\n<p><strong>Hotel Manager:</strong> Yes, there’s plenty of space in the middle of the dining room.</p>\n<p><strong>Woman:</strong> Oh yeah, I remember now. So, just to give you an idea, would you like me to tell you about our special wedding package?</p>\n<p><strong>Hotel Manager:</strong> Sure. Right, so for 80 guests, you’d have the exclusive use of the Oxford Suite, as I said, and then a meal. So that would be in the dining room, and that would be a sit down meal with three courses.</p>\n<p><strong>Woman:</strong> And how’s the room arranged? I seem to remember you have <strong>(3) round</strong> tables?</p>\n<p><strong>Hotel Manager:</strong> That’s right. Most people prefer them to long tables. Long tables aren’t really very friendly, are they?</p>\n<p><strong>Woman:</strong> And what about <strong>(4) decorations</strong> on the tables?</p>\n<p><strong>Hotel Manager:</strong> They’re included in the package. And we have white linen tablecloths and white chair covers, and we also include an individually designed <strong>(5) menu</strong> specially printed for you. It’s something that people can take away to remember the occasion. That’s something we’ve just started doing this year.</p>\n<p><strong>Woman:</strong> Alright.</p>\n<hr />\n<p><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions 6 to ten. Now listen and answer questions 6 to ten.</p>\n<p><strong>Hotel Manager:</strong> And then towards the end of the evening, when everyone’s beginning to run out of energy, we bring in a buffet. Nothing too complicated, just a selection of <strong>(6) sandwiches</strong> together with tea or coffee. That’s always very popular.</p>\n<p><strong>Woman:</strong> Right. And we want some music. Is that included in the package?</p>\n<p><strong>Hotel Manager:</strong> No, but we could probably get you a DJ. Oh, we know of a very good band, if you’d prefer that.</p>\n<p><strong>Woman:</strong> Yes, that’d be better actually. Something to get everyone on their feet.</p>\n<p><strong>Hotel Manager:</strong> Good. So, apart from the music, you said that’s an all-inclusive package. So, how much does that package come to?</p>\n<p><strong>Hotel Manager:</strong> <strong>£5,995</strong>.</p>\n<p><strong>Woman:</strong> That’s a bit more than the package they quoted for me at the Stanley Hotel. Theirs was £4,500.</p>\n<p><strong>Hotel Manager:</strong> Yes, but I think if you look at what you’re getting for the money, you’ll find we’re the best value, and it is a big day after all.</p>\n<p><strong>Woman:</strong> Yes, you’re probably right. Oh, and I nearly forgot. I’m looking for someone who can make me a really special <strong>(8) cake</strong>. Can you suggest one?</p>\n<p><strong>Hotel Manager:</strong> Certainly. There’s a new company that we’ve started using. They’re very good. In fact, our wedding coordinator will be able to give you all sorts of advice. We can offer you a free consultation and a tour of the venue.</p>\n<p><strong>Woman:</strong> Yes, well I’d definitely be interested.</p>\n<p><strong>Hotel Manager:</strong> Right. Well, the coordinator’s name is Sarah <strong>(9) Izard</strong>. That’s I-Z-A-R-D. Now, when would you like to meet her? She’s available from 9 to 5 most weekdays, or later if that’s more convenient.</p>\n<p><strong>Woman:</strong> Uh, I’m free on October 12th in the morning sometime, or <strong>(10) October 15th</strong> that would be better, thanks. Should we say 11:30?</p>\n<p><strong>Hotel Manager:</strong> Fine. And can I just take your name and a contact number?</p>\n<p><strong>Woman:</strong> Sure. It’s Debbie…</p>\n<p><strong>Narrator:</strong> That is the end of part 1. You now have one minute to check your answers to part one.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('acadbb3a-e0e7-420f-a460-4a34bbf98389', '9b6d9897-cf82-4f9c-a390-603e391efdb0', 'radio', 'Questions 31-35', NULL, '<p>Choose the correct letter, <strong>A, B, C,</strong> or <strong>D.</strong> Write the correct letter in boxes 31-35 on your answer sheet.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A. Criticizing the conclusions of one publication"}, {"content": "B. Praising the contribution of a famous inventor"}, {"content": "C. Dismissing one common idea about innovation"}, {"content": "D. Suggesting that innovation changes over time"}], "question": "What is the writer doing in the third paragraph?"}, {"correct": 1, "options": [{"content": "A. Each industry will innovate in its own way."}, {"content": "B. There are pros and cons to strong leaders."}, {"content": "C. Some individuals are more innovative than others."}, {"content": "D. Leadership requires building teams that work together."}], "question": "What is the writer''s main point in the fourth paragraph?"}, {"correct": 3, "options": [{"content": "A. Compare how two different innovations developed."}, {"content": "B. Illustrate an exception to his point about innovation."}, {"content": "C. Show why one approach to innovation was correct."}, {"content": "D. Give an example of a general rule about innovation."}], "question": "The writer refers to Gutenberg''s printing press in order to:"}, {"correct": 0, "options": [{"content": "A. Companies should cooperate to turn ideas into products."}, {"content": "B. A company tends to make profits from its own innovations."}, {"content": "C. Science and business can often have common goals."}, {"content": "D. Competition between businesses produces innovation."}], "question": "What is the writer''s main point in the seventh paragraph?"}, {"correct": 3, "options": [{"content": "A. Have published valuable research about innovation."}, {"content": "B. Help companies recruit people with skills in innovation."}, {"content": "C. Run university courses teaching innovation skills."}, {"content": "D. Can be hired to give businesses advice about innovation."}], "question": "According to the writer, companies like Previously Unavailable:"}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"2\" data-index-in-node=\"0\">31. What is the writer doing in the third paragraph?</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"8\">C. Dismissing one common idea about innovation.</strong></li>\n<li><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, câu 1 và câu cuối: <em data-path-to-node=\"3,1,0\" data-index-in-node=\"38\">&#8220;There seems to be a widespread belief that the world’s best ideas are sudden and intuitive&#8230; Thus, business managers&#8230; must <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"165\">reject the false assumption</strong> that innovation is just a moment of brilliance waiting to strike.&#8221;</em></li>\n<li><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nêu lên một niềm tin phổ biến (widespread belief) rằng đổi mới là sự đột phá tức thời, sau đó dùng ví dụ về sự nỗ lực của Edison để bác bỏ (<strong data-path-to-node=\"3,2,0\" data-index-in-node=\"160\">reject/dismiss</strong>) quan điểm sai lầm này.</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">32. What is the writer’s main point in the fourth paragraph?</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"8\">B. There are pros and cons to strong leaders.</strong></li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu 3 và câu cuối: <em data-path-to-node=\"6,1,0\" data-index-in-node=\"38\">&#8220;&#8230;it was the fuel for his visionary innovations&#8230; but his <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"99\">egotistical behavior could have undesirable consequences</strong>, too&#8230; affects sickness rates and group morale, which in turn may squash creativity&#8230;&#8221;</em></li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả trình bày hai mặt của Steve Jobs: một mặt sự quyết liệt của ông là động lực cho đổi mới (pros), nhưng mặt khác tính cách ích kỷ và khắt khe lại gây ra hậu quả xấu cho tinh thần nhân viên (cons).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">33. The writer refers to Gutenberg’s printing press in order to:</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">D. Give an example of a general rule about innovation.</strong></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, câu cuối: <em data-path-to-node=\"9,1,0\" data-index-in-node=\"29\">&#8220;A good case to cite in support of this <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"69\">universal truth</strong> would be Gutenberg’s printing press&#8230; the press also affected an unrelated industry by causing a rise in demand for reading glasses.&#8221;</em></li>\n<li><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhắc đến máy in Gutenberg như một ví dụ điển hình để minh chứng cho một &#8220;sự thật phổ quát&#8221; (<strong data-path-to-node=\"9,2,0\" data-index-in-node=\"112\">universal truth</strong>) – quy luật chung rằng tiến bộ ở một lĩnh vực có thể thúc đẩy sự phát triển ở một lĩnh vực khác không liên quan.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">34. What is the writer’s main point in the seventh paragraph?</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"8\">A. Companies should cooperate to turn ideas into products.</strong></li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 7, câu cuối: <em data-path-to-node=\"12,1,0\" data-index-in-node=\"29\">&#8220;Instead, Kode’s approach is to <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"61\">collaborate with similar nanotechnology businesses</strong>, which take its innovations and develop them into commodities that can be sold&#8230;&#8221;</em></li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông qua ví dụ về Kode Biotech, tác giả nhấn mạnh rằng các công ty nên hợp tác (<strong data-path-to-node=\"12,2,0\" data-index-in-node=\"93\">collaborate/cooperate</strong>) với nhau để biến các phát minh thành sản phẩm thực tế có giá trị thương mại.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">35. According to the writer, companies like Previously Unavailable:</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">D. Can be hired to give businesses advice about innovation.</strong></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 8, câu 4 và 6: <em data-path-to-node=\"15,1,0\" data-index-in-node=\"31\">&#8220;Previously Unavailable, a <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"58\">specialist innovation consultancy</strong>&#8230; will <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"100\">lease a team of innovation experts</strong> on a short-term basis to client organizations to assist with conceiving, developing&#8230;&#8221;</em></li>\n<li><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả mô tả Previously Unavailable là một công ty tư vấn chuyên nghiệp (<strong data-path-to-node=\"15,2,0\" data-index-in-node=\"86\">consultancy</strong>), nơi các doanh nghiệp khác có thể thuê (<strong data-path-to-node=\"15,2,0\" data-index-in-node=\"139\">lease</strong>) các chuyên gia để nhận lời khuyên và hỗ trợ thực hiện quá trình đổi mới.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('6c9d3376-43d5-4baf-9aa8-8f33c7cd2556', '2a493320-c627-4c1a-9232-2f815afc09cd', 'fillup', 'Questions 31–40', '<p data-start="101" data-end="169">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p data-start="171" data-end="207"><strong><span style="font-size: 14pt;">Using natural building materials</span></strong></p>
<p data-start="209" data-end="300">With all methods of building using natural materials, a good {foundation} is needed</p>
<h3 data-start="307" data-end="325">Rammed earth</h3>
<p>• A framework made from wood filled with soil<br data-start="371" data-end="374">• The best soil has large quantities of {sand}</p>
<h3 data-start="439" data-end="462">Adobe (mud brick)</h3>
<p data-start="463" data-end="542">• The most suitable soil for adobe bricks contains lots of {clay}</p>
<p data-start="544" data-end="556">Advantages</p>
<ul data-start="557" data-end="646">
<li data-start="557" data-end="589">
<p data-start="559" data-end="589">cheap and {convenient}</p>
</li>
<li data-start="590" data-end="646">
<p data-start="592" data-end="646">little {training} is needed for brick-making</p>
</li>
</ul>
<p data-start="648" data-end="662">Disadvantage</p>
<ul data-start="663" data-end="723">
<li data-start="663" data-end="723">
<p data-start="665" data-end="723">a lot of water, time and {labour} are required</p>
</li>
</ul>
<h3 data-start="730" data-end="747">Straw bales</h3>
<p data-start="748" data-end="927">• Bales – large rectangular blocks of straw</p>
<p data-start="748" data-end="927">• A {roof} needs to be constructed first</p>
<p data-start="748" data-end="927">• The bales are covered with plaster for protection against {insects}</p>
<p data-start="929" data-end="940">Advantage</p>
<ul data-start="941" data-end="982">
<li data-start="941" data-end="982">
<p data-start="943" data-end="982">the bales act as efficient insulation</p>
</li>
</ul>
<h3 data-start="989" data-end="1001">Bamboo</h3>
<p data-start="1002" data-end="1034">• This is a versatile material</p>
<p data-start="1036" data-end="1047">Advantage</p>
<ul data-start="1048" data-end="1112">
<li data-start="1048" data-end="1112">
<p data-start="1050" data-end="1112">the shape of the bamboo stalks gives them {strength}</p>
</li>
</ul>
<p data-start="1114" data-end="1129">Disadvantages</p>
<ul data-start="1130" data-end="1183">
<li data-start="1130" data-end="1154">
<p data-start="1132" data-end="1154">not widely available</p>
</li>
<li data-start="1155" data-end="1183">
<p data-start="1157" data-end="1183">risk of {fire}</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: NATURAL BUILDING MATERIALS</strong></span></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> There is growing interest in building structures using natural materials these days. I’ll begin this lecture by looking at how some of these materials work, some advantages and problems associated with each.</p>\n<p data-path-to-node=\"4\">However, I must start by saying that all these materials and construction techniques require, first and foremost, a solid <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"122\">(31) foundation</strong></span>, which will most often need to be made of concrete. Thus the goal of using 100% natural materials may have to be slightly compromised.</p>\n<hr data-path-to-node=\"5\">\n<h3 data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">RAMMED EARTH</strong></h3>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Lecturer:</strong> One type of natural building material is what is known as rammed earth. Rammed earth is a construction method whereby a framework constructed of wood is set in place to act as temporary walls, and then damp earth or soil is placed within this framework. As it is added, the earth is packed down and subjected to intense compression, either by hand or by using specialized machinery.</p>\n<p data-path-to-node=\"8\">Across parts of Africa today, you can see military fortifications built in this way over 10,000 years ago still standing in remarkably good condition. The most appropriate type of soil for this construction method is one with a high concentration of <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"250\">(32) sand</strong></span> in it, though other kinds of soil are sometimes successfully used. Rammed earth buildings are well suited to dry, arid climates.</p>\n<hr data-path-to-node=\"9\">\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">ADOBE (MUD BRICK)</strong></h3>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Lecturer:</strong> Another form of natural construction is called the Adobe method, or sometimes the mud brick method. This utilizes bricks which can be made from a variety of soils, but are most suitable when made from a soil rich in <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"226\">(33) clay</strong></span>. The bricks have got to be carefully made to prevent them from cracking.</p>\n<p data-path-to-node=\"12\">The main advantage of this Adobe brick method is that the materials are cheap and also that it’s <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"97\">(34) convenient</strong></span> for people in many geographical areas. Thus, Adobe buildings have been traditional forms of construction in many societies and today can be found all over the world. The construction method is also popular because making the bricks requires minimal <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"362\">(35) training</strong>.</span></p>\n<p data-path-to-node=\"13\">However, the Adobe method does have its drawbacks. For proper preparation of the bricks, large quantities of water are required, and because these bricks are manufactured by hand, the process demands significant investment of time as well as <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"242\">(36) labor</strong></span> (hoặc labour), which can be backbreaking and exhausting.</p>\n<hr data-path-to-node=\"14\">\n<h3 data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">STRAW BALES</strong></h3>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Lecturer:</strong> A natural building material which has been popularized in the US is the use of straw bales to create walls. Straw is, of course, dried stalks of plants, especially tall grasses. The straw is shaped into large rectangular blocks called bales, tightly bound together, and these are excellent for use in the building of walls.</p>\n<p data-path-to-node=\"17\">When building with straw bales, the first thing that needs to be done is to construct a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"88\">(37) roof</strong> </span>supported by poles so that work can continue even if it rains. Then the straw bales are stacked up to form walls. The bales are then coated with a layer of plaster which seals and protects them and keeps the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"306\">(38) insects</strong></span> out of them. The most common reason for their use in building today is the fact that they provide a very effective means of insulation for the building.</p>\n<hr data-path-to-node=\"18\">\n<h3 data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">BAMBOO</strong></h3>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Lecturer:</strong> Another great building material is bamboo. This highly versatile plant is one of the fastest-growing plants in the world. One of its primary advantages is due to the hollow, round, and segmented shape of its individual stalks, which give it its <strong data-path-to-node=\"20\" data-index-in-node=\"255\"><span style=\"background-color: #f1c40f;\">(39) strength</span></strong>. And because of its lightweight, it is easy to handle.</p>\n<p data-path-to-node=\"21\">A significant drawback, however, is that the large varieties of bamboo which are best suited for construction grow only in tropical and subtropical regions of the world. And also, because it catches <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"199\">(40) fire</strong></span> easily, bamboo can be problematic and potentially dangerous.</p>\n<p data-path-to-node=\"22\">Now let’s take a look at possible sources of…</p>"}]', 0);
INSERT INTO public.questions VALUES ('a8626adc-7452-40ba-a6c6-a0cd69532f19', 'b0677a84-4b6c-4fe0-8b9a-e8439b348dda', 'radio', 'Questions 1–6', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Palace was the first structure to be built on its site."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Fishbourne Palace was renovated more than once."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Fishbourne Palace was large in comparison with Roman palaces in Italy."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Research is continuing in the area close to Fishbourne Palace."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Researchers agree on the identity of the person for whom Fishbourne Palace was constructed."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Fishbourne Palace was burnt down by local people."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">1 FALSE</strong></p>\n<p data-path-to-node=\"7,0,1,0,0\"><strong data-path-to-node=\"7,0,1,0,0\" data-index-in-node=\"0\">Câu hỏi:</strong> Fishbourne Palace là cấu trúc đầu tiên được xây trên khu đất đó.</p>\n<p data-path-to-node=\"7,0,1,1,0\"><strong data-path-to-node=\"7,0,1,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> “…built… on the site of <strong data-path-to-node=\"7,0,1,1,0\" data-index-in-node=\"48\">Roman army grain stores</strong>…”</p>\n<p data-path-to-node=\"7,0,1,2,0\"><strong data-path-to-node=\"7,0,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước khi có cung điện, nơi đây đã có các kho ngũ cốc (grain stores). Vậy cung điện không phải là đầu tiên.</p>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">2 TRUE</strong></p>\n<p data-path-to-node=\"7,1,1,0,0\"><strong data-path-to-node=\"7,1,1,0,0\" data-index-in-node=\"0\">Câu hỏi:</strong> Cung điện được cải tạo (renovated) nhiều hơn một lần.</p>\n<p data-path-to-node=\"7,1,1,1,0\"><strong data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> “There were <strong data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"32\">extensive alterations</strong> in the 2nd and 3rd centuries AD… <strong data-path-to-node=\"7,1,1,1,0\" data-index-in-node=\"89\">More alterations</strong> were in progress when…”</p>\n<p data-path-to-node=\"7,1,1,2,0\"><strong data-path-to-node=\"7,1,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Alterations” đồng nghĩa với “renovated”. Bài viết nhắc đến các đợt sửa đổi ở thế kỷ 2, thế kỷ 3 và cả lúc sắp bị cháy. Rõ ràng là hơn một lần.</p>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">3 FALSE</strong></p>\n<p data-path-to-node=\"7,2,1,0,0\"><strong data-path-to-node=\"7,2,1,0,0\" data-index-in-node=\"0\">Câu hỏi:</strong> Cung điện lớn khi so sánh với các cung điện ở Ý.</p>\n<p data-path-to-node=\"7,2,1,1,0\"><strong data-path-to-node=\"7,2,1,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> “…approximately <strong data-path-to-node=\"7,2,1,1,0\" data-index-in-node=\"38\">equivalent to</strong> some of the great Roman palaces of Italy…”</p>\n<p data-path-to-node=\"7,2,1,2,0\"><strong data-path-to-node=\"7,2,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Equivalent to” nghĩa là tương đương/ngang bằng, không phải là “lớn hơn” (large in comparison with).</p>\n<p data-path-to-node=\"7,3,0\"><strong data-path-to-node=\"7,3,0\" data-index-in-node=\"0\">4 TRUE</strong></p>\n<p data-path-to-node=\"7,3,1,0,0\"><strong data-path-to-node=\"7,3,1,0,0\" data-index-in-node=\"0\">Câu hỏi:</strong> Nghiên cứu vẫn đang tiếp tục ở khu vực gần cung điện.</p>\n<p data-path-to-node=\"7,3,1,1,0\"><strong data-path-to-node=\"7,3,1,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> “…are involved in <strong data-path-to-node=\"7,3,1,1,0\" data-index-in-node=\"40\">ongoing</strong> archaeological excavation on the site of <strong data-path-to-node=\"7,3,1,1,0\" data-index-in-node=\"89\">nearby</strong>… buildings.”</p>\n<p data-path-to-node=\"7,3,1,2,0\"><strong data-path-to-node=\"7,3,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Ongoing” = “continuing” (đang tiếp diễn); “nearby” = “close to” (gần đó).</p>\n<p data-path-to-node=\"7,4,0\"><strong data-path-to-node=\"7,4,0\" data-index-in-node=\"0\">5 FALSE</strong></p>\n<p data-path-to-node=\"7,4,1,0,0\"><strong data-path-to-node=\"7,4,1,0,0\" data-index-in-node=\"0\">Câu hỏi:</strong> Các nhà nghiên cứu đồng ý về danh tính chủ nhân cung điện.</p>\n<p data-path-to-node=\"7,4,1,1,0\"><strong data-path-to-node=\"7,4,1,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> “…there are <strong data-path-to-node=\"7,4,1,1,0\" data-index-in-node=\"34\">a number of theories</strong>.”</p>\n<p data-path-to-node=\"7,4,1,2,0\"><strong data-path-to-node=\"7,4,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “A number of theories” (nhiều giả thuyết) đồng nghĩa với việc họ chưa thống nhất (disagree), trái ngược với “agree on”.</p>\n<p data-path-to-node=\"7,5,0\"><strong data-path-to-node=\"7,5,0\" data-index-in-node=\"0\">6 NOT GIVEN</strong></p>\n<p data-path-to-node=\"7,5,1,0,0\"><strong data-path-to-node=\"7,5,1,0,0\" data-index-in-node=\"0\">Câu hỏi:</strong> Cung điện bị người dân địa phương đốt.</p>\n<p data-path-to-node=\"7,5,1,1,0\"><strong data-path-to-node=\"7,5,1,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> “…the north wing was destroyed in a fire around 270 AD.”</p>\n<p data-path-to-node=\"7,5,1,2,0\"><strong data-path-to-node=\"7,5,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói bị cháy (fire), không nói ai đốt hay nguyên nhân do đâu.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('3ce787f8-100c-4ce7-9d96-36221f985b51', 'b0677a84-4b6c-4fe0-8b9a-e8439b348dda', 'fillup', 'Questions 7–13', '<p>Complete the notes.<br />
Choose <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER </strong>from the passage for each answer.</p>
<p data-start="307" data-end="331"><strong data-start="310" data-end="331">Fishbourne Palace</strong></p>
<p data-start="333" data-end="353"><strong data-start="337" data-end="353">Construction</strong></p>
<ul data-start="354" data-end="555">
<li data-start="354" data-end="424">The first buildings on the site contained food for the {Roman army}</li>
<li data-start="425" data-end="471">The palace building surrounded {gardens}</li>
<li data-start="472" data-end="555">In the 2nd and 3rd centuries colour was added to the {floors} of the palace.</li>
</ul>
<p data-start="562" data-end="579"><strong data-start="566" data-end="579">Discovery</strong></p>
<ul data-start="580" data-end="651">
<li data-start="580" data-end="651">The first part of the palace to be found was part of a {wall}</li>
</ul>
<p data-start="658" data-end="686"><strong data-start="662" data-end="686">Possible inhabitants</strong></p>
<ul data-start="687" data-end="913">
<li data-start="687" data-end="739"><strong data-start="689" data-end="703">Cogidubnus</strong> – he is named in several writings</li>
<li data-start="740" data-end="829"><strong data-start="742" data-end="765">Sallustius Lucullus</strong> – he may have lived there until approximately {93} <strong data-start="812" data-end="827">AD</strong></li>
<li data-start="830" data-end="861"><strong data-start="832" data-end="842">Verica</strong> – a British king</li>
<li data-start="862" data-end="913"><strong data-start="864" data-end="876">Catuarus</strong> – his {gold ring} was found there</li>
</ul>
<p data-start="920" data-end="939"><strong data-start="924" data-end="939">Present Day</strong></p>
<ul data-start="940" data-end="1005">
<li data-start="940" data-end="1005">A {modern museum}has been built on the site to help protect it.</li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">7 Roman army</strong></p>\n<p data-path-to-node=\"11,0,1,0,0\"><strong data-path-to-node=\"11,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> “…site of <strong data-path-to-node=\"11,0,1,0,0\" data-index-in-node=\"32\">Roman army</strong> grain stores…”</p>\n<p data-path-to-node=\"11,0,1,1,0\"><strong data-path-to-node=\"11,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Kho chứa thức ăn (ngũ cốc) của quân đội La Mã.</p>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">8 (formal) gardens</strong></p>\n<p data-path-to-node=\"11,1,1,0,0\"><strong data-path-to-node=\"11,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> “…built around <strong data-path-to-node=\"11,1,1,0,0\" data-index-in-node=\"37\">formal gardens</strong>…”</p>\n<p data-path-to-node=\"11,1,1,1,0\"><strong data-path-to-node=\"11,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cung điện bao quanh những khu vườn trang trọng.</p>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">9 (mosaic) floors</strong></p>\n<p data-path-to-node=\"11,2,1,0,0\"><strong data-path-to-node=\"11,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> “…original black and white <strong data-path-to-node=\"11,2,1,0,0\" data-index-in-node=\"49\">mosaic floors</strong> being overlaid with more sophisticated colored ones…”</p>\n<p data-path-to-node=\"11,2,1,1,0\"><strong data-path-to-node=\"11,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Màu sắc được thêm vào các sàn nhà khảm đá.</p>\n<p data-path-to-node=\"11,3,0\"><strong data-path-to-node=\"11,3,0\" data-index-in-node=\"0\">10 wall</strong></p>\n<p data-path-to-node=\"11,3,1,0,0\"><strong data-path-to-node=\"11,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> “…workmen accidentally uncovered a <strong data-path-to-node=\"11,3,1,0,0\" data-index-in-node=\"57\">wall</strong>…”</p>\n<p data-path-to-node=\"11,3,1,1,0\"><strong data-path-to-node=\"11,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thứ đầu tiên được tìm thấy tình cờ là một bức tường.</p>\n<p data-path-to-node=\"11,4,0\"><strong data-path-to-node=\"11,4,0\" data-index-in-node=\"0\">11.  93</strong></p>\n<p data-path-to-node=\"11,4,1,0,0\"><strong data-path-to-node=\"11,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> “…Lucullus was executed… in or shortly after <strong data-path-to-node=\"11,4,1,0,0\" data-index-in-node=\"69\">93</strong> AD.”</p>\n<p data-path-to-node=\"11,4,1,1,0\"><strong data-path-to-node=\"11,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lucullus sống ở đó đến khoảng năm 93 SCN (năm bị xử tử).</p>\n<p data-path-to-node=\"11,5,0\"><strong data-path-to-node=\"11,5,0\" data-index-in-node=\"0\">12 (gold) ring</strong></p>\n<p data-path-to-node=\"11,5,1,0,0\"><strong data-path-to-node=\"11,5,1,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> “…discovery of a <strong data-path-to-node=\"11,5,1,0,0\" data-index-in-node=\"39\">gold ring</strong> belonging to him [Catuarus].”</p>\n<p data-path-to-node=\"11,5,1,1,0\"><strong data-path-to-node=\"11,5,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tìm thấy chiếc nhẫn của Catuarus.</p>\n<p data-path-to-node=\"11,6,0\"><strong data-path-to-node=\"11,6,0\" data-index-in-node=\"0\">13 (modern) museum</strong></p>\n<p data-path-to-node=\"11,6,1,0,0\"><strong data-path-to-node=\"11,6,1,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> “A <strong data-path-to-node=\"11,6,1,0,0\" data-index-in-node=\"23\">modern museum</strong> has been built… incorporating most of the visible remains…”</p>\n<p data-path-to-node=\"11,6,1,1,0\"><strong data-path-to-node=\"11,6,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bảo tàng được xây để bảo vệ/lưu giữ các di tích.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('4a6a5934-afe3-4cb0-8f9f-8efcec05b466', 'fc3c63e2-33c1-4681-ab31-aed26f251a57', 'matching', 'Question 14-19', NULL, '<p>Reading Passage 2 has five sections.</p>
<p>Choose the correct heading or each section rom the list of headings below.</p>
<p>Choose the correct letter, <strong>i-vii</strong> in boxes <strong>14-18.</strong></p>
', 'matching', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. The desire to make expensive jewellery"}, {"optionText": "ii The clues that indicate ancient items were decorative"}, {"optionText": "iii Querying the changes in the value of traded items"}, {"optionText": "iv A natural human talent"}, {"optionText": "v How status can be gained from ownership of goods"}, {"optionText": "vi. Recent finds alter theories about when consumerism started"}, {"optionText": "vii. Changes in research methods"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">Đáp án &amp; Giải thích: BORN TO TRADE</strong></p>\n<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">1. Đoạn 1 (Paragraph 1) – Đáp án: iv (A natural human talent)</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Câu đầu tiên của đoạn 1.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"3,1,0\" data-index-in-node=\"11\">“Humans are <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"23\">born to trade</strong>… the heart of commerce is an <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"68\">instinctive ability</strong>… Evidence… leaves little doubt that the exchange of food and flavors is <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"164\">innate</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định con người sinh ra đã có bản năng giao thương (born to trade). Các từ khóa như <em data-path-to-node=\"3,2,0\" data-index-in-node=\"109\">instinctive ability</em> (khả năng bản năng) và <em data-path-to-node=\"3,2,0\" data-index-in-node=\"152\">innate</em> (bẩm sinh) hoàn toàn khớp với tiêu đề “A natural human talent” (Một tài năng tự nhiên của con người).</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">2. Đoạn 2 (Paragraph 2) – Đáp án: iii (Querying the changes in the value of traded items)</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Cuối đoạn 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,1,0\" data-index-in-node=\"11\">“Clearly, the <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"25\">worth of such goods is not inherent</strong> but resides in certain <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"84\">intangible qualities</strong>… When did humans start holding these goods in <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"153\">such high esteem</strong>?”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này đặt ra câu hỏi về giá trị của hàng hóa. Thay vì giá trị thực dụng (subsistence), con người bắt đầu coi trọng những giá trị vô hình (intangible qualities). Câu hỏi ở cuối đoạn chính là một sự “querying” (thắc mắc/truy vấn) về sự thay đổi giá trị này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">3. Đoạn 3 (Paragraph 3) – Đáp án: vi (Recent finds alter theories about when consumerism started)</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Giữa đoạn 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,1,0\" data-index-in-node=\"11\">“All the archaeological evidence… has up to now pointed to a date of around <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"89\">40,000 years ago</strong>. However, <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"116\">discoveries in Africa are pushing the origins of consumerism much further back</strong>… many of them proved to be more than <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"234\">100,000 years old</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước đây người ta tin văn hóa tiêu dùng bắt đầu từ 40,000 năm trước, nhưng những khám phá mới (recent finds) tại hang Blombos đã đẩy mốc thời gian này lùi xa hơn (100,000 năm), làm thay đổi các lý thuyết cũ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">4. Đoạn 4 (Paragraph 4) – Đáp án: ii (The clues that indicate ancient items were decorative)</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đầu và giữa đoạn 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,1,0\" data-index-in-node=\"11\">“Each cluster contains shells of a <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"46\">similar size and colour</strong> with <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"75\">consistently placed holes</strong>. What’s more, all the beads display a <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"139\">pattern of wear suggesting friction from rubbing against thread, clothes</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả liệt kê các “clues” (manh mối) như: kích thước đồng đều, lỗ khoan nhất quán và dấu vết mòn do cọ xát vào chỉ/quần áo để chứng minh những vỏ ốc này được dùng làm đồ trang trí (beads/jewellery) chứ không phải do tự nhiên tích tụ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">5. Đoạn 5 (Paragraph 5) – Đáp án: v (How status can be gained from ownership of goods)</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Giữa đoạn 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,1,0\" data-index-in-node=\"11\">“Among our ancestors, superior skills… would have brought respect – in other words, <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"97\">prestige</strong>. And because prestige brings social benefits, <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"152\">people would want to show off</strong> their talents… through demonstrating <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"221\">possession of material items</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích mối liên hệ giữa việc sở hữu hàng hóa và địa vị xã hội (status/prestige). Việc sở hữu những vật phẩm hiếm (như răng thú dữ hay xe Bugatti ngày nay) là cách để khẳng định vị thế và sự thành công của cá nhân.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('7906b628-b481-412c-af09-5a08680dd945', '6a45cfea-1f8b-4031-82fd-b931cebd3ecb', 'checkbox', 'Questions 23 and 24', '', '<p>Choose <strong>TWO </strong>letters, <strong>A-E</strong>.</p>
<p>Which <strong>TWO </strong>points did students most frequently make about music practice?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. They prefer to practise alone."}, {"correct": false, "option_text": "B. They try to practise every day."}, {"correct": true, "option_text": "C. They are motivated to practise by fear."}, {"correct": false, "option_text": "D. They feel they don''t do enough practice."}, {"correct": true, "option_text": "E. They enjoy the challenge of a difficult piece."}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('12ccd6c5-a448-4020-baba-e67bf3e7ce61', '9b6d9897-cf82-4f9c-a390-603e391efdb0', 'matching', 'Questions 36-40', '', '<p>Complete each sentence with the correct ending, A-G, below.</p>', 'matching_paragraph_information', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "A Innovators do not get enough credit for their own ideas."}, {"optionText": "B Innovation may influence a completely different field."}, {"optionText": "C Expressing what everyone already knows is pointless."}, {"optionText": "D Innovation can be enhanced through collaboration with similar companies."}, {"optionText": "E Innovation requires a great deal of hard work."}, {"optionText": "F Copying ideas that already exist is not true innovation."}, {"optionText": "G Certain personality types can limit innovation."}], "matchingItems": [{"questionPart": "A book about the life and work of Thomas Edison suggests that", "correctAnswer": "E"}, {"questionPart": "People who have worked for CEOs like Steve Jobs claim that", "correctAnswer": "G"}, {"questionPart": "Critics of Harford''s 2011 TED Talk argue that", "correctAnswer": "C"}, {"questionPart": "Steven Johnson''s hummingbird effect proposes that", "correctAnswer": "B"}, {"questionPart": "Kode Biotech CEO Steve Henry believes that", "correctAnswer": "D"}]}', 'null', '[{"content": "<p><strong data-path-to-node=\"2\" data-index-in-node=\"0\">36. A book about the life and work of Thomas Edison suggests that</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: E. Innovation requires a great deal of hard work.</strong></li>\n<li><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, câu 2: <em data-path-to-node=\"3,1,0\" data-index-in-node=\"26\">“…the book Edison: His Life and Inventions shows that Edison’s own inspiration usually resulted from <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"129\">laborious experimentation</strong>, rather than a moment of genius.”</em></li>\n<li><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cuốn sách về Edison chỉ ra rằng những phát minh của ông là kết quả của quá trình thử nghiệm gian khổ (<strong data-path-to-node=\"3,2,0\" data-index-in-node=\"114\">laborious experimentation</strong>), tương ứng với cụm từ <strong data-path-to-node=\"3,2,0\" data-index-in-node=\"163\">“a great deal of hard work”</strong> (rất nhiều công sức).</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">37. People who have worked for CEOs like Steve Jobs claim that</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: G. Certain personality types can limit innovation.</strong></li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu cuối: <em data-path-to-node=\"6,1,0\" data-index-in-node=\"29\">“Jobs’ former employees have suggested this type of <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"81\">demanding behavior</strong> affects sickness rates and group morale, which in turn may <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"159\">squash creativity and innovation</strong>.”</em></li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những nhân viên cũ cho rằng tính cách khắt khe (personality type/demanding behavior) của các CEO như Jobs có thể dập tắt (<strong data-path-to-node=\"6,2,0\" data-index-in-node=\"134\">squash/limit</strong>) sự sáng tạo và đổi mới.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38. Critics of Harford’s 2011 TED Talk argue that</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: C. Expressing what everyone already knows is pointless.</strong></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, câu 2: <em data-path-to-node=\"9,1,0\" data-index-in-node=\"26\">“It sounds like common sense, and some commentators have claimed Harford’s TED Talk was <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"114\">not persuasive because it was stating the obvious</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những người chỉ trích cho rằng bài nói của Harford không thuyết phục vì nó chỉ đang nói những điều hiển nhiên (<strong data-path-to-node=\"9,2,0\" data-index-in-node=\"123\">stating the obvious</strong>), tương ứng với ý <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"161\">“expressing what everyone already knows”</strong>.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">39. Steven Johnson’s hummingbird effect proposes that</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: B. Innovation may influence a completely different field.</strong></li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 6, câu 3: <em data-path-to-node=\"12,1,0\" data-index-in-node=\"26\">“This points out that progress in a specific area or discipline can end up <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"101\">triggering small but significant developments elsewhere entirely</strong>.”</em></li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Hiệu ứng chim ruồi (hummingbird effect) mô tả việc tiến bộ ở một lĩnh vực này có thể tạo ra tác động hoặc sự phát triển ở một lĩnh vực hoàn toàn khác (<strong data-path-to-node=\"12,2,0\" data-index-in-node=\"163\">elsewhere entirely/completely different field</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">40. Kode Biotech CEO Steve Henry believes that</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án: D. Innovation can be enhanced through collaboration with similar companies.</strong></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 7, câu cuối: <em data-path-to-node=\"15,1,0\" data-index-in-node=\"29\">“Instead, Kode’s approach is to <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"61\">collaborate with similar nanotechnology businesses</strong>, which take its innovations and develop them into commodities…”</em></li>\n<li><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Steve Henry khẳng định phương pháp của Kode là hợp tác (<strong data-path-to-node=\"15,2,0\" data-index-in-node=\"68\">collaborate</strong>) với các doanh nghiệp tương tự để tối ưu hóa việc đưa đổi mới vào thị trường.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('91b917ea-0e00-44cc-8b5b-9a188946c443', '7eb604be-a003-49e1-80cc-2694d253674d', 'fillup', 'Questions 1–10', '<p data-start="94" data-end="169">Complete the notes below.</p>
<p data-start="94" data-end="169">Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p data-start="176" data-end="209"><strong>Shipping of personal belongings</strong></p>
<p data-start="211" data-end="223"><strong>Example</strong>:</p>
<p data-start="224" data-end="279">Special boxes for packing are provided free of charge.</p>
<p data-start="286" data-end="317"><strong>The company will transport:</strong></p>
<ul data-start="318" data-end="373">
<li data-start="318" data-end="360">
<p data-start="320" data-end="360">some electrical goods, e.g. a computer</p>
</li>
<li data-start="361" data-end="373">
<p data-start="363" data-end="373">a {bicycle}</p>
</li>
</ul>
<p data-start="380" data-end="415"><strong>The company will not transport:</strong></p>
<ul data-start="416" data-end="553">
<li data-start="416" data-end="464">
<p data-start="418" data-end="464">any single item weighing more than {40} kg</p>
</li>
<li data-start="465" data-end="511">
<p data-start="467" data-end="511">any {liquids} (for security reasons) or foods</p>
</li>
<li data-start="512" data-end="553">
<p data-start="514" data-end="553">anything in containers made of {plastic}</p>
</li>
</ul>
<p data-start="560" data-end="584"><strong>Additional services:</strong></p>
<ul data-start="585" data-end="678">
<li data-start="585" data-end="607">
<p data-start="587" data-end="607">special deliveries</p>
</li>
<li data-start="608" data-end="630">
<p data-start="610" data-end="630">delivery on {Saturdays}</p>
</li>
<li data-start="631" data-end="651">
<p data-start="633" data-end="651">express delivery</p>
</li>
<li data-start="652" data-end="678">
<p data-start="654" data-end="678">organisation of {storage}</p>
</li>
</ul>
<p data-start="685" data-end="706"><strong>Example of price:</strong></p>
<ul data-start="707" data-end="808">
<li data-start="707" data-end="808">
<p data-start="709" data-end="808">for fifteen boxes and one violin sent from the UK to {Sweden},<br data-start="769" data-end="772">the cost would be about £ {575}</p>
</li>
</ul>
<p data-start="815" data-end="835"><strong>Payment options:</strong></p>
<ul data-start="836" data-end="902">
<li data-start="836" data-end="902">
<p data-start="838" data-end="902">on the phone by debit or credit card, or in cash to the {driver}</p>
</li>
</ul>
<p data-start="909" data-end="934"><strong>Documentation needed:</strong></p>
<ul data-start="935" data-end="979">
<li data-start="935" data-end="958">
<p data-start="937" data-end="958">photocopy of {passport}</p>
</li>
<li data-start="959" data-end="979">
<p data-start="961" data-end="979">insurance papers</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>SECTION 1: SHIPPING OF PERSONAL BELONGINGS</strong><br><strong>Staff</strong>: Hello, Move It Shipping.</p>\n<p><strong>Customer</strong>: Hi, I’d like a few more details about your services, please.</p>\n<p><strong>Staff</strong>: Certainly.</p>\n<p><strong>Customer</strong>: I’ve been on your website looking into sending some things abroad when I go away to study next term. I see that you provide special empty (Example) boxes so that I can pack them myself, and you then transport them.</p>\n<p><strong>Staff</strong>: That’s right, we provide those free of charge.</p>\n<p><strong>Customer</strong>: And can I ask what goods you can transport? Like, do you take electrical goods?</p>\n<p><strong>Staff</strong>: Well, it depends. If you’ve got something like a computer, that’s fine. But things like washing machines and fridges are too heavy and bulky for our service.</p>\n<p><strong>Customer</strong>: No, I wouldn’t be taking that sort of stuff.</p>\n<p><strong>Staff</strong>: You can always check with us if there’s anything you’re not sure about.</p>\n<p><strong>Customer</strong>: Including… I was wondering about my <span style=\"background-color: #f1c40f;\"><strong>(1) bicycle</strong></span>. I suppose that would be too bulky?</p>\n<p><strong>Staff</strong>: No, that’s fine. Though we wouldn’t be able to take a motorbike, sure.</p>\n<p><strong>Customer</strong>: Is there anything else you don’t take?</p>\n<p><strong>Staff</strong>: Well, basically the service is restricted to what one man can lift, so <span style=\"background-color: #f1c40f;\"><strong>(2) 40</strong></span> kg is the maximum for each package. We do have a list of particular things we can’t transport on our website, but I’ll tell you the main points. So in order to comply with security regulations, we don’t take any sort of <strong><span style=\"background-color: #f1c40f;\">(3) liquids</span></strong>, and we also don’t accept any type of foods.</p>\n<p><strong>Customer</strong>: And if you provide your own containers rather than using ours, we only allow certain types. So can I use cardboard containers?</p>\n<p><strong>Staff</strong>: Yes, they’re okay if they’re strong enough. But we won’t carry things that have been packed in <span style=\"background-color: #f1c40f;\"><strong>(4) plastic</strong></span> containers—they crack and break so easily that our policy is simply not to take them.</p>\n<p><strong>Customer</strong>: Okay, fine. And once I’ve packed everything, you can collect my things from my home and deliver them to wherever I live abroad, is that right?</p>\n<p><strong>Staff</strong>: Yes, and we do have some special services. For example, we can make special arrangements to deliver on <strong><span style=\"background-color: #f1c40f;\">(5) Saturdays</span></strong> if that’s more convenient for you. Or if you’re in a hurry, we have an express delivery option. There’s a surcharge for these services, of course, but it’s very reasonable.</p>\n<p><strong>Customer</strong>: OK, I’ll keep that in mind. And what happens if the delivery can’t be made for some reason? Like if I haven’t finalised my accommodation, can you keep my stuff for me for a few days?</p>\n<p><strong>Staff</strong>: Yes, we can arrange <span style=\"background-color: #f1c40f;\"><strong>(6) storage</strong></span>, though again, there would be an extra charge for that, sure.</p>\n<p><strong>Customer</strong>: And can you give me an idea of your prices?</p>\n<p><strong>Staff</strong>: Of course. Roughly how much would you want transported?</p>\n<p><strong>Customer</strong>: Say for example I had 15 boxes, and I’ve also got a violin that would need packing with special care, I think.</p>\n<p><strong>Staff</strong>: OK, and it would be collection in the UK?</p>\n<p><strong>Customer</strong>: Yes, and <span style=\"background-color: #f1c40f;\"><strong>(7) Sweden</strong></span> would be the destination.</p>\n<p><strong>Staff</strong>: OK, I’ll do a quick calculation. Let me just get that up on the screen. 15 boxes and one special package… let’s see… it’d be something in the order of £(<span style=\"background-color: #f1c40f;\"><strong>8) 575.</strong></span></p>\n<p><strong>Customer</strong>: Right. And how would I pay that?</p>\n<p><strong>Staff</strong>: Well, you can pay by debit or credit card over the phone, or if you prefer to pay in cash, you can just give it to the <span style=\"background-color: #f1c40f;\"><strong>(9) driver</strong></span> when he arrives to collect your belongings, and he’ll give you a receipt.</p>\n<p><strong>Customer</strong>: Fine.</p>\n<p><strong>Staff</strong>: And at the same time, you’ll need to hand over some documentation. So you’ll need a copy of your <span style=\"background-color: #f1c40f;\"><strong>(10) passport.</strong></span></p>\n<p><strong>Customer</strong>: A photocopy?</p>\n<p><strong>Staff</strong>: That’s right, so make sure you get that done in advance and have it ready with you. Then there are also some papers you’ll need that we’ll send you in advance so that you can get them completed in good time. The most important ones are the insurance documents…</p>"}]', 0);
INSERT INTO public.questions VALUES ('541304c7-3a90-4788-b10a-0157f1d943d5', 'a1112cfc-f151-4f5f-bb43-1f9cc01bfe3e', 'radio', 'Questions 1–6', '<p>Choose TRUE if the statement agrees with the information given in the text, choose FALSE if the statement contradicts the information, or choose NOT GIVEN if there is no information on this. </p>
<p> </p>
', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Palace was the first structure to be built on its site."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Fishbourne Palace was renovated more than once."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Fishbourne Palace was large in comparison with Roman palaces in Italy."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Research is continuing in the area close to Fishbourne Palace."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Researchers agree on the identity of the person for whom Fishbourne Palace was constructed."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Fishbourne Palace was burnt down by local people."}]', 'null', 'null', 'null', '[{"content": "<p>1. FALSE<br />\n(Đoạn 4, “The first buildings to be erected on the site were constructed in the early part of the conquest in 43 AD… Later… the palace itself… was constructed around 73–75 AD.”)<br />\n→ Có công trình khác được xây trước (kho chứa, nhà gỗ) nên palace không phải công trình đầu tiên.</p>\n<p>2. TRUE<br />\n(Đoạn 1, “There were extensive alterations in the 2nd and 3rd centuries AD, with many of the original black and white mosaic floors being overlaid with more sophisticated coloured ones.”)<br />\n→ Có nhiều lần sửa đổi qua các thế kỷ → được cải tạo hơn một lần.</p>\n<p>3. FALSE<br />\n(Đoạn 3, “Fishbourne Palace would have been approximately equivalent to some of the great Roman palaces of Italy.”)<br />\n→ Kích thước chỉ tương đương, không lớn hơn → phát biểu sai.</p>\n<p>4. TRUE<br />\n(Đoạn 3, “A team of volunteers and professional archaeologists are involved in an ongoing archaeological excavation on the site of nearby, possibly military, buildings.”)<br />\n→ Nghiên cứu vẫn đang tiếp tục gần khu vực Fishbourne Palace.</p>\n<p>5. FALSE<br />\n(Đoạn 6–7, “With regard to who lived in Fishbourne Palace, there are a number of theories…”)<br />\n→ Có nhiều giả thuyết khác nhau (Cogidubnus, Lucullus, Verica, Catuarus) → không có sự đồng thuận.</p>\n<p>6. NOT GIVEN<br />\n(Đoạn 1, “…the palace burnt down in around 270 AD, after which it was abandoned.”)<br />\n→ Không nói ai gây ra vụ cháy, chỉ nêu sự kiện → không có thông tin.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('b108edf4-f1a5-4ecf-aded-fc0339537422', 'aff5f03b-531f-4364-98df-910d0d47a6be', 'radio', 'Questions 27–32', '', '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer,<strong>NO</strong> if the statement contradicts the claims of the writer,<strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The Grimm brothers believed they would achieve international fame."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The Grimm brothers were forced to work in secret."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Some parents today still think Grimm fairy tales are not suitable for children."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The first edition of Grimm’s fairy tales sold more widely in England than in Germany."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Adults like reading Grimm’s fairy tales for reasons different from those of children."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The Grimm brothers based the story “Cinderella” on the life of Dorothea Viehmann"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. The Grimm brothers believed they would achieve international fame. — {NO}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Such lasting <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"34\">fame would have shocked the humble Grimms</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói rằng sự nổi tiếng bền vững này sẽ làm anh em nhà Grimm khiêm tốn phải <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"94\">kinh ngạc (shocked)</strong>. Điều này trái ngược với việc họ “tin rằng” mình sẽ đạt được sự nổi tiếng quốc tế.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. The Grimm brothers were forced to work in secret. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1 có nói họ làm việc khi Đức bị Napoleon xâm lược và muốn bảo tồn truyền thống đang bị đe dọa.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói họ là những học giả “nghiện việc” (workaholic) làm việc trong một căn hộ chật hẹp, nhưng <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"117\">không hề có thông tin</strong> nào nói họ bị “ép buộc phải làm việc trong bí mật” (forced to work in secret).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. Some parents today still think Grimm fairy tales are not suitable for children. — {YES}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Even <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">today some protective parents shy from the Grimms’ tales</strong> because of their reputation for <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"115\">violence</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Shy from” (né tránh) đồng nghĩa với việc họ nghĩ những câu chuyện này không phù hợp (not suitable) cho trẻ em vì yếu tố bạo lực. Thông tin này khớp hoàn toàn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. The first edition of Grimm’s fairy tales sold more widely in England than in Germany. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“English publishers led the way, issuing high-quality picture books…”</em> và đoạn 1 nói <em data-path-to-node=\"11,0,0\" data-index-in-node=\"106\">“the collection sold modestly in Germany”</em>.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói ấn bản đầu tiên bán rất chậm ở Đức và các nhà xuất bản Anh dẫn đầu trong việc in sách tranh, nhưng <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"126\">không có sự so sánh cụ thể</strong> về số lượng bản bán ra của “ấn bản đầu tiên” (first edition) giữa Anh và Đức.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. Adults like reading Grimm’s fairy tales for reasons different from those of children. — {YES}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> * Trẻ em thích vì: <em data-path-to-node=\"13,0,0\" data-index-in-node=\"39\">“handsome lads and beautiful damsels… magic… triumph over giants”</em> (phép thuật, cái thiện thắng cái ác).</p>\n<ul data-path-to-node=\"13,0,1\">\n<li>\n<p data-path-to-node=\"13,0,1,0,0\">Người lớn (phụ huynh) thích vì: <em data-path-to-node=\"13,0,1,0,0\" data-index-in-node=\"32\">“they approve of the <strong data-path-to-node=\"13,0,1,0,0\" data-index-in-node=\"53\">finger-wagging lessons</strong> inserted into the stories: keep your promises, don’t talk to strangers…”</em> (các bài học đạo đức, giáo dục).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trẻ em đọc vì sự kỳ ảo và mơ mộng, còn người lớn đọc vì mục đích giáo dục hành vi. Hai lý do này là hoàn toàn khác nhau (different reasons).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">32. The Grimm brothers based the story “Cinderella” on the life of Dorothea Viehmann. — {NO}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“Among her [Dorothea Viehmann] treasure was <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"64\">“Aschenputtel” – Cinderella</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dorothea Viehmann là một trong những <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"49\">người kể chuyện</strong> (storytellers) cho anh em nhà Grimm. Bà là người kể lại câu chuyện Cinderella cho họ ghi chép, chứ không phải anh em nhà Grimm lấy cuộc đời bà để viết nên nhân vật Cinderella. (Dựa trên lời kể khác với dựa trên cuộc đời).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('c7878b31-890c-4964-b6ab-ad12a72f7892', '66c96c6b-6658-4eb4-91b4-a83422eb09d7', 'radio', 'Questions 1–7', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Before attending college Jacob was capable of recognising people he knew well."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Researchers believe that prosopagnosia may be a growing problem."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "It is harder to identify developmental prosapagnosics in babies than in young children."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "A German study seems to support the Harvard and UCL research findings."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In general, prosopagnosics are aware that other people can recognize faces more easily than they can."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In most cases, prosopagnosics have developed ways to deal with their problem."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The study of prosopagnosia may help neuroscientists to treat different kinds of brain injury."}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"4\">1. Before attending college Jacob was capable of recognising people he knew well.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “He had had the same trouble all his life. Friends and relatives would greet him and he would have <strong>no idea who they were</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Jacob đã gặp vấn đề nhận dạng người thân và bạn bè (<em>people he knew well</em>) <strong>suốt đời</strong>, mâu thuẫn với việc có khả năng nhận ra họ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"7\">2. Researchers believe that prosopagnosia may be a growing problem.</h3>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3 &amp; 4) Việc khám phá ra <strong>dạng thứ hai</strong> (<em>developmental prosopagnosia</em>) cùng các khảo sát cho thấy tỷ lệ lên tới 2-2.5% (một con số lớn hơn nhiều so với “a few dozen cases” trước đây), cho thấy đây là một <strong>vấn đề lớn hơn/phổ biến hơn</strong> (<em>growing problem</em> về mặt nhận thức) so với suy nghĩ ban đầu.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Mặc dù bài đọc không dùng từ “growing”, nhưng ngữ cảnh khám phá ra tỷ lệ cao bất ngờ cho thấy các nhà nghiên cứu nhận thấy đây là một vấn đề có tầm quan trọng <strong>đang gia tăng</strong>.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">3. It is harder to identify developmental prosopagnosics in babies than in young children.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> Bài đọc đề cập đến chứng bệnh này có thể có từ khi sinh ra (<em>present from birth</em>), nhưng <strong>không so sánh</strong> mức độ khó khăn trong việc xác định chứng bệnh giữa trẻ sơ sinh và trẻ nhỏ.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Thiếu thông tin so sánh trực tiếp mức độ khó khăn giữa hai nhóm tuổi.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">4. A German study seems to support the Harvard and UCL research findings.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) Nghiên cứu của Đức đã <strong>“similarly reported”</strong> (báo cáo tương tự) rằng 2.5% học sinh gặp vấn đề nhận dạng khuôn mặt.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Việc báo cáo kết quả <strong>tương tự</strong> (<em>similarly reported</em>) cho thấy nghiên cứu của Đức ủng hộ các phát hiện của Harvard và UCL.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">5. In general, prosopagnosics are aware that other people can recognize faces more easily than they can.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “…they <strong>often don’t realise that other people have better recognition skills than they do</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Người mắc chứng mù mặt thường <strong>không nhận ra</strong> (<em>don’t realise</em>) rằng người khác có kỹ năng nhận dạng khuôn mặt tốt hơn họ, mâu thuẫn với việc họ “nhận thức được” (<em>aware</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"19\">6. In most cases, prosopagnosics have developed ways to deal with their problem.</h3>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “<strong>the majority of developmental prosopagnosics possess strategies that allow them to get around their difficulty</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong>Giải thích:</strong> Phần lớn người mắc chứng mù mặt (<em>majority</em>) đã phát triển các <strong>chiến lược</strong> (<em>strategies</em> / ways to deal with their problem) để vượt qua khó khăn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"22\">7. The study of prosopagnosia may help neuroscientists to treat different kinds of brain injury.</h3>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “…This difference, they believe, could help <strong>solve the problem of how the brain deals with information in general</strong>: not just visual data.”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong>Giải thích:</strong> Văn bản khẳng định nghiên cứu này có thể giúp giải quyết vấn đề về cách bộ não xử lý thông tin <strong>nói chung</strong>. Tuy nhiên, nó <strong>không nói rõ</strong> rằng điều này sẽ trực tiếp dẫn đến việc <strong>điều trị</strong> (<em>treat</em>) các loại <strong>chấn thương não khác nhau</strong> (<em>different kinds of brain injury</em>).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('3d712d1a-28e0-4e79-af32-3eab9c31536d', '66c96c6b-6658-4eb4-91b4-a83422eb09d7', 'fillup', 'Questions 8–13', '<div class="quests-inner-desc">
<div class="txt">
<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY </strong>from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><span style="font-size: 12pt;"><strong>The challenges for prosopagnosia researchers</strong></span></p>
<p><strong>Differences in prosopagnosics</strong></p>
<p>As we as being unable to recognize facial features, prosopagnosics may also have problems recognizing</p>
<p>– commonly seen {animals} and objects.</p>
<p>– the {emotion} on someone else’s face.</p>
<p>Some prosopagnosics can recognize that people are regarded as attractive by others.</p>
<p><strong>Causes of prosopagnosia</strong></p>
<p>Prosopagnosia may be caused by</p>
<p>– just one {gene} according to Martina Gruter</p>
<p>– a defect in the {left}<span class="fill-history-correct"> </span>eye according to Brad Duchaine</p>
<p><strong>Treatment for prosopagnosia</strong></p>
<p>Joseph Degutis patent proved he had been successfully trained to recognize faces inside the {laboratory} and in the outside world.</p>
<p>Duchaine’s training may allow prosopagnosics to recognise faces belonging to family and workmates.</p>
<p>Thomas Gruter doubts that train will work and mentions that {cheating} by some subjects can affect research results.</p>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"25\">8. Differences in prosopagnosics: As well as being unable to recognize facial features, prosopagnosics may also have problems recognizing – commonly seen <strong>animals</strong> and objects.</h3>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong>Đáp án:</strong> <strong>animals</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “…others have trouble with ordinary everyday objects and, so it turns out, <strong>animals</strong> which would normally be familiar as well.”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"28\">9. – the <strong>emotion</strong> on someone else’s face.</h3>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>emotion</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “When some have been tested they could identify the <strong>emotion</strong> which was conveyed on another’s face, even though the face itself seemed unfamiliar…”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"31\">10. Causes of prosopagnosia: Prosopagnosia may be caused by – just one <strong>gene</strong> according to Martina Gruter.</h3>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong>Đáp án:</strong> <strong>gene</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “…the German team believe they have good evidence that a single <strong>gene</strong> could be responsible.”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"34\">11. – a defect in the <strong>left</strong> eye according to Brad Duchaine.</h3>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong>Đáp án:</strong> <strong>left</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “…and when it’s the <strong>left</strong> one, being unable to see through this eye during the first two months of life is a major risk factor for prosopagnosia.”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"37\">12. Treatment for prosopagnosia: Joseph Degutis patent proved he had been successfully trained to recognize faces inside the <strong>laboratory</strong> and in the outside world.</h3>\n<ul data-path-to-node=\"38\">\n<li>\n<p data-path-to-node=\"38,0,0\"><strong>Đáp án:</strong> <strong>laboratory</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"38,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 9) “…recently reported successfully training a severe developmental prosopagnosic to recognise faces during tests carried out in the <strong>laboratory</strong>.”</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"40\">13. Thomas Gruter doubts that train will work and mentions that <strong>cheating</strong> by some subjects can affect research results.</h3>\n<ul data-path-to-node=\"41\">\n<li>\n<p data-path-to-node=\"41,0,0\"><strong>Đáp án:</strong> <strong>cheating</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"41,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 9) “He also points out that <strong>cheating</strong> is a possibility during tests and provides an example.”</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('2f672f0f-bfa6-48e1-9019-f259ecc21374', 'fc3c63e2-33c1-4681-ab31-aed26f251a57', 'matching', 'Questions 22-26', NULL, '<p>Complete the summary below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>Why certain objects are valued?</strong></p>\r\n<p>Some researchers argue that we may use ownership of desirable goods to demonstrate our strength and fitness as other {D. species} use their attractive physical features. Showing off one’s superiority is not a new phenomenon, and even in ancient times, successful people would have gained {B. respect} from this. A desire for status could have led to an increase in the worth of prestige goods and to {A. competitiveness} among people wishing to achieve this status.</p>\r\n<p>It is thought that our natural desire to trade provided a basis for organized farming and {E. city} development and finally resulted in the complex societies which can be seen today. Whilst we do not value things such as beads nowadays, other items hold the same appeal for us and bring the same status as owning beads did for our {C. ancestors}.</p>", "answerOptions": [{"optionText": "A. competitiveness"}, {"optionText": "B. respect"}, {"optionText": "C. ancestors"}, {"optionText": "D. species"}, {"optionText": "E. city"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. … ownership of desirable goods to demonstrate our strength and fitness as other {species} use their attractive physical features.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In many animal <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"27\">species</strong>, individuals signal their genetic fitness by showing off with attention-grabbing adornment.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả so sánh việc con người dùng hàng hóa xa xỉ với việc các loài động vật khác dùng vẻ ngoài (như bộ lông) để khoe sức mạnh và sự khỏe mạnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. … even in ancient times, successful people would have gained {respect} from this.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…superior skills in areas such as hunting… would have brought <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"78\">respect</strong>—in other words, prestige.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những kỹ năng vượt trội mang lại sự tôn trọng (respect) hay còn gọi là uy tín (prestige).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. … increase in the worth of prestige goods and to {competitiveness} among people wishing to achieve this status.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The benefits of prestige would also lead to <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"56\">competition</strong> to acquire it.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mong muốn đạt được địa vị dẫn đến sự cạnh tranh (competitiveness) giữa mọi người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">20. … natural desire to trade provided a basis for organized farming and {city} development…</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…paving the way for agriculture and <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"50\">urbanization</strong>.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự phát triển của hàng hóa xa xỉ dẫn đến sự hình thành hệ thống xã hội, nông nghiệp và đô thị hóa (city development).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">21. … other items hold the same appeal for us and bring the same status as owning beads did for our {ancestors}.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “We may not be impressed by beads anymore, but their modern equivalents have the same fascination… status symbol.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những món đồ như xe Bugatti ngày nay có giá trị biểu tượng địa vị tương tự như những chuỗi hạt vỏ sò đối với tổ tiên (ancestors) của chúng ta ngày xưa.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('59b93d55-f963-42ab-ba1e-960489475279', '23e27cfd-6677-4aea-bd8e-192aef5c6043', 'matrix', ' Questions 14–19', NULL, '<p>Reading Passage 2 has eight paragraphs, <strong>A-H</strong>.</p>
<p>Which paragraph contains the following information?</p>
<p>Choose the correct letter, <strong>A-H</strong>, in boxes 14-19.</p>
<p><strong>NB </strong>You may use any letter more than once.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a description of how rapid change has a negative effect on people", "correctCategoryLetter": "C"}, {"itemText": "a reference to an architect whose designs were uncharacteristic of biophilia", "correctCategoryLetter": "B"}, {"itemText": "a definition of the two main aims of biophilia", "correctCategoryLetter": "A"}, {"itemText": "a positive claim about early forms of architecture", "correctCategoryLetter": "H"}, {"itemText": "a reference to the fact that many architects are too focused on innovation", "correctCategoryLetter": "B"}, {"itemText": "a description of features which conserve energy in a biophilic design", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<h3 data-path-to-node=\"4\">14. a description of how rapid change has a negative effect on people</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>C</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “The rates of technological progress are far exceeding rates of psychological evolution, leaving us <strong>ill-equipped to cope with our lifestyle, which in turn leads to increased stress</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Đoạn C mô tả tốc độ tiến bộ công nghệ quá nhanh (<em>rapid change</em>) dẫn đến việc con người không thể thích nghi, gây ra <strong>căng thẳng gia tăng</strong> (<em>increased stress</em> / negative effect on people).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"7\">15. a reference to an architect whose designs were uncharacteristic of biophilia</h3>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>B</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “Though not technically a biophilic design, Fallingwater – the stunning house in rural Pennsylvania designed in the 1930s by Frank Lloyd Wright – arguably speaks to the human soul much more than the <strong>box-like blocks of flats designed by his contemporary Le Corbusier</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Tác giả sử dụng kiến trúc sư Le Corbusier với những khối nhà hộp (<em>box-like blocks of flats</em>) như một ví dụ trái ngược (<em>uncharacteristic</em>) với triết lý thiết kế ái sinh (biophilia), vốn ưu tiên nhu cầu tâm lý con người.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">16. a definition of the two main aims of biophilia</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>A</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) “The premise of biophilic design seeks both to <strong>avoid or minimize harmful impacts on the natural environment</strong>, and equally importantly, to <strong>provide and restore beneficial contacts between people and nature</strong> in the built environment.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Đoạn A đưa ra <strong>hai mục tiêu chính</strong> (<em>two main aims</em>): giảm thiểu tác động xấu lên môi trường và khôi phục liên hệ có lợi giữa con người và thiên nhiên.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">17. a positive claim about early forms of architecture</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>H</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn H) “Ancient architects built for their cultures… They mimicked nature’s forms, producing <strong>magnificent structures with which we are still awed</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Đoạn H ca ngợi (<em>positive claim</em>) các kiến trúc sư cổ đại đã tạo ra <strong>các cấu trúc tráng lệ</strong> (<em>magnificent structures</em>) khiến chúng ta vẫn kinh ngạc.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">18. a reference to the fact that many architects are too focused on innovation</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>B</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “All too often, architects have put <strong>creative originality</strong> before the needs of the people who have to live and work in their futuristic constructions, with scant regard for emotional, as well as practical, considerations.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Việc đặt <strong>sự độc đáo sáng tạo</strong> (<em>creative originality</em> / innovation) lên trên nhu cầu của con người cho thấy sự tập trung quá mức vào sự đổi mới.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"19\">19. a description of features which conserve energy in a biophilic design</h3>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “The Lewis Center is sustainable in a broader sense… It <strong>harnesses solar power, utilizes both active and passive air systems</strong>, and monitors the weather to adapt to conditions.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong>Giải thích:</strong> Đoạn F mô tả các tính năng sử dụng năng lượng mặt trời (<em>solar power</em>) và hệ thống không khí thụ động/chủ động, là các tính năng nhằm <strong>bảo tồn năng lượng</strong> (<em>conserve energy</em>).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('f5b39463-92a4-40f4-97b9-a752abbf208f', '23e27cfd-6677-4aea-bd8e-192aef5c6043', 'fillup', 'Questions 20–24', '<div class="quests-inner-desc">
<div class="txt">
<div class="quests-inner-desc">
<div class="txt">
<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p>In the modern world, {technological} advancements are happening so quickly that humans are unable to adjust to them.</p>
<p>Biophilia can help us deal with the {stress} caused by the difficulties of our current lifestyles.</p>
<p>People instinctively feel more comfortable in places which have plenty of {sunlight} .</p>
<p>An experiment designed to test the effect of nature on patient recovery times found that those who could see a {tree} made a faster recovery.</p>
<p>There is a biophilic design feature in the University of Guelph-Humber building which improves the quality of the {air} .</p>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"4\">20. In the modern world,  <strong>technological</strong> advancements are happening so quickly that humans are unable to adjust to them.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>technological</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “The rates of <strong>technological</strong> progress are far exceeding rates of psychological evolution, leaving us ill-equipped to cope with our lifestyle…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Câu này nói về sự tiến bộ quá nhanh của <strong>công nghệ</strong> (<em>technological</em> advancements) khiến con người không thể thích nghi.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"7\">21. Biophilia can help us deal with the <strong>stress</strong> caused by the difficulties of our current lifestyles.</h3>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>stress</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “…leaving us ill-equipped to cope with our lifestyle, which in turn leads to <strong>increased stress</strong>. Because biophilia attempts to integrate basic and current needs, it can alleviate the difficulties…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Thiết kế Ái sinh giúp giảm bớt khó khăn do lối sống hiện đại gây ra, được đặc trưng bằng <strong>căng thẳng</strong> (<em>stress</em>) gia tăng.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">22. People instinctively feel more comfortable in places which have plenty of <strong>sunlight</strong> , something which is necessary for health and well-being.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>sunlight</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “For example, one crucial element… is <strong>sunlight</strong>. We are evolutionarily programmed to respond positively to sunny areas over dark or overcast ones, and sense that they will foster restoration, improve emotional well-being and promote health.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Mọi người được lập trình để phản ứng tích cực với các khu vực có nhiều <strong>ánh sáng mặt trời</strong> (<em>sunlight</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">23. An experiment designed to test the effect of nature on patient recovery times found that those who could see a <strong>tree</strong> made a faster recovery.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>tree</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “One well-known study looked at the impact of nature on patients after surgery. One group had a view of <strong>tree</strong>; the others had a window looking onto a brick wall.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Thử nghiệm cho thấy bệnh nhân có thể nhìn thấy một <strong>cái cây</strong> (<em>tree</em>) hồi phục nhanh hơn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">24. There is a biophilic design feature in the University of Guelph-Humber building which improves the quality of the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>air</strong>.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>air</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “The wall is covered in dense foliage… The wall <strong>purifies the air</strong> and has the potential to fulfill the building’s fresh air intake requirements.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Tính năng thiết kế sinh học (bức tường cây) trong tòa nhà giúp <strong>lọc sạch không khí</strong> (<em>purifies the air</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('5a56aa2c-c411-4492-bd71-b50744eecfb7', '8d7882b9-8ed2-451f-9853-55edde90f04c', 'fillup', 'Questions 1–10', '<p data-start="92" data-end="184">Complete the notes below</p>
<p data-start="92" data-end="184">Write <strong data-start="125" data-end="167">NO MORE THAN ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<h3 data-section-id="1kac3yy" data-start="186" data-end="214">Fearnley Sports Center</h3>
<p data-start="215" data-end="245"><strong data-start="215" data-end="245">Lifeguard Application Form</strong></p>
<p data-start="247" data-end="267"><strong data-start="247" data-end="267">Personal details</strong></p>
<p data-start="269" data-end="292"><strong data-start="269" data-end="278">Name: </strong>Peter Smith</p>
<p data-start="294" data-end="350"><strong data-start="294" data-end="311">Home address: </strong>130 South Main Street, Lake {Elsinore}</p>
<p data-start="352" data-end="396"><strong data-start="352" data-end="371">Contact number: </strong>{077896245} (cell phone)</p>
<p data-start="398" data-end="421"><strong data-start="398" data-end="421">Present occupation:</strong></p>
<ul data-start="422" data-end="535">
<li data-section-id="a095v2" data-start="422" data-end="467">
<p data-start="424" data-end="467">has temporary job as a part-time {waiter}</p>
</li>
<li data-section-id="1rjyow8" data-start="468" data-end="488">
<p data-start="470" data-end="488">is studying<strong> </strong>PE</p>
</li>
<li data-section-id="8pgyqo" data-start="489" data-end="535">
<p data-start="491" data-end="535">wants to be a high school {baseball} coach</p>
</li>
</ul>
<h3 data-section-id="12f3so4" data-start="542" data-end="560">Qualifications</h3>
<p data-start="562" data-end="607"><strong data-start="562" data-end="580">Already holds: </strong>water safety certificate</p>
<p data-start="609" data-end="646"><strong data-start="609" data-end="636">Certificate expires in: </strong>{October}</p>
<h3 data-section-id="lry4qy" data-start="653" data-end="681">Relevant work experience</h3>
<p><strong data-start="683" data-end="700">Lifeguard at: </strong>the {beach} in Fearnley</p>
<p data-start="730" data-end="774">Additional relevant skills: {diving}</p>
<p data-section-id="qr901a" data-start="781" data-end="802"><strong>Other Information</strong>: is happy to</p>
<ul data-start="804" data-end="876">
<li data-section-id="m8s095" data-start="804" data-end="849">
<p data-start="806" data-end="849">work on {Saturday} mornings</p>
</li>
<li data-section-id="14it1z5" data-start="850" data-end="876">
<p data-start="852" data-end="876">start at {six| 6} o’clock</p>
</li>
</ul>
<p data-start="883" data-end="952">How did the applicant find out about this job? on the<strong> </strong>{radio}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong>IELTS LISTENING PART 1: FERNLEY SPORTS CENTER JOB APPLICATION</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Manager:</strong> Hello, Fernley Sports Center. How can I help you?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Peter:</strong> Yes, I’d like to apply for one of the lifeguard jobs you advertised this week.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Manager:</strong> Right. We can do that now over the phone. I’ll just need some information from you. Let me get a form. OK, so let’s start with your name.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Peter:</strong> Peter Smith.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Manager:</strong> OK. Can you let me have your home address?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Peter:</strong> It’s 130 South Main Street, Lake<span style=\"background-color: #f4d24a;\"> <strong>(1) </strong><strong data-path-to-node=\"8\" data-index-in-node=\"40\">Elsinore</strong>.</span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Manager:</strong> Okay, I’m new around here. Can you spell that for me?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Peter:</strong> Yes, it’s E-L-S-I-N-O-R-E.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Manager:</strong> Uh-huh, okay, got that. And your phone number?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Peter:</strong> My home number’s 951 674 3124. But it’s best to ring me on my cell phone. That’s<span style=\"background-color: #f4d24a;\"><strong> (2) 077896245.</strong></span></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Manager:</strong> Okay. Now, what do you do? Are you still in college or are you working full time?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Peter:</strong> I’m in my second year here at Fernley. And this vacation I’ve got a job as a part-time <span style=\"background-color: #f4d24a;\"><strong>(3) waiter.</strong></span></p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Manager:</strong> Okay. I guess if you’re at Fernley College, you’ll be studying Physical Education. They all seem to do that there.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Peter:</strong> That’s right. Then I hope to go on and coach <span style=\"background-color: #f4d24a;\"><strong>(4) </strong><strong data-path-to-node=\"16\" data-index-in-node=\"52\">baseball</strong> </span>in high school, something like that. I guess it all depends on how I do in my final exams.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Manager:</strong> Okay, sounds good to me.</p>\n<hr data-path-to-node=\"18\">\n<p data-path-to-node=\"19\"><em data-path-to-node=\"19\" data-index-in-node=\"0\">(Pause – Questions 5 to 10)</em></p>\n<hr data-path-to-node=\"20\">\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Manager:</strong> Now the next part of the form deals with qualifications. Do you have the water safety certificate? We absolutely insist on that.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Peter:</strong> Yes, I do.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Manager:</strong> So how long will it last before you have to do a refresher course?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Peter:</strong> I took it last November, so it will run out in<span style=\"background-color: #f4d24a;\"><strong> (5) October.</strong></span></p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Manager:</strong> OK, good. Now, what about work experience as a lifeguard?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Peter:</strong> Well, I’ve had about four months’ experience.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Manager:</strong> Which swimming pool was that at? I need to have details of your employer obviously, so we can get a reference.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Peter:</strong> Oh, it was at the <span style=\"background-color: #f4d24a;\"><strong>(6) </strong><strong data-path-to-node=\"28\" data-index-in-node=\"25\">beach</strong></span> here in Fernley. I can get the number of the person you need to contact.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Manager:</strong> Good. And do you have any other additional skills I can put down?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Peter:</strong> You can put down <span style=\"background-color: #f4d24a;\"><strong>(7) diving</strong></span>. I’ve done that for a long time now. I’m also keen on rock climbing, but that’s not really relevant here.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Manager:</strong> No, okay. And I need to ask when you would prefer to work. You can choose either <strong><span style=\"background-color: #f4d24a;\">(8) Saturday</span> </strong>mornings or anytime Monday to Friday. We’ve got enough people on Sundays at the moment.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Peter:</strong> Well, not Monday to Friday, because I’m at the restaurant weekday evenings.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Manager:</strong> Okay. We open at<span style=\"background-color: #f4d24a;\"><strong> (9) six.</strong></span> Could you start that early?</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Peter:</strong> No, that’s fine. I’d prefer that to working late. </p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Manager:</strong> Okay. Now I need to speak to the committee who run the sports center here, but you should hear back from us pretty soon and then they’ll probably arrange an interview.</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Peter:</strong> Thanks very much.</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Manager:</strong> Great. Now before you go, I’d just like to ask you how you found out about our advertisement. We always ask this. Was it from the newspaper or the <span style=\"background-color: #f4d24a;\"><strong>(10) radio</strong></span>?</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Peter:</strong> I heard the advertisement this morning when I was driving into college. I don’t usually read the local paper. </p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Manager:</strong> Alright, thanks. Well, that’s all. Hope to see you soon.</p>"}]', 0);
INSERT INTO public.questions VALUES ('e3455935-0181-494d-a96a-911567e0b80b', '23e27cfd-6677-4aea-bd8e-192aef5c6043', 'checkbox', 'Questions 25–26', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>of the following statements does the writer make about the Adam Joseph Lewis Center at Oberlin College?</p>
', 'multiple_choice_many', 'null', '[{"option": "It was the first educational establishment designed with biophilic principles.", "correct": false}, {"option": "It is beneficial for both students and the environment.", "correct": true}, {"option": "It has established new concepts for classroom design.", "correct": false}, {"option": "It aims to inspire new ways of thinking about the environment.", "correct": true}, {"option": "It provides solar power to other buildings in the surrounding area.", "correct": false}]', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"3\">25. <strong>Đáp án: It is beneficial for both students and the environment.</strong> <em>(Nó mang lại lợi ích cho cả sinh viên và môi trường.)</em></h2>\n<p data-path-to-node=\"5\"><strong>Dẫn chứng trong bài đọc:</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Lợi ích Môi trường (Environment):</strong> Đoạn văn mô tả Trung tâm Lewis là một công trình tiên phong về môi trường (Net-Zero Energy – sản xuất nhiều năng lượng hơn tiêu thụ) và sử dụng các hệ thống bền vững. Ví dụ, nó <strong>sử dụng năng lượng mặt trời</strong> và có một hệ thống <strong>‘Living Machine’</strong> (Máy sống) để xử lý nước thải, cho thấy sự <strong>trách nhiệm và lợi ích to lớn đối với hành tinh</strong> (sử dụng tài nguyên hiệu quả, không thải chất độc ra môi trường).</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Lợi ích cho Sinh viên (Students):</strong> Đoạn văn thường đề cập đến tác động của môi trường này lên những người học tập và làm việc tại đây. Tác giả David Orr giải thích rằng tòa nhà được thiết kế không chỉ để dạy học mà còn <strong>nâng cao sức khỏe và tinh thần</strong> của người dùng. Việc được tiếp xúc với ánh sáng tự nhiên, không khí sạch, và các yếu tố sinh học giúp <strong>cải thiện khả năng tập trung, sự sáng tạo và hạnh phúc</strong>, từ đó <strong>tác động tích cực đến giáo dục</strong> của sinh viên.</p>\n</li>\n</ul>\n<h2 data-path-to-node=\"8\">26. <strong>Đáp án: It aims to inspire new ways of thinking about the environment.</strong> <em>(Nó nhằm mục đích truyền cảm hứng cho những cách suy nghĩ mới về môi trường.)</em></h2>\n<p data-path-to-node=\"10\"><strong>Dẫn chứng trong bài đọc:</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\">Mục tiêu của tòa nhà không chỉ là đạt được các chứng nhận xanh mà còn là một <strong>công cụ giảng dạy (Building as Pedagogy)</strong>.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\">Giám đốc chương trình, David Orr, đã giải thích rằng mục tiêu của tòa nhà là “<strong>giúp xác định lại mối quan hệ giữa con người và môi trường – một mối quan hệ sẽ mở rộng nhận thức của chúng ta về các khả năng sinh thái</strong>.” (redefine the relationship between humankind and the environment – one that would expand our sense of ecological possibilities).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\">Tòa nhà này được coi là một <strong>hình mẫu</strong> (showcase) cho công nghệ xanh, mục đích là để <strong>truyền cảm hứng</strong> cho các kiến trúc sư, nhà thiết kế, sinh viên, và cộng đồng rộng lớn hơn về việc xây dựng các công trình thân thiện với môi trường, từ đó thay đổi cách mọi người <strong>tư duy về phát triển bền vững</strong> và hệ sinh thái.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('3efc914a-0ae8-4b12-9331-0be962b187ee', '4e32a5d4-5f6f-4b04-a4c8-e89a647627af', 'radio', 'Questions 27–31', NULL, '<p>Choose the correct answer.</p>
', 'multiple-choice', '[{"correct": 2, "options": [{"content": "the universality of Piaget’s insights into the workings of the mind."}, {"content": "the similarity between children’s thought processing in different cultures."}, {"content": "how Piaget’s work represents a crucial turning-point in our approach to education."}, {"content": "how Piaget’s work has aided our understanding of man’s evolution from primitive origins."}], "question": "In the second paragraph the writer mentions the example of modern anthropology to illustrate"}, {"correct": 0, "options": [{"content": "The factual accuracy of what children say is of minor significance."}, {"content": "Children want to learn about scientific principles."}, {"content": "Children’s reasoning processes can be amusing to adults."}, {"content": "Children often pretend that they know the answers to questions."}], "question": "According to the writer, what point is illustrated by the dialogue about the wind?"}, {"correct": 3, "options": [{"content": "preventing children from making false assumptions."}, {"content": "giving children honest feedback on their hypotheses."}, {"content": "showing children how to formulate their own ideas about the world."}, {"content": "maintaining children’s confidence in their ability to interpret the world."}], "question": "Piaget believed in the importance of"}, {"correct": 2, "options": [{"content": "Children’s sense of their surroundings changes as they get older."}, {"content": "Children are able to grasp certain complex ideas as well as adults are."}, {"content": "Even apparently irrational ideas can be worthy of interest."}, {"content": "Sometimes the simplest explanations are the best."}], "question": "What does the writer suggest in the seventh paragraph?"}, {"correct": 2, "options": [{"content": "outline Piaget’s contribution to a range of scientific fields."}, {"content": "summarise how education has benefited from Piaget’s finding."}, {"content": "discuss Piaget’s role in the development of 20th-century psychology."}, {"content": "express doubts about a number of Piaget’s theories."}], "question": "The writer’s main purpose is to"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\">27. In the second paragraph the writer mentions the example of modern anthropology to illustrate</h3>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>C. how Piaget’s work represents a crucial turning-point in our approach to education.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “It was a shift <strong>comparable</strong> to the way modern anthropology displaced stories of primitive tribes being ‘noble savages’ and ‘cannibals’.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Tác giả so sánh sự thay đổi trong cách nhìn nhận trẻ em của Piaget với sự thay đổi lớn trong nhân học hiện đại (từ quan niệm sai lầm sang sự thật). Điều này cho thấy công trình của Piaget đã tạo ra một <strong>bước ngoặt quan trọng</strong> (<em>crucial turning-point</em>) trong cách chúng ta tiếp cận giáo dục.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">28. According to the writer, what point is illustrated by the dialogue about the wind?</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>A. The factual accuracy of what children say is of minor significance.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “Piaget recognized that five-year-old Julia’s beliefs, while not correct by any adult criterion, are not ‘incorrect’ either. <strong>Classifying them as ‘true’ or ‘false’ misses the point</strong> and shows a lack of respect for the child.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Piaget nhấn mạnh rằng việc phân loại ý kiến của trẻ em là “đúng” hay “sai” (<em>factual accuracy</em>) là <strong>bỏ sót vấn đề</strong> (<em>misses the point</em>), tức là độ chính xác thực tế chỉ mang ý nghĩa thứ yếu (<em>minor significance</em>) so với quá trình tư duy của trẻ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"4\">29. Piaget believed in the importance of</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>D. maintaining children’s confidence in their ability to interpret the world.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “But his work strongly suggests that automatic reaction of putting the child right may well be <strong>counter-productive</strong>. If their theories are always greeted by ‘Nice try, but this is how it really is…’ <strong>they might give up after a while on making theories</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Piaget cảnh báo rằng việc sửa lỗi ngay lập tức (<em>putting the child right</em>) có thể gây phản tác dụng (<em>counter-productive</em>) và khiến trẻ em từ bỏ việc tạo ra các lý thuyết của riêng mình (<em>give up after a while on making theories</em>). Điều này ngụ ý rằng điều quan trọng là phải duy trì <strong>sự tự tin</strong> (<em>maintaining children’s confidence</em>) của trẻ em trong khả năng tự diễn giải (<em>interpret</em>) thế giới của chúng.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">30. What does the writer suggest in the seventh paragraph?</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>C. Even apparently irrational ideas can be worthy of interest.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) Tác giả đề cập đến những “định luật vật lý sơ khai” của trẻ em như: “thấy sao bắt vậy” (mặt trăng, mặt trời đi theo mình), và việc trẻ em “khăng khăng rằng đi nhanh hơn có thể tốn nhiều thời gian hơn”. Einstein đã bị <strong>hấp dẫn</strong> (<em>intrigued</em>) bởi những phát hiện này vì chúng <strong>trái ngược với lẽ thường</strong> (<em>contrary to common sense</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Việc Einstein bị hấp dẫn bởi những ý tưởng <em>tưởng chừng phi lý</em> (<em>apparently irrational</em>) đó cho thấy những ý tưởng này <strong>xứng đáng được quan tâm</strong> (<em>worthy of interest</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"15\">31. The writer’s main purpose is to</h3>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong>Đáp án:</strong> <strong>C. discuss Piaget’s role in the development of 20th-century psychology.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong>Dẫn chứng:</strong> (Toàn bộ bài đọc) Bài đọc tập trung vào việc mô tả công việc, các lý thuyết mang tính <strong>nền tảng</strong> của Piaget (“provided the foundation for today’s education-reform movements” [Đoạn 2]), tầm ảnh hưởng <strong>lâu dài</strong> của ông đối với tâm lý học (“influence on psychology may be longer lasting” [Đoạn 3]), và cách ông biến nhận thức luận thành một <strong>khoa học</strong> (<em>“made it a science”</em>) [Đoạn 8].</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong>Giải thích:</strong> Mục đích chính là làm nổi bật <strong>vai trò trung tâm và tầm ảnh hưởng</strong> của Piaget đối với sự phát triển của lĩnh vực tâm lý học nhận thức trong thế kỷ 20.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('c3df8922-af7b-441c-b30e-9120d4692549', '4e32a5d4-5f6f-4b04-a4c8-e89a647627af', 'matching', 'Questions 32–36', NULL, '<p>Complete the summary using the list of words, <strong>A-I</strong>, below.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p>Piaget maintained that children’s mental processes were far more {G logical} than they might appear. He encouraged the view that a child was not a ‘blank slate’ waiting to be filled with information, but rather a systematic builder of knowledge who regularly tries out his or her own {B theories} about the world.</p>\r\n<p>Piaget’s impact on the area of {F psychology} could well outlast that of more celebrated pioneers of this discipline. Despite doubts cast over his ideas by the current view associating knowledge exclusively with the {C brain} , the effects of his work are still strong today. His principles are still widely used in the professional development of {E teachers} .</p>", "answerOptions": [{"optionText": "A correct"}, {"optionText": "B theories"}, {"optionText": "C brain"}, {"optionText": "D simple"}, {"optionText": "E teachers"}, {"optionText": "F psychology"}, {"optionText": "G logical"}, {"optionText": "H thought"}, {"optionText": "I philosophers"}], "matchingItems": null}', 'null', '[{"content": "<h3 data-path-to-node=\"4\">32. Piaget maintained that children’s mental processes were far more <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>G. logical</strong> than they might appear.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>G. logical</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) “…behind their cute and seemingly irrational utterances were thought processes that had their own kind of order and their own special <strong>logic</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Piaget nhận thấy quá trình tư duy của trẻ em có trật tự và <strong>logic</strong> (<em>logical</em>) riêng, khác biệt so với người lớn.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"7\">33. He encouraged the view that a child was not a ‘blank slate’ waiting to be filled with information, but rather a systematic builder of knowledge who regularly tries out his or her own <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>B. theories</strong> about the world.</h3>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>B. theories</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “…but active builders of knowledge – little scientists who are constantly creating and testing their own <strong>hypotheses</strong> about the world.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Trẻ em là những nhà khoa học nhỏ bé, liên tục tạo ra và kiểm tra <strong>giả thuyết</strong> (<em>hypotheses</em>) của riêng mình, đồng nghĩa với <strong>lý thuyết</strong> (<em>theories</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">34. Piaget’s impact on the area of <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>F. psychology</strong> could well outlast that of more celebrated pioneers of this discipline.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>F. psychology</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “And though he may not be as famous as Sigmund Freud or even B F Skinner, his influence on <strong>psychology</strong> may be longer lasting.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Ảnh hưởng của Piaget trong lĩnh vực <strong>tâm lý học</strong> (<em>psychology</em>) có thể lâu dài hơn các nhà tiên phong khác.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">35. Despite doubts cast over his ideas by the current view associating knowledge exclusively with the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>C. brain</strong>, the effects of his work are still strong today.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>C. brain</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) “In the past decade, Piaget has been vigorously challenged by the current fashion of viewing knowledge as an intrinsic property of the <strong>brain</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Công trình của Piaget bị thách thức bởi quan điểm hiện tại cho rằng kiến thức là một thuộc tính cố hữu của <strong>bộ não</strong> (<em>brain</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">36. His principles are still widely used in the professional development of <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>E. teachers</strong>.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>E. teachers</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “He has been revered by generations of <strong>teachers</strong> inspired by the belief that children are not empty vessels…” (Đoạn 8) “Although every <strong>teacher</strong> in training still memorises Piaget’s successive stages of childhood development…”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Các nguyên tắc của ông vẫn được sử dụng rộng rãi trong quá trình đào tạo và phát triển nghề nghiệp của <strong>giáo viên</strong> (<em>teachers</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('1526c692-000a-467f-9062-e19e295e2975', 'ddb76a69-fe13-4a91-9787-34087773f770', 'matching', 'Questions 14 – 20', '', '<p><span class="citation-3788 citation-3789 citation-3790 citation-3791 citation-3792">Write the correct number, </span><strong data-path-to-node="7" data-index-in-node="26"><span class="citation-3788 citation-3789 citation-3790 citation-3791 citation-3792">i-viii</span></strong><span class="citation-3788 citation-3789 citation-3790 citation-3791 citation-3792 citation-end-3792">, in boxes 14-20 on your answer sheet.</span></p>', 'matching_paragraph_information', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i Technological developments improve CRSP data"}, {"optionText": "ii Initial findings of the CRSP project"}, {"optionText": "iii A request and a far-reaching result"}, {"optionText": "iv Difficulties in collecting CRSP data"}, {"optionText": "v What the future holds"}, {"optionText": "vi Too much data for people to have an overall understanding"}, {"optionText": "vii Other university departments which depend on CRSP"}, {"optionText": "viii CRSP data not always being a useful basis for investment"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Paragraph A — {iii. A request and a far-reaching result}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“It all began in 1958 with a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"40\">phone call from Louis Engel… who wanted to know</strong> [A request]… The result… was the launch of the University’s Center for Research in Security Prices… <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"196\">data are everywhere. They provided the foundation of at least one-third of all empirical research</strong> [A far-reaching result].”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A kể về một lời yêu cầu (request) từ Louis Engel hỏi về hiệu suất cổ phiếu và kết quả là sự ra đời của CRSP – một tổ chức có tầm ảnh hưởng sâu rộng (far-reaching), cung cấp nền tảng cho 1/3 nghiên cứu tài chính 40 năm qua.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Paragraph B — {iv. Difficulties in collecting CRSP data}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Getting the CRSP data together was a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"49\">tough process</strong>… pieces of information… were <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"96\">transferred from paper… to magnetic tape</strong>. A lot of <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"149\">time was spent adjusting prices to take account of complexities</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B mô tả quy trình thu thập dữ liệu đầy khó khăn (difficulties/tough process) trong thời kỳ đầu của máy tính, bao gồm việc chuyển dữ liệu từ giấy sang băng từ và xử lý các biến số phức tạp của thị trường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. Paragraph C — {ii. Initial findings of the CRSP project}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“When these two economists published the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"52\">first study</strong>… they <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"72\">reported</strong> that the annual compound return… between 6.8% and 9%… the study claimed that the rate of return on shares was <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"195\">substantially higher than for alternative investment</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C tập trung vào những phát hiện đầu tiên (initial findings) của dự án: cổ phiếu có tỉ lệ lợi nhuận cao hơn các kênh khác và đưa ra khái niệm “equity risk premium” (phần bù rủi ro vốn cổ phần).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Paragraph D — {i. Technological developments improve CRSP data}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“…this resource became <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"36\">ever more useful as computing power became more affordable</strong>. The CRSP database has since been <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"129\">expanded</strong> to include a full range of different types of investments.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn D nói về việc dữ liệu CRSP ngày càng hoàn thiện và hữu ích hơn nhờ vào sự phát triển của công nghệ máy tính (computing power) giúp việc xử lý dữ liệu rẻ và nhanh hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. Paragraph E — {viii. CRSP data not always being a useful basis for investment}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…meaning there are <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"33\">no predictable movements</strong> in prices for smart investors to exploit… it seems that <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"116\">no sooner are such anomalies discovered and reported… than they typically disappear</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E thảo luận về “giả thuyết thị trường hiệu quả”. Dữ liệu cho thấy giá biến động ngẫu nhiên và các kịch bản kiếm lời (anomalies) thường biến mất ngay khi bị phát hiện. Vì vậy, dữ liệu lịch sử không phải lúc nào cũng là cơ sở hữu ích (not always a useful basis) để đầu tư sinh lời trong thực tế.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. Paragraph F — {vi. Too much data for people to have an overall understanding}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“Some economists worry that much of this statistical analysis is… <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"79\">drowning out serious thinking</strong>… economists who are <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"131\">so specialized in data analysis that they fail to see and understand the whole</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Robert Shiller lo ngại rằng việc có quá nhiều dữ liệu khiến các nhà kinh tế quá sa đà vào chi tiết (chuyên môn hóa hẹp) mà mất đi cái nhìn tổng thể (fail to see the whole/overall understanding), dẫn đến việc không dự báo được các cuộc khủng hoảng lớn như năm 2008.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">20. Paragraph G — {v. What the future holds}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“…<strong data-path-to-node=\"17,0,0\" data-index-in-node=\"15\">plans were unveiled</strong> to publish indicators on an <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"63\">expanding range of investments</strong>… these indicators… will be more academically rigorous and cheaper… ensure CRSP’s <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"181\">continuing success</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn cuối nói về các kế hoạch tương lai (plans/future) của CRSP: mở rộng phạm vi chỉ số đầu tư và duy trì sự thành công bền vững.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('de931d94-f53e-47eb-a786-136c22be2bc3', '4e32a5d4-5f6f-4b04-a4c8-e89a647627af', 'radio', 'Questions 37–40', NULL, '<p>Choose <strong>YES</strong> if the statement agrees with the claims of the writer, choose <strong>NO</strong> if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Piaget’s early work in Paris involved innovative research techniques."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Piaget gave clear guidelines as to how adults should give information to children."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Piaget made a significant contribution to the field of epistemology."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "We still have much to learn about the nature of knowledge."}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\">37. Piaget’s early work in Paris involved innovative research techniques.</h3>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;In 1920, while doing research in a child-psychology laborartory in Paris, Piaget noticed that children of the same age made similar errors on intelligence tests.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Bài đọc chỉ đề cập đến việc Piaget làm nghiên cứu ở Paris và <strong>nhận thấy</strong> (<em>noticed</em>) những sai sót tương tự của trẻ em trong các bài kiểm tra trí thông minh. <strong>Không có thông tin</strong> nào mô tả liệu những kỹ thuật nghiên cứu (<em>research techniques</em>) mà ông sử dụng lúc đó có phải là <strong>đổi mới</strong> (<em>innovative</em>) hay không.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">38. Piaget gave clear guidelines as to how adults should give information to children.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;<strong>Piaget was not an educator and never laid down rules about how to intervene in such situations.</strong>&#8220;</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Bài đọc khẳng định Piaget <strong>không phải là nhà giáo dục và chưa bao giờ đặt ra các quy tắc</strong> (<em>never laid down rules</em>) về cách người lớn nên can thiệp hoặc truyền đạt thông tin cho trẻ em. Điều này mâu thuẫn trực tiếp với nhận định rằng ông đã đưa ra các <strong>hướng dẫn rõ ràng</strong> (<em>clear guidelines</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"9\">39. Piaget made a significant contribution to the field of epistemology.</h3>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) &#8220;His real interest was <strong>epistemology</strong> – the theory of knowledge – which, like physics, was considered of a branch of philosophy until <strong>Piaget came along and made it a science</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Piaget đã biến kiến thức luận (<em>epistemology</em>) từ một nhánh của triết học thành một <strong>khoa học</strong> (<em>made it a science</em>). Việc thay đổi bản chất của một lĩnh vực nghiên cứu từ triết học sang khoa học được coi là một <strong>đóng góp đáng kể</strong> (<em>significant contribution</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">40. We still have much to learn about the nature of knowledge.</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 10) &#8220;&#8230;the difference between what the baby brings and what the adult has is so immense that the new discoveries do not significantly reduce the gap, but <strong>only increase the mystery</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Mặc dù đã có những khám phá mới, sự khác biệt giữa kiến thức sơ khai và kiến thức người lớn vẫn còn quá lớn, đến mức các khám phá mới chỉ <strong>làm tăng thêm sự bí ẩn</strong> (<em>increase the mystery</em>). Điều này ngụ ý rằng chúng ta <strong>còn rất nhiều điều để học</strong> (<em>still have much to learn</em>) về bản chất của kiến thức.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('544fd4ef-9ef9-47a4-be6b-ebcae0945618', '3763dda6-1ba8-4b1a-a5eb-7726b97d5a43', 'fillup', 'Question 33–36', '<p>Choose <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 33–36 on your answer sheet.</p>
<p>Which creatures are particularly well underwater? {Mantis Shrimp}</p>
<p>In addition to a computer, what technical equipment is fitted in Dr Zelenisky’s robot? {Panoramic camera}</p>
<p>Where is the Cataglyphis ant found? {Sahara desert}</p>
<p>What atmospheric effect helps the Cataglyphis ant to know its direction? {Polarized light}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Câu 33: Which creatures see particularly well underwater?</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án:</strong> Mantis Shrimp</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"16\">mantis shrimp</strong> scans its aquatic world through hyperspectral eyes.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tôm tít (mantis shrimp) có thị giác cực tốt trong môi trường nước nhờ đôi mắt đa phổ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Câu 34: In addition to a computer, what technical equipment is fitted in Dr Zelinsky’s robot?</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án:</strong> Panoramic camera</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a robot can navigate its way… using a <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"55\">panoramic camera</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngoài máy tính, robot của Dr. Zelinsky còn được trang bị camera toàn cảnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Câu 35: Where is the Cataglyphis ant found?</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Đáp án:</strong> Sahara desert</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…journeyed from Switzerland to the <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"49\">Sahara desert</strong> where <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"69\">Cataglyphis</strong>, a tiny ant… performs acts of navigational genius…”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,2,0\"><strong data-path-to-node=\"24,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Loài kiến Cataglyphis được tìm thấy ở sa mạc Sahara.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Câu 36: What atmospheric effect helps the Catalyphis ant to know its direction?</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Đáp án:</strong> Polarized light</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"26,1,0\" data-index-in-node=\"12\">Cataglyphis</strong> uses <strong data-path-to-node=\"26,1,0\" data-index-in-node=\"29\">polarised light</strong>, caused when air molecules scatter light, to orient and steer itself.”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong data-path-to-node=\"26,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Hiện tượng ánh sáng phân cực trong khí quyển giúp loài kiến này định hướng.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('301c1b7d-0cd0-4855-ab12-e10658c9b34e', '3763dda6-1ba8-4b1a-a5eb-7726b97d5a43', 'matching', 'Question 37–40', NULL, '<p>Look at the following people and the list of robots below.</p>
<p>Match each person or people with the correct robot <strong>A–G</strong>.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A. a robot that makes use of light as well as stored images for navigational purposes"}, {"optionText": "B. a robot that can contribute to environmental health"}, {"optionText": "C. a robot that can move over difficult surfaces"}, {"optionText": "D. a robot that categorises information from the environment according to its usefulness"}, {"optionText": "E. a robot that can be used to clean surfaces and collect rubbish"}, {"optionText": "F. a robot that has improved on the ability of the insect on which it is based"}, {"optionText": "G. a robot that can replace soldiers in war"}], "matchingItems": [{"questionPart": "Dr Alex Zelinsky", "correctAnswer": "D. a robot that categorises information from the environment according to its usefulness", "sectionContent": null}, {"questionPart": "Professor Ruediger Wehner", "correctAnswer": "A. a robot that makes use of light as well as stored images for navigational purposes", "sectionContent": null}, {"questionPart": "Professor Robert Michelson", "correctAnswer": "F. a robot that has improved on the ability of the insect on which it is based", "sectionContent": null}, {"questionPart": "Roger Quinn and Professor Roy Ritzmann", "correctAnswer": "C. a robot that can move over difficult surfaces", "sectionContent": null}]}', 'null', '[{"content": "<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Câu 37: Dr Alex Zelinsky</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Đáp án:</strong> D</p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Mô tả robot D:</strong> Một robot phân loại thông tin từ môi trường theo mức độ hữu ích.</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong data-path-to-node=\"31,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The robot’s panoramic camera logs the surrounding area… which are then <strong data-path-to-node=\"31,2,0\" data-index-in-node=\"85\">sorted in its computer according to how reliable they are</strong> as navigational aids.”</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Câu 38: Professor Ruediger Wehner</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Đáp án:</strong> A</p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Mô tả robot A:</strong> Một robot sử dụng ánh sáng và hình ảnh lưu trữ để định vị.</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong data-path-to-node=\"33,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Using the ant’s ability to steer by <strong data-path-to-node=\"33,2,0\" data-index-in-node=\"48\">polarised light</strong> and to <strong data-path-to-node=\"33,2,0\" data-index-in-node=\"71\">store and reuse landscape images</strong>, Wehner… built ‘Sahabot’…”</p>\n</li>\n</ul>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Câu 39: Professor Robert Michelson</strong></p>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong data-path-to-node=\"35,0,0\" data-index-in-node=\"0\">Đáp án:</strong> F</p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong data-path-to-node=\"35,1,0\" data-index-in-node=\"0\">Mô tả robot F:</strong> Một robot cải tiến khả năng của loài côn trùng mà nó dựa trên đó.</p>\n</li>\n<li>\n<p data-path-to-node=\"35,2,0\"><strong data-path-to-node=\"35,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…he has <strong data-path-to-node=\"35,2,0\" data-index-in-node=\"22\">gone beyond nature</strong> to devise a completely new concept… enabling it to fly slowly or hover in the thin Martain air…”</p>\n</li>\n<li>\n<p data-path-to-node=\"35,3,0\"><strong data-path-to-node=\"35,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Michelson không chỉ mô phỏng mà còn vượt xa tự nhiên (cải tiến) để robot có thể bay trong khí quyển mỏng của sao Hỏa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Câu 40: Roger Quinn and Professor Roy Ritzmann</strong></p>\n<ul data-path-to-node=\"37\">\n<li>\n<p data-path-to-node=\"37,0,0\"><strong data-path-to-node=\"37,0,0\" data-index-in-node=\"0\">Đáp án:</strong> C</p>\n</li>\n<li>\n<p data-path-to-node=\"37,1,0\"><strong data-path-to-node=\"37,1,0\" data-index-in-node=\"0\">Mô tả robot C:</strong> Một robot có thể di chuyển trên các bề mặt khó khăn.</p>\n</li>\n<li>\n<p data-path-to-node=\"37,2,0\"><strong data-path-to-node=\"37,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…enabling them to handle <strong data-path-to-node=\"37,2,0\" data-index-in-node=\"39\">surprisingly rugged terrain</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"37,3,0\"><strong data-path-to-node=\"37,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Robot dựa trên loài gián của họ được thiết kế để vượt qua các địa hình hiểm trở (rugged terrain).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('f3f90a1d-3e88-4afb-b3da-23fb80105768', 'b96c35df-426e-437f-bb29-4ad3858e2ecb', 'radio', 'Questions 27-32', '', '<p>Choose the correct letter, A, B, C, or D.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "Computer scientists are rarely represented at the Oscars."}, {"option_text": "Film-industry awards hold little interest for computer scientists."}, {"option_text": "The USA rewards film actors more than computer scientists."}, {"option_text": "Computer scientists are becoming a vital part of the film industry."}], "question": "What is the writer’s main point in the first paragraph?"}, {"correct": 0, "options": [{"option_text": "CGI looks best from a distance."}, {"option_text": "CGI interferes with actors’ facial expressions."}, {"option_text": "Audiences expect too much of CGI."}, {"option_text": "The scientists had hoped for more convincing results."}], "question": "When describing the way computer-generated imagery changes actors’ appearance, what does the writer suggest?"}, {"correct": 0, "options": [{"option_text": "They were motivated to get as near to reality as possible."}, {"option_text": "They were interested in gaining recognition for their work."}, {"option_text": "They thought it could have medical applications."}, {"option_text": "They hoped to receive further funding for their research."}], "question": "What does the writer suggest about the scientists’ attitude to their work in the fourth paragraph?"}, {"correct": 1, "options": [{"option_text": "It has only recently been used by doctors."}, {"option_text": "It is similar to X-rays in the way it works."}, {"option_text": "Filmmakers have used it for many years for special lighting effects."}, {"option_text": "It can be administered using traditional radiography machines."}], "question": "What are we told about computerised tomography?"}, {"correct": 1, "options": [{"option_text": "It is most effective when used to create images of skin."}, {"option_text": "It can make a few people seem like a crowd."}, {"option_text": "It allows clothes designers to create new designs."}, {"option_text": "It is practical because of the time it takes."}], "question": "Which of these advantages does the writer attribute to the current use of computerised tomography?"}, {"correct": 3, "options": [{"option_text": "comment on the success of CGI in commercial contexts."}, {"option_text": "highlight the link between CGI and photography."}, {"option_text": "show that Marschner’s team are uncertain about the future of CGI."}, {"option_text": "demonstrate a use for CGI outside the film industry."}], "question": "The writer mentions Kavita Bala in order to"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">Questions 27–32: Multiple Choice</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. What is the writer’s main point in the first paragraph?</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: D</strong> (Computer scientists are becoming a vital part of the film industry.)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…computer scientists that has become <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"51\">fundamental</strong> to moviemaking.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh rằng các nhà khoa học máy tính đang trở thành một phần thiết yếu/nền tảng (fundamental = vital part) của ngành làm phim.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. When describing the way CGI changes actors’ appearance, what does the writer suggest?</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: A</strong> (CGI looks best from a distance.)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it is possible if the altered actors are <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"56\">not filmed too closely</strong>. This is because… the effect is <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"113\">less convincing when seen close up</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết nói rằng kỹ xảo CGI sẽ kém thuyết phục khi nhìn gần, nghĩa là nó trông tốt nhất khi nhìn từ một khoảng cách nhất định (not filmed too closely).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. What does the writer suggest about the scientists’ attitude to their work in the fourth paragraph?</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: A</strong> (They were motivated to get as near to reality as possible.)</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…continued their <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"31\">search for perfection</strong>, as they still did not feel that they had yet satisfactorily recreated the <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"128\">subtle ways light is reflected</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “search for perfection” (tìm kiếm sự hoàn hảo) và việc chưa hài lòng với kết quả hiện tại cho thấy họ muốn đạt tới mức độ thực tế nhất có thể.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. What are we told about computerised tomography?</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: B</strong> (It is similar to X-rays in the way it works.)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"12\">Like classical radiology, it uses X-rays</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết khẳng định kỹ thuật chụp cắt lớp vi tính (CT) cũng sử dụng tia X giống như phương pháp chụp X-quang truyền thống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. Which of these advantages does the writer attribute to the current use of computerised tomography?</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: B</strong> (It can make a few people seem like a crowd.)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…in the same way that a <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"38\">small group of actors</strong> can be made to look like <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"85\">hundreds of people</strong> gathered together.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả so sánh việc ghép các mảnh vải CGI với việc biến một nhóm nhỏ diễn viên trông như hàng trăm người (đám đông).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">32. The writer mentions Kavita Bala in order to</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: D</strong> (demonstrate a use for CGI outside the film industry.)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the technology might have an <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"44\">application in online retailing</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc nhắc đến Kavita Bala là để chỉ ra một ứng dụng tiềm năng của công nghệ này trong ngành bán lẻ trực tuyến, vốn nằm ngoài lĩnh vực điện ảnh.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('1c21f0e6-a8ea-4a09-86a2-2ba6d82a8ef5', 'a819a046-884a-455b-bd10-82b8ce6a1ccb', 'matching', 'Questions 37–40', NULL, '<p>Complete each sentence with the correct ending below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A is dependent on adapting to unfamiliar interaction formats."}, {"optionText": "B is key in determining whether a student has a sense of belonging in a course."}, {"optionText": "C is a subject that the writer believes will require more study."}, {"optionText": "D is essential to excel in study and scholarship."}, {"optionText": "E is key in determining whether a student feels they have learned something from a course."}, {"optionText": "F is important for determining their validity."}], "matchingItems": [{"questionPart": "The ability to succeed in an online course", "correctAnswer": "A is dependent on adapting to unfamiliar interaction formats.", "sectionContent": null}, {"questionPart": "The need to be mindful of the source of comments in an online discussion ", "correctAnswer": "F is important for determining their validity.", "sectionContent": null}, {"questionPart": "In online courses, it is presence, rather than interaction, that ", "correctAnswer": "B is key in determining whether a student has a sense of belonging in a course.", "sectionContent": null}, {"questionPart": "The relationship between interaction and learning achievement ", "correctAnswer": "C is a subject that the writer believes will require more study.", "sectionContent": null}]}', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Câu 37</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"8\">A (is dependent on adapting to unfamiliar interaction formats.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…effective web-based learning requires adjustments on the part of students and teachers for successful interactions to occur…”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong data-path-to-node=\"28,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Để thành công/hiệu quả, người học cần sự “adjustment” (điều chỉnh/thích nghi) với các hình thức tương tác trực tuyến.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Câu 38</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"8\">F (is important for determining their validity.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…students need to have the experience and knowledge base to sift through the discussion for misinformation.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong data-path-to-node=\"30,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc chú ý đến nguồn gốc ý kiến giúp sinh viên lọc bỏ thông tin sai lệch (misinformation) để xác định tính đúng đắn/hợp lệ (validity) của nội dung.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Câu 39</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"8\">B (is key in determining whether a student has a sense of belonging in a course.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The simplest definition of presence… refers to a student’s sense of being registered and belonging in a course…”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong data-path-to-node=\"32,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả định nghĩa “presence” gắn liền với cảm giác thuộc về (belonging), và phân biệt nó với hành động tương tác thuần túy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Câu 40</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"34,0,0\" data-index-in-node=\"8\">C (is a subject that the writer believes will require more study.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…how interaction affects learning outcomes and what the relationships between the two are, is in need of further study.”</p>\n</li>\n<li>\n<p data-path-to-node=\"34,2,0\"><strong data-path-to-node=\"34,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả kết luận mối quan hệ giữa tương tác và kết quả học tập “cần được nghiên cứu thêm” (in need of further study).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('84f736b7-5fc5-495a-aced-500e1f14ddf4', 'b96c35df-426e-437f-bb29-4ad3858e2ecb', 'radio', 'Questions 33-36', NULL, '<p>Choose <strong data-path-to-node="18,0,0" data-index-in-node="0">YES</strong> if the statement agrees with the views of the writer, <strong data-path-to-node="18,1,0" data-index-in-node="0">NO</strong> if the statement contradicts the views of the writer, <strong data-path-to-node="18,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "It used to be unusual for university researchers to receive a cinematography award."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "CGI is popular among ageing actors."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The scientists’ success in generating images of complete CGI garments has won them many awards."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "It will be a long time before computerised tomographic imaging of fabric is used by filmmakers."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. It used to be unusual for university researchers to receive a cinematography award.</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In 2004 a <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"22\">notable event</strong> took place: the <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"52\">academic world met the cinematographic world</strong> when researchers from Stanford University… were awarded an Oscar.”</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc gọi sự kiện năm 2004 là “notable event” (sự kiện đáng chú ý/hiếm thấy) khi giới học thuật gặp giới điện ảnh cho thấy trước đó điều này là không thường xuyên (unusual).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. CGI is popular among ageing actors.</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Films have shown that it is possible to use CGI to <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"63\">make actors look younger</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói CGI có thể làm diễn viên trông trẻ hơn, nhưng <strong data-path-to-node=\"20,2,0\" data-index-in-node=\"74\">không hề đề cập</strong> đến việc nó có “phổ biến” (popular) trong nhóm diễn viên đang già đi hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. The scientists’ success in generating images of complete CGI garments has won them many awards.</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc nhắc đến giải Oscar cho việc mô phỏng độ xuyên thấu của da (subsurface scattering), nhưng <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"109\">không nói</strong> việc tạo ra trang phục (garments) hoàn chỉnh có mang về cho họ “nhiều giải thưởng” (many awards) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">36. It will be a long time before computerised tomographic imaging of fabric is used by filmmakers.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…for the <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"23\">moment</strong> the movement of a <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"48\">virtual cloak</strong> or the lifting of a <strong data-path-to-node=\"24,1,0\" data-index-in-node=\"82\">computerized hat</strong> should look far more realistic.”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,2,0\"><strong data-path-to-node=\"24,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết nói rằng kỹ thuật này <strong data-path-to-node=\"24,2,0\" data-index-in-node=\"43\">hiện tại</strong> (for the moment) đã có thể giúp các vật dụng bằng vải như áo choàng hay mũ trông thực tế hơn, trái ngược với ý kiến “phải chờ đợi lâu” (long time).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('e731ef98-f97e-4b32-96be-b9618b69f314', 'b96c35df-426e-437f-bb29-4ad3858e2ecb', 'matching', 'Questions 37–40', NULL, '<p>Complete the summary using the list of words, <strong data-path-to-node="22" data-index-in-node="46">A–I</strong>, below.</p>', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">The work of Marschner and his colleagues</strong> </span></p>\n<p>For many years, CGI characters did not appear entirely lifelike as their skin appeared plastic. Marschner and his colleagues were the first to apply an understanding of how {A light} interacts with human skin. Their CGI model is based on a novel application of principles of {F mathematics}, which had previously been applied in other scientific research. The importance of CGI to the film industry has led to the {D use}of Marschner''s model by special-effects studios. Marschner''s model has led to the {G improvement} of cinematography.</p>", "answerOptions": [{"optionText": "A light"}, {"optionText": "B transparency"}, {"optionText": "C age"}, {"optionText": "D use"}, {"optionText": "E astrophysics"}, {"optionText": "F mathematics"}, {"optionText": "G improvement"}, {"optionText": "H colour"}, {"optionText": "I translucency"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">37. {A. light}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> “…simulates translucency; this is when <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"61\">light</strong> penetrates skin and then scatters below the skin’s surface…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nguyên nhân khiến da nhân vật CGI trước đây trông như nhựa là do chưa mô phỏng được cách <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"101\">ánh sáng (light)</strong> tương tác (xuyên thấu và tán xạ) với làn da con người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">38: F mathematics </strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“This is called subsurface scattering, and the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"67\">mathematics for the model goes back many decades</strong> to the time when it was used in astrophysics.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mô hình CGI này dựa trên việc ứng dụng các nguyên lý toán học (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"75\">mathematics</strong>) vốn đã từng được sử dụng trong ngành vật lý thiên văn từ nhiều thập kỷ trước. Từ cần chọn trong hộp là <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"191\">mathematics</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">39. {D. use}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> “…all the major special-effects studios had <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"66\">incorporated</strong> it into their digital rendering systems.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Incorporated into digital rendering systems” đồng nghĩa với việc đưa vào <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"86\">sử dụng (use)</strong>. Các studio kỹ xảo lớn đã nhanh chóng ứng dụng mô hình này chỉ trong vòng hai năm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">40. {G. improvement}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> “<strong data-path-to-node=\"10,0,0\" data-index-in-node=\"21\">Cinematography will benefit</strong> from this because… the movement of a virtual cloak or the lifting of a computerized hat should look <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"151\">far more realistic</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc làm cho các chuyển động và hình ảnh trở nên thực tế hơn (realistic) chính là sự <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"97\">cải thiện (improvement)</strong> cho ngành điện ảnh. Cụm từ “benefit from” (hưởng lợi từ) cũng ám chỉ một sự thay đổi tích cực.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('ab538ffa-3e77-4841-836c-153f6544a6a9', '53565693-8342-4eab-8fb9-b732f264e9c8', 'matrix', 'Questions 23–26', '', '<p><span class="citation-36731 citation-36732 citation-36733 citation-36734">Write the correct letter, </span><strong data-path-to-node="17" data-index-in-node="26"><span class="citation-36731 citation-36732 citation-36733 citation-36734">A–D</span></strong><span class="citation-36731 citation-36732 citation-36733 citation-36734 citation-end-36734">, in boxes 23–26 on your answer sheet.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Experts", "matrixItems": [{"itemText": "Communities living in wetland regions must be included in discussions about the future of these areas.", "correctCategoryLetter": "A"}, {"itemText": "Official policies towards wetlands vary from one nation to the next.", "correctCategoryLetter": "C"}, {"itemText": "People cause harm to wetlands without having any intention to do so.", "correctCategoryLetter": "D"}, {"itemText": "Initiatives to reverse environmental damage need not be complex.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Matthew McCartney", "categoryLetter": "A"}, {"categoryText": "Pieter van Eijk", "categoryLetter": "B"}, {"categoryText": "Marcel Silvius", "categoryLetter": "C"}, {"categoryText": "Dave Tickner", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">23. A (Matthew McCartney) — {Communities living in wetland regions must be included in discussions about the future of these areas.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“For sustainability, it’s essential that <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"61\">local people are involved in wetland planning and decision making</strong>...” says McCartney.</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Communities living in wetland regions\" tương ứng với \"local people\" (người dân địa phương). \"Included in discussions about the future\" tương ứng với \"involved in planning and decision making\" (tham gia vào việc lập kế hoạch và đưa ra quyết định). Quan điểm này hoàn toàn thuộc về chuyên gia <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"304\">Matthew McCartney</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">24. C (Marcel Silvius) — {Official policies towards wetlands vary from one nation to the next.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn H):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">Silvius suggests... “<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"41\">Different governments have different attitudes</strong>,” he says, and goes on to explain that some countries place a high priority on restoring wetlands, while others still deny the issue.</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Official policies\" (chính sách chính thức) và \"vary from one nation to the next\" (khác nhau giữa các quốc gia) tương ứng với ý \"Different governments have different attitudes\" (các chính phủ khác nhau có thái độ/quan điểm khác nhau). Đây là phát biểu của <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"268\">Marcel Silvius</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">25. D (Dave Tickner) — {People cause harm to wetlands without having any intention to do so.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“It isn''t something that <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"45\">people generally set out to do</strong>. Quite often, the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"94\">effects simply come from people trying to make a living</strong>,” says Dr Dave Tickner.</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Without having any intention to do so\" (không hề có ý định làm vậy) đồng nghĩa với \"not generally set out to do\" (không chủ định làm). Tác giả nhấn mạnh việc gây hại này chỉ là vô tình do người dân cố gắng mưu sinh. Đây là quan điểm của <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"250\">Dave Tickner</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">26. B (Pieter van Eijk) — {Initiatives to reverse environmental damage need not be complex.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn </strong><strong>chứng</strong><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\"> (Đoạn C):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"21\">“<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"22\">It can be as simple as planting a few trees per hectare</strong> to create shade and substantially change a microclimate,” he says [Pieter van Eijk]. “Implementing climate change projects isn’t so much about money.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Initiatives to reverse environmental damage\" (các sáng kiến đảo ngược thiệt hại môi trường) tương ứng với các dự án ứng phó biến đổi khí hậu (implementing climate change projects). Cụm \"need not be complex\" (không cần phải phức tạp) tương ứng với ví dụ \"It can be as simple as...\" (nó có thể đơn giản như là...). Người phát biểu là <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"345\">Pieter van Eijk</strong>.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('8413db4a-693f-4705-9e3b-fe92f1b5e488', 'e674a859-fea5-4fa4-b005-35d527afb782', 'matrix', 'Questions 14–18', '', '<p>The text has five paragraphs, <strong>A–E</strong>. Which paragraph contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a description of a company that provides financial assistance for employees to continue their learning", "correctCategoryLetter": "B"}, {"itemText": "a mention of worldwide trends in the changing attitudes of businesses and customers", "correctCategoryLetter": "E"}, {"itemText": "details about years of continuous service by employees at one company", "correctCategoryLetter": "C"}, {"itemText": "a reference to the reason why many people-centered workers first start their own businesses", "correctCategoryLetter": "A"}, {"itemText": "a comment about how certain groups are still fighting for respect in the business world", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">14. A description of a company that provides financial assistance for employees to continue their learning — {B}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">pays,</span><span class=\"\"> at least partially,</span><span class=\"\"> for </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"45\">educational opportunities and textbooks</strong><span class=\"\">.</span><span class=\"\">” (Đoạn B)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Công ty Plastic Solutions của Stephen Harper hỗ trợ một phần chi phí giáo dục và sách giáo khoa cho nhân viên.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">15. A mention of worldwide trends in the changing attitudes of businesses and customers — {E}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Family-friendly entrepreneurs are becoming more </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"60\">commonplace internationally</strong><span class=\"\">…</span><span class=\"\"> parents are important </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"113\">consumers and investors</strong><span class=\"\"> who can change buying practices.</span><span class=\"\">” (Đoạn E)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn E nói về xu hướng quốc tế (worldwide trends) và vai trò của khách hàng (consumers) trong việc thay đổi hành vi mua sắm dựa trên chính sách gia đình của doanh nghiệp.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">16. Details about years of continuous service by employees at one company — {C}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">this year the company will celebrate </span><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"52\">six 5-year anniversaries, and one 25-year anniversary</strong><span class=\"\"> among its employees.</span><span class=\"\">” (Đoạn C)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn C đưa ra số liệu cụ thể về thâm niên làm việc (số năm cống hiến liên tục) của nhân viên tại Margaret Mills Corporation.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">17. A reference to the reason why many people-centered workers first start their own businesses — {A}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Many of these go into business themselves as a </span><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"59\">result of negative experiences</strong><span class=\"\"> they have had in the workplace.</span><span class=\"\">” (Đoạn A)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Jennifer West giải thích rằng nhiều chủ doanh nghiệp tự khởi nghiệp vì họ từng có những trải nghiệm không tốt (negative experiences) tại nơi làm việc cũ.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">18. A comment about how certain groups are still fighting for respect in the business world — {D}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong class=\"\" data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Working mothers still need to be </span><strong class=\"\" data-path-to-node=\"12,0,0\" data-index-in-node=\"45\">taken more seriously</strong><span class=\"\">,</span><span class=\"\"> and so do mothers who are business owners.</span><span class=\"\">” (Đoạn D)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Hazel Gibbs đề cập đến việc những người mẹ đi làm hoặc làm chủ doanh nghiệp vẫn chưa được tôn trọng hoặc coi trọng đúng mức (</span><em class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"137\">taken seriously</em><span class=\"\">).</span></p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('7bb7f535-99f0-48d7-9acc-3feaad726b5a', '6a45cfea-1f8b-4031-82fd-b931cebd3ecb', 'checkbox', 'Questions 25 and 26 ', '', '<p>Choose <strong>TWO </strong>letters, <strong>A-E</strong>.<br>Which <strong>TWO </strong>points were most frequently made by students about the pieces they select for assessed performances?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A. They like to hear others performing the same pieces."}, {"correct": false, "option_text": "B. They like to choose little-known pieces."}, {"correct": true, "option_text": "C. They like to play pieces from memory."}, {"correct": false, "option_text": "D. They like their tutor to choose their pieces"}, {"correct": false, "option_text": "E. They like to choose technically demanding pieces."}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('32de0520-b5ff-4105-99f8-d7e166677df1', 'aff5f03b-531f-4364-98df-910d0d47a6be', 'radio', 'Questions 33-35', '', '<p>Choose the correct letter, <strong>A, B, C</strong> or <strong>D</strong>.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A. Literacy levels of the population increased."}, {"option_text": "B. The development of printing technology made it easier to publish."}, {"option_text": "C. Schools were open to children."}, {"option_text": "D. People were fond of collecting superb picture books."}], "question": "In paragraph 4, what changes happened at that time in Europe?"}, {"correct": 2, "options": [{"option_text": "A. They made the stories shorter."}, {"option_text": "B. They used more oral language."}, {"option_text": "C. The content of the tales became less violent."}, {"option_text": "D. They found other origins of the tales."}], "question": "What changes did the Grimm Brothers make in later editions?"}, {"correct": 3, "options": [{"option_text": "A. She wrote stories."}, {"option_text": "B. She discussed the stories with them."}, {"option_text": "C. She translated a popular book for the brothers using her talent for languages."}, {"option_text": "D. She told the oral stories that were based on traditional Italian stories."}], "question": "What did Marie Hassenpflug contribute to the Grimm’s Fairy tales?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">33. In paragraph 4, what changes happened at that time in Europe? — {A. Literacy levels of the population increased.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3 &amp; 4):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"24\">“…all to satisfy a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"45\">newly literate audience</strong> seeking virtuous material for the nursery.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “newly literate audience” (nhóm công chúng mới biết chữ) ám chỉ rằng tại thời điểm đó ở châu Âu, trình độ biết chữ của người dân đã tăng lên (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"158\">literacy levels increased</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">34. What changes did the Grimm Brothers make in later editions? — {C. The content of the tales became less violent.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3 &amp; 4):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"24\">“Once the Brothers Grimm sighted this new public, they set about <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"89\">refining and softening their tales</strong>… cruel mothers became nasty stepmothers, unmarried lovers were made chaste…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để phù hợp với công chúng mới là trẻ em và phụ huynh, hai anh em đã “refining and softening” (tinh chỉnh và làm mềm mỏng hóa) các câu chuyện. Việc biến mẹ đẻ độc ác thành mẹ kế hay giảm bớt các tình tiết nhạy cảm chính là làm cho nội dung bớt bạo lực/thô ráp hơn (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"276\">less violent/softened</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">35. What did Marie Hassenpflug contribute to the Grimm’s Fairy tales? — {D. She told the oral stories that were based on traditional Italian stories.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Marie’s wonderful stories <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"47\">blended motifs from the oral tradition and from Perrault’s</strong> influential 1697 book… Many of these <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"145\">had been adapted from earlier Italian tales</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Marie Hassenpflug là một người kể chuyện (told the oral stories). Những câu chuyện của bà là sự pha trộn giữa truyền thống truyền miệng và sách của Perrault, vốn có nguồn gốc từ các câu chuyện của Ý (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"212\">based on traditional Italian stories</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('cf898fa8-4479-4b62-877b-275a2efef4f3', 'aaceccaf-7e60-4c47-ae27-6a70e5e6dc40', 'radio', 'Questions 11–16', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "There will be free entry."}, {"option_text": "There will be fewer people."}, {"option_text": "There will be special classes."}], "question": "Why does Jane recommend visiting the Music Tent on Tuesday?"}, {"correct": 2, "options": [{"option_text": "weekends only"}, {"option_text": "every evening"}, {"option_text": "every afternoon"}], "question": "When do the educational workshops take place in the Music Tent?"}, {"correct": 0, "options": [{"option_text": "The tickets will be cheaper there"}, {"option_text": "You can get tickets in advance there"}, {"option_text": "It''s easier to get tickets there than in the city"}], "question": "Why does Jane recommend going to the library to buy a ticket?"}, {"correct": 2, "options": [{"option_text": "its gardens"}, {"option_text": "its architecture"}, {"option_text": "its location"}], "question": "What will history lovers find interesting about Macquarie House?"}, {"correct": 1, "options": [{"option_text": "it will be much larger than before."}, {"option_text": "there will be free entertainment."}, {"option_text": "the food will be cooked by international chefs."}], "question": "The Big Barbecue is different this year because"}, {"correct": 2, "options": [{"option_text": "see a steam engine working"}, {"option_text": "dress up in a railway worker''s uniform"}, {"option_text": "have a meal inside an old train"}], "question": "What can you do at the Railway Museum?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Host:</strong> Good afternoon listeners, thanks for tuning in to 4KB. Jane Lewis is with us from Tourism Queensland to tell us about the annual Queensland Festival. Jane, welcome.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Jane:</strong> Morning John. So much is going on for the next couple of weeks in our festival here in the state’s capital of Brisbane. The Music Tent opens this week, and this will be an event not to be missed. As the name suggests, the Music Tent is an enormous tent where musical performances and activities will be going on throughout the day for the next two weeks.</p>\n<p data-path-to-node=\"5\">Monday is going to be really busy as it’s a public holiday and the first day of the event. It’s going to be lots of fun, but <strong data-path-to-node=\"5\" data-index-in-node=\"125\"><span style=\"background-color: #f1c40f;\">(Q11) if you’re free, it’s probably a better option to leave it till Tuesday unless you love crowds</span>.</strong> The following day is when the master classes take place, and this requires pre-registration, so you can’t just turn up, I’m afraid. The weekend educational workshops were so popular last year that they have been extended this year. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"458\">(Q12) They now run each afternoon from 1:00 till 4:00, before the evening performances start from 5:00.</strong></span> If you’re learning to play an instrument, these workshops are great fun, so make sure you get along there.</p>\n<p data-path-to-node=\"6\">Tickets for the Music Tent events are available from the door, or you can purchase them at the ticket office located in the city centre. For the best deal, though, take proof of your home address to any library. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"212\">(Q13) As a local resident, you will be able to purchase discounted tickets.</strong></span></p>\n<p data-path-to-node=\"7\">Apart from music, we’ll also be celebrating our local history with a special walking tour around Brisbane’s city centre. Not to be missed on the walk is a tour of Macquarie House, the home of Queensland’s first governor. It has lovely gardens you can walk around or picnic in. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"277\">(Q14) This building has a fascinating history because it was built on the very same spot where the first settlers landed</strong></span>, so it’s really worth a visit if you enjoy learning about our local history.</p>\n<p data-path-to-node=\"8\">No Australian event is complete without a Barbie, and I think the big barbecue is going to be fantastic. It’s not quite as big as the Millennium Year barbecue, but <strong data-path-to-node=\"8\" data-index-in-node=\"164\"><span style=\"background-color: #f1c40f;\">(Q15) there’ll be local and international bands playing on the main stage for the first time this year at no extra cost</span>.</strong> As always, the food will be prepared by top local chefs—my mouth is watering already!</p>\n<p data-path-to-node=\"9\">I really recommend going along to the Railway Museum during the festival because trains are such an important part of Queensland’s history. On loan from Queensland Rail at the moment is our very first steam train. You won’t be able to see it in operation, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"260\">(Q16) you can hop on board and have a meal in the old dining carriage.</strong></span> There is also a wonderful display of uniforms that have been worn over the last 100 years.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Narrator:</strong> Now listen and answer questions 17 to 20.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Jane:</strong> Another really special opportunity is a return trip on our only remaining steam train, which runs from Ipswich to Toowoomba. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"131\">(Q17-18) If you purchase a family ticket, as well as a trip on the train, you receive a free Australian flag each to wave while aboard.</strong></span></p>\n<p data-path-to-node=\"13\">There is a small charge for the Ipswich Museum tour, but I think it’s worth it as it makes an educational day out. The documentary film you can see there is interesting, and it’s well worth the two-dollar entry fee. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"216\">(Q17-18) On the return train journey, the kids get a lovely activity book designed to teach them about the history of the steam train.</strong></span> Don’t forget to bring your sunscreen and hats—it’s going to be hot up there in Toowoomba at this time of year!</p>\n<p data-path-to-node=\"14\">And finally, I’m going to tell you about an event called “Our Favourite Place”. This is an opportunity for the public to vote for their favourite spot anywhere in the state—maybe a park or a restaurant, it’s up to you. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"219\">(Q19-20) You can vote even if you’re not living in the area at the moment.</strong><strong data-path-to-node=\"14\" data-index-in-node=\"294\"> You can vote as often as you like by sending in the voting form</strong>,</span> or if you prefer, send a text message from any Australian mobile phone number with the name of the location. It’s so easy! Not much time left, though, so get those votes in as soon as possible. The winning location will be announced on the last Saturday of the festival. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"639\">(Q19-20) Also, remember that no age limit applies for this one</strong></span>, so this is a great way to get the whole family involved.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Host:</strong> Well, thank you very much for that, Jane. Now we have music…</p>"}]', 0);
INSERT INTO public.questions VALUES ('de9b6a32-9c9f-43b8-8f71-3c6c2953159a', 'aaceccaf-7e60-4c47-ae27-6a70e5e6dc40', 'checkbox', 'Questions 17–18', '', '<div class="quests-inner-desc">
<div class="txt">
<p>Choose <strong>TWO</strong> correct answers.</p>
<p>Which <strong>TWO </strong>free things does the family ticket on the steam train include?</p>
</div>
</div>', 'list_selection', 'null', '[{"correct": false, "option_text": "an educational talk"}, {"correct": true, "option_text": "a children''s book"}, {"correct": false, "option_text": "a short film"}, {"correct": true, "option_text": "a flag"}, {"correct": false, "option_text": "a tour of the Ipswich Museum"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('dabc2229-94b3-4168-a54f-f757be53ae09', 'aaceccaf-7e60-4c47-ae27-6a70e5e6dc40', 'checkbox', 'Questions 19–20 ', '', '<div class="quests-inner-desc">
<div class="txt">
<p>Choose <strong>TWO</strong> correct answers.</p>
</div>
</div>
<div class="quests-list">
<div id="4751" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="1877" data-numctn="19" data-count="19" data-quest="19-20" data-choices="2">
<div class="tt-head">Which <strong>TWO </strong>things apply when voting for Our Favourite Place?</div>
</div>
</div>', 'list_selection', 'null', '[{"correct": true, "option_text": "People of any age may vote."}, {"correct": false, "option_text": "You may send in your vote by email."}, {"correct": false, "option_text": "Only local residents may vote."}, {"correct": true, "option_text": "You may vote several times."}, {"correct": false, "option_text": "Voting ends at midnight on Saturday."}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('42f8cd91-32e1-442d-b630-26b6d3a7c45d', 'be181726-6b55-4461-8def-2e7e5088f594', 'matching', 'Questions 14-20', '', '<p>Reading Passage 2 has seven paragraphs, A-G.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p><strong>List of Headings</strong></p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i. Some of the problems that developed at Talbot Park"}, {"optionText": "ii. Where the residents lived while the work was being completed"}, {"optionText": "iii. The ethnic makeup of the new Talbot Park"}, {"optionText": "iv. The unexpectedly high standard of the housing"}, {"optionText": "v. Financial hardship in Talbot Park and a neighbouring community"}, {"optionText": "vi. The experiences of one family living at Talbot Park today"}, {"optionText": "vii. How to co-ordinate and assist the people who live at Talbot Park"}, {"optionText": "viii. A close community in the original Talbot Park development"}, {"optionText": "ix. Raising the money to pay for the makeover"}, {"optionText": "x. Details of the style of buildings used in the makeover"}], "matchingItems": []}', 'null', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">14. Paragraph A: iv (The unexpectedly high standard of the housing)</strong></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\"><strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “‘There is no reason why state housing should look cheap in my view,’ says architect Neil Cotton… I was anticipating a backlash by those who objected to the <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"170\">quality</strong> of what is provided…”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,1,0\"><strong data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Kiến trúc sư Neil Cotton nhấn mạnh rằng tiêu chuẩn xây dựng tại đây cao đến mức ông lo ngại người dân sẽ phản đối vì nó trông quá sang trọng so với một dự án nhà ở xã hội (vốn thường bị coi là rẻ tiền).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">15. Paragraph B: viii (A close community in the original Talbot Park development)</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Initially, there was a <strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"35\">strong sense of neighborliness</strong>. Former residents recall how the garden played a big part in their childhoods… ‘We had respect for our neighbours…’”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn hồi tưởng về những năm 1960 khi Talbot Park còn là một cộng đồng gắn kết, nơi trẻ em chơi đùa cùng nhau và mọi người cư xử với nhau rất lễ độ.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">16. Paragraph C: i (Some of the problems that developed at Talbot Park)</strong></p>\n<ul data-path-to-node=\"3,2,1\">\n<li>\n<p data-path-to-node=\"3,2,1,0,0\"><strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…standards dropped and the neighbourhood began to look shabbier… buildings themselves were also deteriorating… petty crime was on the rise and the garden was considered unsafe.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,1,0\"><strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Liệt kê các vấn đề xuất hiện từ cuối thập niên 70 như nhà cửa xuống cấp, sự thiếu hòa nhập của người nhập cư và tình hình an ninh mất kiểm soát.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,3,0\"><strong data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">17. Paragraph D: x (Details of the style of buildings used in the makeover)</strong></p>\n<ul data-path-to-node=\"3,3,1\">\n<li>\n<p data-path-to-node=\"3,3,1,0,0\"><strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The first priority was to mix up the housing by employing a variety of plans… free-standing houses, some semi-detached, some low level, multi-apartment blocks.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,1,1,0\"><strong data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tập trung vào chi tiết thiết kế “mix and match” với sự đa dạng về kiểu dáng nhà ở để tránh sự đơn điệu và tạo bản sắc riêng cho cư dân.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,4,0\"><strong data-path-to-node=\"3,4,0\" data-index-in-node=\"0\">18. Paragraph E: iii (The ethnic makeup of the new Talbot Park)</strong></p>\n<ul data-path-to-node=\"3,4,1\">\n<li>\n<p data-path-to-node=\"3,4,1,0,0\"><strong data-path-to-node=\"3,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The population today is cosmopolitan: <strong data-path-to-node=\"3,4,1,0,0\" data-index-in-node=\"50\">50% Pacific Islanders, 20% Maori, 15% Asian, 10% New Zealand European</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,4,1,1,0\"><strong data-path-to-node=\"3,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cung cấp số liệu thống kê cụ thể về cơ cấu sắc tộc đa dạng của cư dân đang sống tại dự án mới.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,5,0\"><strong data-path-to-node=\"3,5,0\" data-index-in-node=\"0\">19. Paragraph F: v (Financial hardship in Talbot Park and a neighbouring community)</strong></p>\n<ul data-path-to-node=\"3,5,1\">\n<li>\n<p data-path-to-node=\"3,5,1,0,0\"><strong data-path-to-node=\"3,5,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The area has a high density of households with incomes in the <strong data-path-to-node=\"3,5,1,0,0\" data-index-in-node=\"74\">$5,000 to $15,000 range</strong> and very few with an income over $70,000.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,5,1,1,0\"><strong data-path-to-node=\"3,5,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đưa ra số liệu cụ thể về thu nhập để làm nổi bật thực trạng khó khăn về kinh tế (financial hardship) của người dân tại khu vực này so với phần còn lại của thành phố.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,6,0\"><strong data-path-to-node=\"3,6,0\" data-index-in-node=\"0\">20. Paragraph G: vii (How to co-ordinate and assist the people who live at Talbot Park)</strong></p>\n<ul data-path-to-node=\"3,6,1\">\n<li>\n<p data-path-to-node=\"3,6,1,0,0\"><strong data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…you have to actually <strong data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"36\">help them to get to know each other</strong> by organising morning teas and street barbecues.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,6,1,1,0\"><strong data-path-to-node=\"3,6,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mô tả cách quản lý không chỉ bằng kỷ luật (strict rules) mà còn bằng các hoạt động hỗ trợ cộng đồng để giúp cư dân sinh sống hòa thuận trong một môi trường đông đúc.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('26714eb7-df41-4792-b64a-775e32bd9a86', 'be181726-6b55-4461-8def-2e7e5088f594', 'matching', 'Questions 21–23', '', '<p>Match each person with the correct idea, A-F.</p>
<p>Write the correct letter, A-F, in boxes 21-23 on your answer sheet.</p>', 'matching_name', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "Good tenant management involves supervision and regulation."}, {"optionText": "State housing must be built at minimum expense to the public."}, {"optionText": "Organising social events helps tenants to live close together."}, {"optionText": "Mixed-race communities require adaptable and responsive designs."}, {"optionText": "Complaints were expected about the high standard of the development."}, {"optionText": "Too many rules and regulations will cause resentment from tenants."}], "matchingItems": [{"questionPart": "James Lundy", "correctAnswer": "D"}, {"questionPart": "Graham Bodman", "correctAnswer": "A"}, {"questionPart": "Stuart Bracey", "correctAnswer": "C"}]}', 'null', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">21. James Lundy: J (Mixed-race communities require adaptable and responsive designs.)</strong></p>\n<ul data-path-to-node=\"6,0,1\">\n<li>\n<p data-path-to-node=\"6,0,1,0,0\"><strong data-path-to-node=\"6,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…important that the buildings were sufficiently <strong data-path-to-node=\"6,0,1,0,0\" data-index-in-node=\"62\">flexible to cater for the needs of people from a wide variety of cultural backgrounds</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,0,1,1,0\"><strong data-path-to-node=\"6,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lundy tin rằng thiết kế linh hoạt (flexible) là cần thiết để đáp ứng nhu cầu của các nhóm sắc tộc khác nhau (mixed-race/cultural backgrounds).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">22. Graham Bodman: G (Good tenant management involves supervision and regulation.)</strong></p>\n<ul data-path-to-node=\"6,1,1\">\n<li>\n<p data-path-to-node=\"6,1,1,0,0\"><strong data-path-to-node=\"6,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The focus is on <strong data-path-to-node=\"6,1,1,0,0\" data-index-in-node=\"28\">frequent inspections</strong> and <strong data-path-to-node=\"6,1,1,0,0\" data-index-in-node=\"53\">setting clear guidelines and boundaries</strong> regarding the sort of behaviour we expect from tenants.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,1,1,0\"><strong data-path-to-node=\"6,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ông nhấn mạnh việc kiểm soát thông qua giám sát (inspections) và các quy định (guidelines/rules).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">23. Stuart Bracey: I (Organising social events helps tenants to live close together.)</strong></p>\n<ul data-path-to-node=\"6,2,1\">\n<li>\n<p data-path-to-node=\"6,2,1,0,0\"><strong data-path-to-node=\"6,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…help them to get to know each other by <strong data-path-to-node=\"6,2,1,0,0\" data-index-in-node=\"54\">organising morning teas and street barbecues</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,1,1,0\"><strong data-path-to-node=\"6,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ông cho rằng các sự kiện xã hội (social events) là chìa khóa để cư dân sống gần nhau một cách hòa thuận.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('89c1479c-2308-4293-adb6-0dcd2c496579', '4ee4193c-58c2-4d76-86e2-af33bfb93cd5', 'radio', 'Questions 21–25', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "maximizing profits"}, {"option_text": "minimizing environmental damage"}, {"option_text": "meeting legal requirements"}], "question": "What do Pam and Jason primarily hope to learn more about from their project?"}, {"correct": 1, "options": [{"option_text": "providing information about contents"}, {"option_text": "extending the useful life of products"}, {"option_text": "reducing excess waste from packaging"}], "question": "Which issue about packaging do Pam and Jason feel is most important to food shoppers today?"}, {"correct": 2, "options": [{"option_text": "They are the subjects of previously published studies."}, {"option_text": "They are the most profitable food retail businesses."}, {"option_text": "They will offer good opportunities for interviews."}], "question": "Why have Pam and Jason decided to concentrate specifically on large supermarkets?"}, {"correct": 0, "options": [{"option_text": "its range of nationalities"}, {"option_text": "its high education level"}, {"option_text": "its young age"}], "question": "The professor says that the local population has unusual food-shopping habits because of"}, {"correct": 0, "options": [{"option_text": "taste"}, {"option_text": "price"}, {"option_text": "health benefits"}], "question": "According to the literature, what influences food shoppers most?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Professor:</strong> Hello, Pam, Jason. Thanks for coming to discuss your marketing project. I’ve read your proposal and outline, so let’s go over it, okay?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Jason:</strong> Right.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Professor:</strong> You’ve chosen the topic of food packaging. So, what did you want to get out of doing this project?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Pam:</strong> <strong data-path-to-node=\"6\" data-index-in-node=\"5\"><span style=\"background-color: #f1c40f;\">(Q21) We decided if we did our project on packaging, we might find some practical tips on how a business could make more money</span>.</strong> After all, we’re Business Admin students, and that’s the ultimate reason we’re on the course, isn’t it?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Jason:</strong> So, although we know the impact of packaging on the environment is important, we feel the government regulations are pretty strict already in that area.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Professor:</strong> Okay. Now, you’ve decided to look specifically at the packaging of food. What do you think the main issue is for shoppers these days?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Jason:</strong> Some people get upset about the waste with all the plastic and stuff used to package food, but I guess most don’t pay much attention to that.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Pam:</strong> A few years ago, people seemed concerned about packaging food so that buyers knew more about what it contains, from labels like calories, additives, and stuff. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"165\">(Q22) But in the current economic climate, Jason and I think people are most interested in packaging that helps keep food fresh for longer.</strong></span></p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Professor:</strong> And you’ve chosen to concentrate on big supermarket chains. Why not look at local stores or even convenience stores?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Jason:</strong> Well, there are some interesting published studies based on small retail outlets, and we looked at those. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"113\">(Q23) But after a little investigation, we found that the managers of the large supermarkets in this area wanted to be helpful and are willing to let us talk to them and their employees.</strong></span></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Pam:</strong> Of course, the supermarkets do account for most food sales around here, but that wasn’t our reason for choosing them.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Professor:</strong> Speaking of this area, you know, the food buying choices here are quite unusual. Since we’re in a university town, the population is quite young.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Jason:</strong> But actually, my research shows that age isn’t the factor in making the area unique. And although the education level is pretty high, that doesn’t seem very important either.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Pam:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"5\">(Q24) I guess it’s because we’ve got people from all over the world living here with all the foreign students at university.</strong></span></p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Professor:</strong> That’s it. Our supermarkets cater for a huge diversity of cultures.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Jason:</strong> In our survey of the literature, I was struck by what shoppers say is most important to them when they buy. I would have thought how much the buyer had to pay would be the key, but that doesn’t appear to be the case.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Pam:</strong> That’s right.<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"19\" data-index-in-node=\"19\">(Q25) How delicious the buyer considers the product seems to be the main thing.</strong></span> Whether or not the food is good for you is pretty low down on the customer’s priorities.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Professor:</strong> That’s interesting.</p>\n<h2 data-path-to-node=\"22\"> </h2>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Professor:</strong> Let’s discuss the practical experiment you’re planning. You’re going to design the box for a new breakfast cereal, which you’ll try to market… Let’s talk through the experiment.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Jason:</strong> Okay, that would be helpful.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Professor:</strong> Now, the number of different designs you’re proposing to show each student is two. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"94\">(Q26) If I were you, I’d make it at least four. That way you can examine their reaction to more variety in the kinds of packaging.</strong></span></p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Pam:</strong> Okay, good idea. We do have several more designs.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Jason:</strong> Now we’ve got a sample from our class of about 20. Is that enough?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Professor:</strong> Probably not. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"28\" data-index-in-node=\"25\">(Q27) Try talking to the assistant in the Business Studies department; he can sort out how to recruit some more from other classes for you.</strong></span></p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Pam:</strong> Right.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Professor:</strong> Now, as to how you’re going to display your packages to the students. I did talk about those technical issues in one of your first classes. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"151\">(Q28) Go back and look over what I said about the practical realities of conducting experiments.</strong></span></p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Jason:</strong> Okay, we can do that.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Pam:</strong> We are going to ask each student to choose the one design they think is best, but how will we know why they chose that one?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Professor:</strong> Well, don’t just rely on oral prompts. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"33\" data-index-in-node=\"50\">(Q29) Give them a series of written questions. That way you’ll have hard data.</strong></span></p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Jason:</strong> Okay. But what about analyzing the data?</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Professor:</strong> Well, we’ve got an excellent computer program to gather it all together, but we still need to interpret it ourselves.</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Pam:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"36\" data-index-in-node=\"5\">(Q30) So we’ll need to give ourselves a few more days for that.</strong></span></p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Professor:</strong> Yes, we will. Anyway, it’s all looking good now.</p>"}]', 0);
INSERT INTO public.questions VALUES ('78c88d0d-a344-4979-98d9-6fad17cd3579', '5252c317-0163-4fcf-a9d5-e8baa4860d36', 'matching', 'Questions 14-20', NULL, '<p>Reading Passage 2 has seven paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i The best moment to migrate"}, {"optionText": "ii The unexplained rejection of closer feeding grounds"}, {"optionText": "iii The influence of weather on the migration route"}, {"optionText": "iv Physical characteristics that allow birds to migrate"}, {"optionText": "v The main reason why birds migrate"}, {"optionText": "vi The best wintering grounds for birds"}, {"optionText": "vii Research findings on how birds migrate"}, {"optionText": "viii Successful migration despite the trouble of wind"}, {"optionText": "ix The contrast between long-distance migration and short-distance migration"}, {"optionText": "x Mysterious migration despite lack of teaching"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"1\">Câu 14: iv (Physical characteristics that allow birds to migrate)</p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Birds have many unique design features that enable them to perform such amazing feats of endurance.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn này tập trung liệt kê hàng loạt các đặc điểm cấu tạo cơ thể giúp chim di cư như: xương rỗng nhẹ, lông thiết kế tinh xảo, hệ thống hô hấp hiệu quả và khả năng tích trữ mỡ để cung cấp năng lượng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\">Câu 15: v (The main reason why birds migrate)</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The fundamental reason that birds migrate is to find adequate food during the winter months when it is in short supply.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định lý do cơ bản và quan trọng nhất khiến loài chim phải di cư chính là để tìm kiếm nguồn thức ăn đầy đủ khi mùa đông đến (đặc biệt là ở vùng Bắc Cực và ôn đới).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\">Câu 16: ii (The unexplained rejection of closer feeding grounds)</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One puzzling fact is that many birds journey much further than would be necessary just to find food and good weather.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về một điều bí ẩn: tại sao chim lại bay qua những nơi có môi trường sống phù hợp để đi đến những nơi xa hơn rất nhiều (ví dụ như chim swallow bay tận sang Nam Phi thay vì dừng lại ở xích đạo Phi Châu).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\">Câu 17: x (Mysterious migration despite lack of teaching)</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One of the greatest mysteries is how young birds know how to find the traditional wintering areas without parental guidance.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nội dung nhấn mạnh vào việc chim non (như loài cuckoo) có thể tự tìm đường đến nơi tránh rét của tổ tiên mà không cần sự dạy dỗ hay dẫn dắt của chim bố mẹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\">Câu 18: vii (Research findings on how birds migrate)</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Mounting evidence has confirmed that birds use the positions of the sun and stars to obtain compass directions. They also seem to be able to detect the earth’s magnetic field…”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn trình bày các kết quả nghiên cứu và thí nghiệm về cách chim định vị bằng ánh sáng mặt trời, các vì sao và từ trường trái đất để di chuyển chính xác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\">Câu 19: i (The best moment to migrate)</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…part of the skill in arriving safely is setting off at the right time. This means accurate weather forecasting and utilizing favourable winds.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về kỹ năng chọn thời điểm khởi hành dựa trên khả năng dự báo thay đổi thời tiết và áp suất của loài chim để đảm bảo hành trình an toàn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\">Câu 20: viii (Successful migration despite the trouble of wind)</p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Conversely, each autumn a small number of North American birds are blown across the Atlantic by fast-moving westerly tailwinds. Not only do they arrive safely in Europe, but… some make it back to North America…”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra ví dụ về những con chim bị gió thổi bay lệch hướng qua đại dương nhưng vẫn sống sót, đến nơi an toàn và thậm chí có thể quay trở về vào mùa xuân sau.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('8cf62f34-05f4-4b94-9a91-1b4d3e80d2c0', '8e5f840f-92b8-42e5-80e6-6125b945edf9', 'radio', 'Questions 11 - 16', '', '<p>Choose the correct letter A, B or C</p>
<p><span style="font-size: 14pt;"><strong>Museum tour</strong></span></p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A. see the most popular exhibits first"}, {"option_text": "B. pay a brief visit to each gallery"}, {"option_text": "C. go to the photography gallery last"}], "question": "What does the tour guide advise the visitors to do in the museum today?"}, {"correct": 1, "options": [{"option_text": "A. a textile factory"}, {"option_text": "B. the town hall"}, {"option_text": "C. the railway station"}], "question": "The museum was designed by William Craven, who also designed"}, {"correct": 0, "options": [{"option_text": "A. staircase"}, {"option_text": "B. floor"}, {"option_text": "C. windows"}], "question": "The museum won an award for the preservation of the"}, {"correct": 2, "options": [{"option_text": "A. the pubic"}, {"option_text": "B. the government"}, {"option_text": "C. local businesses"}], "question": "Most of the money for the project came from"}, {"correct": 0, "options": [{"option_text": "A. restoring existing collections"}, {"option_text": "B. developing educational programmes"}, {"option_text": "C. purchasing new objects for display"}], "question": "Over the next five years, the museum will invest mainly in"}, {"correct": 2, "options": [{"option_text": "A. visit the museum''s website"}, {"option_text": "B. read the leaflets on display"}, {"option_text": "C. attend the monthly lectures"}], "question": "Visitors who are interested in learning more about the exhibits should"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 2: MUSEUM TOUR</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Guide:</strong> Okay well, first of all, I’ll give you a bit of background to the museum and then tell you about some of the galleries. You probably won’t have time to see everything today, so <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"3\" data-index-in-node=\"184\">(11) what I recommend you do is go to the Egyptian Room first because it’s everyone’s favourite place [A – see most popular exhibits first]</strong></span> and it gets very crowded with the school parties later in the day. Oh, and I should mention that the photography gallery is undergoing refurbishment at the moment, so while that’s definitely worth seeing, it’ll have to wait for another time.</p>\n<p data-path-to-node=\"4\">Now, the actual museum building itself is quite interesting. It was designed by a local architect called William Craven in the 19th century, at a time when the city was developing rapidly with new factories to cope with the expansion of the textile industry. The museum’s built in a very similar style to the railway station, which was constructed at around the same time. That was designed by another architect, but <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"417\">(12) William Craven did also provide the plans for the town hall [B]</strong>,</span> which was built just a few years later.</p>\n<p data-path-to-node=\"5\">Construction of the museum began in 1888 with a large team of carpenters, stonemasons and builders. Then in recent years it’s been extensively refurbished. The lovely big windows have been retained to let the daylight flood in, but the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"5\" data-index-in-node=\"236\">(13) award-winning part of the project was the restoration of the area around the central hall, in particular the beautiful wrought iron staircase [A]</strong>,</span> which was brought back to its former glory. Unfortunately, the museum’s original tiled floor had to be replaced with new tiles of a similar design.</p>\n<p data-path-to-node=\"6\">It was a very expensive project, and since we don’t charge admission fees, we had to find other ways of funding it. We did get some money from the department of culture at national level, but <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"6\" data-index-in-node=\"192\">(14) we had even more generous support from companies and industries here in the city who were our main benefactors [C – local businesses]</strong></span>. However, we do also depend on donations from people living in the area for the ongoing maintenance of the building.</p>\n<p data-path-to-node=\"7\">So how will the museum mainly be spending its money in the next five years? We already work with schools and colleges, helping people get a better understanding of all the creative disciplines. We consider the most important part of our work <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"242\">(15) the restoration of the valuable historical objects we are lucky enough to have in our possession, and this will continue to be where the most funding is allocated [A – restoring existing collections]</strong></span>. Of course it would be wonderful to purchase new objects for the museum, but we simply don’t have the space at the moment.</p>\n<p data-path-to-node=\"8\">Well, we do hope you enjoy your day today, but if you would like to learn more about our exhibits on display here, <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"8\" data-index-in-node=\"115\">(16) I suggest you come to one of the Saturday morning lectures which are given every month by one of our team of experts [C]</strong></span>. Of course you can pick up leaflets about the exhibits in most of the galleries too, but you’ll only get a basic introduction from those. We’re also working to update our website so that it provides more background on the exhibits, but that’s still at the planning stage.</p>\n<hr>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Guide:</strong> Okay now, let me just tell you a bit about what’s on at the moment. Well, we’re very well known for our collection of <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"125\">(17) 18th-century paintings [C – various countries]</strong></span>. Both oils and watercolours, some of these are English landscapes and portraits, but <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"262\">we also have paintings by other European artists who were working during this period</strong>.</span></p>\n<p data-path-to-node=\"12\">If you’re interested in art that’s a bit nearer home,<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"12\" data-index-in-node=\"54\">(18) The Farnley Collection [B – local resident]</strong></span></span> is a set of drawings by Paul Farnley. He was born in Ireland, but <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"12\" data-index-in-node=\"169\">he came to work here in the city in the early 20th century and then made it his home</strong></span>. He worked in a factory but spent his spare time drawing the buildings and urban landscape of the city, and his work has now been collected and displayed here.</p>\n<p data-path-to-node=\"13\">On a more practical note, we have a display of <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"13\" data-index-in-node=\"47\">(19) kitchen appliances [E – things no longer common]</strong></span>, which might interest you. These are the sorts of things you wouldn’t normally expect to see in a museum. There’s an electric potato peeler from the 1970s which sold really well at the time, <span style=\"text-decoration: underline; background-color: #f3db7b;\">but <strong data-path-to-node=\"13\" data-index-in-node=\"296\">no one’s got one now</strong>.</span> There are lots of other similar appliances which must have seemed like great ideas at the time but which never took off.</p>\n<p data-path-to-node=\"14\">You might also like to visit the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"14\" data-index-in-node=\"33\">(20) Fashion Gallery [D – temporary displa</strong><strong data-path-to-node=\"14\" data-index-in-node=\"33\">y]</strong>. This is an exhibition which is <strong data-path-to-node=\"14\" data-index-in-node=\"110\">running for the next few weeks only</strong></span> and shows men’s and women’s fashion from 1900 to 2000, including some of the famous designers of the time. Okay, so if anyone’s got any questions, follow me.</p>"}]', 0);
INSERT INTO public.questions VALUES ('216b9e0c-a482-4a74-98af-8df3acd2906d', '4ee4193c-58c2-4d76-86e2-af33bfb93cd5', 'matching', 'Questions 26–30', '', '<p>What action do Pam and Jason agree to take for each of the following aspects of their experiment?</p>
<p>Choose <strong>FIVE</strong> correct answers, <strong>A</strong>–<strong>G</strong>, next to questions 26-30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Aspects of the experiment</strong></p>\n<p> </p>\n<p>the number of different designs offered {B widen the choice}</p>\n<p> </p>\n<p>the sample size of students {E ask for help}</p>\n<p> </p>\n<p>how to display the packages {A refer to course notes}</p>\n<p> </p>\n<p>finding the reasons for students'' choices {F design a questionnaire}</p>\n<p> </p>\n<p>analysis of data collected {D allow for more time}</p>", "answerOptions": [{"optionText": "A refer to course notes"}, {"optionText": "B widen the choice"}, {"optionText": "C use more colours"}, {"optionText": "D allow for more time"}, {"optionText": "E ask for help"}, {"optionText": "F design a questionnaire"}, {"optionText": "G plan for oral interviews"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('b218b1f5-baa7-439a-8bf4-589ff5b67f1a', '5252c317-0163-4fcf-a9d5-e8baa4860d36', 'checkbox', 'Questions 21-22', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>of the following statements are true of bird migration?</p>
', 'multiple_choice_many', 'null', '[{"option": "Birds often fly further than they need to.", "correct": true}, {"option": "Birds travelling in family groups are safe.", "correct": false}, {"option": "Birds flying at night need less water.", "correct": true}, {"option": "Birds have much sharper eyesight than humans.", "correct": false}, {"option": "Only shorebirds are resistant to strong winds.", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\">Câu 21: A (Birds often fly further than they need to)</p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 1-2.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One puzzling fact is that many birds journey much further than would be necessary just to find food and good weather.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định một sự thật gây khó hiểu là nhiều loài chim thực hiện những hành trình xa hơn mức cần thiết so với việc chỉ đơn thuần là đi tìm thức ăn hay thời tiết tốt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\">Câu 22: C (Birds travelling at night need less water)</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 13-14.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the danger of dehydration due to flying for long periods in warm, sunlit skies is reduced.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc di cư vào ban đêm giúp chim tránh được tình trạng mất nước (dehydration) so với khi bay dưới bầu trời nắng ấm vào ban ngày. Điều này đồng nghĩa với việc chúng cần ít nước hơn hoặc giữ nước tốt hơn khi bay đêm.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('5dae993e-15c9-411c-8cfb-2bdb021c8869', '5252c317-0163-4fcf-a9d5-e8baa4860d36', 'fillup', 'Questions 23-26', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the sentences below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p>It is a great mystery that young birds like cuckoos can find their wintering grounds without {parental guidance}</p>
<p>Evidence shows birds can tell directions like a {compass} by observing the sun and the stars.</p>
<p>One advantage for birds flying at night is that they can avoid contact with {daytime predators}</p>
<p>Laboratory tests show that birds can detect weather without {visible} signs.</p>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\">Câu 23: parental guidance</p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1-2.</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One of the greatest mysteries is how young birds know how to find the traditional wintering areas without <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"118\">parental guidance</strong>.”</li>\n<li><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nêu rõ một trong những bí ẩn lớn nhất là làm thế nào những con chim non như chim cúc cu có thể tìm thấy nơi tránh rét mà không cần sự “hướng dẫn của bố mẹ” (parental guidance).</li>\n</ul>\n<p data-path-to-node=\"3\">Câu 24: compass</p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 1-2.</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Mounting evidence has confirmed that birds use the positions of the sun and stars to obtain <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"104\">compass</strong> directions.”</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các bằng chứng cho thấy chim sử dụng vị trí của mặt trời và các vì sao để xác định phương hướng giống như một chiếc “lạt bàn” (compass).</li>\n</ul>\n<p data-path-to-node=\"5\">Câu 25: daytime predators</p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 15-16.</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"12\">Daytime predators</strong> are avoided and the danger of dehydration… is reduced.”</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một trong những lợi ích của việc bay vào ban đêm là chim có thể tránh được sự tiếp xúc hoặc tấn công từ các “động vật săn mồi ban ngày” (daytime predators).</li>\n</ul>\n<p data-path-to-node=\"7\">Câu 26: visible</p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 4-5.</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Often birds react to weather changes before there is any <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"69\">visible</strong> sign of them.”</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các bài kiểm tra trong phòng thí nghiệm và quan sát thực tế cho thấy chim có phản ứng với sự thay đổi thời tiết ngay cả khi chưa có bất kỳ dấu hiệu “có thể nhìn thấy được” (visible) nào.</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('de4d965d-5914-4f91-b439-263ceb40062d', '2a59950a-dfd8-4aaa-9464-37388e2b4424', 'matching', 'Question 14-19', '', '<p>Reading Passage 2 has five sections.</p>
<p>Choose the correct heading or each section rom the list of headings below.</p>
<p>Choose the correct letter, <strong>i-vii</strong> in boxes <strong>14-18.</strong></p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i. The desire to make expensive jewellery"}, {"optionText": "ii The clues that indicate ancient items were decorative"}, {"optionText": "iii Querying the changes in the value of traded items"}, {"optionText": "iv A natural human talent"}, {"optionText": "v How status can be gained from ownership of goods"}, {"optionText": "vi. Recent finds alter theories about when consumerism started"}, {"optionText": "vii. Changes in research methods"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">1. Đoạn 1 (Paragraph 1) – Đáp án: iv (A natural human talent)</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Câu đầu tiên của đoạn 1.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"3,1,0\" data-index-in-node=\"11\">“Humans are <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"23\">born to trade</strong>… the heart of commerce is an <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"68\">instinctive ability</strong>… Evidence… leaves little doubt that the exchange of food and flavors is <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"164\">innate</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định con người sinh ra đã có bản năng giao thương (born to trade). Các từ khóa như <em data-path-to-node=\"3,2,0\" data-index-in-node=\"109\">instinctive ability</em> (khả năng bản năng) và <em data-path-to-node=\"3,2,0\" data-index-in-node=\"152\">innate</em> (bẩm sinh) hoàn toàn khớp với tiêu đề “A natural human talent” (Một tài năng tự nhiên của con người).</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">2. Đoạn 2 (Paragraph 2) – Đáp án: iii (Querying the changes in the value of traded items)</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Cuối đoạn 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,1,0\" data-index-in-node=\"11\">“Clearly, the <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"25\">worth of such goods is not inherent</strong> but resides in certain <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"84\">intangible qualities</strong>… When did humans start holding these goods in <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"153\">such high esteem</strong>?”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này đặt ra câu hỏi về giá trị của hàng hóa. Thay vì giá trị thực dụng (subsistence), con người bắt đầu coi trọng những giá trị vô hình (intangible qualities). Câu hỏi ở cuối đoạn chính là một sự “querying” (thắc mắc/truy vấn) về sự thay đổi giá trị này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">3. Đoạn 3 (Paragraph 3) – Đáp án: vi (Recent finds alter theories about when consumerism started)</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Giữa đoạn 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,1,0\" data-index-in-node=\"11\">“All the archaeological evidence… has up to now pointed to a date of around <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"89\">40,000 years ago</strong>. However, <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"116\">discoveries in Africa are pushing the origins of consumerism much further back</strong>… many of them proved to be more than <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"234\">100,000 years old</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước đây người ta tin văn hóa tiêu dùng bắt đầu từ 40,000 năm trước, nhưng những khám phá mới (recent finds) tại hang Blombos đã đẩy mốc thời gian này lùi xa hơn (100,000 năm), làm thay đổi các lý thuyết cũ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">4. Đoạn 4 (Paragraph 4) – Đáp án: ii (The clues that indicate ancient items were decorative)</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đầu và giữa đoạn 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,1,0\" data-index-in-node=\"11\">“Each cluster contains shells of a <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"46\">similar size and colour</strong> with <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"75\">consistently placed holes</strong>. What’s more, all the beads display a <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"139\">pattern of wear suggesting friction from rubbing against thread, clothes</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả liệt kê các “clues” (manh mối) như: kích thước đồng đều, lỗ khoan nhất quán và dấu vết mòn do cọ xát vào chỉ/quần áo để chứng minh những vỏ ốc này được dùng làm đồ trang trí (beads/jewellery) chứ không phải do tự nhiên tích tụ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">5. Đoạn 5 (Paragraph 5) – Đáp án: v (How status can be gained from ownership of goods)</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Giữa đoạn 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,1,0\" data-index-in-node=\"11\">“Among our ancestors, superior skills… would have brought respect – in other words, <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"97\">prestige</strong>. And because prestige brings social benefits, <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"152\">people would want to show off</strong> their talents… through demonstrating <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"221\">possession of material items</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích mối liên hệ giữa việc sở hữu hàng hóa và địa vị xã hội (status/prestige). Việc sở hữu những vật phẩm hiếm (như răng thú dữ hay xe Bugatti ngày nay) là cách để khẳng định vị thế và sự thành công của cá nhân.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('2a2f842c-74dd-4ae0-b4fb-cc73ee0c9422', 'd884be37-2871-489b-9c49-20bcca0ba827', 'radio', 'Questions 1–7', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Hokusai’s earliest artistic works mainly focused on landscapes and actors."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "He was officially recognized as the heir of the Nakajima family."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Hokusai’s apprenticeship with a wood-block engraver contributed to his later success as a printmaker."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The series Thirty-six Views of Mount Fuji was the first landscape work ever created in Japan."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Hokusai often competed with Utamaro in producing prints of women."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "His eldest son helped secure financial stability for him through the Nakajima family connections."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Hokusai changed his residence and artistic name multiple times throughout his life."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. Hokusai’s earliest artistic works mainly focused on landscapes and actors.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4 nói rằng những tác phẩm đầu tiên được xuất bản của ông là về các diễn viên kịch Kabuki (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"106\">actor prints</em>). Đoạn 5 đề cập sau khi kết hôn (khoảng 25 tuổi), ông mới chuyển sang đề tài lịch sử và phong cảnh (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"219\">landscapes</em>).</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc không khẳng định hai đề tài này là &#8220;trọng tâm chính&#8221; (<em data-path-to-node=\"5,2,0\" data-index-in-node=\"74\">mainly focused</em>) trong giai đoạn <strong data-path-to-node=\"5,2,0\" data-index-in-node=\"106\">sớm nhất</strong> (<em data-path-to-node=\"5,2,0\" data-index-in-node=\"116\">earliest</em>). Thực tế, phong cảnh xuất hiện muộn hơn một chút so với tranh diễn viên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. He was officially recognized as the heir of the Nakajima family.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 2: &#8220;&#8230;was adopted&#8230; by a prestigious artisan family named Nakajima but was <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"93\">never accepted as an heir</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Dẫn chứng trực tiếp khẳng định ông <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"47\">chưa bao giờ</strong> được chấp nhận làm người thừa kế chính thức, trái ngược hoàn toàn với câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. Hokusai’s apprenticeship with a wood-block engraver contributed to his later success as a printmaker.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3: &#8220;&#8230;from 15 to 18 years of age he was apprenticed to a wood-block engraver. This early training&#8230; <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"118\">obviously contributed to Hokusai’s artistic development</strong> as a printmaker.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết khẳng định rõ ràng việc học nghề thợ khắc gỗ đã đóng góp quan trọng vào sự nghiệp của ông sau này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. The series Thirty-six Views of Mount Fuji was the first landscape work ever created in Japan.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1 và 13: &#8220;&#8230;marked the <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"40\">summit</strong> in the history of the Japanese landscape print&#8230; in grandeur of concept&#8230; there was <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"133\">little approaching it before</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ &#8220;summit&#8221; (đỉnh cao) và cụm &#8220;little approaching it before&#8221; (có ít tác phẩm đạt đến tầm đó trước đây) ngụ ý rằng đã có các tác phẩm phong cảnh khác tồn tại trước đó, chỉ là không hoành tráng bằng. Do đó, đây không phải là tác phẩm phong cảnh đầu tiên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Hokusai often competed with Utamaro in producing prints of women.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 7: &#8220;Hokusai <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"28\">only occasionally</strong>&#8230; chose to compete with Utamaro&#8230; the acknowledged master of voluptuous women figure prints.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ &#8220;often&#8221; (thường xuyên) trong câu hỏi mâu thuẫn với &#8220;only occasionally&#8221; (chỉ thỉnh thoảng) trong bài đọc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. His eldest son helped secure financial stability for him through the Nakajima family connections.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 9: &#8220;&#8230;as adopted heir to the affluent Nakajima family, the son had been <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"89\">instrumental in obtaining a generous stipend for Hokusai</strong>, so that he did not need to worry about the uncertainties of income&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Con trai cả của ông (với tư cách là người thừa kế nhà Nakajima) đã giúp ông có một khoản trợ cấp ổn định, giúp ông không phải lo lắng về tài chính.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. Hokusai changed his residence and artistic name multiple times throughout his life.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 14: &#8220;Hokusai’s frequent changes in domicile (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"61\">more than 90 dwellings</strong>) và of his <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"95\">own name</strong> are indicative of the artist’s restless nature.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nêu rõ ông đã đổi chỗ ở hơn 90 lần và thay đổi nghệ danh liên tục (khoảng mỗi thập kỷ một lần).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('3b85856c-e419-4b24-8ad8-18c9d2d12d67', '6f7820cf-3185-44c4-8f9a-04328d0cc13e', 'matching', 'Questions 26–30', '', '<p>What action do Pam and Jason agree to take for each of the following aspects of their experiment?</p>
<p>Choose <strong>FIVE</strong> correct answers, <strong>A</strong>–<strong>G</strong>, next to questions 26-30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Aspects of the experiment</strong></p>\n<p> </p>\n<p>the number of different designs offered {B widen the choice}</p>\n<p> </p>\n<p>the sample size of students {E ask for help}</p>\n<p> </p>\n<p>how to display the packages {A refer to course notes}</p>\n<p> </p>\n<p>finding the reasons for students'' choices {F design a questionnaire}</p>\n<p> </p>\n<p>analysis of data collected {D allow for more time}<br><br></p>", "answerOptions": [{"optionText": "A refer to course notes"}, {"optionText": "B widen the choice"}, {"optionText": "C use more colours"}, {"optionText": "D allow for more time"}, {"optionText": "E ask for help"}, {"optionText": "F design a questionnaire"}, {"optionText": "G plan for oral interviews"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('b3da4235-7af3-4017-8dea-73e6ec395cc7', 'aff5f03b-531f-4364-98df-910d0d47a6be', 'matching', 'Questions 36-40', '', '<p data-path-to-node="2">Write the correct letter, <strong>A-H</strong>, in boxes 36-40 on your answer sheet.</p>', 'matching_sentence_endings', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "reflect what life was like at that time"}, {"optionText": "help children deal with their problems"}, {"optionText": "demonstrate the outdated system"}, {"optionText": "tell of the simplicity of life in the German countryside"}, {"optionText": "encourage people to believe that they can do anything"}, {"optionText": "recognize the heroes in the real life"}, {"optionText": "contribute to the belief in nature power"}, {"optionText": "avoid details about characters’ social settings."}], "matchingItems": [{"questionPart": "Heinz Rolleke said the Grimm’s tales are “German” because the tales", "correctAnswer": "D"}, {"questionPart": "Heinz Rolleke said the abandoned children in tales", "correctAnswer": "A"}, {"questionPart": "Bernhard Lauer said the writing style of the Grimm brothers is universal because they", "correctAnswer": "H"}, {"questionPart": "Jack Zipes said the pursuit of happiness in the tales means they", "correctAnswer": "E"}, {"questionPart": "Bruno Bettelheim said the therapeutic value of the tales means that the fairy tales", "correctAnswer": "B"}]}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">36. Heinz Rolleke said the Grimm’s tales are “German” because the tales — {D. tell of the simplicity of life in the German countryside}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“How German are the Grimm tales? Very, says scholar Heinz Rolleke. Love of the underdog, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"109\">rustic simplicity [simplicity of life in the countryside]</strong>, creative energy—these are Teutonic [German] traits.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Rolleke khẳng định tính “Đức” của truyện nằm ở sự giản dị mộc mạc (rustic simplicity), một đặc điểm tiêu biểu của người Teuton (Đức).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. Heinz Rolleke said the abandoned children in tales — {A. reflect what life was like at that time}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Throughout Europe, children were often neglected and abandoned, like Hansel and Gretel… ‘The cruelty in the stories was not the Grimm’s fantasy’, Rolleke points out. ‘<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"190\">It reflected the law-and-order system of the old times [what life was like at that time]</strong>‘.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những đứa trẻ bị bỏ rơi hay sự tàn khốc trong truyện không phải là hư cấu mà nó phản ánh đúng thực trạng xã hội và hệ thống luật pháp thời bấy giờ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38. Bernhard Lauer said the writing style of the Grimm brothers is universal because they — {H. avoid details about characters’ social settings.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Bernhard Lauer points to the ‘universal style’ of the writing, you have <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"93\">no concrete descriptions of the land, or the clothes, or the forest, or the castles</strong>. It makes the stories <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"199\">timeless and placeless</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Phong cách “phổ quát” (universal) của truyện là do tác giả lược bỏ các chi tiết cụ thể về địa điểm, trang phục hay bối cảnh xã hội (social settings), giúp câu chuyện có thể xảy ra ở bất cứ đâu, vào bất cứ thời đại nào.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">39. Jack Zipes said the pursuit of happiness in the tales means they — {E. encourage people to believe that they can do anything}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“…says Jack Zipes… ‘They show a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"56\">striving for happiness</strong> that none of us knows but that we sense is <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"122\">possible</strong>. We can identify with the heroes… and <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"171\">become in our mind the masters and mistresses of our own destinies [believe they can do anything]</strong>.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc mưu cầu hạnh phúc giúp người đọc tin rằng mọi thứ đều khả thi và chính họ có thể làm chủ vận mệnh của mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">40. Bruno Bettelheim said the therapeutic value of the tales means that the fairy tales — {B. help children deal with their problems}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“Bruno Bettelheim famously promoted the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"60\">therapeutic [value]</strong>… children find they can <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"106\">master their anxieties [deal with their problems]</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Giá trị trị liệu (therapeutic value) của truyện cổ tích giúp trẻ em đối mặt và giải quyết những nỗi lo âu/vấn đề tâm lý của chính mình thông qua các hình tượng biểu trưng.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('a292d7f0-f95d-4159-80bf-0c4c6f758f39', 'd884be37-2871-489b-9c49-20bcca0ba827', 'fillup', 'Questions 8–13', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Hokusai showed interest in drawing at the age of five and may have been the son of a {concubine}. As a teenager, he was apprenticed to a wood-block engraver, and later studied under the Ukiyo-e master Shunshō, producing actor prints of the {theatre}.</p>
<p>During his career, Hokusai created a wide variety of works, including landscapes, actor prints, and {Surimono} produced for special occasions. He also published sketchbooks for amateur artists known as Hokusai {manga}. In many of his landscape works, he experimented Western-style colouring and {perspective} for a time.</p>
<p>Although he worked in different genres, Hokusai also competed with other masters such as {Utamaro}, who was famous for figure prints.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"26\">8. Hokusai showed interest in drawing at the age of five and may have been the son of a <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>concubine</strong>.</h3>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>concubine</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “…though the true son of Nakajima, he had been born of a <strong>concubine</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong>Giải thích:</strong> Có khả năng Hokusai được sinh ra từ một <strong>thứ phi</strong> (<em>concubine</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"28\">9. As a teenager, he was apprenticed to a wood-block engraver, and later studied under the Ukiyo-e master Shunshō, producing actor prints of the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>theatre</strong>.</h3>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong>Đáp án:</strong> <strong>theatre</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “…The young Hokusai’s first published works appeared the following year-actor prints of the Kabuki <strong>theatre</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong>Giải thích:</strong> Các tác phẩm xuất bản đầu tiên của ông là tranh diễn viên của <strong>sân khấu</strong> Kabuki (<em>Kabuki theatre</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"30\">10. During his career, Hokusai created a wide variety of works, including landscapes, actor prints, and <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>Surimono</strong> produced for special occasions.</h3>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong>Đáp án:</strong> <strong>Surimono</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1 &amp; 5) Các tác phẩm đầu tiên bao gồm “<em>surimono</em> (‘printed things’), such as greetings and announcements” và “Surimono were prints issued privately for <strong>special occasions</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong>Giải thích:</strong> <strong>Surimono</strong> là loại bản in được phát hành riêng cho các dịp đặc biệt.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"32\">11. He also published sketchbooks for amateur artists known as Hokusai <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>manga</strong>.</h3>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong>Đáp án:</strong> <strong>manga</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 11) “…to the picture book and, particularly, to the type of wood-block-printed copybook designed for amateur artists (including the famous Hokusai <strong>manga</strong>).”</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong>Giải thích:</strong> Ông đã xuất bản các cuốn sách phác họa (<em>sketchbooks</em>) cho các nghệ sĩ nghiệp dư, bao gồm Hokusai <strong>manga</strong>.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"34\">12. In many of his landscape works, he experimented Western-style colouring and <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>perspective</strong> for a time.</h3>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong>Đáp án:</strong> <strong>perspective</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “Around the turn of the century he experimented for a time with Western-style perspective and colouring.”</p>\n</li>\n<li>\n<p data-path-to-node=\"35,2,0\"><strong>Giải thích:</strong> Ông đã thử nghiệm phong cách tô màu và <strong>phối cảnh</strong> (<em>perspective</em>) phương Tây.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"36\">13. Although he worked in different genres, Hokusai also competed with other masters such as <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>Utamaro</strong>, who was famous for figure prints.</h3>\n<ul data-path-to-node=\"37\">\n<li>\n<p data-path-to-node=\"37,0,0\"><strong>Đáp án:</strong> <strong>Utamaro</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"37,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “…Hokusai only occasionally… chose to compete with <strong>Utamaro</strong>, the acknowledged master of voluptuous women figure prints.”</p>\n</li>\n<li>\n<p data-path-to-node=\"37,2,0\"><strong>Giải thích:</strong> Ông thỉnh thoảng cạnh tranh với <strong>Utamaro</strong>, người nổi tiếng với tranh in hình người phụ nữ.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('1c3cd911-f9bb-44e5-be21-3e496e6a6cb5', '0840e372-1cec-45c4-97f7-92c66ed98f7b', 'matrix', ' Questions 14–17', NULL, '<p>Look at the following findings (Questions 14-17) and the list of researchers below.</p>
<p>Match each finding with the correct researcher <strong>A</strong>, <strong>B</strong> or <strong>C</strong></p>
<p>NB You may use any letter more than once</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "the physiological mechanism which controls the body’s sleep patterns", "correctCategoryLetter": "B"}, {"itemText": "an observation that some creatures may have no need for sleep", "correctCategoryLetter": "A"}, {"itemText": "data indicating the dangers of extended periods of sleeplessness", "correctCategoryLetter": "B"}, {"itemText": "an animal behaviour which could serve as a basis for modifying human sleep pattern", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Jerome Siegel", "categoryLetter": "A"}, {"categoryText": "Clifford Saper", "categoryLetter": "B"}, {"categoryText": "Verner Bingman", "categoryLetter": "C"}]}', '[{"content": "<h3 data-path-to-node=\"6\">14. The physiological mechanism which controls the body’s sleep patterns.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>B (Clifford Saper)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “Neuroscientist <strong>Clifford Saper</strong> of the Harvard Medical School has located a small area at the base of the brain called the ventrolateral preoptic nucleus that sends chemical signals to other parts of the brain during sleep to slow those brain parts down and <strong>determines the best sleep budget for the animal</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Clifford Saper là người đã xác định được vùng nhỏ ở đáy não (ventrolateral preoptic nucleus) chịu trách nhiệm gửi tín hiệu hóa học để <strong>kiểm soát và xác định</strong> (<em>controls and determines</em>) kiểu ngủ của cơ thể.</p>\n</li>\n</ul>\n<div class=\"attachment-container search-images\">\n<p>&nbsp;</p>\n<div class=\"image-container ng-star-inserted\" data-full-size-image-uri=\"https://encrypted-tbn1.gstatic.com/licensed-image?q=tbn:ANd9GcSjh6ULyHuhDZXiFY-NoFBs5yye9fum1tgzxWXG9lsZgB0emd1JuD3o1tt8RHGuB9e3F1Hd7WViwHIaq_pG0m6QhquOYMSVxPX25C8ryD0kxHuHiHg\"></div>\n<p>&nbsp;</p>\n</div>\n<h3 data-path-to-node=\"10\">15. An observation that some creatures may have no need for sleep.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>A (Jerome Siegel)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “According to <strong>Siegel</strong>, the results of his orca study fundamentally change our view of sleep. ‘…here we have a creature which grows one of the largest brains in the animal kingdom, and yet it is doing this <strong>without sleep</strong>.’”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Jerome Siegel đã quan sát thấy cá orca mẹ và con <strong>không ngủ</strong> (<em>without sleep</em>) trong tháng đầu tiên sau khi sinh, đặt ra nghi vấn về tính cần thiết tuyệt đối của giấc ngủ.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"13\">16. Data indicating the dangers of extended periods of sleeplessness.</h3>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>B (Clifford Saper)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) <strong>Saper</strong>, tuy không đồng ý với việc giảm ngủ, đã cảnh báo: “The effect of 20 hours of wakefulness on driving is the equivalent of two shots of whiskey… <strong>Sleep deprivation is unfortunately a major cause of death in the US</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Clifford Saper cung cấp dữ liệu về <strong>nguy cơ</strong> (<em>dangers</em>) mất ngủ kéo dài, đặc biệt là mối liên hệ giữa thiếu ngủ và tai nạn giao thông gây tử vong.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"16\">17. An animal behaviour which could serve as a basis for modifying human sleep pattern.</h3>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án:</strong> <strong>C (Verner Bingman)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F &amp; G) <strong>Verner Bingman</strong> đang nghiên cứu hành vi ngủ ngắn (<em>micro naps</em>) của chim hét Swainson di cư và hy vọng “develop techniques or drugs that could <strong>recreate a similar brain pattern in humans</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Verner Bingman tin rằng hành vi ngủ của loài chim này có thể dùng làm <strong>cơ sở</strong> (<em>basis</em>) để điều chỉnh kiểu ngủ của con người, cho phép con người ngủ ít hơn mà vẫn duy trì hiệu quả.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('cb727748-e843-4009-948f-290b4f2d4bde', '0840e372-1cec-45c4-97f7-92c66ed98f7b', 'fillup', 'Questions 18–23', '<p>Complete the sentences below.</p>
<p>Write <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p>Movement and wakefulness in young orcas assist them in maintaining {body temperature} .</p>
<p>New orca mothers need to be awake in order to protect their young from {sharks} .</p>
<p>Sleep deprivation experiments on {rats | laboratory rats} have shown that animals die without adequate sleep.</p>
<p>Scientists have not yet worked out why almost all animals sleep with {closed eyes} .</p>
<p>For humans, sleep is vital for the efficient functioning of the {brain} .</p>
<p>During periods of {migration} Swainson’s thrushes experience severe sleep deprivation.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"4\">18. Movement and wakefulness in young orcas assist them in maintaining <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>body temperature</strong>.</h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>body temperature</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) “The young orcas’ movement and wakefulness help them keep their <strong>body temperature</strong> constant until mass and blubber insulation develop and allow for frequent respiration.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Cá orca con cần di chuyển và thức để duy trì <strong>nhiệt độ cơ thể</strong> (<em>body temperature</em>) ổn định.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\">19. New orca mothers need to be awake in order to protect their young from <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>sharks</strong>.</h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>sharks</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) “Meanwhile the mothers of newborn orcas must constantly look out for <strong>sharks</strong>, while teaching the calves to breath.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> Cá orca mẹ phải thức để cảnh giác với <strong>cá mập</strong> (<em>sharks</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">20. Sleep deprivation experiments on <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>rats</strong> have shown that animals die without adequate sleep.</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>rats</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn C) “Some animals die without proper sleep, and experiments have shown that sleep deprivation can cause death more quickly than food deprivation. Two weeks without sleep can kill laboratory <strong>rats</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Các thí nghiệm thiếu ngủ trên <strong>chuột</strong> (<em>rats</em>) đã chứng minh điều này.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\">21. Scientists have not yet worked out why almost all animals sleep with <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>closed eyes</strong>.</h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>closed eyes</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “However, for unknown reasons, <strong>closed eyes</strong> seem to be a virtually universal prerequisite for sleep.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Mặc dù cá heo có thể ngủ bằng nửa bộ não, nhưng việc <strong>nhắm mắt</strong> (<em>closed eyes</em>) dường như là điều kiện tiên quyết cho giấc ngủ ở hầu hết các loài động vật.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\">22. For humans, sleep is vital for the efficient functioning of the <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>brain</strong>.</h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>brain</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) “…sleep is no more effective than a comparable period of wakeful resting – except for one critical organ, the <strong>brain</strong>. The human brain apparently cannot do without sleep.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích:</strong> Giấc ngủ là cần thiết cho hoạt động hiệu quả của <strong>bộ não</strong> (<em>brain</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"14\">23. During periods of <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> <strong>migration</strong> Swainson’s thrushes experience severe sleep deprivation.</h3>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong>Đáp án:</strong> <strong>migration</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) “…the behavior of the migratory birds Swainson’s thrushes, which for <strong>migration</strong> purposes, go from a normal night’s sleep of 10 to 12 hours down to about 2.5 hours so they can fly at night.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong>Giải thích:</strong> Chim hét Swainson trải qua tình trạng thiếu ngủ nghiêm trọng trong mục đích <strong>di cư</strong> (<em>migration</em>).</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('62f551f4-6f1f-45b1-9879-eaf9e7756a41', 'e043772b-af03-47ea-bc06-c4a28053b316', 'radio', 'Questions 7-13', '', '<p>Choose TRUE if the statement agrees with the information,FALSE if the statement contradicts the information,NOT GIVEN if there is no information on this</p>', 'multiple_choice_single', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "For steamboats to cross the Atlantic Ocean, engines which used fuel economically were needed.", "explanation": "Đây là một cái giải thích rất giải tích"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('28511c2e-d036-45c0-ac5c-3b4cbd645cc2', '7c69aed1-b61c-48bf-8434-fca30ae4a00d', 'matching', 'Questions 37–40', '', '<p>Complete the summary using the list of words, <strong data-path-to-node="22" data-index-in-node="46">A–I</strong>, below.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">The work of Marschner and his colleagues</strong> </span></p>\n<p>For many years, CGI characters did not appear entirely lifelike as their skin appeared plastic. Marschner and his colleagues were the first to apply an understanding of how {A light} interacts with human skin. Their CGI model is based on a novel application of principles of {F mathematics}, which had previously been applied in other scientific research. The importance of CGI to the film industry has led to the {D use}of Marschner''s model by special-effects studios. Marschner''s model has led to the {G improvement} of cinematography.</p>", "answerOptions": [{"optionText": "A light"}, {"optionText": "B transparency"}, {"optionText": "C age"}, {"optionText": "D use"}, {"optionText": "E astrophysics"}, {"optionText": "F mathematics"}, {"optionText": "G improvement"}, {"optionText": "H colour"}, {"optionText": "I translucency"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">37. {A. light}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> “…simulates translucency; this is when <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"61\">light</strong> penetrates skin and then scatters below the skin’s surface…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nguyên nhân khiến da nhân vật CGI trước đây trông như nhựa là do chưa mô phỏng được cách <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"101\">ánh sáng (light)</strong> tương tác (xuyên thấu và tán xạ) với làn da con người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">38 F mathematics </strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“This is called subsurface scattering, and the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"67\">mathematics for the model goes back many decades</strong> to the time when it was used in astrophysics.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mô hình CGI này dựa trên việc ứng dụng các nguyên lý toán học (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"75\">mathematics</strong>) vốn đã từng được sử dụng trong ngành vật lý thiên văn từ nhiều thập kỷ trước. Từ cần chọn trong hộp là <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"191\">mathematics</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">39. {D. use}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> “…all the major special-effects studios had <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"66\">incorporated</strong> it into their digital rendering systems.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Incorporated into digital rendering systems” đồng nghĩa với việc đưa vào <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"86\">sử dụng (use)</strong>. Các studio kỹ xảo lớn đã nhanh chóng ứng dụng mô hình này chỉ trong vòng hai năm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">40. {G. improvement}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> “<strong data-path-to-node=\"10,0,0\" data-index-in-node=\"21\">Cinematography will benefit</strong> from this because… the movement of a virtual cloak or the lifting of a computerized hat should look <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"151\">far more realistic</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc làm cho các chuyển động và hình ảnh trở nên thực tế hơn (realistic) chính là sự <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"97\">cải thiện (improvement)</strong> cho ngành điện ảnh. Cụm từ “benefit from” (hưởng lợi từ) cũng ám chỉ một sự thay đổi tích cực.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('0f057a64-083d-499b-8fa5-b2deb41c91e6', '0840e372-1cec-45c4-97f7-92c66ed98f7b', 'matrix', 'Questions 24–26', NULL, '<p>Reading Passage 2 has 7 paragraphs, <strong>A-G</strong>.</p>
<p>Which paragraph contains the following information?</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "mention of the potential use of chemicals to reduce sleep periods", "correctCategoryLetter": "G"}, {"itemText": "reference to a lack of expert consensus regarding the behaviour of certain types of animal", "correctCategoryLetter": "B"}, {"itemText": "an example of an animal which continues to function normally during its sleep periods", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<h3 data-path-to-node=\"5\">24. mention of the potential use of chemicals to reduce sleep periods.</h3>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>G</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “The trick would be to develop techniques or <strong>drugs</strong> that could recreate a similar brain pattern in humans.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Đoạn G đề cập đến khả năng phát triển các kỹ thuật hoặc <strong>thuốc</strong> (<em>drugs</em>) để tái tạo mô hình não giống như chim hét, cho phép con người giảm thời gian ngủ. <strong>Thuốc</strong> (<em>drugs</em>) chính là hình thức của <strong>hóa chất</strong> (<em>chemicals</em>).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\">25. reference to a lack of expert consensus regarding the behaviour of certain types of animal.</h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>B</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn B) “All mammals and birds appear to need sleep, but <strong>scientists are unsure if reptiles and fish do</strong>. ‘When you come downstairs at three in the morning, the goldfish isn’t lying on the bottom of the bowl, it’s swimming around,’ Siegel says. <strong>But other scientists believe fish do enter a restful dormant state that is at least similar to sleep.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong>Giải thích:</strong> Đoạn B trình bày sự khác biệt trong ý kiến chuyên môn (<em>expert consensus</em>) về việc liệu các loài vật như cá có cần ngủ hay không, khi một số nhà khoa học không chắc chắn (<em>unsure</em>) và những người khác lại tin rằng chúng có trạng thái nghỉ ngơi tương tự.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"11\">26. an example of an animal which continues to function normally during its sleep periods.</h3>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Đáp án:</strong> <strong>D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) “In dolphin’s <strong>half the brain may rest while the other half stays vigilantly awake, and the animal carries on everyday activities</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Giải thích:</strong> Đoạn D cung cấp ví dụ về cá heo (<em>dolphin</em>) – loài động vật có thể ngủ bằng một nửa bộ não trong khi nửa còn lại vẫn tỉnh táo và <strong>tiếp tục các hoạt động hàng ngày</strong> (<em>carries on everyday activities</em> / function normally).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('83037425-81ab-43b6-b91d-aacf094438d3', 'ddb76a69-fe13-4a91-9787-34087773f770', 'matrix', 'Questions 21-23', '', '<p>Match each statement with the correct economist, <strong data-path-to-node="4" data-index-in-node="49">A, B, C or D</strong>, in boxes 21-23 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "A traditional approach may have helped predict a financial downturn.", "correctCategoryLetter": "D"}, {"itemText": "Some people invest conservatively and as a result make less money.", "correctCategoryLetter": "A"}, {"itemText": "It may be possible to predict short-term movements in share prices but not over the long term.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Fischer and Lorie", "categoryLetter": "A"}, {"categoryText": "Myron Scholes", "categoryLetter": "B"}, {"categoryText": "Eugene Fama", "categoryLetter": "C"}, {"categoryText": "Robert Shiller", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. A traditional approach may have helped predict a financial downturn. — {D. Robert Shiller}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“To have seen the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"38\">2008 global financial crisis coming [predict a financial downturn]</strong>, he [Robert Shiller] argues, it would have better to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"158\">go back to old-fashioned readings of history, studying institutions and laws [traditional approach]</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Robert Shiller lập luận rằng để dự báo được cuộc khủng hoảng tài chính 2008 (financial downturn), chúng ta nên quay lại cách đọc lịch sử kiểu cũ (traditional/old-fashioned approach) thay vì chỉ nhìn vào dữ liệu máy tính khô khan.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. Some people invest conservatively and as a result make less money. — {A. Fischer and Lorie}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">Fisher and Lorie</strong> also observed that many people chose to invest in assets with <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"100\">lower returns [make less money]</strong> because they were <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"150\">cautious by nature [invest conservatively]</strong>, and were concerned about the risk…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hai ông nhận thấy nhiều người có bản tính thận trọng (cautious/conservative) nên chọn các kênh đầu tư có lợi nhuận thấp (lower returns/less money) để tránh rủi ro mất mát.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. It may be possible to predict short-term movements in share prices but not over the long term. — {C. Eugene Fama}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">Fama</strong> did concede that there was some evidence of <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"70\">temporary short-term predictability</strong> in share prices… [but] all relevant information is reflected in share prices at any given moment, meaning there are <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"224\">no predictable movements</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Eugene Fama thừa nhận có bằng chứng về việc có thể dự báo được giá trong ngắn hạn (short-term predictability), nhưng về cơ bản thị trường là hiệu quả và giá biến động ngẫu nhiên, không thể dự báo lâu dài.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('79da813f-df35-459a-a1a0-b507ad4e8254', '95c04d1b-de93-461f-adb3-40a979fe87fb', 'radio', 'Questions 27-31', NULL, '<p>Choose the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C</strong> or <strong>D</strong>.<br />Write the correct letter in boxes <strong>27-31</strong> on your answer sheet.</p>
', 'multiple-choice', '[{"correct": 2, "options": [{"content": "A. They thought there was only one large island."}, {"content": "B. They had not come to study natural history."}, {"content": "C. They had no interest in the tuatara."}, {"content": "D. They sent a tuatara to the British Museum."}], "question": "What are we told about the Europeans who arrived in 1769?"}, {"correct": 1, "options": [{"content": "A. He believed the tuatara could fetch a high price."}, {"content": "B. He was typical of his generation of scientists."}, {"content": "C. He disagreed with Charles Darwin''s theory."}, {"content": "D. He wanted to stop the tuatara becoming extinct."}], "question": "What does the writer say about Albert Gunther in paragraph 3?"}, {"correct": 1, "options": [{"content": "A. They did not eat the tuatara."}, {"content": "B. There was one species of rat."}, {"content": "C. There had always been rats in New Zealand."}, {"content": "D. They were killed by Polynesians."}], "question": "What did Albert Gunther think about the rats in New Zealand?"}, {"correct": 3, "options": [{"content": "A. Tuatara are safe on small islands."}, {"content": "B. Ship''s rats kill more tuatara than kiore."}, {"content": "C. Kiore cannot swim to offshore islands."}, {"content": "D. Rats and tuatara cannot live together."}], "question": "What did Ian Crook conclude from his research?"}, {"correct": 3, "options": [{"content": "A. Maori settled more recently than previously thought."}, {"content": "B. The first Polynesian explorers formed permanent settlements."}, {"content": "C. Ship''s rats are the oldest rat species in the country."}, {"content": "D. Rats caused extinctions before any humans settled."}], "question": "What were the findings of Richard Holdaway''s research?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. What are we told about the Europeans who arrived in 1769?</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> C. They had no interest in the tuatara.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 3–4.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The naturalists who came with the explorers <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"56\">disregarded the tuatara</strong>, though it is improbable none were seen.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,3,0\"><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ <strong data-path-to-node=\"4,3,0\" data-index-in-node=\"15\">“disregarded”</strong> có nghĩa là lờ đi, không quan tâm hoặc coi thường. Mặc dù chắc chắn họ đã nhìn thấy chúng, nhưng những nhà tự nhiên học đi cùng đoàn thám hiểm đã không mảy may để ý đến loài này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. What does the writer say about Albert Gunther in paragraph 2?</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. He was typical of his generation of scientists.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 8–11.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “He and his contemporaries were <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"43\">products of their age</strong>, strongly influenced by Charles Darwin’s theory… Their views were something like this: Extinction is a natural process.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,3,0\"><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ <strong data-path-to-node=\"6,3,0\" data-index-in-node=\"19\">“products of their age”</strong> ngụ ý rằng Gunther và những người cùng thời chịu ảnh hưởng sâu sắc bởi tư tưởng của thời đại đó (đặc biệt là thuyết tiến hóa của Darwin). Do đó, thái độ “bình thản” của ông trước sự tuyệt chủng của Tuatara là đặc trưng tiêu biểu của giới khoa học thời bấy giờ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. What did Albert Gunther think about the rats in New Zealand?</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. There was one species of rat.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Gunther <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"20\">failed to recognise the distinction</strong>, believing <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"67\">all rats</strong> to be a relatively recent introduction.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,3,0\"><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ ra rằng có hai loài chuột (chuột tàu biển và chuột kiore), nhưng Gunther đã không nhận ra sự khác biệt này (<strong data-path-to-node=\"8,3,0\" data-index-in-node=\"132\">failed to recognise the distinction</strong>) và coi tất cả chuột chỉ là một nhóm mới được đưa vào New Zealand gần đây.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. What did Ian Crook conclude from his research?</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> D. Rats and tuatara cannot live together.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This should not be seen, however, as evidence that <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"63\">tuatara and kiore can coexist</strong>. Rather… small populations represent extinctions in progress.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,3,0\"><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Ian Crook khẳng định việc tìm thấy Tuatara sống cùng chuột kiore không phải là bằng chứng của sự chung sống hòa bình (<strong data-path-to-node=\"10,3,0\" data-index-in-node=\"130\">coexist</strong>), mà thực chất là dấu hiệu cho thấy loài Tuatara đang dần bị tiêu diệt (extinctions in progress). Nói cách khác, chúng không thể sống cùng nhau lâu dài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. What were the findings of Richard Holdaway’s research?</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> D. Rats caused extinctions before any humans settled.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 6–8.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Thereafter, the rats were agents of ecological warfare, exterminating perhaps 1000-3000 species. Thus, tuatara and many other species were <strong data-path-to-node=\"12,2,0\" data-index-in-node=\"151\">already rare or extinct when permanent human inhabitants… arrived around 1300</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,3,0\"><strong data-path-to-node=\"12,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu của Holdaway cho thấy chuột kiore đến New Zealand khoảng 1800 năm trước (theo chân các nhà thám hiểm nhưng họ không định cư). Đến khi người Maori chính thức định cư (khoảng năm 1300), các loài chuột này đã kịp tiêu diệt hàng ngàn loài khác. Vậy nên, chuột đã gây ra sự tuyệt chủng trước khi con người định cư lâu dài.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('3cdc88d9-9b8e-4b6b-b33b-6c6c6195868b', '8e5f840f-92b8-42e5-80e6-6125b945edf9', 'matching', 'Questions 17-20', '', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text   ">
<div class="">
<div class="s-component-content s-font-body">
<p>What information does the guide give about each of the following collections?</p>
<p>Choose <strong>FOUR</strong> answers from the box next to Questions 17-20</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Collections</strong></p>\n<p> </p>\n<p>18th-century paintings {has exhibits from various countries}</p>\n<p> </p>\n<p>Farnley collection {consists of work by a local resident}</p>\n<p> </p>\n<p>kitchen appliances {shows things that are no longer common}</p>\n<p> </p>\n<p>fashion gallery {in only on temporary display}</p>", "answerOptions": [{"optionText": "has been shown in different museums"}, {"optionText": "consists of work by a local resident"}, {"optionText": "has exhibits from various countries"}, {"optionText": "in only on temporary display"}, {"optionText": "shows things that are no longer common"}, {"optionText": "is on loan from foreign museum"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('00b172b7-4d94-470d-a374-586f3297422f', '95c04d1b-de93-461f-adb3-40a979fe87fb', 'radio', 'Questions 32-35', NULL, '<p><span style="font-size: 12pt;">Choose <strong>YES </strong>if the statement agrees with the information given in the text, choose <strong>NO </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</span></p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES "}, {"content": "NO "}, {"content": "NOT GIVEN"}], "question": "The available research supports Holdaway''s theory but it has not been proved."}, {"correct": 0, "options": [{"content": "YES "}, {"content": "NO "}, {"content": "NOT GIVEN"}], "question": "Nowadays, it is possible to totally destroy a population of rats on a small island."}, {"correct": 2, "options": [{"content": "YES "}, {"content": "NO "}, {"content": "NOT GIVEN"}], "question": "Crook was the first person to recognize the potential of offshore islands as sanctuaries."}, {"correct": 1, "options": [{"content": "YES "}, {"content": "NO "}, {"content": "NOT GIVEN"}], "question": "Tuatara numbers are continuing to fall."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">32. The available research supports Holdaway’s theory but it has not been proved.</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"8\">YES</strong></li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, câu cuối.</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"17\">hypothesis is still being debated</strong>, but the <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"60\">evidence continues to accumulate in its favour</strong>.”</li>\n<li><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “still being debated” (vẫn đang được tranh luận) tương ứng với ý “it has not been proved” (chưa được chứng minh tuyệt đối). Cụm “evidence continues to accumulate in its favour” (bằng chứng tiếp tục tích lũy theo hướng có lợi cho nó) tương ứng với “available research supports” (nghiên cứu hiện có ủng hộ).</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">33. Nowadays, it is possible to totally destroy a population of rats on a small island.</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"8\">YES</strong></li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, câu 1 và 2.</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Eradication of rats from any given environment was believed to be virtually impossible until about 1980, but <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"121\">since then has become routine</strong>.”</li>\n<li><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> “Eradication” có nghĩa là sự tiêu diệt hoàn toàn (totally destroy). “Since then has become routine” (kể từ đó đã trở thành việc thường quy) xác nhận rằng ngày nay (nowadays) việc này là hoàn toàn khả thi và có thể thực hiện được.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">34. Crook was the first person to recognize the potential of offshore islands as sanctuaries.</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4 và đoạn 6.</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc có nói Ian Crook công bố phát hiện vào năm 1973 (đoạn 4) và các hòn đảo ngoài khơi đang cung cấp nơi trú ẩn (sanctuaries) (đoạn 6).</li>\n<li><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù bài đọc nhấn mạnh tầm quan trọng của nghiên cứu của Crook đối với việc bảo tồn trên đảo, nhưng <strong data-path-to-node=\"8,3,0\" data-index-in-node=\"114\">không có thông tin nào khẳng định</strong> ông là <strong data-path-to-node=\"8,3,0\" data-index-in-node=\"155\">người đầu tiên</strong> (the first person) nhận ra tiềm năng này. Có thể đã có người khác nhận ra trước đó nhưng chưa công bố rộng rãi hoặc nghiên cứu của họ không được nhắc đến trong bài.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">35. Tuatara numbers are continuing to fall.</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">NO</strong></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, câu cuối.</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…but for the first time in 1800 years the <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"56\">decline has been reversed</strong>.”</li>\n<li><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> “The decline has been reversed” nghĩa là sự sụt giảm đã được đảo ngược (số lượng không còn giảm nữa mà đang có xu hướng ổn định hoặc tăng lên). Điều này trực tiếp phủ định (contradicts) khẳng định “numbers are continuing to fall” của câu hỏi.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('618ffc29-3351-40fb-8237-853d0d9c88bc', 'c1144789-9cb6-4a96-a54b-5cb5398e63ad', 'checkbox', 'Questions 24–25', '', '<p data-start="610" data-end="637">Choose TWO correct answers.</p>
<h3 data-start="639" data-end="699">Who will Sylvia and Greg ask to take part in the survey?</h3>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "companies"}, {"correct": false, "option_text": "lecturers"}, {"correct": true, "option_text": "local residents"}, {"correct": false, "option_text": "schoolchildren"}, {"correct": true, "option_text": "university students"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('d5e5984c-15d1-4bf0-8d68-c24373549a72', '95c04d1b-de93-461f-adb3-40a979fe87fb', 'matching', 'Questions 36-40', NULL, '<p>Complete the summary using the list of words, <strong>A-H</strong>, below.<br />Write the correct letter, <strong>A-H</strong>, in boxes <strong>36-40</strong> on your answer sheet.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>What conclusions can we draw?</strong></p>\n<p style=\"text-align: left;\">The most important result of the tuatara research is that it frees our {B creative thought} . For example, there are many similarities between rats and {D trout} . Should we now go further and consider reintroducing {G native fish} to our mainland rivers? Perhaps our children will come to believe in the {F restoration} of species, in the same way that our generation refuses to accept {H extinction} .</p>", "answerOptions": [{"optionText": "A natural evolution"}, {"optionText": "B creative thought"}, {"optionText": "C indigenous plants"}, {"optionText": "D trout"}, {"optionText": "E pollution"}, {"optionText": "F restoration"}, {"optionText": "G native fish"}, {"optionText": "H extinction"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">36. B (creative thought)</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 1–2.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;the truly significant outcome of this research is that it <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"73\">liberates the imagination</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ &#8220;liberates the imagination&#8221; (giải phóng trí tưởng tượng) trong bài tương ứng hoàn toàn với &#8220;frees our <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"121\">creative thought</strong>&#8221; (khơi dậy tư duy sáng tạo) trong đoạn tóm tắt. Thành công với loài Tuatara giúp chúng ta dám nghĩ đến những mục tiêu bảo tồn tham vọng hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">37. D (trout)</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 4–5.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Our rivers, for example, are full of <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"49\">surrogate rats</strong>, in the form of introduced species of fish called <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"114\">trout</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả dùng phép ẩn dụ &#8220;surrogate rats&#8221; (vật thay thế cho chuột) để nói về cá hồi (<strong data-path-to-node=\"6,2,0\" data-index-in-node=\"96\">trout</strong>). Ý nói cá hồi gây hại cho hệ sinh thái dưới nước tương tự như cách loài chuột gây hại trên đất liền.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">38. G (native fish)</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng 8–9.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;where we can once again establish those species of <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"66\">indigenous fish</strong> that used to live in our rivers?&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong bài dùng từ &#8220;indigenous fish&#8221;, và từ đồng nghĩa trong danh sách lựa chọn là <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"94\">native fish</strong> (cá bản địa). Tác giả đặt vấn đề về việc đưa các loài cá nguyên bản trở lại sông ngòi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">39. F (restoration)</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 8, dòng 4–6.</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;imagining and then <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"34\">creating the future</strong> we wish for&#8230; we may no longer accept a mainland <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"104\">devoid of the biological wonders of our past</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Toàn bộ ngữ cảnh đoạn cuối nói về việc đưa các loài vật của quá khứ trở lại và tái thiết lập hệ sinh thái. Do đó, từ <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"129\">restoration</strong> (sự phục hồi/khôi phục) là từ phù hợp nhất để mô tả niềm tin của thế hệ tương lai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">40. H (extinction)</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 8, dòng 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Just as we now no longer tolerate <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"46\">extinction</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là một dẫn chứng trực tiếp. Tác giả so sánh: nếu thế hệ chúng ta không chấp nhận sự tuyệt chủng (<strong data-path-to-node=\"12,2,0\" data-index-in-node=\"113\">extinction</strong>), thì thế hệ con cháu sẽ tin tưởng vào sự phục hồi (restoration).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('da4d8678-ef3e-4dc0-8ced-8c5d13d42b4a', 'b9ef0b64-fa89-4074-a14a-eaa566018b09', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text   ">
<div class="">
<div class="s-component-content s-font-body">
<p>Complete the notes below</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text   ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 14pt;"><strong>Reasons for and against urban migration</strong></span></p>
<p><strong>Cities today</strong></p>
<ul>
<li>
<p>account for 3% of our planet’s land area</p>
</li>
<li>
<p>produce less {carbon} than non-urban areas</p>
</li>
</ul>
<p><strong>The advantages of more people moving to the city</strong></p>
<ul>
<li>
<p>some {forests} would recover</p>
</li>
<li>
<p>more energy efficient for services like electricity and water</p>
</li>
<li>
<p>{transport} in the city is more environmentally friendly</p>
</li>
<li>
<p>Recycling: energy could be generated from the methane gas from {rubbish}</p>
</li>
<li>
<p>Population: urban women</p>
<ul>
<li>
<p>start a family much later</p>
</li>
<li>
<p>are more likely to gain {promotion} at work</p>
</li>
</ul>
</li>
</ul>
<p><strong>The downsides of living in the city</strong></p>
<ul>
<li>
<p>possible loss of {culture} amongst some migrants</p>
</li>
<li>
<p>the higher {crime} rate among the population</p>
</li>
<li>
<p>the poor quality of the {air}</p>
</li>
<li>
<p>Economic factors: increased {wealth} in a population leads to more energy consumption</p>
</li>
<li>
<p>citizens may find the quantity of daily {traffic} stressful</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: URBAN MIGRATION AND THE ENVIRONMENT</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> </p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Good morning everyone.</strong> Today we’re looking at urban migration—the movement of people migrating from outside cities into cities. I think it’s easy to jump to the conclusion that a rural lifestyle is greener; however, recent studies have suggested otherwise.</p>\n<p data-path-to-node=\"4\">First of all, if we take the land area of the earth, the proportion that cities take up is a mere 3%. And these same cities actually produce 30 to 40% of the <span style=\"background-color: #f3db7b;\"><strong>31 </strong><strong data-path-to-node=\"4\" data-index-in-node=\"158\">{carbon}</strong></span> that is released into the atmosphere—a lower amount than the 60 to 70% from non-urban areas.</p>\n<p data-path-to-node=\"5\">Anyway, let’s imagine that most people decide to migrate to the city. What kind of impact would that have? For a start, this movement of people from the countryside should lift the pressure of intensive agriculture from the land, allowing <span style=\"background-color: #f3db7b;\"><strong>32 </strong><strong data-path-to-node=\"5\" data-index-in-node=\"239\">{forests}</strong></span> to regenerate.</p>\n<p data-path-to-node=\"6\">Another point in favour of urban migration is that it can be far more energy efficient if services are concentrated in the city. For example, this is true for electricity and, as you can imagine, water. Then, once you remember that rural communities are often very spread out, you can see yet another green reason to live in the city: rural citizens rely on the car to make their journeys far more than city dwellers, who have other more environmentally friendly forms of <span style=\"background-color: #f3db7b;\"><strong>33 </strong><strong data-path-to-node=\"6\" data-index-in-node=\"472\">{transport}</strong></span> that they can use, such as buses and trains. The journeys tend to be shorter too.</p>\n<p data-path-to-node=\"7\">Yet another point in favour of urban migration is the kind of recycling schemes that can only take place where the population is concentrated. Take, for instance, Seattle in the USA, where methane gas is being put to good use and is generating energy for the city. It’s produced from the city’s <span style=\"background-color: #f3db7b;\"><strong>34 {rubbish}</strong></span>, which could not be collected so efficiently from rural areas.</p>\n<p data-path-to-node=\"8\">Now, another factor that threatens the environment is the growing world population. It’s estimated that 75 million babies are now born every year and in some countries, the birth rate shows no signs of slowing down. Urban migration may provide an answer here. Now in cities, one of the reasons that women tend to have fewer children is that they get married later and start their families later. And the reason for this is that it’s far easier to find a job, and once you have one, to get a <strong><span style=\"background-color: #f3db7b;\">35 {promotion}</span></strong>. So yes, the focus isn’t on bearing children.</p>\n<p data-path-to-node=\"9\">Well, it would be foolish to pretend that there are no downsides to urban living, when clearly there are. The thing that critics often mention is the idea that migrants may end up losing their <span style=\"background-color: #f3db7b;\"><strong>36 </strong><strong data-path-to-node=\"9\" data-index-in-node=\"193\">{culture}</strong></span>, although some studies have found the opposite is true; rather than give up their traditions, people actually work hard to maintain them.</p>\n<p data-path-to-node=\"10\">More evident is the fact that, compared to the lower rate that is observed in rural areas, we can see that there is more <span style=\"background-color: #f3db7b;\"><strong>37</strong></span><strong data-path-to-node=\"10\" data-index-in-node=\"121\"><span style=\"background-color: #f3db7b;\">{crime</span>}</strong> occurring in cities. There won’t be many of us here today who can say we haven’t been directly or indirectly affected by it. There’s another issue that we have to deal with: so many cities, including our own, now suffer from high levels of pollution, so that the <strong><span style=\"background-color: #f3db7b;\">38 {air}</span></strong> we breathe is far from pure.</p>\n<p data-path-to-node=\"11\">And another factor against the “urban is greener” idea is that urbanization often drives a country’s economy. Put simply, when there is greater <span style=\"background-color: #f3db7b;\"><strong>39 </strong><strong data-path-to-node=\"11\" data-index-in-node=\"144\">{wealth}</strong></span> in society, more energy is consumed. One of the direct effects of a stronger economy—something that many citizens will now experience every day and may well find stressful—is the amount of <span style=\"background-color: #f3db7b;\"><strong>40 </strong></span><strong data-path-to-node=\"11\" data-index-in-node=\"342\"><span style=\"background-color: #f3db7b;\">{traffic</span>}</strong> on the road. Despite the other options we mentioned earlier, this is a problem that is not about to go away…</p>"}]', 0);
INSERT INTO public.questions VALUES ('5acf22db-a58b-49fc-b02e-5d70625797b9', 'dd5aee5d-45a9-4230-915a-5ab4f331aff4', 'radio', 'Questions 1–4', '', '<p><span class="citation-5685">Choose</span><strong data-path-to-node="5,0" data-index-in-node="0"><span class="citation-5685"> TRUE</span></strong><span class="citation-5685 citation-end-5685"> if the statement agrees with the information<sup class="superscript" data-turn-source-index="3"><!----></sup></span> <strong data-path-to-node="5,0" data-index-in-node="50"><span class="citation-5684">FALSE</span></strong><span class="citation-5684 citation-end-5684"> if the statement contradicts the in<sup class="superscript" data-turn-source-index="4"><!----></sup></span>formation <strong data-path-to-node="5,0" data-index-in-node="101">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Scientists studied hunter-gatherer societies because their sleep patterns are assumed to be similar to those of humans more than 10,000 years ago."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The medical devices used in the research were specially designed for humid conditions."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Researchers found that tribespeople stayed longer in bed than inhabitants of industrialised regions."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Jerome Siegel believes that environment and culture have little effect on sleep patterns."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. Scientists studied hunter-gatherer societies because their sleep patterns are assumed to be similar to those of humans more than 10,000 years ago. — {TRUE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…these pre-industrial societies are <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"59\">thought to sleep the way humans did more than 10,000 years ago</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “thought to sleep” đồng nghĩa với “assumed to be similar” (được giả định/cho là giống với). Mục đích nghiên cứu các bộ lạc này là vì các nhà khoa học tin rằng họ vẫn giữ thói quen ngủ như con người từ 10.000 năm trước.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. The medical devices used in the research were specially designed for humid conditions. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Traveling to where they lived, often in <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"61\">humid, remote locations</strong>, researchers used <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"103\">medical devices</strong> to record the sleeping habits…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc các địa điểm nghiên cứu thường có khí hậu <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"79\">ẩm ướt</strong> (humid) và các nhà khoa học có dùng <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"122\">thiết bị y tế</strong> (medical devices). Tuy nhiên, bài <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"170\">không hề nói</strong> rằng các thiết bị này được “thiết kế đặc biệt” (specially designed) cho điều kiện ẩm ướt đó hay không.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. Researchers found that tribespeople stayed longer in bed than inhabitants of industrialised regions. — {FALSE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Like many of us… This adds up to a <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"58\">sleep efficiency that is very similar to today’s industrial populations</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói rằng các bộ lạc này cũng dành thời gian ở trên giường nhiều hơn thời gian ngủ thực tế (từ 6.9 đến 8.5 giờ), và hiệu quả giấc ngủ của họ <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"160\">rất giống</strong> (very similar) với người dân ở các vùng công nghiệp hóa ngày nay. Vì vậy, nói họ ở trên giường “lâu hơn” (longer) là sai (contradicts).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. Jerome Siegel believes that environment and culture have little effect on sleep patterns. — {TRUE}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“According to Jerome Siegel… evidence suggests sleep habits <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"82\">may not be environmental or cultural</strong>, but central to the physical makeup of humans.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Jerome Siegel tin rằng thói quen ngủ không phải do môi trường hay văn hóa quyết định, mà nằm ở cấu tạo thể chất của con người. Điều này tương ứng với việc tin rằng môi trường và văn hóa có ít tác động (little effect) đến giấc ngủ.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('b5b27318-5668-4917-b81f-50c2b81312d2', '0c312afa-2efb-46dd-929a-5b505fc07cba', 'fillup', 'Questions 31-40', '<p>Write <strong>NO MORE THAN TWO WORDS</strong> for each answer</p>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text   ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 14pt;"><strong>Research on A Chain Store in the UK</strong></span></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text   ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Initial expansion</strong></p>
<ul>
<li>
<p>The company expanded by opening more {petrol stations} to increase market share in England.</p>
</li>
<li>
<p>They could raise capital by reducing the number of branches in southern {Scotland}.</p>
</li>
</ul>
<p><strong>Consultation</strong></p>
<ul>
<li>
<p>They shut down the<strong> </strong>{head office} of the convenience stores in Oxford.</p>
</li>
<li>
<p>Over 200 staff had to be transferred and {retrained}.</p>
</li>
<li>
<p>A new brand image was established to focus on selling {fresh food}.</p>
</li>
</ul>
<p><strong>The future way</strong></p>
<ul>
<li>
<p>A<strong> </strong>{manager} was assigned to hold each discussion.</p>
</li>
<li>
<p>Retail stores should be flexible in making {profits}.</p>
</li>
<li>
<p>Changes should be introduced in {stages} so that the staff can become accustomed the new rules.</p>
</li>
</ul>
<p><strong>Conclusion</strong></p>
<ul>
<li>
<p>Be open-minded about the<strong> </strong>{strategies} for expansion they choose.</p>
</li>
<li>
<p>Companies have saved costs by changing the structure of the {organisation} department.</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 4: RESEARCH ON A CHAIN STORE IN THE UK</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Welcome ladies and gentlemen to the second lecture in our series on chain stores in the UK. Today I will be focusing on a very successful global petrol company called Tesla, <span class=\"citation-4465 citation-end-4465\">paying particular attention to their expansion and future development. There will be time for questions at the end, so please refrain from interrupting during the talk.<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span></p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"4\"><span class=\"citation-4464 citation-end-4464\">When it was founded, the company was a family-ru<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span>n organisation with only one shop open in a small town in southern England. The family was <span class=\"citation-4463 citation-end-4463\">able to compete with other local companies by offering special discounts for returning customers, which resulted in a huge expansion of their client base. This strategy was so successful that they were able to<sup class=\"superscript\" data-turn-source-index=\"3\"><!----></sup></span> open<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"354\">(31) petrol stations</strong></span></span> across the country, subsequently increasing their market share in England.</p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"5\">Within a decade, Tesla <span class=\"citation-4461 citation-4462 citation-end-4462\">were running establishments throughout the UK, including Wales and Scotland. By comparing the sales income from all of their stores, they were able to collate data that highlighted which areas were the most profitable and receptive to their busin<sup class=\"superscript\" data-turn-source-index=\"4\"><!----></sup></span><span class=\"citation-4461\">ess. They discovered that by closing the less profitable stations in the south of<span style=\"text-decoration: underline;\"> </span></span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"5\" data-index-in-node=\"351\"><span class=\"citation-4461 citation-end-4461\">(<sup class=\"superscript\" data-turn-source-index=\"5\"><!----></sup></span>32) Scotland</strong></span>, they could increase the income from their other more profitable stations. This example demonstrates the importance of constantly monitoring and maintaining a clear view of the finances of the company.</p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<hr data-path-to-node=\"6\">\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Lecturer:</strong> <span class=\"citation-4459 citation-4460 citation-end-4460\">Once the expertise required to run the company had exceeded the abilities of the family, they needed to hire professional consultants. After assessing the company’s financial statements, the consultants advised that <sup class=\"superscript\" data-turn-source-index=\"6\"><!----></sup></span><span class=\"citation-4459 citation-end-4459\">Tesla clos<sup class=\"superscript\" data-turn-source-index=\"7\"><!----></sup></span>e the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"242\">(33) head office</strong></span> <span class=\"citation-4457 citation-4458 citation-end-4458\">of the convenience stores in Oxford. They deemed the head office unnecessary and identified it as a financial drain on the company, as the premises were expensive to run and generated no income.<sup class=\"superscript\" data-turn-source-index=\"8\"><!----></sup></span><span class=\"citation-4457 citation-end-4457\"><sup class=\"superscript\" data-turn-source-index=\"9\"><!----></sup></span></p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"8\"><span class=\"citation-4455 citation-4456 citation-end-4456\">In order to avoid firing any employees, they transferred over 200 <sup class=\"superscript\" data-turn-source-index=\"10\"><!----></sup></span><span class=\"citation-4455\">staff to other offices and </span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"8\" data-index-in-node=\"93\"><span class=\"citation-4455 citation-end-4455\">(<sup class=\"superscript\" data-turn-source-index=\"11\"><!----></sup></span>34) retrained</strong></span> them to carry out their new roles. Now that Tesla had conquered the petrol market in the UK, they were able to branch out into other niche areas that offered prospects for profits. They realised that they could establish a new environmentally friendly brand image by selling <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"8\" data-index-in-node=\"383\">(35) fresh food</strong></span> in their convenience stores that had been grown by local farmers. This strategy would not only broaden the scope of the company but also help to strengthen its relationships with local communities.</p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<hr data-path-to-node=\"9\">\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Lecturer:</strong> Every year, Tesla <span class=\"citation-4453 citation-4454 citation-end-4454\">holds a meeting in London where all of the consultants and managers meet to discuss future plans for development and improvement. These meetings are essential to the evolution of the company, as feedback is<sup class=\"superscript\" data-turn-source-index=\"12\"><!----></sup></span><span class=\"citation-4453\"> heard from all levels of the organization, from the sales staff to the CEOs. They did this by assigning every </span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"345\"><span class=\"citation-4453 citation-end-4453\">(<sup class=\"superscript\" data-turn-source-index=\"13\"><!----></sup></span>36) manager</strong> </span><span class=\"citation-4452 citation-end-4452\">the task of holding staff discussions, at which ideas and concerns would be passed on for evaluation.<sup class=\"superscript\" data-turn-source-index=\"14\"><!----></sup></span></p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"11\"><span class=\"citation-4451 citation-end-4451\">At the meeting, Tesla decided to accommodate the individuality of each of their stores instead of forcing them to conform to one overriding company identity. They realized that by increasing the flexibility o<sup class=\"superscript\" data-turn-source-index=\"15\"><!----></sup></span>f the <strong><span style=\"text-decoration: underline; background-color: #f3db7b;\">(37) </span><span style=\"text-decoration: underline;\"><span style=\"background-color: #f3db7b;\">profit-making</span></span></strong> <span style=\"background-color: #ffffff;\">strategies</span> of each of the retail stores, they subsequently became more commercially successful.</p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"12\">The level of staff satisfaction also increased as a result, as the individuals felt that<span class=\"citation-4450\"> they were not being constrained to one way of thinking. To avoid misunderstandings and mistakes, any future changes were introduced in<span style=\"text-decoration: underline;\"> </span></span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"12\" data-index-in-node=\"224\"><span class=\"citation-4450\">(38) stages</span></strong></span><span class=\"citation-4450 citation-end-4450\"> in order to familiarise the staff with the new regulations.<sup class=\"superscript\" data-turn-source-index=\"16\"><!----></sup></span></p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<hr data-path-to-node=\"13\">\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Lecturer:</strong> Now it’s time to conclude the lecture for today, so I will leave you with some food for <span class=\"citation-4449\">thought before you leave. In order to run a successful business, one cannot underestimate the importance of maintaining an open mind when deciding on </span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"14\" data-index-in-node=\"248\"><span class=\"citation-4449\">(39) strategies</span></strong></span><span class=\"citation-4449 citation-end-4449\"> for expansion.<sup class=\"superscript\" data-turn-source-index=\"17\"><!----></sup></span></p>\n<p class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></p>\n<p data-path-to-node=\"1\"><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"15\"><span class=\"citation-4448 citation-end-4448\">Sometimes, it’s necessary to employ an independent con<sup class=\"superscript\" data-turn-source-index=\"18\"><!----></sup></span>sultant who can o<span class=\"citation-4446 citation-4447\">ffer an objective and unbiased view on the running of your company. Emotion will only ever cloud your ability to make business-related decisions. Research suitable case studies and look at how department stores, for example, were able to alter their </span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"15\" data-index-in-node=\"321\"><span class=\"citation-4446 citation-4447 citation-end-4447\">(40) organis<sup class=\"superscript\" data-turn-source-index=\"19\"><!----></sup></span><span class=\"citation-4446\">ation</span></strong></span><span class=\"citation-4446 citation-end-4446\"> structure whilst minimizing costs and staff redundancies. Precedents <sup class=\"superscript\" data-turn-source-index=\"20\"><!----></sup></span>are an essential re<span class=\"citation-4445 citation-end-4445\">source when it comes to making decisions for your own business, so don’t undervalue them. Well, that wraps up our lecture for today.</span></p>"}]', 0);
INSERT INTO public.questions VALUES ('2c87b2cc-863a-49aa-a7f1-5c4f7b18da76', '667e19cf-bb39-4492-8404-5ff2984beefc', 'matching', 'Questions 14–19', '', '<p data-start="101" data-end="201">The text has six paragraphs.</p>
<p data-start="101" data-end="201">Choose the correct heading for each paragraph and move it into the gap.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "Sending messages underground"}, {"optionText": "Potential advantages for farmers"}, {"optionText": "The widespread rejection of an idea"}, {"optionText": "One species accelerating growth in another"}, {"optionText": "Some obstacles to plant communication"}, {"optionText": "Evidence leading to renewed belief in a theory"}, {"optionText": "New technologies which helped researchers"}, {"optionText": "A suggested benefit to the sender of plant communication"}], "matchingItems": []}', 'null', '[{"content": "<p><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">14.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đoạn 1: {The widespread rejection of an idea}</strong></p>\n<ul data-path-to-node=\"5,0,1\">\n<li>\n<p data-path-to-node=\"5,0,1,0,0\"><strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the plant research community <strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"44\">did not accept this</strong>. …most ecologists felt that Schultz and Baldwin’s ideas had been <strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"131\">discredited</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,0,1,1,0\"><strong data-path-to-node=\"5,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về việc các nhà khoa học ban đầu bác bỏ ý tưởng thực vật biết “báo động” cho nhau.<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">.</strong></p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">15.</strong></li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Đoạn 2: {Evidence leading to renewed belief in a theory}</strong></p>\n<ul data-path-to-node=\"5,1,1\">\n<li>\n<p data-path-to-node=\"5,1,1,0,0\"><strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a number of more <strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"32\">carefully designed experiments</strong> began to yield <strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"78\">convincing indications to the contrary</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,1,1,0\"><strong data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau một thập kỷ, các thí nghiệm của Richard Karban và các cộng sự đã đưa ra bằng chứng thuyết phục để hồi sinh lý thuyết này.</p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">16.</strong></li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Đoạn 3: {A suggested benefit to the sender of plant communication}</strong></p>\n<ul data-path-to-node=\"5,2,1\">\n<li>\n<p data-path-to-node=\"5,2,1,0,0\"><strong data-path-to-node=\"5,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One hypothesis is that external communication channels are merely an <strong data-path-to-node=\"5,2,1,0,0\" data-index-in-node=\"81\">extension of within-plant signaling</strong>… to protect itself.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,1,1,0\"><strong data-path-to-node=\"5,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích lợi ích của chính cái cây phát tín hiệu (để tự bảo vệ các phần khác của chính nó) chứ không chỉ giúp hàng xóm.</p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">17.</strong></li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">Đoạn 4: {Sending messages underground}</strong></p>\n<ul data-path-to-node=\"5,3,1\">\n<li>\n<p data-path-to-node=\"5,3,1,0,0\"><strong data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…distress signals can be passed through the <strong data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"58\">plants’ roots</strong>. …labyrinths of hair-like <strong data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"100\">fungi</strong> that occur around the roots…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,1,1,0\"><strong data-path-to-node=\"5,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tập trung vào kênh giao tiếp dưới lòng đất qua rễ và mạng lưới nấm.</p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,4,0\" data-index-in-node=\"0\">18.</strong></li>\n<li>\n<p data-path-to-node=\"5,4,0\"><strong data-path-to-node=\"5,4,0\" data-index-in-node=\"0\">Đoạn 5: {One species accelerating growth in another}</strong></p>\n<ul data-path-to-node=\"5,4,1\">\n<li>\n<p data-path-to-node=\"5,4,1,0,0\"><strong data-path-to-node=\"5,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…chili plant seedlings grown next to fennel plants <strong data-path-to-node=\"5,4,1,0,0\" data-index-in-node=\"65\">developed more quickly</strong> than seedlings grown with other chili plants.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,4,1,1,0\"><strong data-path-to-node=\"5,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ví dụ về việc cây ớt phát triển nhanh hơn khi ở gần cây thì là (fennel).</p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,5,0\" data-index-in-node=\"0\">19.</strong></li>\n<li>\n<p data-path-to-node=\"5,5,0\"><strong data-path-to-node=\"5,5,0\" data-index-in-node=\"0\">Đoạn 6: {Potential advantages for farmers}</strong></p>\n<ul data-path-to-node=\"5,5,1\">\n<li>\n<p data-path-to-node=\"5,5,1,0,0\"><strong data-path-to-node=\"5,5,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…could eventually be <strong data-path-to-node=\"5,5,1,0,0\" data-index-in-node=\"35\">applied to agriculture</strong>, and lead to the cultivation of <strong data-path-to-node=\"5,5,1,0,0\" data-index-in-node=\"90\">hardier crops</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,5,1,1,0\"><strong data-path-to-node=\"5,5,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nói về triển vọng ứng dụng kiến thức này vào nông nghiệp để tạo ra cây trồng chống chịu tốt hơn.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('79f6b3ca-f8c5-402f-9456-73cf6e306aad', '667e19cf-bb39-4492-8404-5ff2984beefc', 'fillup', 'Questions 20–23', '<p data-start="609" data-end="685">Complete the summary. Write <strong data-start="637" data-end="654">ONE WORD ONLY</strong> from the text for each answer.</p>
<h3 data-start="687" data-end="742">Plant communication research in Israel and Scotland</h3>
<p data-start="744" data-end="1191">Plants may send messages via their {roots} according to Ariel Novoplansky of Ben-Gurion University in Israel. In one study, Novoplansky’s team planted rows of garden peas, and created conditions like a {drought} around the first plant in each row. The plants responded by closing the tiny holes on their leaf surfaces, known as pores. They then appeared to signal to other plants nearby, causing them to respond in a similar way.</p>
<p data-start="1193" data-end="1629">Research at the University of Aberdeen in Scotland, meanwhile, has focused on the networks of {fungi} which connect the plants beneath the soil. These structures, which extract sugars from the plants and supply them with phosphorus and nitrogen, also seem to play a key role in plant communication. Experiments involving broad bean and plant-eating insects called {aphids} have also produced some interesting results.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">20. Plants may send messages via their {roots}…</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…distress signals can be passed through the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"58\">plants’ roots</strong>.” (Đoạn 4)</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">21. …created conditions like a {drought} around the first plant…</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…subjected the first in each row to conditions similar to those experienced in a <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"95\">drought</strong>.” (Đoạn 4)</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">22. …focused on the networks of {fungi} which connect the plants…</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…labyrinths of hair-like <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"39\">fungi</strong> that occur around the roots of most plants.” (Đoạn 4)</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">23. …plant-eating insects called {aphids} have also produced some interesting results.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…broad bean plants were infested with <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"52\">aphids</strong> – small herbivorous insects…” (Đoạn 4)</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('36fcc8c2-b931-4bdf-ad68-4760396b29f1', 'dcf9912b-d9c8-4938-a878-d0eaa4499bff', 'fillup', 'Questions 21 – 27', '<p style="text-align: center;"><span style="font-size: 12pt;"><strong data-path-to-node="8" data-index-in-node="0">Lifting heavy objects at work</strong></span></p>
<ul data-path-to-node="9">
<li><strong data-path-to-node="9,0,0" data-index-in-node="0">Causes of accidents and long term problems:</strong>
<ul data-path-to-node="9,0,1">
<li>
<p>lifting, pushing and pulling badly</p>
</li>
<li>
<p>performing a {repetitive task} .</p>
</li>
</ul>
</li>
<li>
<p><strong data-path-to-node="9,1,0" data-index-in-node="0">Employers should</strong></p>
<ul data-path-to-node="9,1,1">
<li>
<p>spot potential problems through undertaking a risk assessment</p>
</li>
<li>
<p>find {alternatives} to lifting where possible.</p>
</li>
</ul>
</li>
<li>
<p><strong data-path-to-node="9,2,0" data-index-in-node="0">Employees should</strong></p>
<ul data-path-to-node="9,2,1">
<li>
<p>consider using equipment such as {trolleys} to help them</p>
</li>
<li>
<p>think about dividing a load into {smaller packages}</p>
</li>
<li>
<p>request training</p>
</li>
<li>
<p>be familiar with their personal {limitations} as to what weight they can lift</p>
</li>
<li>
<p>make sure a workable {emergency plan} is in place to deal with accidents</p>
</li>
<li>
<p>get help.</p>
</li>
</ul>
</li>
<li>
<p><strong data-path-to-node="9,3,0" data-index-in-node="0">Employees are entitled to</strong></p>
<ul data-path-to-node="9,3,1">
<li>
<p>consult their {supervisor} if worried about lifting something</p>
</li>
<li>
<p>refer to the lifting tips on the official HSE diagrams.</p>
</li>
</ul>
</li>
</ul>', '<p>Complete the notes below.</p>
<p>Choose <strong data-path-to-node="7" data-index-in-node="51">NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 21-27 on your answer sheet.</p>', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. Causes of accidents: – performing a {repetitive} task</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"20,0,0\" data-index-in-node=\"11\">“…any <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"19\">repetitive</strong> task which involves moving in the same way over and over again”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những công việc mang tính lặp đi lặp lại (repetitive) là một trong những nguyên nhân gây ra rối loạn cơ xương khớp (MSDs).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. Employers should: – find {alternatives} to lifting where possible</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"22,0,0\" data-index-in-node=\"11\">“…look at ways to avoid manual handling; provide <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"62\">alternatives</strong>, if any are available”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người sử dụng lao động có trách nhiệm tìm các phương án thay thế (alternatives) cho việc bê vác thủ công.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">23. Employees should: – consider using equipment such as {trolleys} to help them.</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"24,0,0\" data-index-in-node=\"11\">“For example, <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"25\">trolleys</strong> may be an easier and more efficient way of moving heavy objects…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Xe đẩy (trolleys) là ví dụ điển hình cho thiết bị hỗ trợ di chuyển vật nặng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">24. Employees should: – think about dividing a load into {smaller packages}</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"26,0,0\" data-index-in-node=\"11\">“…possible to repack a large consignment in <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"57\">smaller packages</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Dividing a load” tương ứng với việc đóng gói lại thành các kiện nhỏ hơn (smaller packages).</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">25. Employees should: – be familiar with their personal {limitations} as to what weight they can lift.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"28,0,0\" data-index-in-node=\"11\">“know your own <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"26\">limitations</strong>, because there are no general weight limits that can be applied to everyone”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Do không có giới hạn trọng lượng chung, mỗi người cần biết giới hạn (limitations) của bản thân.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">26. Employees should: – make sure a workable {emergency plan} is in place to deal with accidents.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"30,0,0\" data-index-in-node=\"11\">“prepare a practical <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"32\">emergency plan</strong> in case something goes wrong”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Workable” đồng nghĩa với “practical”. Cần có kế hoạch khẩn cấp (emergency plan) phòng khi có sự cố.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">27. Employees should: – check they have a {good grip} before lifting.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"32,0,0\" data-index-in-node=\"11\">“ensure you have a <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"30\">good grip</strong> before lifting”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Kiểm tra độ bám/tay cầm (good grip) là bước an toàn quan trọng trước khi nhấc vật nặng lên.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('52e2eb63-030c-4d38-946c-f4ee9dedc3d7', '667e19cf-bb39-4492-8404-5ff2984beefc', 'matrix', 'Questions 24–26', '', '<p>Choose the correct researcher, <strong>A</strong>–<strong>E</strong>, for each statement.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "It is likely that research into plant communication will one day help to improve our food supply", "correctCategoryLetter": "C"}, {"itemText": "Plant communication could occur as a consequence of internal mechanisms intended to help a single plant", "correctCategoryLetter": "A"}, {"itemText": "Attitudes towards plant communication have changed greatly in recent decades.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Richard Karban", "categoryLetter": "A"}, {"categoryText": "Ariel Novoplansky", "categoryLetter": "B"}, {"categoryText": "David Johnson", "categoryLetter": "C"}, {"categoryText": "Monica Gagliano", "categoryLetter": "D"}, {"categoryText": "Carel ten Cate", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">24. It is likely that research… will one day help to improve our food supply — {C} David Johnson</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “‘Applying our limited knowledge… to <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"50\">agriculture</strong> is a big jump,’ says <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"83\">Johnson</strong>, ‘but it is definitely on the horizon.’” (Đoạn 6)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">25. Plant communication could occur as a consequence of internal mechanisms… — {A} Richard Karban</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"22,0,0\" data-index-in-node=\"12\">Karban agrees</strong>, saying, ‘The interplant signaling we see may be a result of plants <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"94\">co-opting that process</strong> [within-plant signaling].’” (Đoạn 3)</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">26. Attitudes towards plant communication have changed greatly in recent decades — {B} Ariel Novoplansky</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “‘During my PhD [in the late 1980s], all this stuff was <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"67\">considered very weird</strong>,’ recalls <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"99\">Ariel Novoplansky</strong>. ‘Today, there is <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"135\">no doubt</strong>…’” (Đoạn 6)</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('c2eafe33-2859-4feb-972c-75f76a998c0c', 'fe4f5ae3-1d85-4c09-b948-251b57efe95f', 'fillup', 'Questions 1–10', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the form below.</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border-spacing: 1px; border: 1px solid rgb(0, 0, 0); width: 78.0008%;" border="1"><colgroup> <col style="width: 100%;" width="100"></colgroup>
<tbody>
<tr data-row="row-nh7r">
<td style="border-width: 1px; padding: 1px; border-color: #000000;" colspan="1" rowspan="1" data-row="row-nh7r">
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1"><strong>Two-day course</strong></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">This covers basic techniques.</p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Children are always accompanied by their <span class="fill-history-correct">{instructor}</span></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Cost: £<span class="fill-history-correct">{65}</span></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1"><strong>Five-day course</strong></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Cost: £125</p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Children can sail alone from the third day onwards<strong>.</strong></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Children can learn how to sail in different kinds of weather.</p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Children receive a {certificate} on the last day.</p>
</td>
</tr>
<tr data-row="row-j0bk">
<td style="border-width: 1px; padding: 1px; border-color: #000000;" colspan="1" rowspan="1" data-row="row-j0bk">
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1"><strong>Clothing</strong></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Children should wear warm clothes.</p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Children must wear <span class="fill-history-correct">{shoes}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Children are recommended to bring extra trousers which are <span class="fill-history-correct">{waterproof}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Children are not allowed to wear <span class="fill-history-correct">{jeans}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1"><strong>Additional information</strong></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Visitors can buy a {snack}<span class="fill-history-correct"> </span>in the Marina Stores.</p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">There is a free car park next to the <span class="fill-history-correct">{bridge}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Send the registration form two weeks before the course.</p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Remember to include the name of Jacob’s <span class="fill-history-correct">{doctor}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">There is an optional form giving permission to take <span class="fill-history-correct">{photographs}</span></p>
</td>
</tr>
</tbody>
</table>
<p> </p>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-start=\"167\" data-end=\"292\"><strong data-start=\"167\" data-end=\"177\">Woman:</strong> Hello, oh good morning. I’m calling on behalf of my 13-year-old son, Jacob. He’s interested in learning to sail.</p>\n<p data-start=\"294\" data-end=\"371\"><strong data-start=\"294\" data-end=\"302\">Man:</strong> Great, well, we have what we call a taster day on 22nd June.</p>\n<p data-start=\"373\" data-end=\"501\"><strong data-start=\"373\" data-end=\"383\">Woman:</strong> I’m not sure he can make it, but we’ll see. Jacob’s really interested though, so can you tell me about the courses?</p>\n<p data-start=\"503\" data-end=\"591\"><strong data-start=\"503\" data-end=\"511\">Man:</strong> OK, we have two types of courses for children under 16: two-day and five-day.</p>\n<p data-start=\"593\" data-end=\"639\"><strong data-start=\"593\" data-end=\"603\">Woman:</strong> Could you explain the difference?</p>\n<p data-start=\"641\" data-end=\"780\"><strong data-start=\"641\" data-end=\"649\">Man:</strong> Well, the two-day one just covers basic techniques in sailing, and on this course the kids always sail with an<span style=\"background-color: #f1c40f;\"> <strong data-start=\"761\" data-end=\"777\">{instructor}</strong>.</span></p>\n<p data-start=\"782\" data-end=\"801\"><strong data-start=\"782\" data-end=\"792\">Woman:</strong> Right.</p>\n<p data-start=\"803\" data-end=\"840\"><strong data-start=\"803\" data-end=\"811\">Man:</strong> And the cost is £<span style=\"background-color: #f1c40f;\"><strong data-start=\"829\" data-end=\"837\">{65}</strong>.</span></p>\n<p data-start=\"842\" data-end=\"912\"><strong data-start=\"842\" data-end=\"852\">Woman:</strong> Oh, I thought it was more than that. I heard it was £125.</p>\n<p data-start=\"914\" data-end=\"956\"><strong data-start=\"914\" data-end=\"922\">Man:</strong> That’s for the five-day course.</p>\n<p data-start=\"958\" data-end=\"1024\"><strong data-start=\"958\" data-end=\"968\">Woman:</strong> OK, I presume that course goes into much more detail?</p>\n<p data-start=\"1026\" data-end=\"1272\"><strong data-start=\"1026\" data-end=\"1034\">Man:</strong> Yes, and from the third day, the kids are given the choice to sail on their own if they want. We use the same types of boat, but we help them learn more techniques, in particular how to manage the boat in a variety of types of weather.</p>\n<p data-start=\"1274\" data-end=\"1396\"><strong data-start=\"1274\" data-end=\"1284\">Woman:</strong> Hmm, I think Jacob would enjoy that course. Do you give them a <span style=\"background-color: #f1c40f;\"><strong data-start=\"1348\" data-end=\"1365\">{certificate}</strong></span> if they complete the course?</p>\n<p data-start=\"1398\" data-end=\"1492\"><strong data-start=\"1398\" data-end=\"1406\">Man:</strong> Absolutely, we give them out on the final day, which a lot of the kids really like.</p>\n<p data-start=\"1494\" data-end=\"1594\"><strong data-start=\"1494\" data-end=\"1504\">Woman:</strong> Great, could you tell me a bit more about what the children have to bring and so forth?</p>\n<p data-start=\"1596\" data-end=\"1792\"><strong data-start=\"1596\" data-end=\"1604\">Man:</strong> Well, the most important thing is the clothing. It goes without saying that whatever the time of year, they should have plenty of warm clothes, as it can be quite cool out on the water.</p>\n<p data-start=\"1794\" data-end=\"1866\"><strong data-start=\"1794\" data-end=\"1804\">Woman:</strong> What about footwear? Do they have to wear anything special?</p>\n<p data-start=\"1868\" data-end=\"1976\"><strong data-start=\"1868\" data-end=\"1876\">Man:</strong> The only rule is that they’ve got to have <span style=\"background-color: #f1c40f;\"><strong data-start=\"1919\" data-end=\"1930\">{shoes}</strong></span> of some kind — they mustn’t have bare feet.</p>\n<p data-start=\"1978\" data-end=\"1994\"><strong data-start=\"1978\" data-end=\"1988\">Woman:</strong> OK.</p>\n<p data-start=\"1996\" data-end=\"2149\"><strong data-start=\"1996\" data-end=\"2004\">Man:</strong> And we suggest the kids pack an extra pair of trousers, you know <span style=\"background-color: #f1c40f;\"><strong data-start=\"2070\" data-end=\"2086\">{waterproof}</strong></span> ones. They don’t have to wear them unless it starts to rain.</p>\n<p data-start=\"2151\" data-end=\"2217\"><strong data-start=\"2151\" data-end=\"2161\">Woman:</strong> Fine, so basically it’s just using your common sense.</p>\n<p data-start=\"2219\" data-end=\"2366\"><strong data-start=\"2219\" data-end=\"2227\">Man:</strong> Yes, oh, and one other thing we do say is that the children mustn’t wear <span style=\"background-color: #f1c40f;\"><strong data-start=\"2301\" data-end=\"2312\">{jeans}</strong></span>, because they get extremely heavy when they’re wet.</p>\n<p data-start=\"2368\" data-end=\"2388\"><strong data-start=\"2368\" data-end=\"2378\">Woman:</strong> Oh, OK.</p>\n<h3 data-section-id=\"392fk7\" data-start=\"2395\" data-end=\"2408\"> </h3>\n<p data-start=\"2410\" data-end=\"2497\"><strong data-start=\"2410\" data-end=\"2420\">Woman:</strong> One thing I forgot to ask is whether it’s possible to get a meal anywhere.</p>\n<p data-start=\"2499\" data-end=\"2604\"><strong data-start=\"2499\" data-end=\"2507\">Man:</strong> I’m afraid not, but we do have a shop called the Marina Stores where he can get a<span style=\"background-color: #f1c40f;\"> <strong data-start=\"2590\" data-end=\"2601\">{snack}</strong>.</span></p>\n<p data-start=\"2606\" data-end=\"2684\"><strong data-start=\"2606\" data-end=\"2616\">Woman:</strong> OK, and before I forget, when I drop Jacob off, where can I park?</p>\n<p data-start=\"2686\" data-end=\"2857\"><strong data-start=\"2686\" data-end=\"2694\">Man:</strong> Good question, there’s spaces near the entrance, but you have to pay for them. But there’s no charge for the car park just by the <span style=\"background-color: #f1c40f;\"><strong data-start=\"2825\" data-end=\"2837\">{bridge}</strong></span> — do you know it?</p>\n<p data-start=\"2859\" data-end=\"2905\"><strong data-start=\"2859\" data-end=\"2869\">Woman:</strong> Oh yes, I know what you mean now.</p>\n<p data-start=\"2907\" data-end=\"3115\"><strong data-start=\"2907\" data-end=\"2915\">Man:</strong> We do need you to fill in a registration form. You should send that in a couple of weeks before the course starts. The form is on the website, but we ask you to print it off and add your signature.</p>\n<p data-start=\"3117\" data-end=\"3183\"><strong data-start=\"3117\" data-end=\"3127\">Woman:</strong> Yes, of course. What sort of information do you need?</p>\n<p data-start=\"3185\" data-end=\"3269\"><strong data-start=\"3185\" data-end=\"3193\">Man:</strong> About your child’s swimming ability, any special requirements, and so on.</p>\n<p data-start=\"3271\" data-end=\"3324\"><strong data-start=\"3271\" data-end=\"3281\">Woman:</strong> Will you need to know who his doctor is?</p>\n<p data-start=\"3326\" data-end=\"3341\"><strong data-start=\"3326\" data-end=\"3334\">Man:</strong> Yes.</p>\n<p data-start=\"3343\" data-end=\"3446\"><strong data-start=\"3343\" data-end=\"3353\">Woman:</strong> We’ve just recently changed surgeries, so I’ll make a note to get that — his <span style=\"background-color: #f1c40f;\"><strong data-start=\"3431\" data-end=\"3443\">{doctor}</strong></span>.</p>\n<p data-start=\"3448\" data-end=\"3616\"><strong data-start=\"3448\" data-end=\"3456\">Man:</strong> And one more thing, there’s a separate form on the website which is optional, that asks whether you’re willing for photographs to be taken during the course.</p>\n<p data-start=\"3618\" data-end=\"3687\"><strong data-start=\"3618\" data-end=\"3628\">Woman:</strong> Yes, of course, no problem — <span style=\"background-color: #f1c40f;\"><strong data-start=\"3658\" data-end=\"3675\">{photographs}</strong></span> are fine.</p>\n<p data-start=\"3689\" data-end=\"3724\"><strong data-start=\"3689\" data-end=\"3697\">Man:</strong> Great, so I’ll send you…</p>"}]', 0);
INSERT INTO public.questions VALUES ('c0a6f4b1-c228-4515-a342-163cd3ee6228', '7261888e-0e11-43bc-92ed-f7823fafa601', 'radio', 'Questions 1–4', '', '<p><span class="citation-5685">Choose</span><strong data-path-to-node="5,0" data-index-in-node="0"><span class="citation-5685"> TRUE</span></strong><span class="citation-5685 citation-end-5685"> if the statement agrees with the information<sup class="superscript" data-turn-source-index="3"><!----></sup></span> <strong data-path-to-node="5,0" data-index-in-node="50"><span class="citation-5684">FALSE</span></strong><span class="citation-5684 citation-end-5684"> if the statement contradicts the in<sup class="superscript" data-turn-source-index="4"><!----></sup></span>formation <strong data-path-to-node="5,0" data-index-in-node="101">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Scientists studied hunter-gatherer societies because their sleep patterns are assumed to be similar to those of humans more than 10,000 years ago."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The medical devices used in the research were specially designed for humid conditions."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Researchers found that tribespeople stayed longer in bed than inhabitants of industrialised regions."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Jerome Siegel believes that environment and culture have little effect on sleep patterns."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. Scientists studied hunter-gatherer societies because their sleep patterns are assumed to be similar to those of humans more than 10,000 years ago. — {TRUE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…these pre-industrial societies are <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"59\">thought to sleep the way humans did more than 10,000 years ago</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “thought to sleep” đồng nghĩa với “assumed to be similar” (được giả định/cho là giống với). Mục đích nghiên cứu các bộ lạc này là vì các nhà khoa học tin rằng họ vẫn giữ thói quen ngủ như con người từ 10.000 năm trước.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. The medical devices used in the research were specially designed for humid conditions. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Traveling to where they lived, often in <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"61\">humid, remote locations</strong>, researchers used <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"103\">medical devices</strong> to record the sleeping habits…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc các địa điểm nghiên cứu thường có khí hậu <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"79\">ẩm ướt</strong> (humid) và các nhà khoa học có dùng <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"122\">thiết bị y tế</strong> (medical devices). Tuy nhiên, bài <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"170\">không hề nói</strong> rằng các thiết bị này được “thiết kế đặc biệt” (specially designed) cho điều kiện ẩm ướt đó hay không.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. Researchers found that tribespeople stayed longer in bed than inhabitants of industrialised regions. — {FALSE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Like many of us… This adds up to a <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"58\">sleep efficiency that is very similar to today’s industrial populations</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói rằng các bộ lạc này cũng dành thời gian ở trên giường nhiều hơn thời gian ngủ thực tế (từ 6.9 đến 8.5 giờ), và hiệu quả giấc ngủ của họ <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"160\">rất giống</strong> (very similar) với người dân ở các vùng công nghiệp hóa ngày nay. Vì vậy, nói họ ở trên giường “lâu hơn” (longer) là sai (contradicts).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. Jerome Siegel believes that environment and culture have little effect on sleep patterns. — {TRUE}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“According to Jerome Siegel… evidence suggests sleep habits <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"82\">may not be environmental or cultural</strong>, but central to the physical makeup of humans.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Jerome Siegel tin rằng thói quen ngủ không phải do môi trường hay văn hóa quyết định, mà nằm ở cấu tạo thể chất của con người. Điều này tương ứng với việc tin rằng môi trường và văn hóa có ít tác động (little effect) đến giấc ngủ.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('f425b423-fe0b-4053-b458-c20dfc092ba1', '092a14bb-8886-44d1-b77e-0cca16c70c5b', 'radio', 'Questions 11–16', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "seen as an opportunity to learn."}, {"option_text": "predicted and minimised."}, {"option_text": "avoided at all costs"}], "question": "Arthur feels that when starting a business, mistakes should be"}, {"correct": 0, "options": [{"option_text": "sometimes reduce people''s chances of success."}, {"option_text": "be increased by reading self-help books."}, {"option_text": "ensure good results on business courses."}], "question": "Recent American studies found that confidence will"}, {"correct": 2, "options": [{"option_text": "listen to their colleagues'' advice."}, {"option_text": "get professional help when things go wrong."}, {"option_text": "remain concentrated on their aims."}], "question": "The American studies recommended that new entrepreneurs"}, {"correct": 1, "options": [{"option_text": "He relied on what he already knew."}, {"option_text": "He hired an expert to take care of it."}, {"option_text": "He realised its importance too late."}], "question": "What does Arthur say about his own experience of marketing?"}, {"correct": 2, "options": [{"option_text": "They are ambitious for their company."}, {"option_text": "They can deal with difficult people."}, {"option_text": "They earn the respect of their workforce."}], "question": "What does Arthur think Is an important quality shared by good leaders?"}, {"correct": 0, "options": [{"option_text": "He advises being cautious"}, {"option_text": "He favours a long-term view."}, {"option_text": "He believes it is financially advantageous."}], "question": "What does Arthur say about taking risks?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Presenter:</strong> Everybody dreams of becoming a millionaire one day, so we asked Arthur Knowles, who made his millions in the plumbing business, to give the budding entrepreneurs among you a few tips on how to make your first million. Arthur, welcome to the programme.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Arthur:</strong> Thanks, Sue.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Presenter:</strong> So Arthur, what advice do you have for our listeners?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Arthur:</strong> Well, one thing I’ve heard people say is that when you’re starting up a business, you can’t afford to make mistakes. Well, I believe in the old saying: a person who never made a mistake never made anything.<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"6\" data-index-in-node=\"215\">(Q11) You can’t really predict when you’ll make mistakes, and you have to look at them as a positive experience — and one that means you won’t make the same mistake again.</strong></span></p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Arthur:</strong> You need to be able to cope with the world of business, but according to recent American business school studies, believing in yourself isn’t enough by itself to guarantee success. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"189\">(Q12) Confidence can be a good thing, but a person can have too much confidence, and people who try to learn to be confident by buying those how-to-succeed books are just wasting their time.</strong></span></p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Arthur:</strong> The advice given in these American studies was that being a successful entrepreneur comes down to having the right attitude. It’s no good getting depressed every time something goes wrong. <strong data-path-to-node=\"8\" data-index-in-node=\"197\"><span style=\"background-color: #f1c40f;\">(Q13) Always keep your goals in mind and never give up</span>.</strong> And don’t listen to all the people around you who say, “Oh, this will never work.”</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Arthur:</strong> One thing I’ve learned in business is that you don’t have to be an expert in everything, like marketing for example. When I started my business, I tried to do it all myself, but I soon realised that although I knew everything there was to know about plumbing, I didn’t have much idea about how to sell my ideas. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"320\">(Q14) So I got someone who knew more about this to take care of the marketing side of things for me.</strong></span></p>\n<p data-path-to-node=\"10\"><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Arthur:</strong> <strong data-path-to-node=\"10\" data-index-in-node=\"8\">(Q15) And as for leadership, well, you’ve got to be someone your workers look up to because you’ve been seen to make the right decisions.</strong></span> You have to be able to control people, but listen to them at the same time. Some people are driven to make their companies successful, but that too often leads to a ruthless approach.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Arthur:</strong> Then there’s the question of taking risks, even calculated ones. <strong data-path-to-node=\"11\" data-index-in-node=\"73\"><span style=\"background-color: #f1c40f;\">(Q16) I personally feel it’s actually better to tread carefully when it comes to taking short-term risks</span>.</strong> You need a degree of vision, certainly, but it’s easy to get carried away by your desire to increase profits, and if things go wrong, you can end up losing more than you gain.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Arthur:</strong> So if you have a great idea for a business, what should you do next? Well, the first thing to ask yourself is whether there’s a need for your product or service. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"170\">(Q17-18) Can you cater for people’s needs better than existing companies?</strong></span> You don’t need to worry about whether it’s original or not, because there isn’t always enough demand for completely new ideas.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Arthur:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"8\">(Q17-18) And the second thing to ask yourself is not what colour should the packet be or how much should it cost, but do I care enough about this idea to dedicate the next 10 years of my life to it?</strong></span> Because realistically, that’s how long it will take.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Presenter:</strong> Tell us how you got started, Arthur. How do you explain your early success?</p>\n<p id=\"p-rc_a2ca37fe4d43f8dc-54\" data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Arthur:</strong> <span class=\"citation-221 citation-end-221\">Well, I started my business just as the economy was going into a recession, which wasn’t the best time, and I was lucky to survive, especially as the banks weren’t being particularly supportive to small businesses at that tim</span>e.</p>\n<p id=\"p-rc_a2ca37fe4d43f8dc-55\" data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Arthur:</strong> If I’d listened to the business advice I was given back then, I’d never have got started. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"98\">(Q19-20) <span class=\"citation-220 citation-end-220\">My strengths were that I knew I could provide a better service than my competitors, who really hadn’t spotted the opportunities that were out there, and that my wife had a good job and was able to pay the household bills while I was getting the company on its fee</span>t.</strong></span></p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Arthur:</strong> The first couple of years were very tough, but I knew I would make it eventually.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Presenter:</strong> OK, now we’re going to take some calls from listeners.</p>"}]', 0);
INSERT INTO public.questions VALUES ('e0a21242-d18e-4f55-87ba-5045a25c9e09', 'c1144789-9cb6-4a96-a54b-5cb5398e63ad', 'fillup', 'Questions 21–23', '<p data-start="93" data-end="157">Complete the notes below.<br data-start="118" data-end="121">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><strong><span style="font-size: 14pt;">Products using renewable energy sources</span></strong></p>
<p data-start="208" data-end="249"><strong>a) Kites produced by German company</strong></p>
<ul data-start="250" data-end="367">
<li data-start="250" data-end="290">are attached to ships by long cables</li>
<li data-start="291" data-end="327">can use wind power in any {weather}</li>
<li data-start="328" data-end="367">could reduce toxic emissions by 50%</li>
</ul>
<p data-start="369" data-end="411"><strong>b) Sports car produced by US company</strong></p>
<ul data-start="412" data-end="474">
<li data-start="412" data-end="445">uses {electricity} as a power source</li>
<li data-start="446" data-end="474">will have zero emissions</li>
</ul>
<p data-start="476" data-end="524"><strong>c) Ethanol stoves produced in South Africa</strong></p>
<ul data-start="525" data-end="584">
<li data-start="525" data-end="584">are safer than paraffin stoves as less likely to {explode}</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: RENEWABLE ENERGY PROJECT</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Sylvia:</strong> Greg, about this project on renewable energy, we’ve got to look at some products that use it and then see how aware people are of this kind of energy.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Greg:</strong> Well, first we must clarify what renewable energy is.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Sylvia:</strong> I’ve done that. It’s energy from a source which is replaced by a natural process, such as wind, tidal energy from the sea, energy from the sun and so on. And I found some very interesting examples of products using these sources.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Greg:</strong> So have I. What have you got?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Sylvia:</strong> Well, the first one is a company in Germany which is producing huge kites that pull ships along. The kites are attached by long cables and they fly up to 500 meters above the sea.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Greg:</strong> They must be pretty big. And it means that they can be powered by the wind <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"81\">(21) no matter what the weather [Answer: weather]</strong>.</span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Sylvia:</strong> That sounds like a good idea, but will they really help reduce energy use?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Greg:</strong> You bet. As well as that, apparently the shipping industry is one of the worst polluters on the planet as they use cheap diesel fuel which has terrible toxic emissions. The company believes these kites could cut the use of these fuels by 50% and reduce the emissions by the same amount.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Sylvia:</strong> Sounds good. And I found a company in the US which is developing a new type of car. Apparently, they’re producing a sports car which doesn’t use petrol at all, just <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"173\">(22) electricity [Answer: electricity]</strong></span>, but for the US market only.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Greg:</strong> Sounds intriguing. Do we know what it’ll look like?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Sylvia:</strong> They’re very secretive about it, and all they say is that it won’t look ugly and it’ll have zero emissions.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Greg:</strong> Wow, really? So they say. Any other products?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Sylvia:</strong> I found an interesting article about a man in South Africa who’s selling stoves using ethanol to the local people.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Greg:</strong> Ethanol?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Sylvia:</strong> Yes, it’s made from the sugar of certain crops. Most of the local people use paraffin stoves at the moment and they are dangerous because they can <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"155\">(23) explode [Answer: explode]</strong></span> quite easily.</p>\n<hr data-path-to-node=\"18\">\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">THE SURVEY (Questions 24–30)</strong></p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Greg:</strong> Right. Now for the next part, we have to do a survey to find out how aware the public is about this kind of energy. Who shall we approach? Local businesses?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Sylvia:</strong> I think it’s easier to do a survey of the general public rather than local companies. Why? Last time we sent all those email surveys to commercial organizations and we only had replies from 5% of them.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Greg:</strong> Oh, I forgot that. OK then, what about the other students and the lecturer here in the university?</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Sylvia:</strong> You know what the lecturers are like, they’re so busy they won’t have the time. But the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"96\">(24 &amp; 25) students [Answer: university students]</strong></span> will, I’m sure.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Greg:</strong> Okay. And as well as that, we could target the local schools like last time. School kids just love doing surveys.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Sylvia:</strong> I think we want to stick to adults for this, don’t you? you’re probably right. Maybe we could approach <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"88\">(24 &amp; 25) people who rent or own properties [Answer: local residents]</strong></span> around here, since they’re the ones who have to pay for the energy.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Greg:</strong> Exactly.</p>\n<p data-path-to-node=\"26\"><strong>Greg</strong>: Now, what about the kind of questions we want to include in the survey?</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Sylvia:</strong> Well, we need to find out if they know what renewable energy is and how familiar people are with the concept. I know it’s been all over the news lately, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"27\" data-index-in-node=\"120\">(26) I think a lot of people are still in the dark about it [Answer: A – Many people know little about it]</strong>.</span></p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Greg:</strong> Do you think so? I’m not sure I agree, but we can have that in if you want. We also need to find out what they think about traditional energy sources like gas and coal and if they know what effect these types of energy have on their environment and what they cost that’s not so important</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Sylvia:</strong> But <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"29\" data-index-in-node=\"12\">(27) we ought to see what they think is going to happen to the consumption of traditional energy sources [Answer: B – possible future developments]</strong>.</span></p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Greg:</strong> You’re right. Then there’s nuclear power. That’s an interesting one because it’s cleaner and more efficient in many ways than other fuels, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"132\">(28) the safety factor has always worried people [Answer: C – Some people think it is unsafe]</strong>.</span></p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Sylvia:</strong> Yes, I know that the technology has improved greatly since it was first used, but I don’t think everyone is convinced. Are there any problems with renewable energy? Yes and we need to know what people think about them</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Greg:</strong> One argument is that it’s going to be too expensive to use solar or wind power. But once people realize the benefits to us all the price is bound to come down it’s always expensive to start with <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"32\" data-index-in-node=\"63\">(29) once enough people want it, the price is bound to come down [Answer: A – Prices will drop in the future]</strong>.</span></p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Sylvia:</strong> Hmm, that’s true. But the other thing is they don’t like it; they say some of the technology is ugly, like the big windmills used. A lot of people think they spoil the countryside.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Greg:</strong> I agree they’re not that bad, they’re pretty efficient. So perhaps it’s a case of <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"34\" data-index-in-node=\"88\">(30) choosing the right place for them, where they look least out of place [Answer: B – should be put in carefully selected locations]</strong>.</span></p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Sylvia:</strong> A good point. It’ll be very interesting to see the results of this survey.</p>"}]', 0);
INSERT INTO public.questions VALUES ('a13224e1-a604-4c19-9bc2-eca959f04e76', 'e043772b-af03-47ea-bc06-c4a28053b316', 'fillup', 'Questions 1-6', '<p>Complete the notes below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 1-6 on your answer sheet.</p>
<p>Period<br>Key developments<br>1600s<br>Early inventors like Papin started to develop boats that relied on steam instead of manpower or wind.<br>1730s<br>The engine of Jonathan Hulls’ steamboat was {inefficient} due to its weight.<br>1780s<br>A French paddle steamer did not have the {endurance} to keep going for more than a quarter of an hour.<br>John Fitch overcame a number of {technical} problems with his steamboat designs.<br>Early 1800s<br>The Charlotte Dundas pulled barges to Glasgow.<br>In France, Fulton used a steamboat to try to raise interest in a {submarine}.<br>Passengers in the US began to be carried regularly by a steamboat called the {Clermont}<br>1812 onwards<br>In Scotland, steamboats transported some passengers, but mostly {cargo}<br> </p>', '', 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">1. {inefficient} (Thập kỷ 1730)</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“Englishman Jonathan Hulls took out patents on a steamboat in 1736, but it was to be driven by a Newcomen engine, which was heavy and therefore <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"164\">inefficient</strong>…”</em></li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Động cơ Newcomen mà Jonathan Hulls sử dụng quá nặng, dẫn đến việc nó không hiệu quả (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"97\">inefficient</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">2. {endurance} (Thập kỷ 1780)</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“Nearly 20 years later, in the 1780s, a steam-powered paddle-wheeler managed to last fifteen minutes… but lacked the <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"139\">endurance</strong> for longer trips.”</em></li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Fifteen minutes” (15 phút) tương ứng với “a quarter of an hour” trong đề bài. Con tàu này không đủ sức bền (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"121\">endurance</strong>) để đi những chuyến dài hơn.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">3. {technical} (Thập kỷ 1780)</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“…John Fitch successfully trialled his first steamboat in 1787, but although he tried a number of designs and solved many <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"144\">technical</strong> challenges…”</em></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong đề bài dùng từ “problems”, trong bài đọc dùng “challenges”. John Fitch đã giải quyết được nhiều vấn đề/thách thức về mặt kỹ thuật (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"149\">technical</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">4. {submarine} (Đầu những năm 1800)</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">“Fulton ran steamboat trials on the River Seine, in an attempt to attract French support for his <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"117\">submarine</strong> Nautilus.”</em></li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “raise interest” tương ứng với “attract support”. Robert Fulton trình diễn tàu hơi nước tại Pháp thực chất là để thu hút sự chú ý/ủng hộ cho dự án tàu ngầm (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"173\">submarine</strong>) của mình.</li>\n</ul>\n<p><strong data-path-to-node=\"13\" data-index-in-node=\"0\">5. {Clermont} (Đầu những năm 1800)</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"20\">“In 1807, the <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"34\">Clermont</strong> began a scheduled passenger steamboat service between New York and Albany…”</em></li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tên con tàu hơi nước đầu tiên thực hiện dịch vụ chở khách định kỳ (scheduled/regularly) tại Mỹ là <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"110\">Clermont</strong>.</li>\n</ul>\n<p><strong data-path-to-node=\"15\" data-index-in-node=\"0\">6. {cargo} (Từ năm 1812 trở đi)</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">“…carrying <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"33\">cargo</strong> and occasionally passengers.”</em></li>\n<li><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tại Scotland, các tàu hơi nước chủ yếu vận chuyển hàng hóa (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"72\">cargo</strong>), còn hành khách chỉ là thỉnh thoảng (occasionally).</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('2a43b7dd-3389-4ccd-acaa-de7536123985', 'c1144789-9cb6-4a96-a54b-5cb5398e63ad', 'radio', 'Questions 26–30', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "Many people know little about it"}, {"option_text": "People understand it because it has been in the news recently"}, {"option_text": "People are eager to find out more about it"}], "question": "What does Sylvia say about people''s knowledge of renewable energy?"}, {"correct": 1, "options": [{"option_text": "the best way of preventing pollution"}, {"option_text": "possible future developments"}, {"option_text": "how expensive people find it"}], "question": "What do Sylvia and Greg decide to ask about traditional energy consumption?"}, {"correct": 2, "options": [{"option_text": "It is not important for their survey"}, {"option_text": "People today have a positive attitude towards it"}, {"option_text": "Some people think it is unsafe"}], "question": "What does Greg say about nuclear power?"}, {"correct": 0, "options": [{"option_text": "Prices will drop in the future"}, {"option_text": "People won''t pay the high price"}, {"option_text": "The benefits outweigh the high cost"}], "question": "What do Sylvia and Greg agree about the cost of renewable energy?"}, {"correct": 1, "options": [{"option_text": "are the most efficient way of harnessing energy"}, {"option_text": "should be put in carefully selected locations"}, {"option_text": "make the landscape look unattractive"}], "question": "Sylvia and Greg agree that modern windmills"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('6712c3c6-5970-446f-945f-882a6762a4f5', 'dd63ef71-292e-44f7-a201-4dae628d3065', 'radio', 'Questions 1 – 6', '', '<p data-start="189" data-end="231">Choose: <strong data-start="233" data-end="241">TRUE </strong>if the statement agrees with the information, <strong data-start="290" data-end="299">FALSE </strong>if the statement contradicts the information, <strong data-start="348" data-end="361">NOT GIVEN </strong>if there is no information on this</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "If you change your car, you can transfer your permit to your new car."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Some Residents’ Parking Permits can be obtained for less than $90."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In order to obtain a permit, a letter from your landlord is satisfactory proof that you are renting accommodation."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It is possible to get a permit only if you are the owner of the car."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "An extra fee is payable for a temporary permit."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "If you apply for a permit by post, you will be able to park immediately."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. If you change your car, you can transfer your permit to your new car. — {FALSE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Residents’ Parking Permits are issued to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"62\">specific vehicles</strong>. If you buy a new vehicle you will <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"115\">also need a new permit</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc ghi rõ giấy phép cấp cho “phương tiện cụ thể”. Nếu bạn đổi xe mới, bạn <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"91\">cần một giấy phép mới</strong> chứ không thể dùng lại (transfer) tờ giấy cũ từ xe này sang xe khác. (Lưu ý: Chỉ có thời gian còn lại là được nạp vào thẻ mới, nhưng bản thân cái “permit” phải là cái mới).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. Some Residents’ Parking Permits can be obtained for less than $90. — {TRUE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Applications):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"30\">“Residents’ Parking Permits cost $90 per year… and are also available for <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"106\">shorter periods</strong>, as required, at a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"141\">reduced cost</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mức giá $90 là cho 1 năm. Nếu đăng ký thời hạn ngắn hơn, chi phí sẽ được giảm xuống (reduced cost), tức là thấp hơn $90.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. In order to obtain a permit, a letter from your landlord is satisfactory proof that you are renting accommodation. — {TRUE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Applications – Dấu chấm đầu tiên):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"50\">“If you are a tenant, provide a copy of your tenancy agreement… or a <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"121\">letter from the owner of the property</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Landlord” (chủ nhà) tương ứng với “owner of the property”. Bài đọc xác nhận thư từ chủ nhà là bằng chứng thỏa đáng (satisfactory proof) để làm thủ tục.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. It is possible to get a permit only if you are the owner of the car. — {FALSE}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Applications – Dấu chấm thứ 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"47\">“If you <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"55\">do not own the vehicle</strong>, include a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"89\">letter from the owner authorising you to use it</strong>.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bạn vẫn có thể lấy giấy phép ngay cả khi không sở hữu xe, miễn là có thư ủy quyền của chủ xe. Từ “only” (chỉ khi) trong câu hỏi làm cho khẳng định này trở nên sai so với thực tế trong bài.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. An extra fee is payable for a temporary permit. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Temporary Permits):</strong> Đoạn này chỉ nói về cách thức để nhận giấy phép tạm thời (đăng ký trực tiếp tại văn phòng).</li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"20\">không hề đề cập</strong> đến việc có phải trả thêm phí (extra fee) cho giấy phép tạm thời hay không.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. If you apply for a permit by post, you will be able to park immediately. — {FALSE}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Temporary Permits):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"35\">“If you send in your completed application form and fee <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"91\">by mail, no temporary permit will be issued</strong>. You will be able to <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"156\">park only when the permanent permit is mailed out to you</strong>…”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nếu đăng ký qua đường bưu điện (by post/mail), bạn sẽ không được cấp giấy phép tạm thời và chỉ được đậu xe khi nhận được giấy phép chính thức sau đó (thường là 3 ngày). Do đó, bạn <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"192\">không thể</strong> đậu xe ngay lập tức (immediately).</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('f9bd286e-ed10-4f07-8398-dee7dde10e59', 'f2fb4447-a526-4152-adff-c533d6a2e336', 'radio', 'Questions 16–20', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "sell as many books as possible"}, {"option_text": "create an energetic environment"}, {"option_text": "attract people to remain in the store"}], "question": "bookshop aims to"}, {"correct": 1, "options": [{"option_text": "on the ground floor"}, {"option_text": "on the highest level"}, {"option_text": "midway up the building"}], "question": "children’s books can be found"}, {"correct": 2, "options": [{"option_text": "trains shop floor-staff to look after children"}, {"option_text": "has a free nursery for children"}, {"option_text": "offers professional childcare"}], "question": "in order to help parents relax in the store, Bibiliostack"}, {"correct": 0, "options": [{"option_text": "persuading people to buy books"}, {"option_text": "encouraging authors to get together"}, {"option_text": "bringing in extra money by charging"}], "question": " Bibiliostack holds regular book reading as a way of"}, {"correct": 2, "options": [{"option_text": "were encouraged to have their work published"}, {"option_text": "were considering becoming professional poets"}, {"option_text": "were willing to read their own work in public"}], "question": "The people who took part in Bibiliostack''s poetry workshop"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('a3db1529-7e7d-4b68-ad0e-15da055d9bc2', '092a14bb-8886-44d1-b77e-0cca16c70c5b', 'checkbox', 'Questions 17–18', '', '<div class="quests-inner-desc">
<div class="txt">
<p>Choose <strong>TWO </strong>correct answers.</p>
</div>
</div>
<div class="quests-list">
<div id="4573" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="1806" data-numctn="17" data-count="17" data-quest="17-18" data-choices="2">
<div class="tt-head">
<p class="tt"><span class="numquest">17-18</span> Which <strong>TWO </strong>things does Arthur say people should focus on when developing their business idea?</p>
</div>
<div class="anwsers">
<div id="anwsers_1806_17-18_0" class="anwsers-item disable"></div>
</div>
</div>
</div>', 'list_selection', 'null', '[{"correct": false, "option_text": "making sure the idea is original"}, {"correct": true, "option_text": "offering a better deal than competitors"}, {"correct": true, "option_text": "being committed to it"}, {"correct": false, "option_text": "paying attention to detail"}, {"correct": false, "option_text": "fixing realistic prices"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('6fd2a5a1-797f-4302-86a1-1a6b5dd88d46', '092a14bb-8886-44d1-b77e-0cca16c70c5b', 'checkbox', 'Questions 19–20', '', '<div class="quests-inner-desc">
<div class="txt">
<p>Choose <strong>TWO</strong> correct answers.</p>
</div>
</div>
<div class="quests-list">
<div id="4574" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="1807" data-numctn="19" data-count="19" data-quest="19-20" data-choices="2">
<div class="tt-head">
<p class="tt"><span class="numquest">19-20</span> Which <strong>TWO </strong>things does Arthur say helped him get his business started?</p>
</div>
</div>
</div>', 'list_selection', 'null', '[{"correct": true, "option_text": "family support"}, {"correct": false, "option_text": "getting a loan from a bank"}, {"correct": false, "option_text": "good business advice"}, {"correct": false, "option_text": "a favourable economic climate"}, {"correct": true, "option_text": "an effective approach to business"}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('09de976b-533a-4f62-a1a2-a2467666851e', '7eb85a88-59dd-4b52-8d09-bdd5e8c70228', 'radio', 'Questions 21-25', '', '<p>Choose the correct letter, A, B or C.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A. a history textbook"}, {"option_text": " B. an academic article"}, {"option_text": "C. a lecture handout"}], "question": "What source did Mike use for his definition?"}, {"correct": 0, "options": [{"option_text": "A. the permanent preservation of recordings"}, {"option_text": "B. an increase in student interest"}, {"option_text": "C. wide access to the interviews by the public"}], "question": "According to Mike and his tutor, what is the most important contribution of the intern to oral history?"}, {"correct": 1, "options": [{"option_text": "A. he is football fan"}, {"option_text": "B. his father loves football."}, {"option_text": "C. his friends encouraged him"}], "question": "Mikes says he chose his particular topic because"}, {"correct": 0, "options": [{"option_text": "A. doing research in the local newspaper archives"}, {"option_text": "B. speaking to the team manager"}, {"option_text": "C. looking at materials in the local library"}], "question": "What does Mike say was his best source of information about the team?"}, {"correct": 2, "options": [{"option_text": "A. on the internet"}, {"option_text": "B. in the team records"}, {"option_text": "C. in the phone book"}], "question": "How did Mike find the former players he has arranged to interview?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: ORAL HISTORY PROJECT</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Tutor:</strong> Thanks Mike for dropping by. I''ve read the proposal for your project, which is an oral history of the local football team, particularly the time around 1983 when they won the league championship. But first, how do you define oral history?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Mike:</strong> Well, in fact, I use the definition you gave us last year in our research methodology class. <strong data-path-to-node=\"4\" data-index-in-node=\"99\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q21) I found the handout in my file</span>.</strong> The definition says that oral histories are planned interviews or conversations about some aspect of the past which is considered historically or socially important. The interviews are with people who took part in whatever it''s about, so there''ll be a record which historians can use later for all those academic articles they write. And although history textbooks are mostly about famous people and important events, oral history can be about ordinary people doing ordinary things.Oral history really seems to have started in the States.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Tutor:</strong>  You''re right. In fact, the first modern oral history interviews were done by a historian in New York. By that time, audio technology had improved so much that it was fairly easy to record those interviews. </p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Mike:</strong>  I was also interested in how the internet has contributed to oral history studies.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Tutor:</strong> Yes, it means that lots of people can access the material and that''s great. Also, the interactive nature of the better websites means that more students get interested in oral history.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Mike:</strong> But from what I''ve read, the real contribution of the internet is that <strong data-path-to-node=\"8\" data-index-in-node=\"77\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q22) the recording of the interviews will be preserved forever</span>.</strong> In the old days, the tapes would just wear out and after some years you couldn''t really use them, but not now.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Tutor:</strong> You''re right, of course. Anyhow, let''s move on to the subject of your project. Why did you decide to study a sports team?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Mike:</strong> Well actually, I don''t even like football very much and some of my friends think I''m crazy to go for that subject. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"121\">(Q23) But my dad is a huge fan</strong> </span>and he might be able to help me.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Tutor:</strong> Hmm, and how did you find out background about the team? You talked to the team manager, I assume?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Mike:</strong> Yes, I did manage to track him down. <strong data-path-to-node=\"12\" data-index-in-node=\"43\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q24) And I looked at all the old news stories about the team in the town newspaper office. That was where I got the most helpful information</span>.</strong> I had high hopes that the local library would have lots of stuff, but they don''t keep many records for more than 10 years.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Tutor:</strong> I know that you managed to locate 10 of the original 18 members of the team using an old-fashioned method, didn''t you? Not a website or anything. <span style=\"background-color: #f1c40f;\"><strong>(Q25) Just the telephone directory. </strong></span></p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Mike:</strong>Yes, I didn''t even need to use the local team''s records.</p>\n<hr data-path-to-node=\"15\">\n<h3 data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">PROJECT IMPROVEMENTS (Questions 26–30)</strong></h3>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Tutor:</strong> OK, now I''ve read your proposal carefully. Overall, your plans seem excellent, but I want to discuss how you might improve them.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Mike:</strong> Great.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Tutor:</strong> I''ve read through the list of questions you''ve drafted. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"19\" data-index-in-node=\"63\">(Q26) I felt most of them are rather complex (G)</strong></span> to be processed as oral questions. You don''t have too many, which is good, but you should try to do something about that problem.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Mike:</strong> Right, I''ll work on them.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Tutor:</strong> And the time you''ve allotted for each interview... actually, I think you may have scheduled <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"99\">(Q27) too much time (D - too long)</strong></span> for each. You want them to be tight, not going on and on. That makes for better results.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Mike:</strong> I can change the schedule. One thing I''m nervous about is the recording equipment I use. I''ve got an old recorder. It runs without making too much noise and it isn''t complicated, but it <strong data-path-to-node=\"22\" data-index-in-node=\"192\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q28) sometimes just doesn''t seem to work (A - too unreliable)</span>.</strong> It stopped during an interview I tried out with my dad.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Tutor:</strong> Well, the important thing is just be ready if anything happens. Uh, take some spare batteries or even an extra recorder.  Now, I''m a little concerned with the subjects you''ve chosen to cover. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"141\">(Q29) The topics seem quite general, not very specific (H - too vague)</strong></span>. For example, \"Why did they like playing for this team?\". You need to talk about more exact things and feelings.That way your results will be more valuable.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Mike:</strong> I''ll try to refine them. And the plan for my report seems to be just to report back more or less what the players say... <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"24\" data-index-in-node=\"127\">(Q30) what happened when, what they each did and so on (F - too factual).</strong></span>But I''m not sure about that.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Tutor:</strong> Yes, although your outline seems long enough, change it to indicate that you plan to include your own evaluation of the data you get from your interviewees. Anyhow, best of luck on your project.I look forward to seeing the results.</p>\n<p data-path-to-node=\"25\"><strong>Mike:</strong> Thanks for your help!</p>"}]', 0);
INSERT INTO public.questions VALUES ('9f0856f7-67ba-480b-95b1-18d85d6d4342', 'a1112cfc-f151-4f5f-bb43-1f9cc01bfe3e', 'fillup', 'Questions 7–13', '<p>Complete the notes.<br>Choose <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER </strong>from the passage for each answer.</p>
<h2 data-start="307" data-end="331"><strong data-start="310" data-end="331">Fishbourne Palace</strong></h2>
<h3 data-start="333" data-end="353"><strong data-start="337" data-end="353">Construction</strong></h3>
<ul data-start="354" data-end="555">
<li data-start="354" data-end="424">
<p data-start="356" data-end="424">The first buildings on the site contained food for the {Roman army}</p>
</li>
<li data-start="425" data-end="471">
<p data-start="427" data-end="471">The palace building surrounded {gardens | formal gardens}</p>
</li>
<li data-start="472" data-end="555">
<p data-start="474" data-end="555">In the 2nd and 3rd centuries colour was added to the {floors} of the palace.</p>
</li>
</ul>
<h3 data-start="562" data-end="579"><strong data-start="566" data-end="579">Discovery</strong></h3>
<ul data-start="580" data-end="651">
<li data-start="580" data-end="651">
<p data-start="582" data-end="651">The first part of the palace to be found was part of a {wall}</p>
</li>
</ul>
<h3 data-start="658" data-end="686"><strong data-start="662" data-end="686">Possible inhabitants</strong></h3>
<ul data-start="687" data-end="913">
<li data-start="687" data-end="739">
<p data-start="689" data-end="739"><strong data-start="689" data-end="703">Cogidubnus</strong> – he is named in several writings</p>
</li>
<li data-start="740" data-end="829">
<p data-start="742" data-end="829"><strong data-start="742" data-end="765">Sallustius Lucullus</strong> – he may have lived there until approximately {93} <strong data-start="812" data-end="827">AD</strong></p>
</li>
<li data-start="830" data-end="861">
<p data-start="832" data-end="861"><strong data-start="832" data-end="842">Verica</strong> – a British king</p>
</li>
<li data-start="862" data-end="913">
<p data-start="864" data-end="913"><strong data-start="864" data-end="876">Catuarus</strong> – his {gold ring} was found there</p>
</li>
</ul>
<h3 data-start="920" data-end="939"><strong data-start="924" data-end="939">Present Day</strong></h3>
<ul data-start="940" data-end="1005">
<li data-start="940" data-end="1005">
<p data-start="942" data-end="1005">A {modern museum}</p>
<p data-start="942" data-end="1005">has been built on the site to help protect it.</p>
</li>
</ul>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>7. Roman army<br />\n(Đoạn 1, “…on the site of Roman army grain stores which had been established after the invasion…”)<br />\n→ Công trình đầu tiên trên nền đó là kho lương của quân đội La Mã.</p>\n<p>8. gardens<br />\n(Đoạn 1, “The rectangular palace was built around formal gardens…”)<br />\n→ Cung điện được xây xung quanh khu vườn.</p>\n<p>9. floors<br />\n(Đoạn 1, “…original black and white mosaic floors being overlaid with more sophisticated coloured ones.”)<br />\n→ Màu sắc được thêm vào sàn (floors) ở thế kỷ 2–3.</p>\n<p>10. wall<br />\n(Đoạn 2, “…after workmen accidentally uncovered a wall while they were laying a water main.”)<br />\n→ Phần đầu tiên được tìm thấy là một bức tường.</p>\n<p>11. 93<br />\n(Đoạn 6, “…Lucullus was executed by the Emperor Domitian in or shortly after 93 AD.”)<br />\n→ Lucullus sống đến khoảng năm 93 AD.</p>\n<p>12. gold ring<br />\n(Đoạn 7, “…Tiberius Claudius Catuarus, following the recent discovery of a gold ring belonging to him.”)<br />\n→ Vật được tìm thấy là nhẫn vàng của ông.</p>\n<p>13. modern museum<br />\n(Đoạn cuối, “A modern museum had been built by the Sussex Archaeological Society, incorporating most of the visible remains…”)<br />\n→ Một bảo tàng hiện đại được xây để bảo tồn di tích.</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('b0a16700-f0cc-4f21-810b-270c986d1794', '8d4559e4-4bd2-42d8-afa6-d5138f5b9d07', 'radio', 'Questions 21–24', '', '<p>Choose the correct answer.</p>
<p class="ql-align-center"><strong>Stone Point: a New Zealand historical site</strong></p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "it was used for defence or attack purposes."}, {"option_text": "it was the landing point for the first Maori settlers."}, {"option_text": "it was developed as a commercial port."}], "question": "According to Liz, Stone Point played a key role in local history because"}, {"correct": 1, "options": [{"option_text": "its rich soil."}, {"option_text": "the supply of fish."}, {"option_text": "available building materials."}], "question": "Scott and Liz agree that Maori originally chose to inhabit Stone Point because of"}, {"correct": 2, "options": [{"option_text": "will be of interest to international students."}, {"option_text": "is required as a component of their research."}, {"option_text": "would be best avoided."}], "question": "Scott and Liz agree that using Maori terminology in their presentation"}, {"correct": 0, "options": [{"option_text": "focus on the human aspect instead."}, {"option_text": "check the accuracy of specific dates."}, {"option_text": "explain complex technical language."}], "question": "When Scott mentions the engines at Stone Point. Liz advises him to"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Liz:</strong> Hi Scott. Here are my notes. Let’s sort this presentation out then. The first thing I found out about Stone Point is it’s an extinct volcanic cone.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Scott:</strong> You probably know that already, being a New Zealander.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Liz:</strong> Yes, and there are two other cones nearby which also overlook the harbour.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Scott:</strong> Right, yeah. The first settlers of New Zealand, the Maori, sailed to New Zealand thousands of years after these volcanoes erupted. I think the tutor allocated us this topic, though, because of Stone Point’s significant historical role. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"243\">(Q21) It’s been used by both Maori and European settlers as a place to shelter from attack or launch an attack for centuries.</strong></span></p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Liz:</strong> Yeah, and the fact it was an ideal place for building a village. It would have been quite a sheltered spot. I suppose the Maori settled there because they thought the volcanic soil would help their crops grow well.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Scott:</strong> They would have realised the benefits of the soil after a few good harvests, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"88\">(Q22) initially the fishing opportunities would have been the attraction.</strong></span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Liz:</strong> Hmm, you’re right. Actually, I also read that Maori regard Stone Point as taonga. I believe that means a “treasured thing”.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Scott:</strong> Wow, your Maori vocabulary is improving, Scott!</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Liz:</strong> Hmm. We do have to deal with Stone Point’s cultural value for Maori—that’s still part of its historical significance—but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"126\">(Q23) we need to keep most Maori terminology out of the presentation. Otherwise, a lot of the international students won’t be able to follow us.</strong></span></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Scott:</strong> That’s a shame. I’m sure they’d be interested. I mean, I am. But yeah, we wouldn’t be able to explain it in the time allowed, so I guess we have to stick to English.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Liz:</strong> Anyway, European migrants turned Stone Point into a lookout point for ships. Then it became a fort, an army base, in the late 1880s. And then during the World Wars, the fort was modernized again. It’s also been a public park. Sometimes I’d prefer to devote more of the presentation to the military use of Stone Point. There are some great websites about the engines they installed.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Scott:</strong> Sorry, I wouldn’t go into the technical side if I were you. If you start describing mechanical stuff, people will switch off. <strong data-path-to-node=\"14\" data-index-in-node=\"133\"><span style=\"background-color: #f1c40f;\">(Q24) I think it’s more interesting to look at the impact Stone Point had on the people’s lives at the time</span>.</strong> I mean, for example, there were about 25 years when they used local prisoners to build the tunnels and the underground rooms.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Liz:</strong> They lived there too? Yeah, I guess if we can find some first-hand accounts…</p>\n<h2 data-path-to-node=\"17\"> </h2>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Scott:</strong> Okay, so let’s make a checklist of things to do. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"56\">(Q25) For the early Maori habitation section, we have to look at the material we’ve used again and make sure we know who the writers were and when they wrote it.</strong></span></p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Liz:</strong> Yes, that needs work. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"19\" data-index-in-node=\"27\">(Q26) And for the part about Stone Point being used as a lookout point, I’m sure we can locate some drawings of how Stone Point looked then and the kind of ships coming in.</strong></span></p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Scott:</strong> Nice. And what else?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Liz:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"5\">(Q27) We haven’t got a lot of detail for the reconstruction of the fort. We should add some more information about what it was the prisoners were adding to it.</strong></span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Scott:</strong> Okay, I’ll do that bit too.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Liz:</strong> So, I’ll deal with the section regarding the modernization that happened in the 1930s and 40s. I mean, that’s the bit where we have the most visible evidence of historic buildings. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"186\">(Q28) I’ll ring the Department of Conservation and see if they’ll agree to let me film the site—maybe allow me access to some of the tunnels the public don’t see.</strong></span></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Scott:</strong> OK. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"24\" data-index-in-node=\"11\">(Q29) For the 1950s onwards, could you also arrange a meeting with someone from the Department of Conservation to ask them about their restoration work?</strong></span></p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Liz:</strong> I could try. Oh, and just about its use as a public park today—<span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"68\">(Q30) where is the boundary exactly? Does it go all the way to the beach?</strong></span></p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Scott:</strong> Not sure. I’ll check that out.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Liz:</strong> Great. I suppose it would finish off the presentation nicely if we explain the future plans for the site.</p>"}]', 0);
INSERT INTO public.questions VALUES ('8ee69e59-6b7b-42c5-babd-d777500bede1', '7eb85a88-59dd-4b52-8d09-bdd5e8c70228', 'matching', 'Questions 26-30', '', '<p>What problems with the following aspects of the proposed interviews do the speakers identify?</p>
<p>Choose <strong>FIVE </strong>answers from the box and write the correct letter, A-H, next to questions 26-30.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><span style=\"font-size: 12pt;\"><strong>Problems</strong></span></p>\n<p> </p>\n<p>Questions drafted {too complicated}</p>\n<p> </p>\n<p>Time allotted {too long}</p>\n<p> </p>\n<p>Recording equipment used {too unreliable}</p>\n<p> </p>\n<p>Subjects chosen {too vague}</p>\n<p> </p>\n<p>Proposed report {too factual}</p>", "answerOptions": [{"optionText": "too unreliable"}, {"optionText": "too short"}, {"optionText": "too noisy"}, {"optionText": "too long"}, {"optionText": "too formal"}, {"optionText": "too factual"}, {"optionText": "too complicated"}, {"optionText": "too vague"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('c90ab4a3-677f-4078-96f2-5f19726dfc92', '8d4559e4-4bd2-42d8-afa6-d5138f5b9d07', 'matching', 'Questions 25–30', '', '<p>What do Liz and Scott agree they must do for each of the following sections of their presentation on Stone Point?</p>
<p>Choose <strong>SIX</strong> correct answers, <strong>A-H.</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Sections of Presentation</strong></p>\n<p> </p>\n<p>Early Maori inhabitation of Stone Point {D check authors details}</p>\n<p> </p>\n<p>The use of Stone Point as a lookout point  {B find images}</p>\n<p> </p>\n<p>The reconstruction of the fort {A provide further description}</p>\n<p> </p>\n<p>Modernisation of the fort in the 1930s-40s {F obtain official permission}</p>\n<p> </p>\n<p>Uses of Stone Point from 1950s to the present day {C set up an interview}</p>\n<p> </p>\n<p>The use of Stone Point as a public park {E check the exact location}<br><br></p>", "answerOptions": [{"optionText": "A provide further description"}, {"optionText": "B find images"}, {"optionText": "C set up an interview"}, {"optionText": "D check authors details"}, {"optionText": "E check the exact location"}, {"optionText": "F obtain official permission"}, {"optionText": "G be more objective"}, {"optionText": "H reduce it in length"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('4af8a103-6365-4faf-a164-fd0734e8bbf7', 'ed771c0e-626b-4376-bc14-6c752d472fbb', 'radio', 'Questions 1–7', '', '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Early European settlers made detailed studies of the morepork."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The Polynesian rat had a negative effect on the number of laughing owls."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The laughing owl was larger than the morepork"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Rats pose a risk to young moreporks."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The New Zealand Department of Conservation is hoping to limit the population of moreporks."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Other bird species are frightened away when they hear the morepork’s cry."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In Maori tradition, the low call of the morepork had negative associations."}]', 'null', 'null', 'null', '[{"content": "<p>1. Early European settlers made detailed studies of the morepork.</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) Văn bản đề cập đến việc những người châu Âu định cư đã đến (<em>“European settlers arrived in the middle of the 19th century”</em>), nhưng không có thông tin chi tiết về việc họ có thực hiện các nghiên cứu tỉ mỉ (<em>detailed studies</em>) về chim morepork hay không.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong>Giải thích:</strong> Không có thông tin để xác nhận hoặc phủ nhận tuyên bố này.</p>\n</li>\n</ul>\n<p>2. The Polynesian rat had a negative effect on the number of laughing owls.</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) “Where other native birds suffered from predation by the Polynesian rat, the laughing turned the tables and <strong>adapted its diet to include the rodent</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong>Giải thích:</strong> Chim cú cười (<em>laughing owl</em>) đã thích nghi và ăn thịt chuột Polynesian, vì vậy chuột trở thành nguồn thức ăn và <strong>không gây tác động tiêu cực</strong> lên số lượng chim cú cười.</p>\n</li>\n</ul>\n<p>3. The laughing owl was larger than the morepork.</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) Chim cú cười có khả năng bắt và giết <strong>“the other New Zealand owl, the Morepork, and even larger birds, such as the weka”</strong>.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Việc cú cười có thể bắt và giết Morepork (<em>“capable of catching and killing the other New Zealand owl, the Morepork”</em>) ngụ ý rằng nó lớn hơn Morepork.</p>\n</li>\n</ul>\n<p>4. Rats pose a risk to young moreporks.</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong>Đáp án:</strong> <strong>TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “…and <strong>eggs and chicks are also be at risk from rats</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> Chuột là mối đe dọa đối với trứng và chim non Morepork.</p>\n</li>\n</ul>\n<p>5. The New Zealand Department of Conservation is hoping to limit the population of moreporks.</p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 7) “The New Zealand Department of Conservation is taking steps to <strong>ensure the preservation</strong> of New Zealand’s only native owl… it is hoped that the morepork will <strong>continue to survive and thrive</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong>Giải thích:</strong> Mục tiêu của cơ quan bảo tồn là <strong>bảo tồn</strong> (preservation) và giúp Morepork <strong>sinh tồn và phát triển</strong> (<em>survive and thrive</em>), trái ngược với việc hạn chế số lượng.</p>\n</li>\n</ul>\n<p>6. Other bird species are frightened away when they hear the morepork’s cry.</p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) Văn bản nói tiếng kêu <em>ruru</em> là để <strong>gọi các con khác và tuyên bố lãnh thổ</strong> (<em>“calls to other moreporks and claims territory”</em>), nhưng không nói về phản ứng sợ hãi của các loài chim khác.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Không có thông tin để xác nhận việc tiếng kêu gây sợ hãi.</p>\n</li>\n</ul>\n<p>7. In Maori tradition, the low call of the morepork had negative associations.</p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong>Đáp án:</strong> <strong>FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 8) “The occasional high, piercing call of the morepork signified bad news, but the <strong>lower-pitched and more common ‘ruru’ call heralded good news</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong>Giải thích:</strong> Tiếng kêu <em>thấp</em> (<em>lower-pitched</em>) và phổ biến hơn (<em>ruru</em>) mang lại điềm <strong>lành</strong> (<em>good news</em>), trái ngược với nhận định về sự liên hệ tiêu cực (negative associations).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('f9bec6a3-4c36-4e57-8077-f27e7dc2dfc1', '1d2a260b-e8ae-4438-bcaf-70625727c3d3', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center"><span style="font-size: 14pt;"><strong>BIOMASS FUEL</strong></span></p>
<p>– Biomass is waste plant material, e.g. sawdust, straw.</p>
<p>– Biomass briquettes can be used as domestic or industrial fuel.</p>
<p><strong>Benefits of biomass briquettes</strong></p>
<p>– Financial: no {cost} for materials</p>
<p>– Convenience: clean and easy to handle and <span class="fill-history-correct">{store}</span></p>
<p><strong>Production by machine</strong></p>
<p>– Biomass is first converted to a {powder}Then other substances are added.</p>
<p>– The machine expels the mixture through {holes} of different shapes.</p>
<p>– <strong><em>NB</em></strong> Only a relatively small amount of <span class="fill-history-correct">{electricity| energy}</span> is needed to operate the machine.</p>
<p><strong>Production by hand</strong></p>
<p>– Biomass is mixed with water and sticky material, e.g. <span class="fill-history-correct">{starch}</span>, and then pressed into shape.</p>
<p><strong>Current use</strong></p>
<p>– <strong>Europe and the USA</strong></p>
<p>+ Briquettes have been in use for some time for <span class="fill-history-correct">{agriculture}</span>.</p>
<p>+ The use of briquettes made from wood has increased rapidly.</p>
<p>– <strong>India and China</strong></p>
<p>+ 1990s: briquette manufacture began.</p>
<p>+ 2002: China had about 600 <span class="fill-history-correct">{factories}</span>.</p>
<p>– <strong>Uganda</strong></p>
<p>+ Customers are mainly public institutions or <span class="fill-history-correct">{businesses}</span>.</p>
<p><strong>Prospects for biomass fuel</strong></p>
<p>– The {demand} is likely to increase.</p>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p id=\"p-rc_c21eee174a61121a-58\" data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> <span class=\"citation-1008 citation-1009 citation-end-1009\">Good afternoon, everyone. In this course, we’ve been discussing the principles of sustainable development, and now we’re going to look at some of the ways in which these principles are being put into practice.</span></p>\n<p id=\"p-rc_c21eee174a61121a-59\" data-path-to-node=\"4\"><span class=\"citation-1006 citation-1007\">Today I’m </span><span class=\"citation-1004 citation-1005 citation-1006 citation-1007 citation-end-1007\">going to talk about the use of biomass. And for those of you who don’t know what biomas</span><span class=\"citation-1004 citation-1005 citation-1006 citation-end-1006\">s is, it’s plant material, usually</span><span class=\"citation-1004 citation-1005 citation-end-1005\"> agricultural waste such as sawdust or straw. And briquettes made out of biomass are used as fuel, either in the ho</span><span class=\"citation-1004 citation-end-1004\">me or in industry.</span></p>\n<p id=\"p-rc_c21eee174a61121a-60\" data-path-to-node=\"5\"><span class=\"citation-1003 citation-end-1003\">I’ll start with the benefits. Using briquettes has a financial benefit because they make use of waste products as raw material</span>s,<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"5\" data-index-in-node=\"129\">(Q31) so there isn’t any cost involved for that.</strong></span> Another advantage is convenience. Handling briquettes is cleaner than handling materials like wood or charcoal. Also, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"296\">(Q32) briquettes are less trouble to store because they are of uniform size and shape.</strong></span></p>\n<p id=\"p-rc_c21eee174a61121a-61\" data-path-to-node=\"6\">Right, let’s look briefly now at how these briquettes are made. There are two basic methods of manufacture. The first method uses machinery. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"141\">(Q33) <span class=\"citation-1001 citation-1002\">At the initial stage, all the loose plant material is ground into a powder and then mixed with other materials.</span></strong></span><span class=\"citation-1001 citation-1002 citation-end-1002\"> Next, a machine compresses the biomass mixture, and that process raises the temperature and cau</span><span class=\"citation-1001 citation-end-1001\">ses it to m</span>elt. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"370\">(Q34) <span class=\"citation-1000\">The machine forces the biomass mixture out through rectangular or circular holes.</span></strong></span><span class=\"citation-1000 citation-end-1000\"> Then, as the pressure decreases, the mixture cools and becomes solid again, and that’s how the briquettes are formed.</span></p>\n<p id=\"p-rc_c21eee174a61121a-62\" data-path-to-node=\"7\"><span class=\"citation-999 citation-end-999\">It’s important to point out that with this method</span>, <strong data-path-to-node=\"7\" data-index-in-node=\"51\"><span style=\"background-color: #f1c40f;\">(Q35) electricity (hoặc energy) </span><span class=\"citation-997 citation-998\"><span style=\"background-color: #f1c40f;\">is essential to operate the machinery</span>.</span></strong><span class=\"citation-997 citation-998 citation-end-998\"> And the exact amount you need depends on the type of biomass you use, but generally, the amount required is only 3% to 9% of the energy that’s produced by the briquettes when they are burnt.</span></p>\n<p id=\"p-rc_c21eee174a61121a-63\" data-path-to-node=\"8\"><span class=\"citation-995 citation-996 citation-end-996\">The second method</span><span class=\"citation-995\"> involves making briquettes by hand. This method is suitable when the biomass is mainly composed of material that doesn’t melt, like paper. </span><strong data-path-to-node=\"8\" data-index-in-node=\"157\"><span style=\"background-color: #f1c40f;\"><span class=\"citation-995 citation-end-995\">(</span>Q36) </span><span class=\"citation-994\"><span style=\"background-color: #f1c40f;\">The biomass is made into a paste by adding water and, in addition, something sticky such as starch</span>.</span></strong><span class=\"citation-994 citation-end-994\"> This mixture is then shaped using either a simple metal press or bare hands.</span></p>\n<p data-path-to-node=\"8\"><span class=\"citation-993 citation-end-993\">So, where is biomass fuel used and how extensively? Well, it’s difficult to obtain detailed figures, but</span> <strong data-path-to-node=\"9\" data-index-in-node=\"105\"><span style=\"background-color: #f1c40f;\">(Q37) </span><span class=\"citation-991 citation-992\"><span style=\"background-color: #f1c40f;\">it’s been used for several years in Europe and the USA, mainly for agriculture</span>.</span></strong><span class=\"citation-991 citation-992\"> And since 2000, there’s been a rapid increase in the production and use of briquettes </span><span class=\"citation-990 citation-991 citation-992 citation-end-992\">made out of wood waste. I can give you a ballpark figure: in 2010, a</span><span class=\"citation-990 citation-991 citation-end-991\">bout 5 million ton</span><span class=\"citation-990 citation-end-990\">s were used in Europe. Some of these had to be imported from the USA.</span></p>\n<p id=\"p-rc_c21eee174a61121a-65\" data-path-to-node=\"10\"><span class=\"citation-989 citation-end-989\">Moving further east, both India and China have bee</span>n producing biomass briquettes since the 1990s. Detailed figures are hard to come by, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"140\">(Q38) <span class=\"citation-987 citation-988\">in China in 2002, the number of factories producing biomass briquettes had increased to approximately 600</span></strong></span><span class=\"citation-987 citation-988 citation-end-988\">, and production is still growing.</span></p>\n<p id=\"p-rc_c21eee174a61121a-66\" data-path-to-node=\"11\"><span class=\"citation-985 citation-986 citation-end-986\">I don’t have information about Africa in general, but I can give you an example of one company in Uganda which is producing briquettes. Most of the compa</span><span class=\"citation-985\">ny’s customers are public institutions like schools and universities that provide hot meals for their students. </span><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"265\"><span class=\"citation-985 citation-end-985\">(</span>Q39) <span class=\"citation-984\">The other main users are businesses that need a source of heat for producing their products.</span></strong></span></p>\n<p id=\"p-rc_c21eee174a61121a-67\" data-path-to-node=\"12\"><span class=\"citation-983 citation-end-983\">Okay, well, how viable are biomass fuels like these in economic terms, and what is likely to happen in the future? Well, the answer depends partly on the price of the fuels that they replace, and that varies from place to plac</span>e. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"229\">(Q40) But in general, the demand for biomass fuels is almost certain to grow</strong></span>, and that can only benefit the environment. Let’s turn now to another facet of society…</p>"}]', 0);
INSERT INTO public.questions VALUES ('43fe2574-aa0f-4542-9e6d-415c80d61cd6', 'dd63ef71-292e-44f7-a201-4dae628d3065', 'matrix', 'Questions 7 – 14', '', '<p data-start="1030" data-end="1098">Choose the correct letter, <strong>A–H</strong>, in boxes <strong>7–14 </strong>on your answer sheet.</p>
<p data-start="1100" data-end="1143"><strong>NB </strong>You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "It has somewhere to relax after exercising.", "correctCategoryLetter": "D"}, {"itemText": "It is definitely not to be recommended.", "correctCategoryLetter": "H"}, {"itemText": "It is in a building previously used for another purpose.", "correctCategoryLetter": "F"}, {"itemText": "It is very popular at a certain time of the day.", "correctCategoryLetter": "A"}, {"itemText": "It is recommended, although it lacks certain facilities.", "correctCategoryLetter": "G"}, {"itemText": "It has entertainment facilities for use whilst exercising.", "correctCategoryLetter": "A"}, {"itemText": "It has a wide variety of equipment.", "correctCategoryLetter": "C"}, {"itemText": "Its instructors are frequently unreliable.", "correctCategoryLetter": "H"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">7. It has somewhere to relax after exercising. — {D} Healthlands</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"11\">“…it is wonderful to <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"34\">chill out</strong> in the evening in the <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"66\">comfortable lounge area</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Chill out” đồng nghĩa với thư giãn (relax), và “lounge area” là nơi để thực hiện việc đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">8. It is definitely not to be recommended. — {H} FitKwik</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"20,0,0\" data-index-in-node=\"11\">“Use <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"16\">any other gym</strong> is what I would suggest.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lời khuyên “hãy dùng bất kỳ phòng tập nào khác” cho thấy người đánh giá hoàn toàn không đề xuất nơi này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">9. It is in a building previously used for another purpose. — {F} The Oasis</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"22,0,0\" data-index-in-node=\"11\">“It’s a huge area (<strong data-path-to-node=\"22,0,0\" data-index-in-node=\"30\">formerly a big hardware store</strong>)…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Formerly” (trước đây là) cho thấy tòa nhà này từng được dùng làm cửa hàng kim khí trước khi thành phòng tập.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">10. It is very popular at a certain time of the day. — {A} Bodytone</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"24,0,0\" data-index-in-node=\"11\">“But it’s quite <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"27\">crowded at 6 or 7 in the evening</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Crowded” (đông đúc) chứng tỏ nó rất phổ biến (popular) vào khung giờ tối.</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">11. It is recommended, although it lacks certain facilities. — {G} The Health Garden</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"26,0,0\" data-index-in-node=\"11\">“I think The Health Garden is <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"41\">really well run</strong>… It’s a shame there’s <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"81\">no swimming pool and no classes</strong> but I can’t complain really.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Được khen là vận hành tốt (recommended) dù thiếu bể bơi và lớp học (lacks facilities).</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">12. It has entertainment facilities for use whilst exercising. — {A} Bodytone</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"28,0,0\" data-index-in-node=\"11\">“…a <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"17\">dozen televisions in front of the jogging machines</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> TV đặt trước máy chạy bộ là thiết bị giải trí phục vụ khách khi đang tập luyện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">13. It has a wide variety of equipment. — {C} Peter’s Place</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"30,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"30,0,0\" data-index-in-node=\"12\">Big range of machines</strong> – mostly working.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Big range” tương ứng với “wide variety” (đa dạng thiết bị).</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">14. Its instructors are frequently unreliable. — {H} FitKwik</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"32,0,0\" data-index-in-node=\"11\">“…classes are often cancelled because the <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"55\">trainers don’t turn up</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Huấn luyện viên (trainers/instructors) không đến lớp (don’t turn up) khiến họ trở nên không đáng tin cậy (unreliable).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('d9091431-7601-445f-8d5d-bb9bf26a39a2', '619fba5b-6c8a-4832-b674-507928c622a3', 'matrix', 'Questions 32–36', NULL, '<p>Look at the following statements (Questions 32–36) and the list of people below.<br />Match each statement with the correct person, <strong>A–E</strong>.</p>
', 'classification', NULL, '[{"option": "A", "correct": false}, {"option": "B", "correct": false}, {"option": "C", "correct": false}, {"option": "D", "correct": false}, {"option": "E", "correct": false}]', '{"layoutType": "standard", "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "The use of guard dogs may save the lives of both livestock and wild animals.", "correctCategoryLetter": "D"}, {"itemText": "Claims of a change in behaviour from those using livestock guard dogs may not be totally accurate.", "correctCategoryLetter": "E"}, {"itemText": "There may be negative results if the use of livestock guard dogs is not sufficiently widespread.", "correctCategoryLetter": "B"}, {"itemText": "Livestock guard dogs are the best way of protecting farm animals, as long as the dogs are appropriately handled.", "correctCategoryLetter": "C"}, {"itemText": "Teaching a livestock guard dog how to do its work needs a different focus from teaching a house guard dog.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Dan Macon", "categoryLetter": "A"}, {"categoryText": "Silvia Ribeiro", "categoryLetter": "B"}, {"categoryText": "Linda van Bommel", "categoryLetter": "C"}, {"categoryText": "Julie Young", "categoryLetter": "D"}, {"categoryText": "Bethany Smith", "categoryLetter": "E"}]}', '[{"content": "<p>32. D – Julie Young<br />(Đoạn D: “&#8230;reductions in livestock losses can make farmers more tolerant of predators&#8230; There is common ground from the livestock side as well as the conservation side.”)<br />→ Việc dùng chó có thể cứu cả động vật nuôi lẫn động vật hoang dã – giúp hai bên cùng có lợi. → D.</p>\n<p> <br />33. E – Bethany Smith<br />(Đoạn E: “&#8230;such self-reported results must be taken with a pinch of salt.”)<br />→ Smith nghi ngờ các tuyên bố về việc thay đổi hành vi của nông dân có thể không hoàn toàn chính xác. → E.</p>\n<p> <br />34. B – Silvia Ribeiro<br />(Đoạn E: “If we are not working with everybody, we are transferring the wolf pressure to the neighbour’s herd and he can use poison&#8230;” )<br />→ Ribeiro cảnh báo rằng nếu phạm vi áp dụng chưa đủ rộng, có thể gây hậu quả tiêu cực cho khu vực lân cận. → B.</p>\n<p> <br />35. C – Linda van Bommel<br />(Đoạn C: “If they are managed and used properly, livestock guard dogs are the most efficient control method&#8230;”)<br />→ Khẳng định chó bảo vệ là phương pháp hiệu quả nhất, miễn là được quản lý đúng cách. → C.</p>\n<p> <br />36. A – Dan Macon<br />(Đoạn B: “‘A fluffy white puppy is fun to be around, but too much human affection&#8230;’”)<br />→ Macon giải thích rằng việc huấn luyện chó bảo vệ gia súc phải khác với huấn luyện chó nhà – cần hạn chế gắn bó tình cảm quá mức. → A.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('e84b3453-ef51-4083-849a-fa7c043bbfa3', 'caad1aff-820d-41ab-b54b-c27f27580c0c', 'fillup', 'Questions 23–26', '<p>Complete the summary below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<h3 style="text-align: center;"><strong>Scientists play tricks</strong></h3>
<p>The passage gives two examples of tricks arising from the playfulness of scientists. Researchers at Caltech found that a colleague had been stealing their {data} and used a hoax involving a fake NMR spectrum to trap the offender. Another story concerns a plate which a famous {English navigator} is said to have left behind on a visit to California.</p>
<p>The {copper and zinc} that the plate was made of later revealed that it was a fake, a hoax carried out by friends of the director of the {bancroft library}</p>
', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>23. Researchers at Caltech found that a colleague had been stealing their data…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>data</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Another co-worker had the habit of going through their <strong>data</strong> and rushing to Gray with his interpretation.”</li>\n</ul>\n<p><strong>24. Another story concerns a plate which a famous English navigator is said to have left behind on a visit to California.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>English navigator</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “…the ‘Plate of Brasse’, which stated England’s claim to California and was supposedly left by the <strong>English navigator</strong> Sir Francis Drake during his visit in 1579.”</li>\n</ul>\n<p><strong>25. The copper &amp; zinc that the plate was made of later revealed that it was a fake…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>copper &amp; zinc</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “…Helen Michel and Frank Asaro… showed that the <strong>copper and zinc</strong> used in the plate were of a higher quality than would have been available in the 1500s.”</li>\n</ul>\n<p><strong>26. …a hoax carried out by friends of the director of the Bancroft Library.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>Bancroft Library</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “…a group of friends of Herbert E Bolton, who directed the <strong>Bancroft Library</strong> at the University’s Berkeley campus.”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('feb259f1-4c2d-4212-901e-64788d3a8e4b', 'dcf9912b-d9c8-4938-a878-d0eaa4499bff', 'fillup', 'Questions 15 – 20', '<p>There is a {legal requirement} for a company to ensure staff can read what its grievance procedures involve.</p>
<p>If the issue concerns the line manager, the employee should address the next person up in the {hierarchy} of the organisation.</p>
<p>If informal approaches fail, the employee should produce a {statement} in writing of their complaint.</p>
<p>At the grievance meeting, it is useful to offer{suggestions} to help to clear up the issue.</p>
<p>The employee does not have to accept the employer’s judgement and can {appeal} .</p>
<p>It is wise to obtain {guidance} before taking the grievance further.</p>', '<p>Complete the sentences below.</p>
<p>Choose <strong data-path-to-node="3" data-index-in-node="55">NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 15-20 on your answer sheet.</p>', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. There is a {legal requirement} for a company to ensure staff can read what its grievance procedures involve.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“It is a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"29\">legal requirement</strong> that your employer must tell you <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"80\">in writing</strong> what procedures you should follow…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc nhân viên có thể “đọc” (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"41\">can read</em>) tương ứng với việc người sử dụng lao động phải cung cấp quy trình bằng “văn bản” (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"133\">in writing</em>). Và đây là một yêu cầu pháp lý (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"177\">legal requirement</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. If the issue concerns the line manager, the employee should address the next person up in the {hierarchy} of the organisation.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Supposing your problem is with him or her [line manager], then you should go to the manager who holds the next position according to the company <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"166\">hierarchy</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nếu vấn đề liên quan đến quản lý trực tiếp, nhân viên cần tìm đến người ở vị trí tiếp theo trong sơ đồ cấp bậc của công ty (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"136\">hierarchy</strong>).</p>\n</li>\n</ul>\n<div class=\"attachment-container search-images\">\n<p> </p>\n<div class=\"image-container ng-star-inserted\" data-full-size-image-uri=\"https://encrypted-tbn3.gstatic.com/licensed-image?q=tbn:ANd9GcR1B6Dt5gnn4H0CFBuhwd9Sqx9JH_gb7zBtsTU06uS8R9Naz6PHtb3b5y2NRZJEgHHkIBRZsOYm1DUernC_Uw3mdwZJtsQpQ9NgwZn9XWeR_wzYidc\"> </div>\n<p> </p>\n</div>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. If informal approaches fail, the employee should produce a {statement} in writing of their complaint.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“You must present your grievance in a <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"58\">written statement</strong> and send a copy to your employer.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi các bước giải quyết không chính thức (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"54\">informal</em>) thất bại, bước tiếp theo là lập một bản trình bày khiếu nại bằng văn bản (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"138\">statement</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. At the grievance meeting, it is useful to offer {suggestions} to help to clear up the issue.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">“Use the opportunity to make some <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"54\">suggestions</strong> as to how the problem might be resolved.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong cuộc họp khiếu nại, việc đưa ra các đề xuất (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"63\">suggestions</strong>) để giải quyết vấn đề (clear up the issue/resolve) là rất hữu ích cho cả hai bên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">19. The employee does not have to accept the employer’s judgement and can {appeal}.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"20\">“You have the right to <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"43\">appeal</strong> if you do not agree with it [the decision]…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Judgement” (phán quyết) tương ứng với “decision” (quyết định). Nếu không đồng ý hoặc không chấp nhận, nhân viên có quyền kháng cáo (<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"145\">appeal</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">20. It is wise to obtain {guidance} before taking the grievance further.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">“But seek <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"30\">guidance</strong> first from a reputable source.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Taking the grievance further” (đưa khiếu nại đi xa hơn) tương ứng với việc đưa việc ra tòa án lao động (<em data-path-to-node=\"16,1,0\" data-index-in-node=\"117\">employment tribunal</em>). Trước khi làm vậy, bài đọc khuyên nên tìm kiếm sự tư vấn/hướng dẫn (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"207\">guidance</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('38f8dd3d-f61a-407d-8415-3d8adfff821c', '2d223f3b-d774-46bf-a42c-9c3f4cf60a6c', 'matrix', 'Question 11-14', '', '<p>Which type of accommodation includes the following features?</p>
<p>Choose the correct answers</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of options", "matrixItems": [{"itemText": "a garden", "correctCategoryLetter": "A"}, {"itemText": "a garage", "correctCategoryLetter": "A"}, {"itemText": "an alarm system", "correctCategoryLetter": "B"}, {"itemText": "new furniture", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "the flat", "categoryLetter": "A"}, {"categoryText": "the house", "categoryLetter": "B"}, {"categoryText": "the hostel", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 2</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Agent:</strong> Hello, can I help?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Student:</strong> Yes, I’m looking for accommodation. I’m a student in my second year at the college and I wanted to rent something from September for myself and a friend.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Agent:</strong> Well, we’ve got several choices at the moment near the college. We’ve got a flat, a house or there’s a student hostel. All at about the same rent, but of course they all have different features and different things included in the rent.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Agent:</strong> The properties don’t all have gardens, I’m afraid. The house is quite small, not much space around it. It has got a bit of space at the back, but I wouldn’t call it a garden.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Agent:</strong> The hostel is part of a city development, so there’s no space for a garden. But <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"87\">(11) the flat has a communal garden [A]</strong></span> that is shared by all the tenants. I would say that that’s very good value for the price.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Student:</strong> Have you got a car?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Student:</strong> Yes.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Agent:</strong> Um, there are garages round the corner from the house, but you have to rent those separately and they might not be available.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Agent:</strong> But <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"11\" data-index-in-node=\"11\">(12) each flat is allotted a garage [A]</strong> </span>in the grounds as part of the deal. The hostel doesn’t have the space, I’m afraid.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Student:</strong> Uh huh.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Agent:</strong> I guess you might also want to know about security as well.<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"13\" data-index-in-node=\"67\">(13) The house is the only one which is alarmed [B]</strong>.</span></span></p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Agent:</strong> The flats and the hostel are accessed through a main door which has an intercom for visitors, so they’re quite safe.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Agent:</strong> Now they are all furnished. The stuff in the flats is quite modern looking, which most people like, and it’s in quite good condition considering the use it’s had.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Agent:</strong> <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"16\" data-index-in-node=\"7\">(14) All the furniture and fittings in the house have just been replaced [B]</strong> </span>after the last tenants left, so they’ll be in excellent condition. And the furniture in the hostel is OK; it’s about what you’d expect really.</p>\n<hr>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Student:</strong> Well, I think I’d better go and look at them all. Uh, where are they?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Agent:</strong> Here, let me show you on the map. Uh, right um, we’re here in the accommodation agency on the High Street, facing north.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Agent:</strong> Directly opposite us is <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"21\" data-index-in-node=\"31\">(15) the bank [E]</strong>.</span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Agent:</strong> If you stay on this side of the road and walk towards West Street, <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"22\" data-index-in-node=\"74\">(16) the house [I]</strong> </span>is not that far. It’s next but one to the swimming pool, just before West Street. It’s very convenient because it’s near the shops.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Agent:</strong> <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"23\" data-index-in-node=\"7\">(17) The hostel [J]</strong> </span>is on the corner of West Street and Saint Ann’s Road, near the roundabout. It’s not a very wonderful building, but it’s nice and close to the college.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Agent:</strong> <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"24\" data-index-in-node=\"7\">(18) The flat [A]</strong> </span>is a bit of a walk, but it’s in very nice surroundings. To get to the flat, you go down West Street towards the centre of the city, and the building is on the corner, just before the first turning on the left.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Agent:</strong> Although we’re a bit outside the city centre, the facilities aren’t bad. There’s<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"25\" data-index-in-node=\"88\">(19) a post office [C]</strong></span></span> just round the corner from here. You go down the High Street and turn right into West Street, and it’s on your right.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Agent:</strong> Or if you want to go to the city centre, you could get <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"26\" data-index-in-node=\"62\">(20) the bus from here [G]</strong></span>. Just a few metres down the road from the agency going east. You don’t even need to cross the road.</p>"}]', 0);
INSERT INTO public.questions VALUES ('7870ba69-089e-45e2-aa7f-4812b81e3782', 'f19b896c-7f39-4e5a-8f4a-dff16815e940', 'matrix', 'Questions 28–32', '', '<p data-start="172" data-end="239">Write the correct letter, <strong>A–H</strong>, in boxes 28–32 on your answer sheet.</p>
<p data-start="241" data-end="282"><strong>NB </strong>You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "reference to Tammet’s future intentions regarding the language he has developed", "correctCategoryLetter": "E"}, {"itemText": "the reason for Tammet’s case being of interest world-wide", "correctCategoryLetter": "C"}, {"itemText": "the purpose of a study that has already been carried out on Tammet", "correctCategoryLetter": "F"}, {"itemText": "a description of Tammet’s method of working out solutions", "correctCategoryLetter": "B"}, {"itemText": "examples of Tammet’s various linguistic achievements that have set him apart from other savants", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. Reference to Tammet’s future intentions regarding the language he has developed — {E}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Tammet hopes to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"28\">launch Mänti</strong> – his own personal exploration of the power of words… in academic circles <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"117\">later this year</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Future intentions” (ý định trong tương lai) tương ứng với việc ông hy vọng sẽ ra mắt (launch) ngôn ngữ Mänti vào cuối năm nay. Nội dung này nằm ở cuối đoạn E.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">29. The reason for Tammet’s case being of interest world-wide — {C}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Professor Allan Snyder… explains why Tammet is of particular and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"79\">international scientific interest</strong>: ‘Savants can’t usually tell us how they do what they do… <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"173\">Daniel can</strong>.’”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lý do khiến trường hợp của Tammet được cả thế giới quan tâm (international interest) là vì ông có khả năng hiếm có: mô tả lại được quá trình tư duy trong đầu mình, điều mà các thiên tài tự kỷ khác thường không làm được.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">30. The purpose of a study that has already been carried out on Tammet — {F}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“The ARC team has <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"29\">started scanning Tammet’s brain to find out if</strong> there are modules (or number systems)… that are connected in a way that is different from that in most of us.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A study that has already been carried out” (một nghiên cứu đã được thực hiện) chính là việc quét não bộ (scanning brain). Mục đích (purpose) là để tìm hiểu xem các hệ thống trong não ông có kết nối khác biệt so với người bình thường hay không.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">31. A description of Tammet’s method of working out solutions — {B}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“He is able to <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">see numbers as shapes and colours</strong>. ‘When I multiply numbers together, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"96\">I see two shapes</strong>. The image starts to change and evolve, and a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"159\">third shape emerges. That’s the answer</strong>.’”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B mô tả chi tiết phương pháp (method) giải toán của ông: không phải tính toán bình thường mà là nhìn thấy các hình khối và màu sắc hòa trộn vào nhau để ra kết quả.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">32. Examples of Tammet’s various linguistic achievements that have set him apart from other savants — {E}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“Typically, savants have a limited vocabulary, but there is nothing limited about Tammet’s vocabulary. <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"114\">Tammet is creating his own languages</strong>… (he already <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"166\">speaks French, German, Spanish, Lithuanian, Icelandic and Esperanto</strong>).”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những thành tựu ngôn ngữ (linguistic achievements) khiến ông khác biệt (set him apart) là việc ông nói được nhiều ngoại ngữ và tự tạo ra ngôn ngữ riêng (Mänti), trong khi các savant khác thường bị hạn chế về vốn từ.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('eaaafa1a-f34d-4ab6-8181-1385167364c4', 'f19b896c-7f39-4e5a-8f4a-dff16815e940', 'radio', 'Questions 33–35', '', '<p>Choose<strong data-start="833" data-end="841"> TRUE </strong>if the statement agrees with the information,<strong data-start="889" data-end="898">FALSE </strong>if the statement contradicts the information,<strong data-start="946" data-end="959">NOT GIVEN </strong>if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Evidence suggests that changes in the left hemisphere of the brain may lead to improved mathematical abilities."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Most savants have considerable linguistic abilities."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "People have tried to encourage Tammet to be more flexible."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">33. Evidence suggests that changes in the left hemisphere of the brain may lead to improved mathematical abilities. — {TRUE}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p id=\"p-rc_cd3ec369cf5e83dd-19\" data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\"><span class=\"citation-3\">Dẫn chứng (Đoạn D):</span></strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"20\"><span class=\"citation-3\">“Scans of the brains of autistic savants suggest that the </span><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"78\"><span class=\"citation-3\">right hemisphere might be compensating for changes in the left hemisphere</span></strong><span class=\"citation-3 citation-end-3\">.</span> As a result… <span class=\"citation-2\">they often have </span><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"184\"><span class=\"citation-2\">amazing skills in mathematics</span></strong><span class=\"citation-2\"> and memory.</span></em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc giải thích rằng khi có những thay đổi ở bán cầu não trái (left hemisphere), bán cầu não phải sẽ hoạt động bù đắp (compensating). Kết quả của quá trình này là tạo ra những kỹ năng toán học kinh ngạc (amazing skills in mathematics). Điều này khớp hoàn toàn với ý “thay đổi ở bán cầu trái dẫn đến khả năng toán học được cải thiện”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">34. Most savants have considerable linguistic abilities. — {FALSE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D &amp; E):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"24\">“As a result, although <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"47\">the majority of savants struggle with language and comprehension</strong>… Typically, savants have a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"141\">limited vocabulary</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định phần lớn (the majority/most) các thiên tài tự kỷ gặp khó khăn (struggle) với ngôn ngữ và có vốn từ vựng hạn chế (limited). Do đó, nói họ có “khả năng ngôn ngữ đáng kể” (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"200\">considerable linguistic abilities</em>) là sai so với thông tin trong bài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">35. People have tried to encourage Tammet to be more flexible. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn H):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">I have tried to be more flexible</strong>, but I always end up feeling more uncomfortable.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc Tammet “đã tự cố gắng” (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"61\">I have tried</em>) để trở nên linh hoạt hơn trong cuộc sống. Tuy nhiên, <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"128\">không có thông tin</strong> nào nói rằng “người khác” (people) đã cố gắng khuyến khích hay thúc ép ông làm điều đó. Chúng ta không biết tác động đó đến từ bản thân ông hay từ người ngoài.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('2ad7260a-fe51-46a9-a78e-d019bc53195b', '406344d1-3f47-49b9-9a7c-8649c6e674fc', 'fillup', 'Questions 1–10', '<div class="quests-inner-desc">
<div class="txt">
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<div class="quill-better-table-wrapper">
<div class="choice-table-wrap">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border-spacing: 1px; border: 1px solid rgb(0, 0, 0); width: 78.0008%;" border="1"><colgroup> <col style="width: 100%;" width="100"></colgroup>
<tbody>
<tr data-row="row-nh7r">
<td style="border-width: 1px; padding: 1px; border-color: #000000;" colspan="1" rowspan="1" data-row="row-nh7r">
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1"><strong>Two-day course</strong></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">This covers basic techniques.</p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Children are always accompanied by their <span class="fill-history-correct">{instructor}</span></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Cost: £<span class="fill-history-correct">{65}</span></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1"><strong>Five-day course</strong></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Cost: £125</p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Children can sail alone from the third day onwards<strong>.</strong></p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Children can learn how to sail in different kinds of weather.</p>
<p class="qlbt-cell-line" data-row="row-nh7r" data-cell="cell-xffz" data-rowspan="1" data-colspan="1">Children receive a {certificate} on the last day.</p>
</td>
</tr>
<tr data-row="row-j0bk">
<td style="border-width: 1px; padding: 1px; border-color: #000000;" colspan="1" rowspan="1" data-row="row-j0bk">
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1"><strong>Clothing</strong></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Children should wear warm clothes.</p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Children must wear <span class="fill-history-correct">{shoes}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Children are recommended to bring extra trousers which are <span class="fill-history-correct">{waterproof}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Children are not allowed to wear <span class="fill-history-correct">{jeans}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1"><strong>Additional information</strong></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Visitors can buy a {snack}<span class="fill-history-correct"> </span>in the Marina Stores.</p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">There is a free car park next to the <span class="fill-history-correct">{bridge}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Send the registration form two weeks before the course.</p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">Remember to include the name of Jacob’s <span class="fill-history-correct">{doctor}</span></p>
<p class="qlbt-cell-line" data-row="row-j0bk" data-cell="cell-ukgr" data-rowspan="1" data-colspan="1">There is an optional form giving permission to take <span class="fill-history-correct">{photographs}</span></p>
</td>
</tr>
</tbody>
</table>
<p> </p>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-start=\"167\" data-end=\"292\"><strong data-start=\"167\" data-end=\"177\">Woman:</strong> Hello, oh good morning. I’m calling on behalf of my 13-year-old son, Jacob. He’s interested in learning to sail.</p>\n<p data-start=\"294\" data-end=\"371\"><strong data-start=\"294\" data-end=\"302\">Man:</strong> Great, well, we have what we call a taster day on 22nd June.</p>\n<p data-start=\"373\" data-end=\"501\"><strong data-start=\"373\" data-end=\"383\">Woman:</strong> I’m not sure he can make it, but we’ll see. Jacob’s really interested though, so can you tell me about the courses?</p>\n<p data-start=\"503\" data-end=\"591\"><strong data-start=\"503\" data-end=\"511\">Man:</strong> OK, we have two types of courses for children under 16: two-day and five-day.</p>\n<p data-start=\"593\" data-end=\"639\"><strong data-start=\"593\" data-end=\"603\">Woman:</strong> Could you explain the difference?</p>\n<p data-start=\"641\" data-end=\"780\"><strong data-start=\"641\" data-end=\"649\">Man:</strong> Well, the two-day one just covers basic techniques in sailing, and on this course the kids always sail with an<span style=\"background-color: #f1c40f;\"> <strong data-start=\"761\" data-end=\"777\">{instructor}</strong>.</span></p>\n<p data-start=\"782\" data-end=\"801\"><strong data-start=\"782\" data-end=\"792\">Woman:</strong> Right.</p>\n<p data-start=\"803\" data-end=\"840\"><strong data-start=\"803\" data-end=\"811\">Man:</strong> And the cost is £<span style=\"background-color: #f1c40f;\"><strong data-start=\"829\" data-end=\"837\">{65}</strong>.</span></p>\n<p data-start=\"842\" data-end=\"912\"><strong data-start=\"842\" data-end=\"852\">Woman:</strong> Oh, I thought it was more than that. I heard it was £125.</p>\n<p data-start=\"914\" data-end=\"956\"><strong data-start=\"914\" data-end=\"922\">Man:</strong> That’s for the five-day course.</p>\n<p data-start=\"958\" data-end=\"1024\"><strong data-start=\"958\" data-end=\"968\">Woman:</strong> OK, I presume that course goes into much more detail?</p>\n<p data-start=\"1026\" data-end=\"1272\"><strong data-start=\"1026\" data-end=\"1034\">Man:</strong> Yes, and from the third day, the kids are given the choice to sail on their own if they want. We use the same types of boat, but we help them learn more techniques, in particular how to manage the boat in a variety of types of weather.</p>\n<p data-start=\"1274\" data-end=\"1396\"><strong data-start=\"1274\" data-end=\"1284\">Woman:</strong> Hmm, I think Jacob would enjoy that course. Do you give them a <span style=\"background-color: #f1c40f;\"><strong data-start=\"1348\" data-end=\"1365\">{certificate}</strong></span> if they complete the course?</p>\n<p data-start=\"1398\" data-end=\"1492\"><strong data-start=\"1398\" data-end=\"1406\">Man:</strong> Absolutely, we give them out on the final day, which a lot of the kids really like.</p>\n<p data-start=\"1494\" data-end=\"1594\"><strong data-start=\"1494\" data-end=\"1504\">Woman:</strong> Great, could you tell me a bit more about what the children have to bring and so forth?</p>\n<p data-start=\"1596\" data-end=\"1792\"><strong data-start=\"1596\" data-end=\"1604\">Man:</strong> Well, the most important thing is the clothing. It goes without saying that whatever the time of year, they should have plenty of warm clothes, as it can be quite cool out on the water.</p>\n<p data-start=\"1794\" data-end=\"1866\"><strong data-start=\"1794\" data-end=\"1804\">Woman:</strong> What about footwear? Do they have to wear anything special?</p>\n<p data-start=\"1868\" data-end=\"1976\"><strong data-start=\"1868\" data-end=\"1876\">Man:</strong> The only rule is that they’ve got to have <span style=\"background-color: #f1c40f;\"><strong data-start=\"1919\" data-end=\"1930\">{shoes}</strong></span> of some kind — they mustn’t have bare feet.</p>\n<p data-start=\"1978\" data-end=\"1994\"><strong data-start=\"1978\" data-end=\"1988\">Woman:</strong> OK.</p>\n<p data-start=\"1996\" data-end=\"2149\"><strong data-start=\"1996\" data-end=\"2004\">Man:</strong> And we suggest the kids pack an extra pair of trousers, you know <span style=\"background-color: #f1c40f;\"><strong data-start=\"2070\" data-end=\"2086\">{waterproof}</strong></span> ones. They don’t have to wear them unless it starts to rain.</p>\n<p data-start=\"2151\" data-end=\"2217\"><strong data-start=\"2151\" data-end=\"2161\">Woman:</strong> Fine, so basically it’s just using your common sense.</p>\n<p data-start=\"2219\" data-end=\"2366\"><strong data-start=\"2219\" data-end=\"2227\">Man:</strong> Yes, oh, and one other thing we do say is that the children mustn’t wear <span style=\"background-color: #f1c40f;\"><strong data-start=\"2301\" data-end=\"2312\">{jeans}</strong></span>, because they get extremely heavy when they’re wet.</p>\n<p data-start=\"2368\" data-end=\"2388\"><strong data-start=\"2368\" data-end=\"2378\">Woman:</strong> Oh, OK.</p>\n<h3 data-section-id=\"392fk7\" data-start=\"2395\" data-end=\"2408\"> </h3>\n<p data-start=\"2410\" data-end=\"2497\"><strong data-start=\"2410\" data-end=\"2420\">Woman:</strong> One thing I forgot to ask is whether it’s possible to get a meal anywhere.</p>\n<p data-start=\"2499\" data-end=\"2604\"><strong data-start=\"2499\" data-end=\"2507\">Man:</strong> I’m afraid not, but we do have a shop called the Marina Stores where he can get a<span style=\"background-color: #f1c40f;\"> <strong data-start=\"2590\" data-end=\"2601\">{snack}</strong>.</span></p>\n<p data-start=\"2606\" data-end=\"2684\"><strong data-start=\"2606\" data-end=\"2616\">Woman:</strong> OK, and before I forget, when I drop Jacob off, where can I park?</p>\n<p data-start=\"2686\" data-end=\"2857\"><strong data-start=\"2686\" data-end=\"2694\">Man:</strong> Good question, there’s spaces near the entrance, but you have to pay for them. But there’s no charge for the car park just by the <span style=\"background-color: #f1c40f;\"><strong data-start=\"2825\" data-end=\"2837\">{bridge}</strong></span> — do you know it?</p>\n<p data-start=\"2859\" data-end=\"2905\"><strong data-start=\"2859\" data-end=\"2869\">Woman:</strong> Oh yes, I know what you mean now.</p>\n<p data-start=\"2907\" data-end=\"3115\"><strong data-start=\"2907\" data-end=\"2915\">Man:</strong> We do need you to fill in a registration form. You should send that in a couple of weeks before the course starts. The form is on the website, but we ask you to print it off and add your signature.</p>\n<p data-start=\"3117\" data-end=\"3183\"><strong data-start=\"3117\" data-end=\"3127\">Woman:</strong> Yes, of course. What sort of information do you need?</p>\n<p data-start=\"3185\" data-end=\"3269\"><strong data-start=\"3185\" data-end=\"3193\">Man:</strong> About your child’s swimming ability, any special requirements, and so on.</p>\n<p data-start=\"3271\" data-end=\"3324\"><strong data-start=\"3271\" data-end=\"3281\">Woman:</strong> Will you need to know who his doctor is?</p>\n<p data-start=\"3326\" data-end=\"3341\"><strong data-start=\"3326\" data-end=\"3334\">Man:</strong> Yes.</p>\n<p data-start=\"3343\" data-end=\"3446\"><strong data-start=\"3343\" data-end=\"3353\">Woman:</strong> We’ve just recently changed surgeries, so I’ll make a note to get that — his <span style=\"background-color: #f1c40f;\"><strong data-start=\"3431\" data-end=\"3443\">{doctor}</strong></span>.</p>\n<p data-start=\"3448\" data-end=\"3616\"><strong data-start=\"3448\" data-end=\"3456\">Man:</strong> And one more thing, there’s a separate form on the website which is optional, that asks whether you’re willing for photographs to be taken during the course.</p>\n<p data-start=\"3618\" data-end=\"3687\"><strong data-start=\"3618\" data-end=\"3628\">Woman:</strong> Yes, of course, no problem — <span style=\"background-color: #f1c40f;\"><strong data-start=\"3658\" data-end=\"3675\">{photographs}</strong></span> are fine.</p>\n<p data-start=\"3689\" data-end=\"3724\"><strong data-start=\"3689\" data-end=\"3697\">Man:</strong> Great, so I’ll send you…</p>"}]', 0);
INSERT INTO public.questions VALUES ('d657e352-a5d3-4bc4-8d78-fc5f7646ea76', 'be181726-6b55-4461-8def-2e7e5088f594', 'fillup', 'Questions 24-26', '<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>The ‘mix and match’ strategy</strong></p>
<p>One aspect of the Talbot Park project that some critics are concerned about is that the higher {density} of accommodation would lead to the old social problems returning. To prevent this, a team of various {Architects} worked on the project to ensure the buildings were not uniform. Further, they created pleasant,functional interiors that could still be built within their { budget} Finally, the absence of walls means Talbot Park is characterised by openness, making it easier to regulate behaviour within the community.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">24. density</strong></p>\n<ul data-path-to-node=\"9,0,1\">\n<li>\n<p data-path-to-node=\"9,0,1,0,0\"><strong data-path-to-node=\"9,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…new development has actually made the <strong data-path-to-node=\"9,0,1,0,0\" data-index-in-node=\"53\">density</strong> of housing in Talbot Park greater…” (Đoạn D).</p>\n</li>\n<li>\n<p data-path-to-node=\"9,0,1,1,0\"><strong data-path-to-node=\"9,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một số ý kiến lo ngại rằng mật độ cư dân cao (higher density) có thể gây ra các vấn đề xã hội cũ.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">25. architects</strong></p>\n<ul data-path-to-node=\"9,1,1\">\n<li>\n<p data-path-to-node=\"9,1,1,0,0\"><strong data-path-to-node=\"9,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…employing a variety of plans by different <strong data-path-to-node=\"9,1,1,0,0\" data-index-in-node=\"57\">architects</strong>…” (Đoạn D).</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,1,1,0\"><strong data-path-to-node=\"9,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để tránh sự đơn điệu, dự án đã thuê nhiều kiến trúc sư khác nhau cùng tham gia thiết kế.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">26. budget</strong></p>\n<ul data-path-to-node=\"9,2,1\">\n<li>\n<p data-path-to-node=\"9,2,1,0,0\"><strong data-path-to-node=\"9,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…ensure the project did not go over <strong data-path-to-node=\"9,2,1,0,0\" data-index-in-node=\"50\">budget</strong>.” (Đoạn D).</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,1,1,0\"><strong data-path-to-node=\"9,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các kiến trúc sư sử dụng thiết kế tối giản công nghiệp để đảm bảo chi phí nằm trong ngân sách cho phép.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('06584f8e-7f5b-4b63-ae58-1cfb930c5c56', 'f19b896c-7f39-4e5a-8f4a-dff16815e940', 'fillup', 'Questions 36–40', '<p style="text-align: center;"><span style="font-size: 12pt;"><strong data-start="219" data-end="251">Tammet – the autistic savant</strong></span></p>
<p><strong data-start="253" data-end="279">Mathematical abilities</strong></p>
<ul data-start="280" data-end="539">
<li data-section-id="19arfrf" data-start="280" data-end="361">
<p>amazing mathematical skills (can beat a calculator when working out {cube roots})</p>
</li>
<li data-section-id="evroun" data-start="362" data-end="470">
<p>numbers in his mind represented by shapes and colours – these evolve in calculations to produce the answer</p>
</li>
<li data-section-id="68foej" data-start="471" data-end="539">
<p>Tammet describes this process as {mental imagery} rather than calculation</p>
</li>
</ul>
<p><strong data-start="541" data-end="565">Linguistic abilities</strong></p>
<ul data-start="566" data-end="778">
<li data-section-id="1hc7loh" data-start="566" data-end="683">
<p>amazing linguistic abilities; none of the problems which normally result from changes to the {left hemisphere} of the brain</p>
</li>
<li data-section-id="1w1kfgq" data-start="684" data-end="733">
<p>has created a language which he calls {Mänti}</p>
</li>
<li data-section-id="4s4kz" data-start="734" data-end="778">
<p>has been undergoing tests at the {Autism Research Center}</p>
</li>
</ul>', '<p>Complete the notes below.</p>
<p>Choose <strong>NO MORE THAN THREE WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 36–40 on your answer sheet.</p>', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">36. Amazing mathematical skills (can beat a calculator when working out {cube roots})</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…a mathematical genius who can figure out <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"65\">cube roots</strong> quicker than a calculator.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Beat a calculator” (thắng cả máy tính) tương ứng với “quicker than a calculator” (nhanh hơn máy tính). Phép toán cụ thể mà ông thực hiện cực nhanh là tính căn bậc ba (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"180\">cube roots</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. Tammet describes this process as {mental imagery} rather than calculation.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Actually, he doesn’t really ‘calculate’… It’s <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"69\">mental imagery</strong>. It’s like maths without having to think.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định ông không thực sự “tính toán” (calculation) một cách có ý thức. Thay vào đó, ông gọi quá trình này là sự hình dung trong tâm trí (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"161\">mental imagery</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38. Amazing linguistic abilities; none of the problems which normally result from changes to the {left hemisphere} of the brain.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D &amp; E):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"24\">“Scans… suggest that the right hemisphere might be compensating for changes in the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"109\">left hemisphere</strong>. As a result… the majority of savants struggle with language… but there is <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"204\">nothing limited about Tammet’s vocabulary</strong>.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông thường, những thay đổi ở bán cầu não trái (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"61\">left hemisphere</strong>) khiến các thiên tài tự kỷ gặp khó khăn về ngôn ngữ. Tuy nhiên, Tammet lại không gặp phải những vấn đề này (none of the problems) và có khả năng ngôn ngữ kinh ngạc.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">39. Has created a language which he calls {Mänti}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Tammet is creating his own languages… The vocabulary of the language he has invented – <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"110\">Mänti</strong>, meaning a type of tree…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tên ngôn ngữ tự chế mà Tammet tạo ra được nhắc rõ trong bài là <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"75\">Mänti</strong>.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">40. Has been undergoing tests at the {Autism Research Centre}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“Cambridge University’s Professor Simon Baron-Cohen, director of the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"89\">Autism Research Centre (ARC)</strong>… The ARC team has <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"138\">started scanning Tammet’s brain</strong>…”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Undergoing tests” (đang trải qua các bài kiểm tra/xét nghiệm) tương ứng với việc nhóm nghiên cứu thực hiện quét não (scanning brain). Địa điểm thực hiện là Trung tâm Nghiên cứu Tự kỷ (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"197\">Autism Research Centre</strong>).</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('ba7e1785-769d-40dd-b8b1-282e52c522cb', 'e6765018-69d3-4e49-bb43-b6ee67a9fd2d', 'radio', 'Questions 35–40', '', '<p>Choose <strong data-start="2321" data-end="2328">YES</strong> if the statement agrees with the views of the writer,<strong data-start="2386" data-end="2392">NO</strong> if the statement contradicts the views of the writer,<strong data-start="2450" data-end="2463">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Language translation systems will be seen as very useful throughout the academic and professional worlds."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The overall value of automated translation to family life is yet to be shown."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Automated translation could make life more difficult for immigrant families."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Visual aspects of language translation are being considered by scientists."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "International scientists have found English easier to translate into other languages than Latin."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "As far as language is concerned, there is a difference between people’s social and practical needs."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">35. NO — {Language translation systems will be seen as very useful throughout the academic and professional worlds.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Professors and other professionals <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"56\">will not outsource language awareness to software, though</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói rằng hệ thống dịch thuật sẽ được coi là \"rất hữu ích\" (very useful) trong giới học thuật và chuyên gia. Tuy nhiên, bài đọc khẳng định các giáo sư và chuyên gia sẽ <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"187\">không phó thác/giao phó</strong> (will not outsource) nhận thức ngôn ngữ của họ cho phần mềm. Hai thông tin này mâu thuẫn hoàn toàn với nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">36. YES — {The overall value of automated translation to family life is yet to be shown.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Whether it will help people conduct their family lives or relationships is <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"96\">open to question</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"open to question\" (vẫn là một câu hỏi mở / chưa có câu trả lời chắc chắn) đồng nghĩa với ý \"yet to be shown\" (vẫn chưa được chứng minh/thể hiện rõ ràng). Do đó đáp án là <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"190\">YES</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">37. NO — {Automated translation could make life more difficult for immigrant families.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“...though one noteworthy possibility is that <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"66\">it could overcome the language barriers that often arise between generations after migration</strong>, leaving children and their grandparents without a shared language.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ ra một khả năng đáng chú ý là công nghệ này có thể giúp <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"80\">vượt qua rào cản ngôn ngữ</strong> (overcome language barriers) giữa các thế hệ trong gia đình nhập cư (giữa ông bà và con cháu). Nghĩa là nó giúp cuộc sống dễ dàng hơn chứ không phải làm cho khó khăn hơn (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"277\">more difficult</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">38. NOT GIVEN — {Visual aspects of language translation are being considered by scientists.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Even if voice-morphing technology simulates the speaker’s voice, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"86\">their lip movements won’t match, and they will look like they are in a dubbed movie</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả có nhắc đến khía cạnh hình ảnh/khớp hình khi dịch là chuyển động của môi (lip movements) sẽ không khớp với giọng nói phát ra qua máy dịch. Tuy nhiên, bài đọc <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"178\">không hề nói</strong> liệu các nhà khoa học có đang nghiên cứu hay xem xét để xử lý vấn đề này (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"265\">being considered by scientists</strong>) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">39. NOT GIVEN — {International scientists have found English easier to translate into other languages than Latin.}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“Sharing a language can promote a sense of belonging and community, as with the international scientists who use English as a lingua franca, where their predecessors used Latin.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết chỉ nêu một sự thật lịch sử là các nhà khoa học ngày nay dùng tiếng Anh làm ngôn ngữ chung (lingua franca), thay vì dùng tiếng Latin như các thế hệ đi trước. Bài đọc <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"187\">không hề so sánh</strong> xem tiếng Anh hay tiếng Latinh dễ dịch hơn (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"248\">easier to translate</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">40. YES — {As far as language is concerned, there is a difference between people’s social and practical needs.}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“Though the <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"32\">practical need</strong> for a common language will diminish, the <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"88\">social value</strong> of sharing one will persist.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định rõ ràng: Dù nhu cầu thực tế (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"60\">practical need</strong>) về một ngôn ngữ chung sẽ giảm đi nhờ có máy dịch, nhưng giá trị xã hội (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"148\">social value/needs</strong>) của việc chia sẻ chung một ngôn ngữ vẫn sẽ tồn tại bền vững. Sự phân tách này chứng minh có một sự khác biệt (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"278\">difference</strong>) lớn giữa hai nhu cầu này của con người.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('5a0caefd-a849-490d-ac07-e2a961b50da8', '23f3b20d-526a-48bc-b9cc-459eab4aeaeb', 'fillup', 'Question 31-40', '<p data-path-to-node="2">Complete the sentences below.</p>
<p data-path-to-node="2">Write <strong data-path-to-node="2" data-index-in-node="73">ONE WORD ONLY</strong> for each answer.</p>
<p style="text-align: left;" data-path-to-node="3"><span style="font-size: 12pt;"><strong data-path-to-node="3" data-index-in-node="0">The Restoration of Paintings</strong></span></p>
<p data-path-to-node="4"><strong data-path-to-node="4" data-index-in-node="0">Various Damage:</strong></p>
<ul data-path-to-node="5">
<li>
<p>Ripping canvas was caused by over stretching of putting into a {frame}.</p>
</li>
<li>
<p>Brightness changes due to accumulated {dirt} on top of painting.</p>
</li>
<li>
<p>Paint’s color fades when exposed to the light of the {sun}.</p>
</li>
<li>
<p>Method of storage leads to the emerge of {crack} in the paint.</p>
</li>
<li>
<p>Varied {temperature} cause sticky paint.</p>
</li>
</ul>
<p><strong data-path-to-node="6" data-index-in-node="0">Restoration Process:</strong></p>
<ul data-path-to-node="7">
<li>
<p>Restorers applied {wax} on the back of canvas to make it stronger.</p>
</li>
<li>
<p>Tools such as {microscopes} are used to examine the painting completely.</p>
</li>
</ul>
<p><strong data-path-to-node="8" data-index-in-node="0">Cleaning Tools:</strong></p>
<ul data-path-to-node="9">
<li>
<p>Restorers use sponges made from {cotton} to clean the work softly.</p>
</li>
<li>
<p>Old paintings were covered with varnish, {chemicals} cant be used for cleaning.</p>
</li>
<li>
<p>The most common liquid used in cleaning is human {saliva}.</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 4: THE RESTORATION OF PAINTINGS</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Lecturer:</strong> Welcome to today''s lecture about restoration of paintings. We all know that no matter how carefully a painting is stored or handled, it can be damaged. It''s the job of a restorer to fix this damage, but to do so and return the painting to the original appearance, we need to know about the material that the artist used when creating it.</p>\n<p data-path-to-node=\"5\">So, the first stage for a restorer is to determine what kind of paint was applied to what kind of surface. The restoration process also involves determining what kind of damages have been done to the artwork. There are several damages concluded: When the artist is preparing to hang and display a work, he or she has to stretch the canvas to fit it over a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"356\">(Q31) frame</strong></span>, and this can result in the ripping of the canvas. A restorer needs to be able to fix this kind of problem, and hopefully, make preparation from the beginning.</p>\n<p data-path-to-node=\"6\">And another thing is time; this can cause excessive damage to the art over the years. A painting can change from being quite bright to appearing dull. This is often due to the collection of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"190\">(Q32) dirt</strong></span> on the surface of the work. This all needs to be removed, and is almost the most common task restorers perform.</p>\n<p data-path-to-node=\"7\">Another problem with paintings is fading of the colours. If a painting is hung in the wrong place, particularly in the light of the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"132\">(Q33) sun</strong></span>, this fades the paint and its appearance. This happens not just when hanging the painting, but also in storing them. When artists want to store a painting, it''s common for them to roll it up for storage. This process can result in a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"375\">(Q34) crack</strong></span> in the paint. Some artists such as Picasso said he might disagree, but it''s impossible that the paint could cut off from the canvas entirely—something that a short-broke artist wouldn''t like.</p>\n<p data-path-to-node=\"8\">It''s important when we are restoring paintings to consider how they react to things in a new environment. For example, the paint can become sticky. This can be a very serious problem which can be caused by even minimum changes of <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"230\">(Q35) temperature</strong></span>. This is something else to watch for.</p>\n<p data-path-to-node=\"9\">A lot of damage to artworks in the past was actually caused by the restorers themselves. Restorers used to try to make the canvas stronger, and they put something onto the work. Part of this process involved putting <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"216\">(Q36) wax</strong></span> on the back of the canvas, but this leaves visible marks on the surface of the paintings. Hopefully, nowadays, with improved scientific knowledge, restoration can avoid making similar errors.</p>\n<p data-path-to-node=\"10\">Restorers have several tools at their disposal. Some are high-tech, others surprisingly low-tech. It''s not that common to see a restorer examine an ink painting to use a certain tool to eliminate the mind-line under the surface of the paint, but it''s important to analyze what kind of paint or materials the artist used. Restorers often use <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"143\">(Q37) microscopes</strong></span> so they can analyze the materials thoroughly.</p>\n<p data-path-to-node=\"11\">For restoration involves cleaning the surface of the painting. Restorers use sponges made from <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"95\">(Q38) cotton</strong></span> to gently clean the work. You might be curious about what is used to clean the paintings. Because some of the very old paintings were covered with varnish, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"264\">(Q39) chemicals</strong></span> cannot be used for cleaning, due to the fact that they can remove or damage the varnish layer.</p>\n<p data-path-to-node=\"12\">But restorers have to use something to clean the paintings. This is where the low-tech tools come in. The most common liquid used in the cleaning is human <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"155\">(Q40) saliva</strong></span>. It does a great job of cleaning the painting and it doesn''t cause damage. Now, let’s start by looking at...</p>"}]', 0);
INSERT INTO public.questions VALUES ('e7d181aa-823b-4c3c-bc7b-21801aacaa03', '83f81a59-7c9b-4b10-b20a-c67071a7605a', 'matrix', 'Questions 14–19', '', '<p>Reading Passage 2 has seven sections, <strong data-path-to-node="3" data-index-in-node="38">A–G</strong>.</p>
<p> Which section contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": " research in which two substances that tasted alike had different effects on the subjects", "correctCategoryLetter": "E"}, {"itemText": "an instance where controlling emotions while viewing something upsetting led to a lack of perseverance in other activities", "correctCategoryLetter": "B"}, {"itemText": "an explanation of why it is important to eat something before making a decision at the end of the day", "correctCategoryLetter": "G"}, {"itemText": "a reference to a researcher who was not initially convinced of the effect of glucose", "correctCategoryLetter": "F"}, {"itemText": "an account of research that mirrored an experience the researcher had in his personal life", "correctCategoryLetter": "C"}, {"itemText": "an example of how the location of products in a shop can be used to take advantage of ‘decision fatigue’", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">14. Research in which two substances that tasted alike had different effects on the subjects</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: {E}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…experiments involving <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"37\">lemonade mixed either with sugar or with a diet sweetener</strong>… the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"102\">sugarless sweeteners tasted similar</strong> but did not contain the glucose. Again and again, the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"192\">sugar restored willpower</strong>, but the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"226\">artificial sweetener had no effect</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn E mô tả thí nghiệm sử dụng hai loại nước chanh có vị giống hệt nhau (tasted alike). Tuy nhiên, chỉ loại có đường thật mới giúp phục hồi ý chí, còn loại dùng chất tạo ngọt nhân tạo thì không có tác dụng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">15. An instance where controlling emotions while viewing something upsetting led to a lack of perseverance in other activities</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: {B}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “When they tried to <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"31\">resist the urge to cry during a sad movie</strong>, afterwards they <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"90\">gave up more quickly on tasks</strong> requiring self-discipline, such as working on a <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"168\">geometry puzzle</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn B nêu ví dụ về việc kìm nén cảm xúc (controlling emotions) khi xem phim buồn khiến đối tượng dễ bỏ cuộc hơn (lack of perseverance) khi thực hiện một nhiệm vụ khó khăn ngay sau đó là giải toán hình học.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">16. An explanation of why it is important to eat something before making a decision at the end of the day</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: {G}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “If a decision must be made <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"39\">late in the afternoon or in the evening</strong>, they know <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"90\">not to do it on an empty stomach</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn G giải thích rằng khả năng ra quyết định tốt phụ thuộc vào mức glucose. Vì vậy, các chuyên gia khuyên không nên đưa ra quyết định vào cuối ngày khi bụng đói (empty stomach) để tránh sai lầm do cạn kiệt năng lượng não bộ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">17. A reference to a researcher who was not initially convinced of the effect of glucose</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: {F}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"12\">Todd Heatherton</strong>… believed in ego depletion but <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"61\">didn’t see how this process could be caused simply by variations in glucose levels</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F nhắc đến nhà nghiên cứu Todd Heatherton, người ban đầu hoài nghi (not initially convinced) về việc glucose là nguyên nhân duy nhất dẫn đến sự cạn kiệt ý chí cho đến khi ông thực hiện các thí nghiệm quét não của riêng mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. An account of research that mirrored an experience the researcher had in his personal life</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: {C}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"12\">He [Jonathan Levav] visited a tailor</strong> to have a suit made for his wedding… Levav recalls, ‘I couldn’t tell the choices apart anymore.’… <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"151\">Levav put the experience to use in an experiment</strong> conducted at German car dealerships…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C kể về việc Jonathan Levav đã trải qua cảm giác mệt mỏi khi đi may vest cưới. Ông đã dùng chính trải nghiệm cá nhân (personal life) này để thiết kế nên nghiên cứu về sự mệt mỏi khi lựa chọn phụ tùng xe hơi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">19. An example of how the location of products in a shop can be used to take advantage of ‘decision fatigue’</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: {D}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"15\">sweet snacks are featured prominently at cash registers</strong><span class=\"\"> at most supermarkets.</span><span class=\"\"> With their willpower reduced after shopping,</span><span class=\"\"> people are especially vulnerable to sweet drinks and snacks.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn D chỉ ra một ví dụ thực tế về việc các siêu thị đặt đồ ăn nhẹ và kẹo ngọt ngay tại </span><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"100\">quầy thu ngân (cash registers)</strong><span class=\"\">.</span><span class=\"\"> Đây là một vị trí (location) chiến lược nhằm lợi dụng trạng thái cạn kiệt ý chí của khách hàng sau khi họ đã phải đưa ra quá nhiều quyết định lựa chọn hàng hóa trong suốt quá trình mua sắm,</span><span class=\"\"> khiến họ dễ dàng mua đồ ngọt một cách bốc đồng hơn.</span></p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('38f399d7-7414-4074-9675-cc102882582f', '2d223f3b-d774-46bf-a42c-9c3f4cf60a6c', 'matrix', 'Questions 15-20', '', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
