</div>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "the bank", "correctCategoryLetter": "E"}, {"itemText": "the house", "correctCategoryLetter": "I"}, {"itemText": "the hostel", "correctCategoryLetter": "J"}, {"itemText": "the flat", "correctCategoryLetter": "A"}, {"itemText": "the post office", "correctCategoryLetter": "C"}, {"itemText": "the bus stop", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}, {"categoryText": "J", "categoryLetter": "J"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('75c28fc0-a901-4040-a8fd-0a53d5956414', '2a59950a-dfd8-4aaa-9464-37388e2b4424', 'radio', 'Questions 20-22', '', '<p>Choose the correct letter, A, B, C, or D.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "keep written records of different goods traded"}, {"option_text": "monitor the balance between goods given and received"}, {"option_text": "produce more materials for trading purposes"}, {"option_text": "make money from trading goods and services"}], "question": "In section A, ‘reciprocity’ refers to our ancestors’ ability to"}, {"correct": 3, "options": [{"option_text": " It is of a type only found in this particular area."}, {"option_text": "It has all been dyed to give the same shade of red."}, {"option_text": "It has been perfectly preserved despite its age."}, {"option_text": "It appears it was selected for its color."}], "question": "What is said about the ochre found around Blombos?"}, {"correct": 3, "options": [{"option_text": " They are a great variety of shapes and sizes."}, {"option_text": "They were found in large numbers, all grouped around each other."}, {"option_text": " They have patterns in many different colors."}, {"option_text": "They have holes and markings suggesting they were joined together"}], "question": "What made the researchers realize the purpose of the beads found at the Blombos caves?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">19. In section A, ‘reciprocity’ refers to our ancestors’ ability to:</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"8\">B. monitor the balance between goods given and received</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…allowing individuals to keep a <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"46\">running tally</strong> of their interactions with others… the ability to keep track of the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"130\">credits and debits</strong> that accrue…” (Đoạn A).</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Reciprocity” (sự có đi có lại) được mô tả là khả năng “ghi chép nhẩm” (mental bookkeeping) để theo dõi các khoản nợ và có (credits and debits) trong quá trình trao đổi, đảm bảo sự cân bằng giữa những gì cho đi và nhận lại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">20. What is said about the ochre found around Blombos?</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">D. It appears it was selected for its color.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “For a start, it is <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"31\">predominantly red</strong>—any of the other colors available would have sufficed for curing…” (Đoạn C).</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các nhà nghiên cứu tin rằng đất son (ochre) ở đây được dùng cho mục đích biểu tượng vì họ chủ yếu chọn màu đỏ, mặc dù các màu khác cũng có tác dụng bảo quản da thú tương tự. Điều này chứng tỏ màu sắc là yếu tố được ưu tiên lựa chọn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">21. What made the researchers realize the purpose of the beads found at the Blombos caves?</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">D. They have holes and markings suggesting they were joined together.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…consistently placed <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"35\">holes</strong>… all the beads display a pattern of <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"79\">wear suggesting friction</strong> from rubbing against thread, clothes, or other beads.” (Đoạn D).</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những lỗ thủng được đục đồng nhất và các vết mòn do ma sát với chỉ hoặc quần áo cho thấy những vỏ sò này được xâu chuỗi lại với nhau để làm đồ trang sức, chứ không phải là sự tích tụ tự nhiên.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('6a22c8c5-f146-4012-be26-2a4b24a99b10', '2a59950a-dfd8-4aaa-9464-37388e2b4424', 'matching', 'Questions 22-26', '', '<p>Complete the summary below.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>Why certain objects are valued?</strong></p>\n<p>Some researchers argue that we may use ownership of desirable goods to demonstrate our strength and fitness as other {D. species} use their attractive physical features. Showing off one’s superiority is not a new phenomenon, and even in ancient times, successful people would have gained {B. respect} from this. A desire for status could have led to an increase in the worth of prestige goods and to {A. competitiveness} among people wishing to achieve this status.</p>\n<p>It is thought that our natural desire to trade provided a basis for organized farming and {E. city} development and finally resulted in the complex societies which can be seen today. Whilst we do not value things such as beads nowadays, other items hold the same appeal for us and bring the same status as owning beads did for our {C. ancestors}.</p>", "answerOptions": [{"optionText": "A. competitiveness"}, {"optionText": "B. respect"}, {"optionText": "C. ancestors"}, {"optionText": "D. species"}, {"optionText": "E. city"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. … ownership of desirable goods to demonstrate our strength and fitness as other {species} use their attractive physical features.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In many animal <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"27\">species</strong>, individuals signal their genetic fitness by showing off with attention-grabbing adornment.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả so sánh việc con người dùng hàng hóa xa xỉ với việc các loài động vật khác dùng vẻ ngoài (như bộ lông) để khoe sức mạnh và sự khỏe mạnh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. … even in ancient times, successful people would have gained {respect} from this.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…superior skills in areas such as hunting… would have brought <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"78\">respect</strong>—in other words, prestige.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những kỹ năng vượt trội mang lại sự tôn trọng (respect) hay còn gọi là uy tín (prestige).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. … increase in the worth of prestige goods and to {competitiveness} among people wishing to achieve this status.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The benefits of prestige would also lead to <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"56\">competition</strong> to acquire it.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mong muốn đạt được địa vị dẫn đến sự cạnh tranh (competitiveness) giữa mọi người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">20. … natural desire to trade provided a basis for organized farming and {city} development…</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…paving the way for agriculture and <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"50\">urbanization</strong>.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự phát triển của hàng hóa xa xỉ dẫn đến sự hình thành hệ thống xã hội, nông nghiệp và đô thị hóa (city development).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">21. … other items hold the same appeal for us and bring the same status as owning beads did for our {ancestors}.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “We may not be impressed by beads anymore, but their modern equivalents have the same fascination… status symbol.” (Đoạn E).</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những món đồ như xe Bugatti ngày nay có giá trị biểu tượng địa vị tương tự như những chuỗi hạt vỏ sò đối với tổ tiên (ancestors) của chúng ta ngày xưa.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('fff6719a-efb9-4363-81e3-677f382e7017', 'd6144b69-2fc5-45db-8f6a-fa0eaecc6198', 'fillup', 'Questions 21–27', '<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 21–27 on your answer sheet.</p>
<p>When employees perform poorly, the {turnover} of staff may increase.</p>
<p>An example of poor performance is when employees tell {jokes} that are not suitable for the workplace.</p>
<p>{Misconduct} by an employee could lead to physical harm of another employee.</p>
<p>The most effective way of preventing underperformance is through {communication}</p>
<p>If a meeting takes place to discuss poor performance, the employee can bring a {support person}</p>
<p>At the meeting, the employer and employee should find a {solution} that they both accept.</p>
<p>A policy document can clarify the {possible consequences} of an employee.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. When employees perform poorly, the {turnover} of staff may increase.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Poorly performing staff…):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"44\">“Poorly performing staff can have a negative effect… for example: • higher <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"121\">staff turnover</strong>“</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi nhân viên làm việc kém, một trong những ảnh hưởng tiêu cực là tỉ lệ thay thế nhân viên (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"104\">staff turnover</strong>) sẽ cao hơn (tăng lên).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. An example of poor performance is when employees tell {jokes} that are not suitable for the workplace.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Underperformance…):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"37\">“…unacceptable behaviour at work, e.g. inappropriate <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"92\">jokes</strong>“</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Not suitable” đồng nghĩa với “inappropriate” (không phù hợp). Ví dụ về hành vi không chấp nhận được là kể những câu chuyện đùa (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"141\">jokes</strong>) không phù hợp tại nơi làm việc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. {Misconduct} by an employee could lead to physical harm of another employee.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“There is a difference between underperformance and serious <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"80\">misconduct</strong>. The latter is when an employee causes serious and imminent risk to the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"163\">health and safety of another person</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Serious misconduct” (Hành vi sai trái nghiêm trọng) là khi nhân viên gây ra rủi ro cho sức khỏe và sự an toàn của người khác (tương ứng với “physical harm” – tổn hại thân thể).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">24. The most effective way of preventing underperformance is through {communication}.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“The best way to manage underperformance is to make sure it doesn’t happen in the first place. <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"115\">Communication is the key</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “The best way… to make sure it doesn’t happen” tương ứng với “The most effective way of preventing”. Chìa khóa ở đây chính là sự giao tiếp (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"154\">communication</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">25. If a meeting takes place to discuss poor performance, the employee can bring a {support person}.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“…tell the employee what the meeting is about and ask them if they want a <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"96\">support person</strong> to attend with them.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong cuộc họp thảo luận về việc làm việc kém, người quản lý nên hỏi nhân viên xem họ có muốn một người hỗ trợ (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"124\">support person</strong>) đi cùng hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">26. At the meeting, the employer and employee should find a {solution} that they both accept.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7 – Dấu chấm thứ 2):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"37\">“make sure both parties have discussed and agreed on a <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"92\">solution</strong> together…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Both parties… agreed on” tương ứng với “they both accept” (cả hai cùng chấp nhận). Thứ họ cần đạt được là một giải pháp (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"136\">solution</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">27. A policy document can clarify the {possible consequences} of an employee.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn cuối):</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"23\">“Employers should consider writing down a performance management policy that outlines the <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"113\">possible consequences</strong> of underperformance.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Clarify” tương ứng với “outlines” (phác thảo/làm rõ). Một văn bản chính sách sẽ làm rõ những hậu quả có thể xảy ra (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"129\">possible consequences</strong>) của việc làm việc kém.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('d90257fa-544f-4674-808d-1ed4e77380b6', '4047ff23-71aa-4493-aac0-60af11c61813', 'radio', 'Questions 27–32', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The writer changed her mind about spending time in Tasmania."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Andrew Bain believes that the effect MONA had on Hobart was immediate."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Other factors have contributed as much as MONA to Hobart’s transformation."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The Tourism Industry Council of Tasmania works closely with the director of MONA."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Many local residents are writing to The Mercury expressing concern about tourists’ length of stay in Hobart."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Tourists now regard MONA as a starting point for longer trips in Tasmania."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">27. The writer changed her mind about spending time in Tasmania.</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"16\">A</strong>, dòng 1-3: “As an eighteen-year-old… moving to the ‘mainland’ could not happen soon enough. Now, ten years later, I <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"136\">look forward to going home</strong>.”</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Lúc 18 tuổi, tác giả chỉ muốn rời đi thật nhanh. Nhưng 10 năm sau, cô lại mong ngóng được trở về. Điều này khẳng định cô đã thay đổi suy nghĩ.</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">28. Andrew Bain believes that the effect MONA had on Hobart was immediate.</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"16\">B</strong>, dòng 2-4: “Andrew Bain… wrote, ‘In a <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"58\">virtual blink</strong>, Hobart’s cultural landscape has been transformed…’”</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “in a virtual blink” (trong chớp mắt) đồng nghĩa với “immediate” (ngay lập tức). Andrew Bain tin rằng sự thay đổi diễn ra rất nhanh chóng sau khi MONA mở cửa.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">29. Other factors have contributed as much as MONA to Hobart’s transformation.</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"16\">B</strong>, dòng cuối: “MONA is said to have been <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"57\">solely instrumental</strong> in the reinvention of Hobart as a cultural hub.”</li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “solely” (duy nhất/độc nhất) khẳng định chỉ có MONA là nhân tố chính gây ra sự thay đổi này. Câu hỏi nói rằng “các yếu tố khác cũng đóng góp nhiều như MONA” là sai so với bài đọc.</li>\n</ul>\n<p><strong data-path-to-node=\"13\" data-index-in-node=\"0\">30. The Tourism Industry Council of Tasmania works closely with the director of MONA.</strong></p>\n<ul data-path-to-node=\"14\">\n<li><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></li>\n<li><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"16\">C</strong> và <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"21\">D</strong> có nhắc đến Luke Martin (Giám đốc điều hành Hội đồng Công nghiệp Du lịch) bàn về sự phổ biến của MONA và các kế hoạch điều tra.</li>\n<li><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói hội đồng này đang nghiên cứu các gói du lịch liên quan đến MONA, nhưng <strong data-path-to-node=\"14,2,0\" data-index-in-node=\"95\">không có thông tin</strong> nào nói rằng họ “làm việc chặt chẽ” (<em data-path-to-node=\"14,2,0\" data-index-in-node=\"151\">works closely</em>) với giám đốc của bảo tàng.</li>\n</ul>\n<p><strong data-path-to-node=\"15\" data-index-in-node=\"0\">31. Many local residents are writing to The Mercury expressing concern about tourists’ length of stay in Hobart.</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></li>\n<li><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"16\">C</strong>, dòng 4-6: “As reported in Hobart’s local paper, The Mercury, there is concern about how long people are staying in Tasmania.”</li>\n<li><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài báo <em data-path-to-node=\"16,2,0\" data-index-in-node=\"20\">The Mercury</em> có báo cáo về sự lo ngại về thời gian lưu trú của du khách, nhưng bài đọc <strong data-path-to-node=\"16,2,0\" data-index-in-node=\"106\">không nói rõ</strong> là do “nhiều người dân địa phương viết thư” (<em data-path-to-node=\"16,2,0\" data-index-in-node=\"164\">local residents are writing</em>) gửi đến tòa soạn hay do phóng viên/chuyên gia tự phân tích.</li>\n</ul>\n<p><strong data-path-to-node=\"17\" data-index-in-node=\"0\">32. Tourists now regard MONA as a starting point for longer trips in Tasmania.</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></li>\n<li><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"16\">C</strong>, dòng 6-9: “…people are making <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"51\">short stays in Hobart only to visit the gallery</strong>. The next challenge… is how to entice holiday makers to stay longer, and to venture further afield.”</li>\n<li><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thực tế hiện tại là du khách chỉ đến Hobart ngắn ngày để xem bảo tàng rồi về, chứ họ <strong data-path-to-node=\"18,2,0\" data-index-in-node=\"97\">chưa</strong> coi đây là điểm bắt đầu cho những chuyến đi dài hơn khắp Tasmania. Đây vẫn đang là một “thách thức” (<em data-path-to-node=\"18,2,0\" data-index-in-node=\"203\">challenge</em>) cho tương lai.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('c99b613a-b951-4b16-890f-b304942ac146', '91b576e0-3358-4249-bc84-e6d5e9eaeb68', 'matching', 'Questions 14–20', NULL, '<p>The text has seven paragraphs. Choose the correct heading for each paragraph and move it into the gap.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "The impact of musical performance on the etiquette of applause"}, {"optionText": "The negative effects of applause on a kind of public performer"}, {"optionText": "The initial emergence of applause as a behaviour in the theatre"}, {"optionText": "A form of applause that is more far-reaching than before"}, {"optionText": "The use of applause by political figures to evaluate their own popularity"}, {"optionText": "How music can influence an audience’s level of applause"}, {"optionText": "The different methods of applause employed in ancient times, besides clapping"}, {"optionText": "The re-emergence and disappearance of fake appreciation"}, {"optionText": "How the theatrical world copied the world of politics in giving applause"}, {"optionText": "The use of applause in working out how popular an opponent was"}], "matchingItems": null}', 'null', '[{"content": "<h3 class=\"\" data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">Questions 14–20: Matching Headings</strong></h3>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">14. Paragraph 1: The initial emergence of applause as a behaviour in the theatre</strong></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\"><strong class=\"\" data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 1,</span><span class=\"\"> dòng 3-6.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,1,0\"><strong class=\"\" data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">the common way to end a play was for the chief actor to yell ‘Valete et plaudite!</span><span class=\"\">’…</span><span class=\"\"> signaling to the audience that it was time for them to give praise…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,2,0\"><strong class=\"\" data-path-to-node=\"3,0,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này nói về sự xuất hiện ban đầu của việc vỗ tay trong nhà hát La Mã như một hiệu lệnh kết thúc vở kịch.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">15. Paragraph 2: The use of applause by political figures to evaluate their own popularity</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong class=\"\" data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 2,</span><span class=\"\"> dòng 4-7.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong class=\"\" data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “One of the chief methods they used to </span><strong class=\"\" data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"50\">estimate their standing</strong><span class=\"\"> with the people was gauging the greetings they got…</span><span class=\"\"> an ancient type of </span><strong class=\"\" data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"147\">opinion poll</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,2,0\"><strong class=\"\" data-path-to-node=\"3,1,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Các nhà lãnh đạo dùng tiếng vỗ tay như một cuộc thăm dò ý kiến để đánh giá mức độ ủng hộ (popularity) của dân chúng dành cho mình.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong class=\"\" data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">16. Paragraph 3: The use of applause in working out how popular an opponent was</strong></p>\n<ul data-path-to-node=\"3,2,1\">\n<li>\n<p data-path-to-node=\"3,2,1,0,0\"><strong class=\"\" data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 3,</span><span class=\"\"> dòng 1-3.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,1,0\"><strong class=\"\" data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “Clever leaders…</span><span class=\"\"> researched their </span><strong class=\"\" data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"47\">rivals</strong><span class=\"\">,</span><span class=\"\"> too.</span><span class=\"\"> Cicero…</span><span class=\"\"> taking notes to see what kind of greeting each official got…</span><span class=\"\"> who was beloved…</span><span class=\"\"> and who was not.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,2,0\"><strong class=\"\" data-path-to-node=\"3,2,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Không chỉ đánh giá bản thân,</span><span class=\"\"> họ còn dùng tiếng vỗ tay để đo lường mức độ yêu mến của dân chúng dành cho đối thủ (rivals/opponent).</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,3,0\"><strong class=\"\" data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">17. Paragraph 4: The different methods of applause employed in ancient times, besides clapping</strong></p>\n<ul data-path-to-node=\"3,3,1\">\n<li>\n<p data-path-to-node=\"3,3,1,0,0\"><strong class=\"\" data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 4,</span><span class=\"\"> dòng 4-7.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,1,1,0\"><strong class=\"\" data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">strategies of applause were much more varied than clapping alone…</span><span class=\"\"> ranging from claps,</span><span class=\"\"> to </span><strong class=\"\" data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"106\">snaps</strong><span class=\"\">…</span><span class=\"\"> to </span><strong class=\"\" data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"118\">waves</strong><span class=\"\">…</span><span class=\"\"> waving a special </span><strong class=\"\" data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"144\">handkerchief</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,1,2,0\"><strong class=\"\" data-path-to-node=\"3,3,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Liệt kê các hình thức tán thưởng khác ngoài vỗ tay như búng tay,</span><span class=\"\"> vẫy vạt áo toga hoặc vẫy khăn tay.</span></p>\n<div class=\"attachment-container search-images\">\n<p>&nbsp;</p>\n<div class=\"image-container ng-star-inserted\">\n<div class=\"overlay-container ng-star-inserted\">\n<p>&nbsp;</p>\n<div class=\"placeholder loading ng-star-inserted\"></div>\n<p>&nbsp;</p>\n</div>\n<p>&nbsp;</p>\n</div>\n<p>&nbsp;</p>\n</div>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,4,0\"><strong class=\"\" data-path-to-node=\"3,4,0\" data-index-in-node=\"0\">18. Paragraph 5: The re-emergence and disappearance of fake appreciation</strong></p>\n<ul data-path-to-node=\"3,4,1\">\n<li>\n<p data-path-to-node=\"3,4,1,0,0\"><strong class=\"\" data-path-to-node=\"3,4,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 5,</span><span class=\"\"> dòng 1-3 và câu cuối.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,4,1,1,0\"><strong class=\"\" data-path-to-node=\"3,4,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">bringing back the Roman practice of hiring </span><strong class=\"\" data-path-to-node=\"3,4,1,1,0\" data-index-in-node=\"58\">professional applauders</strong><span class=\"\">…</span><span class=\"\"> The claque lost its power once people became aware of its tricks.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,4,1,2,0\"><strong class=\"\" data-path-to-node=\"3,4,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Nói về sự trở lại của việc thuê người vỗ tay giả (fake) ở Pháp và sự thoái trào của nó khi các mánh khóe bị bại lộ.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,5,0\"><strong class=\"\" data-path-to-node=\"3,5,0\" data-index-in-node=\"0\">19. Paragraph 6: The impact of musical performance on the etiquette of applause</strong></p>\n<ul data-path-to-node=\"3,5,1\">\n<li>\n<p data-path-to-node=\"3,5,1,0,0\"><strong class=\"\" data-path-to-node=\"3,5,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 6,</span><span class=\"\"> dòng 1-4.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,5,1,1,0\"><strong class=\"\" data-path-to-node=\"3,5,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “In the 18th century,</span><span class=\"\"> symphonies and concerts became more serious…</span><span class=\"\"> Knowing when to maintain silence…</span><span class=\"\"> became a mark of </span><strong class=\"\" data-path-to-node=\"3,5,1,1,0\" data-index-in-node=\"133\">sophistication</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,5,1,2,0\"><strong class=\"\" data-path-to-node=\"3,5,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Sự thay đổi trong âm nhạc (nghiêm túc hơn) đã định hình lại quy tắc ứng xử (etiquette) của khán giả:</span><span class=\"\"> phải biết lúc nào im lặng,</span><span class=\"\"> lúc nào vỗ tay.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,6,0\"><strong class=\"\" data-path-to-node=\"3,6,0\" data-index-in-node=\"0\">20. Paragraph 7: A form of applause that is more far-reaching than before</strong></p>\n<ul data-path-to-node=\"3,6,1\">\n<li>\n<p data-path-to-node=\"3,6,1,0,0\"><strong class=\"\" data-path-to-node=\"3,6,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn 7,</span><span class=\"\"> dòng 1-3.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,6,1,1,0\"><strong class=\"\" data-path-to-node=\"3,6,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “In the 21st century we’re reinventing applause…</span><span class=\"\"> digital world allows us to link and share…</span><span class=\"\"> no longer momentary…</span><span class=\"\"> but is far more </span><strong class=\"\" data-path-to-node=\"3,6,1,1,0\" data-index-in-node=\"146\">permanent</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,6,1,2,0\"><strong class=\"\" data-path-to-node=\"3,6,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tiếng vỗ tay thời kỹ thuật số (like,</span><span class=\"\"> share,</span><span class=\"\"> comment) có sức lan tỏa rộng lớn và tồn tại lâu bền hơn so với tiếng vỗ tay tức thời ngày xưa.</span></p>\n</li>\n</ul>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('089b1fee-d98a-4f9b-b5ac-3cf568a20e51', '4047ff23-71aa-4493-aac0-60af11c61813', 'radio', 'Questions 33–37', NULL, '<p>Choose the correct answer.</p>', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "focusing more on MONA as the leading attraction."}, {"content": "combining trips to MONA with visits to other galleries."}, {"content": "encouraging visitors to do activities that are not connected with art galleries."}, {"content": "improving the quality of promotional information about Tasmania’s galleries."}], "question": "Luke Martin plans to promote tourism in Tasmania by"}, {"correct": 0, "options": [{"content": "the man who founded the gallery"}, {"content": "its location close to a river"}, {"content": "visitors’ responses to the gallery spaces"}, {"content": "the striking architecture of the building"}], "question": " According to the writer, what is especially interesting about MONA?"}, {"correct": 3, "options": [{"content": "There is a great number of exhibits."}, {"content": "Visitors tend to come in family groups."}, {"content": "Many of the works are difficult to understand."}, {"content": "The gallery has a physical effect on visitors."}], "question": "Why do visitors spend a long time at the gallery?"}, {"correct": 1, "options": [{"content": "Older people spend longer there than younger people do."}, {"content": "A wide variety of people are interested in MONA."}, {"content": "The majority of visitors are young people."}, {"content": "The visitors are representative of gallery enthusiasts generally."}], "question": "What does the writer say about the visitors to MONA?"}, {"correct": 3, "options": [{"option_text": "to illustrate how interesting they are to visitors of modern galleries"}, {"option_text": "to explain why they are displayed in a separate section of the gallery"}, {"option_text": "to argue that Walsh''s collection is among the best in the world"}, {"option_text": "to express admiration for the way that the exhibits are presented"}], "question": "Why does the writer mention the coins at MONA?"}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"2\" data-index-in-node=\"0\">33. Luke Martin plans to promote tourism in Tasmania by</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: B (combining trips to MONA with visits to other galleries.)</strong></li>\n<li><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"16\">D</strong>, dòng 1-2: “According to Martin, possibilities for <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"69\">packaging up MONA with visits to other galleries</strong> around Tasmania are being investigated.”</li>\n<li><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “packaging up” đồng nghĩa với “combining trips” (kết hợp các chuyến đi). Luke Martin đang nghiên cứu việc tạo ra các gói du lịch kết hợp MONA với các phòng triển lãm khác tại Tasmania.</li>\n</ul>\n<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">34. According to the writer, what is especially interesting about MONA?</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án: A (the man who founded the gallery)</strong></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"16\">E</strong>, dòng 2-4: “MONA’s ‘wow factor’ comes from the <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"65\">notoriety of David Walsh, the museum’s millionaire founder</strong>, and his choice of unusual artworks.”</li>\n<li><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định yếu tố gây kinh ngạc (“wow factor”) của bảo tàng đến từ sự nổi tiếng (và tai tiếng) của người sáng lập David Walsh cùng những lựa chọn tác phẩm khác lạ của ông.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">35. Why do visitors spend a long time at the gallery?</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: D (The gallery has a physical effect on visitors.)</strong></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"16\">F</strong>, dòng 8-10: “the urge to linger is a common feeling here. This is because the <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"96\">gallery engages all of the senses</strong>, and visitors often pause to experience the effect each artwork has on them.”</li>\n<li><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc bảo tàng tác động đến mọi giác quan (engages all of the senses) chính là một tác động vật lý/trực giác khiến khách tham quan muốn nán lại lâu hơn để cảm nhận tầm ảnh hưởng của mỗi tác phẩm.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">36. What does the writer say about the visitors to MONA?</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: B (A wide variety of people are interested in MONA.)</strong></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"16\">F</strong>, dòng 11-14: “…definitely <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"46\">not just the normal gallery-goers</strong>. People from <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"93\">all kinds of socioeconomic backgrounds</strong> are curious about what lies within…”</li>\n<li><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh khách đến MONA không chỉ là những người hay đi xem triển lãm thông thường mà bao gồm mọi tầng lớp xã hội khác nhau, điều này tương ứng với “a wide variety of people”.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">37. Why does the writer mention the coins at MONA?</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án: D (to express admiration for the way that the exhibits are presented)</strong></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"16\">G</strong>, dòng 4-5: “For me, one of the <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"49\">intriguing outcomes</strong> of this strategy was an intensified feeling that the makers of the coins… were the great contemporary artists of their time.”</li>\n<li><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc đặt tiền cổ xen kẽ với nghệ thuật hiện đại là một chiến lược trưng bày mà tác giả thấy rất thú vị (intriguing). Cách trình bày này khiến cô ngưỡng mộ vì nó làm tôn vinh giá trị của những món đồ cổ như những tác phẩm nghệ thuật đương đại thực thụ.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('84cf4fe9-e3cd-4f38-a56b-d4957da72d28', '4047ff23-71aa-4493-aac0-60af11c61813', 'matching', 'Questions 38-40', NULL, '<p>Complete the summary using the list of words, A-H, below.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p class=\"ql-align-center\" style=\"text-align: center;\"><strong>The Bilbao effect</strong></p>\r\n<p class=\"ql-align-justify\">MONA has huge appeal for visitors to Hobart, just as Gehry’s Guggenheim Museum has for Bilbao. While MONA may lack the {C visual<span class=\"fill-history-correct\">}</span> effect of the Guggenheim, David Walsh explains that MONA’s architect had a different objective when designing MONA: unlike the architectural showcasing of the Guggenheim, with MONA there was a major {A challenge<span class=\"fill-history-correct\">}</span> that needed to be dealt with; the gallery was set beneath the ground. In any case, both galleries have transformed their cities, just as successful public buildings have for thousands of years. It remains to be seen how the {D contribution<span class=\"fill-history-correct\">}</span> of David Walsh will be expanded upon in Tasmania.</p>", "answerOptions": [{"optionText": "A challenge"}, {"optionText": "B pipe"}, {"optionText": "C visual"}, {"optionText": "D contribution"}, {"optionText": "E lasting"}, {"optionText": "F essential"}, {"optionText": "G ambition"}, {"optionText": "H attraction"}], "matchingItems": null}', 'null', '[{"content": "<p><strong data-path-to-node=\"2\" data-index-in-node=\"0\">38. C (visual)</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn H, dòng 4-7.</li>\n<li><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…whereas Fender Katsalidis’s MONA does not have the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"66\">same spectacular impact</strong> as the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"97\">shimmering metal surfaces</strong> of Gehry’s building.”</li>\n<li><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc so sánh vẻ ngoài của hai bảo tàng. Trong khi bảo tàng Guggenheim có bề mặt kim loại lung linh tạo ra tác động thị giác cực mạnh, thì kiến trúc của MONA không có được hiệu ứng <strong data-path-to-node=\"3,2,0\" data-index-in-node=\"195\">thị giác (visual effect)</strong> ngoạn mục như vậy vì nó nằm dưới lòng đất.</li>\n</ul>\n<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">39. A (challenge)</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn H, dòng 8-10.</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"citation-13\"> “…Fender Katsalidis </span><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"33\"><span class=\"citation-13\">solved a problem</span></strong><span class=\"citation-13\"> when he designed MONA, in executing a project of this scale in an </span><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"116\"><span class=\"citation-13\">underground location</span></strong><span class=\"citation-13 citation-end-13\">.”</span>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n</li>\n<li><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> David Walsh cho rằng kiến trúc sư của ông phải giải quyết một vấn đề/thử thách (<strong data-path-to-node=\"5,2,0\" data-index-in-node=\"92\">problem</strong> tương ứng với <strong data-path-to-node=\"5,2,0\" data-index-in-node=\"114\">challenge</strong>) thực tế, đó là xây dựng một công trình quy mô lớn hoàn toàn dưới lòng đất, thay vì chỉ tập trung vào phô diễn kiến trúc như ở Bilbao.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">40. D (contribution)</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn H, câu cuối.</li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Now the question is how Tasmania will build on <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"59\">David Walsh’s input</strong> into its cultural setting.”</li>\n<li><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “input” (sự đóng góp/đầu vào) trong bài tương ứng với từ <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"72\">contribution</strong>. Tác giả đặt ra câu hỏi về việc Tasmania sẽ tiếp tục phát triển dựa trên những gì David Walsh đã đóng góp cho bối cảnh văn hóa của bang này như thế nào.</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('6f63e1df-b7d4-4de7-97f5-2fb49da44c22', 'dd5aee5d-45a9-4230-915a-5ab4f331aff4', 'fillup', 'Questions 5–13', '<p>Complete the notes below.</p>
<p>Choose <strong data-path-to-node="10" data-index-in-node="7">ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 5–13 on your answer sheet.</p>
<p data-path-to-node="12"><span style="font-size: 12pt;"><strong data-path-to-node="12" data-index-in-node="0">New Evidence on Sleep Patterns</strong></span></p>
<p><strong data-path-to-node="13" data-index-in-node="0">New ideas about napping</strong></p>
<ul data-path-to-node="14">
<li>
<p>scientists have recorded an afternoon drop in {energy}</p>
</li>
<li>
<p>studies of hunter-gatherer societies show that napping was rare and occurred more often during the {summer}</p>
</li>
<li>
<p>the devices may not have detected {short} naps</p>
</li>
</ul>
<p><strong data-path-to-node="15" data-index-in-node="0">Daily activity cycles</strong></p>
<ul data-path-to-node="16">
<li>
<p>the tribespeople went to sleep several hours after sunset</p>
</li>
<li>
<p>even with {fires} there was little light</p>
</li>
<li>
<p>tribespeople usually woke up around {sunrise}</p>
</li>
<li>
<p>scientists found that {temperature} had almost as much influence on sleep patterns as light</p>
</li>
</ul>
<p><strong data-path-to-node="17" data-index-in-node="0">Differences between tribespeople and people in industrialised regions</strong></p>
<ul data-path-to-node="18">
<li>
<p>{sleeplessness} is something that very few of the tribespeople suffered from</p>
</li>
<li>
<p>the environment of tribespeople may have been more suitable for sleep</p>
</li>
<li>
<p>tribespeople had better fitness than industrialised populations and were not {overweight}</p>
</li>
<li>
<p>tribespeople also had stronger {hearts}</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">5. energy — {scientists have recorded an afternoon drop in energy}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Scientists have documented that people’s <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"62\">energy</strong> often falls in the mid-afternoon.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “documented” đồng nghĩa với “recorded” (ghi nhận). “Mid-afternoon” tương ứng với “afternoon”. Các nhà khoa học đã ghi nhận sự sụt giảm năng lượng (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"162\">energy</strong>) vào giữa buổi chiều.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">6. summer — {napping was rare and occurred more often during the summer}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“The researchers estimated that naps may have occurred on up to 7 percent of winter days and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"113\">22 percent of summer days</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc ngủ trưa rất hiếm, nhưng số liệu cho thấy tỉ lệ ngủ trưa ở mùa hè (22%) cao hơn hẳn mùa đông (7%). Do đó, nó xảy ra thường xuyên hơn vào mùa hè (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"162\">summer</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">7. short — {the devices may not have detected short naps}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…so it is possible that some of the study subjects took <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"79\">naps that were short</strong>, perhaps 15 minutes or less.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thiết bị của họ chỉ phát hiện được những giấc ngủ dài, vì vậy có thể họ đã bỏ lỡ những giấc ngủ ngắn (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"114\">short</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">8. fires — {even with fires there was little light}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“All three tribes had <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"42\">fires</strong> going, but the light itself was much lower than you might get from a light bulb.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù các bộ lạc đều có đốt lửa (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"46\">fires</strong>), nhưng lượng ánh sáng tỏa ra vẫn rất thấp so với bóng đèn hiện đại.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">9. sunrise — {tribespeople usually woke up around sunrise}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“They did, however, have a tendency to wake up anywhere between an hour before and an hour after <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"117\">sunrise</strong>.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các bộ lạc có xu hướng thức dậy trong khoảng 1 tiếng trước hoặc sau khi mặt trời mọc (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"98\">sunrise</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">10. temperature — {temperature had almost as much influence… as light}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“…looking into the significance of <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"57\">temperature</strong>. They found that it also played a big role, though it was <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"127\">somewhat less important than light</strong> in influencing sleep patterns.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nhiệt độ (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"22\">temperature</strong>) đóng vai trò lớn, chỉ kém quan trọng hơn ánh sáng một chút trong việc ảnh hưởng đến giấc ngủ.</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">11. sleeplessness — {sleeplessness is something that very few… suffered from}</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"20\">“Importantly, almost none of them were troubled by <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"71\">sleeplessness</strong>.”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Almost none” đồng nghĩa với “very few”. Chứng mất ngủ (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"68\">sleeplessness</strong>) là thứ mà rất ít người trong các bộ lạc này gặp phải.</li>\n</ul>\n<p><strong data-path-to-node=\"18\" data-index-in-node=\"0\">12. overweight — {tribespeople… were not overweight}</strong></p>\n<ul data-path-to-node=\"19\">\n<li><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"20\">“Not a single one is <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"41\">overweight</strong>, indicating their overall higher levels of physical fitness.”</em></li>\n<li><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Không một ai trong số họ bị thừa cân (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"50\">overweight</strong>), chứng tỏ họ có thể chất tốt hơn người hiện đại.</li>\n</ul>\n<p><strong data-path-to-node=\"20\" data-index-in-node=\"0\">13. hearts — {tribespeople also had stronger hearts}</strong></p>\n<ul data-path-to-node=\"21\">\n<li><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"21,0,0\" data-index-in-node=\"20\">“They also tended to have healthier <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"56\">hearts</strong>.”</em></li>\n<li><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Healthier” đồng nghĩa với “stronger” trong ngữ cảnh này. Họ có trái tim (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"86\">hearts</strong>) khỏe mạnh hơn.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('1e22f163-7ddd-4765-97e0-fc22cfbb0a6e', 'e6765018-69d3-4e49-bb43-b6ee67a9fd2d', 'radio', 'Questions 27–30', '', '<p>Choose the correct letter, A, B, C or D.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A The speakers are communicating in different languages."}, {"option_text": "B Neither of the speakers is familiar with their environment."}, {"option_text": "C The topic of the conversation is difficult for both speakers."}, {"option_text": "D Aspects of the conversation are challenging for both speakers."}], "question": "What does the reader learn about the conversation in the first paragraph?"}, {"correct": 0, "options": [{"option_text": "A the repeated content of lectures"}, {"option_text": "B the students’ reading skills"}, {"option_text": "C the languages used"}, {"option_text": "D the lecturers’ technical ability"}], "question": "What assists the electronic translator during lectures at Karlsruhe Institute of Technology?"}, {"correct": 2, "options": [{"option_text": "A the Babel fish was considered undesirable at the time."}, {"option_text": "B this book was not seriously intending to predict the future."}, {"option_text": "C artificial speech translation was not a surprising development."}, {"option_text": "D some speech translation techniques are better than others."}], "question": "When referring to The Hitchhiker’s Guide to the Galaxy, the writer suggests that"}, {"correct": 1, "options": [{"option_text": "A It is something people will get used to doing."}, {"option_text": "B The reluctance to do this is understandable."}, {"option_text": "C The equipment will be unnecessary in the future."}, {"option_text": "D It is something few people need to worry about."}], "question": "What does the writer say about sharing earpieces?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">27. D. Aspects of the conversation are challenging for both speakers. — {What does the reader learn about the conversation in the first paragraph?}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> * Với GS Waibel: <em data-path-to-node=\"8,0,0\" data-index-in-node=\"28\">\"Noise... is one of the major challenges... will struggle to cope with the kind of <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"111\">background noise I can hear in my office surrounding Professor Waibel as he speaks to me from Kyoto station</strong>\"</em></p>\n<ul data-path-to-node=\"8,0,1\">\n<li>\n<p data-path-to-node=\"8,0,1,0,0\">Với tác giả: <em data-path-to-node=\"8,0,1,0,0\" data-index-in-node=\"13\">\"<strong data-path-to-node=\"8,0,1,0,0\" data-index-in-node=\"14\">I’m struggling to follow him</strong> in English, on a <strong data-path-to-node=\"8,0,1,0,0\" data-index-in-node=\"60\">scratchy line</strong>...\"</em></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cả hai người đều đang gặp khó khăn (challenging). Giáo sư Waibel phải nói chuyện trong môi trường đầy tiếng ồn ở ga tàu, còn tác giả thì chật vật để nghe vì đường truyền bị nhiễu (scratchy line). Ý này khớp hoàn toàn với phương án D: Các khía cạnh của cuộc trò chuyện gây thử thách cho cả hai người.</p>\n<ul data-path-to-node=\"8,1,1\">\n<li>\n<p data-path-to-node=\"8,1,1,0,0\"><em data-path-to-node=\"8,1,1,0,0\" data-index-in-node=\"0\">Loại A:</em> Họ đang nói cùng một ngôn ngữ (speaking the same language, as we are).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,1,1,0\"><em data-path-to-node=\"8,1,1,1,0\" data-index-in-node=\"0\">Loại B &amp; C:</em> Bài viết không nói họ không quen với môi trường hay chủ đề khó.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">28. A. the repeated content of lectures — {What assists the electronic translator during lectures at Karlsruhe Institute of Technology?}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">\"It helps that lecturers speak clearly, don’t have to compete with background chatter, and <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"102\">say much the same thing each year</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ \"It helps\" trong bài đọc đồng nghĩa với \"assists\" (hỗ trợ/giúp ích). Một trong những yếu tố giúp hệ thống dịch hoạt động tốt là việc các giảng viên nói những nội dung gần như giống nhau qua từng năm (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"215\">say much the same thing each year</strong>), tương ứng với \"the repeated content\" (nội dung được lặp lại).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">29. C. artificial speech translation was not a surprising development. — {When referring to The Hitchhiker’s Guide to the Galaxy, the writer suggests that}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">\"It came to represent one of those devices that <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"59\">technology enthusiasts dream of long before they become practically realisable</strong>, like TVs flat enough to hang on walls: objects we once could only dream of having but that are <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"234\">now commonplace</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả so sánh máy dịch giọng nói với TV màn hình phẳng treo tường – đều là những thứ con người đã mơ ước và hình dung từ rất lâu trước khi chế tạo được. Khi công nghệ phát triển, việc chúng xuất hiện và trở nên phổ biến là điều tất yếu theo tiến trình, không có gì đáng ngạc nhiên (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"296\">not a surprising development</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">30. B. The reluctance to do this is understandable. — {What does the writer say about sharing earpieces?}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“We find that there’s a <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"35\">barrier with sharing one of the earphones with a stranger</strong>,” says Ochoa. <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"107\">That can’t have been totally unexpected</strong>.</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc mọi người có rào cản/ngại ngần (barrier) chia sẻ tai nghe với người lạ là điều \"không nằm ngoài dự đoán\" (can''t have been totally unexpected). Cụm này đồng nghĩa với việc sự lưỡng lự/ngại ngần đó là hoàn toàn có thể hiểu được (<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"244\">understandable</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('72d5d0fb-fdd7-4a32-b154-0283f2d7025b', '83f81a59-7c9b-4b10-b20a-c67071a7605a', 'fillup', 'Questions 20–22', '<p style="text-align: center;" data-path-to-node="8"><span style="font-size: 12pt;"><strong data-path-to-node="8" data-index-in-node="0">The biological price of decision-making</strong></span></p>
<p data-path-to-node="9">Even when people attempt to be {rational}, they experience ‘decision fatigue’ if they make several decisions in a row. They are not aware of how {tired} they are, but it is increasingly more difficult for their brains to make decisions as the day progresses. After making many decisions in one day, the brain seeks {shortcuts} in order to conserve energy. The person may fail to consider the consequences of their decision or not make a decision at all. Avoiding decisions reduces the immediate strain but can cause difficulties later.</p>', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">20. Đáp án: {rational}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “No matter how <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"26\">rational</strong> people try to be, they can’t make decision after decision without paying a biological price.” (Đoạn A).</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ ra rằng dù con người có cố gắng hành động theo lý trí (<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"79\">rational</strong>) đến đâu, họ vẫn không thể tránh khỏi việc tiêu tốn năng lượng sinh học khi phải đưa ra các quyết định liên tục. Sự tỉnh táo về mặt lý trí sẽ bị bào mòn bởi sự mệt mỏi sinh học này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">21. Đáp án: {tired}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The experiments confirmed the 19th-century notion of willpower being like a muscle that became <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"107\">tired</strong> with use…” (Đoạn B).</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả sử dụng phép so sánh để giải thích bản chất của ý chí. Ý chí không phải là vô tận; nó giống như một bó cơ, càng sử dụng nhiều để kiểm soát bản thân thì nó càng trở nên mệt mỏi (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"197\">tired</strong>) và yếu đi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">22. Đáp án: {shortcuts}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The more choices one makes throughout the day… eventually it [the brain] looks for <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"97\">shortcuts</strong>…” (Đoạn A).</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi não bộ rơi vào trạng thái quá tải do phải lựa chọn quá nhiều, để tiết kiệm năng lượng, nó sẽ không suy nghĩ thấu đáo nữa mà tìm đến các “lối tắt” (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"163\">shortcuts</strong>). Những lối tắt này thường dẫn đến các quyết định bốc đồng hoặc chọn theo mặc định.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('03ddd125-2f71-4d20-b599-53cd21a454e9', '60aad45b-9e50-476e-9142-89e5624334f4', 'fillup', 'Questions 1–10', '<p data-start="94" data-end="169">Complete the notes below</p>
<p data-start="94" data-end="169">Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p><strong><span style="font-size: 14pt;">Beach Heads Travel</span></strong></p>
<p><span style="font-size: 12pt;"><strong>Customer Request Sheet</strong></span></p>
<p><strong data-start="226" data-end="237">Example</strong></p>
<p>Name: Duncan White</p>
<p>Group details: three adults and two children</p>
<p>Date of arrival: {October 15| October 15th| 15th October| 15 October} (staying for 2 weeks)</p>
<p data-start="364" data-end="375"><strong>Week One</strong></p>
<p data-start="377" data-end="395">Accommodation:</p>
<ul data-start="396" data-end="464">
<li data-start="396" data-end="426">
<p>Book a {hotel} on the beach</p>
</li>
<li data-start="427" data-end="464">
<p>Budget is around $ {175} a night</p>
</li>
</ul>
<p data-start="466" data-end="481">Activities:</p>
<ul data-start="482" data-end="657">
<li data-start="482" data-end="552">
<p>The children want to go {sailing} – arrange for them to have a {class}</p>
</li>
<li data-start="553" data-end="603">
<p>Book a time for Susan and Jenny to play {golf}</p>
</li>
<li data-start="604" data-end="657">
<p>Duncan wants to go {fishing} – send some information</p>
</li>
</ul>
<p data-start="664" data-end="675"><strong>Week Two</strong></p>
<p data-start="677" data-end="695">Accommodation:</p>
<p>National Park – book a {caravan} ($100 per night)</p>
<p data-start="744" data-end="759">Activities:</p>
<ul data-start="760" data-end="827">
<li data-start="760" data-end="790">
<p>Arrange a {massage} for Jenny</p>
</li>
<li data-start="791" data-end="827">
<p>Send Duncan a {menu} for Marco’s</p>
</li>
</ul>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 1: BEACHHEADS TRAVEL CUSTOMER REQUEST</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Pam:</strong> Beachheads Travel, Pam speaking.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Duncan:</strong> Hi, my name is Duncan. I’m hoping you’ll be able to help me organise a trip to Beachheads.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Pam:</strong> Sure. Let me just fill in our customer request sheet while I’m speaking to you. Could you tell me your name again, please?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Duncan:</strong> Yes, it’s Duncan. Duncan White.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Pam:</strong> OK. And is the trip just for yourself?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Duncan:</strong> No, there’s three adults—myself, my wife and my mother—and our two daughters, Chloe and Eden.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Pam:</strong> So when are you thinking of travelling?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Duncan:</strong> During the next school holidays. So they start on October 12th, don’t they?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Pam:</strong> Yes, but we’ll be arriving on the 15th and we want to stay for a fortnight.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Pam:</strong> Right, got all that. Now I’ll just take a few notes about the type of holiday you want so I can make the bookings for you. Have you thought about where you want to stay while you’re here in the first week?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Duncan:</strong> We’d like a bit of luxury, and we’re planning on staying in a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"70\">(1) hotel</strong></span> on the beach. If possible, that’ll be so much better than a campsite. We usually stay in a tent when we go away, but we’re going to treat ourselves this time.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Pam:</strong> And do you have a figure in mind for how much you’d like to spend? Are we likely to get anything for under $150 a night?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Duncan:</strong> Hmm, not really. You’d have to spend at least <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"54\">(2) 175</strong></span> for a big enough room.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Pam:</strong> Okay, we can stretch to that. I’ll just have to stop myself thinking that when we go camping, we only pay about $200 for a whole week! Well, I’m sure it will be worth it. I can also organise some activities for your first week. Is there anything your daughters would particularly like to do?</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Duncan:</strong> They want to try<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"17\" data-index-in-node=\"25\">(3) sailing</strong> </span>this year. Last year it was surfing—they were mad about it.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Pam:</strong> Kids change their minds a lot, don’t they? Mine are into cycling at the moment. I know someone who can teach them to sail. Would you like me to organise a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"160\">(4) class</strong></span> for them?</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Duncan:</strong> Wonderful. We’re bringing our own boat with us.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Pam:</strong> And what about your wife and your mother?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Duncan:</strong> Well, my mother Susan goes bowling when she’s in Brisbane, but my wife Jenny doesn’t really like it. She loves bush walking, but obviously my mother can’t manage that.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Pam:</strong> Can I suggest <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"22\" data-index-in-node=\"19\">(5) golf</strong></span> for them both? It’s a gentler kind of walk. There’s a beautiful course here with magnificent views of the sea.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Duncan:</strong> Sounds perfect. OK, I’ll organise a time. Thanks. Could you send me some leaflets about <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"96\">(6) fishing</strong></span> in the area? I’d like to take the boat out myself.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Pam:</strong> Sure, there are some good spots around. Great.</p>\n<hr data-path-to-node=\"25\" />\n<h3 data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">WEEK TWO: NATIONAL PARK (Questions 8–10)</strong></h3>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Pam:</strong> Okay, so let’s think about the second week. Now we want something totally different. We’d like to stay up in the mountains in the National Park.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Duncan:</strong> Very nice. And what kind of accommodation are you thinking of? There are some beautiful houses you can rent.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Pam:</strong> Yes, we did think about renting a house, but I’m worried about the cost. Is there anything a bit cheaper, say a caravan or even a cabin?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Duncan:</strong> It’ll have to be a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"27\">(7) caravan</strong></span> because they don’t have cabins at the campground, but the standard is very high.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Pam:</strong> How much does it cost?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Duncan:</strong> $100 a night, but they’re very roomy with all mod cons. The campground’s also in a really good spot. What activities are you thinking of doing in that second week?</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Pam:</strong> Well, it’s actually going to be my wife’s birthday, so I’d like to do something a bit special for her.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Duncan:</strong> I can book a really nice <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"34\" data-index-in-node=\"33\">(8) massage</strong></span> for her after lunch on that day.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Pam:</strong> Lovely. Or would she rather try something more adventurous, like a walk in the treetops? It’s really exciting—you go along a really high wooden bridge.</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Duncan:</strong> Oh no, she’d be terrified! Stick with your first idea. Are there any nice places to eat near the campground?</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Pam:</strong> Yes, there’s a fantastic wood-fired pizza restaurant called Marco’s.</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Duncan:</strong> Oh good! I’ve got two very fussy daughters. Could you send me their <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"38\" data-index-in-node=\"76\">(9) menu</strong></span> so we can check?</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Pam:</strong> It’ll be OK, no problem, Duncan. Now while I remember…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('bad2ba07-d2d7-4275-8d73-66bcbb46acea', 'c905f154-4bd4-4dfc-9551-66e20062ece0', 'radio', 'Questions 11 – 14', NULL, '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Choose the correct letter, <strong>A</strong>, <strong>B</strong>, or <strong>C</strong>.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 12pt;"><strong>Canadian Festival Theatre</strong></span></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "A. They can see a second play at a reduced price"}, {"content": "B. They can buy two tickets and get two free"}, {"content": "C. They can get a discount on Mondays"}], "question": "What special offer is there for regular theatre-goers in this season?"}, {"correct": 2, "options": [{"content": "A. They are handed out at the theatre"}, {"content": "B. They provide information on the actors"}, {"content": "C. They give ideas for discussion"}], "question": "What information is given about the study guides?"}, {"correct": 1, "options": [{"content": "A. It is only for those over 65"}, {"content": "B. It applies to a number of productions"}, {"content": "C. It includes a 5% reduction on gifts"}], "question": "What information is given about the ''Bring a friend'' special?"}, {"correct": 0, "options": [{"content": "A. He may retire from acting soon"}, {"content": "B. He writes his own plays"}, {"content": "C. He prefers acting in films to performing live"}], "question": "What does Michael say about the actor Christopher Plunket?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 2: CANADIANA FESTIVAL THEATRE SEASON</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Host:</strong> Michael McKay, the executive director of the Canadiana Festival Theatre is here with us to talk about the season starting in June. Welcome!</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Michael:</strong> Thank you. We have an amazing season this year with some great deals for our clients. You know, we have a lot of regular theater-goers who will be happy to know that we have some great specials for the upcoming season. For example, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"241\">(11) if you order two tickets to any play performed at the theater, you can get 50% off the price of the next play [Answer: A – second play at reduced price]</strong> </span>we put on. This replaces the special offer we had last season, which was for 50% off all performances on Mondays.</p>\n<p data-path-to-node=\"5\">It is good to get youth interested in theater, so many schools arrange class trips to our theater. This year, we will send a special study guide to each class so the students can familiarize themselves with the play beforehand. Having some background information always makes the experience of watching the actors perform the play more enjoyable. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"347\">(12) Each guide has suggestions for classroom discussion [Answer: C]</strong></span> after seeing the show, which teachers find useful for a follow-up activity.</p>\n<p data-path-to-node=\"6\">Also, we mustn’t forget the “Bring a Friend” special for our senior citizens on Tuesday and Wednesday afternoons. Everyone over 60 can buy one ticket and get one free. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"168\">(13) The offer includes all the musicals plus the plays [Answer: B – a number of productions]</strong></span>, so there is lots of choice. We also include $5 off any gift shop purchase for those clients who spend more than $30 there.</p>\n<p data-path-to-node=\"7\">So, what would you say is the best play you have this year?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Michael:</strong> Ha! All the plays are great, but the “must-see” play is called <em data-path-to-node=\"8\" data-index-in-node=\"72\">Something to Say</em>. It stars the amazing actor Christopher Plunkett.<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"8\" data-index-in-node=\"139\">(14) This likely will be the last year we see him perform [Answer: A – retire soon]</strong></span> as he has been on stage for over 60 years. Actually, for the first time, he helped write this play, and it really is a commentary on his amazing career as an actor. You may have seen him in supporting roles in movies, but acting on stage is his first love.</p>\n<hr data-path-to-node=\"9\" />\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">THE SEASON’S MUSICALS (Questions 15–20)</strong></h3>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Michael:</strong> Now let’s talk about the season’s musicals.</p>\n<p data-path-to-node=\"12\">The first one is called <strong data-path-to-node=\"12\" data-index-in-node=\"24\"><em data-path-to-node=\"12\" data-index-in-node=\"24\">The Climb</em></strong>. Of course, the best part is that we have that really amazing singer Justin McDonald playing the part of the hero. It is an inspiring story of a man called Steven who starts working for a newspaper in a very junior job in the mail room. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"271\">(15) After many years and many promotions, he finally gets to the top position [Answer: B – achieving success]</strong></span>. He becomes editor-in-chief of the newspaper.</p>\n<p data-path-to-node=\"13\">Then we have that wonderful classic that we show every two years because it is so popular: <strong data-path-to-node=\"13\" data-index-in-node=\"91\"><em data-path-to-node=\"13\" data-index-in-node=\"91\">The Voyagers</em></strong>. It is a wonderful story of a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"134\">(16) Canadian farming family in the late 1800s [Answer: A – different century]</strong></span>, and how they settled their land near Kingston, Ontario. The musical gives a good description of the times, the struggles and the way of life in that period.</p>\n<p data-path-to-node=\"14\">The next musical, <strong data-path-to-node=\"14\" data-index-in-node=\"18\"><em data-path-to-node=\"14\" data-index-in-node=\"18\">Joey Brown</em></strong>, is a comical story of a piano player who writes songs for kids’ TV shows. However, he ends up having a terrible time when he gets a new boss who always criticizes him and makes his life difficult. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"227\">(17) Poor Joey has to learn how to win over the boss [Answer: H – handling conflict]</strong></span>. The show has a couple of funny twists and a surprise ending.</p>\n<p data-path-to-node=\"15\">In <strong data-path-to-node=\"15\" data-index-in-node=\"3\"><em data-path-to-node=\"15\" data-index-in-node=\"3\">Main Street</em></strong>, Karen Heinz stars in the true story of a young woman whose dream is to compete in the Olympics. She is such a powerful actress in this role. It is about a gymnast who is <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"186\">(18) crushed when, during a practice session, she breaks her ankle just one week before the games [Answer: E – experiencing disappointment]</strong>.</span></p>\n<p data-path-to-node=\"16\">Now for <strong data-path-to-node=\"16\" data-index-in-node=\"8\"><em data-path-to-node=\"16\" data-index-in-node=\"8\">Milly and Mike</em></strong>, what a story this is. Stephanie James and Peter Doomis are only 10 years old, but they star in the musical as the twins Milly and Mike. They have a wonderful <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"182\">(19) upbringing with their grandmother, who teaches them life’s lessons [Answer: D – growing up]</strong></span> through song.</p>\n<p data-path-to-node=\"17\">The final must-see is so whimsical. In <strong data-path-to-node=\"17\" data-index-in-node=\"39\"><em data-path-to-node=\"17\" data-index-in-node=\"39\">Windswept</em></strong>,<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"17\" data-index-in-node=\"50\">(20) a land of imaginary creatures, the flowers and trees dance and the enchanted animals talk [Answer: F – magical place]</strong></span>. It is delightful and we even have a very talented actor who is amazing as he travels with us through the world of make-believe. Kids love this one.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Michael:</strong> That all sounds wonderful. Now, tell me about the restaurants in the theater district…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('50cbe215-8c90-43f9-8024-d689dfb1a99b', 'abae79a8-e023-4414-ba40-5090e823301c', 'matching', 'Questions 28–32', '', '<p>Choose the correct heading for paragraphs A–E from the list of headings below.</p>
<p>Write the correct number, i–ix, in boxes 28–32 on your answer sheet.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i Gold in the rubbish"}, {"optionText": "ii A big find 30 metres down"}, {"optionText": "iii A profitable hobby becomes more popular"}, {"optionText": "iv Metal detectors and shovels are tools of the trade"}, {"optionText": "v A valuable find under a rock"}, {"optionText": "vi A fortunate change of plan"}, {"optionText": "vii Profitable dreams"}, {"optionText": "viii Following an old watercourse leads to success"}, {"optionText": "ix An amateur realises his dream after a week’s work"}], "matchingItems": []}', 'null', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">28. Đoạn A: {vi} A fortunate change of plan</strong></p>\n<ul data-path-to-node=\"5,0,1\">\n<li>\n<p data-path-to-node=\"5,0,1,0,0\"><strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"11\">“they opted to <strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"26\">postpone their Blayney trip</strong> and <strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"58\">instead</strong> take their metal detectors to Windeyer”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,0,1,1,0\"><strong data-path-to-node=\"5,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thay đổi kế hoạch ban đầu (không đi Blayney nữa mà đi Windeyer) đã dẫn đến việc tìm thấy cục vàng trị giá $12,000.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">29. Đoạn B: {vii} Profitable dreams</strong></p>\n<ul data-path-to-node=\"5,1,1\">\n<li>\n<p data-path-to-node=\"5,1,1,0,0\"><strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"11\">“…prospectors spend hours in the bush… <strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"54\">dreaming of striking it rich</strong>… there are enough success stories to <strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"122\">fuel the fever</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,1,1,0\"><strong data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về giấc mơ làm giàu của những người tìm vàng nghiệp dư và sự phát triển của sở thích này.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">30. Đoạn C: {v} A valuable find under a rock</strong></p>\n<ul data-path-to-node=\"5,2,1\">\n<li>\n<p data-path-to-node=\"5,2,1,0,0\"><strong data-path-to-node=\"5,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,2,1,0,0\" data-index-in-node=\"11\">“Clarke exposed a <strong data-path-to-node=\"5,2,1,0,0\" data-index-in-node=\"29\">large stone</strong>… he levered the stone aside… revealed a gold nugget…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,1,1,0\"><strong data-path-to-node=\"5,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi lật một tảng đá lớn sang một bên, Eric Clarke đã tìm thấy cục vàng 100 gram.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">31. Đoạn D: {viii} Following an old watercourse leads to success</strong></p>\n<ul data-path-to-node=\"5,3,1\">\n<li>\n<p data-path-to-node=\"5,3,1,0,0\"><strong data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"11\">“…traced the bed of an <strong data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"36\">ancient river</strong> to uncover a collection of small gold nuggets”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,1,1,0\"><strong data-path-to-node=\"5,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Ancient river” (dòng sông cổ) chính là “old watercourse”. Việc theo dấu dòng sông cạn này đã mang lại thành công.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"5,4,0\"><strong data-path-to-node=\"5,4,0\" data-index-in-node=\"0\">32. Đoạn E: {i} Gold in the rubbish</strong></p>\n<ul data-path-to-node=\"5,4,1\">\n<li>\n<p data-path-to-node=\"5,4,1,0,0\"><strong data-path-to-node=\"5,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,4,1,0,0\" data-index-in-node=\"11\">“spent much of the evening uncovering an assortment of <strong data-path-to-node=\"5,4,1,0,0\" data-index-in-node=\"66\">junk: corrugated roofing iron, bolts, nails and old cutlery</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,4,1,1,0\"><strong data-path-to-node=\"5,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Evelyn Bahr đã tìm thấy vàng ngay tại khu vực chứa đầy rác thải kim loại (rubbish/junk).</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('62e78794-0394-4b17-b4b1-7db05145c30a', '3b9d7e7e-e529-4ba0-bf1d-5e9f7c719599', 'matrix', 'Questions 14–19', '', '<p><span class="citation-11980 citation-11981 citation-end-11981">Which section contains the following information?</span></p>
<p><span class="citation-11978 citation-11979">Write the correct letter, </span><strong data-path-to-node="24" data-index-in-node="121"><span class="citation-11978 citation-11979">A–H</span></strong><span class="citation-11978 citation-11979 citation-end-11979">, in boxes 14–19 on your answer she</span><span class="citation-11978 citation-end-11978">et.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Two things at which leaf-cutter ants have succeeded but humans have failed.", "correctCategoryLetter": "H"}, {"itemText": "A comparison between the nests of leaf-cutter ants and lower attine ants.", "correctCategoryLetter": "C"}, {"itemText": "An assessment of the impact leaf-cutter ants have on their environment.", "correctCategoryLetter": "B"}, {"itemText": "The effect Escovopsis has on ant communities.", "correctCategoryLetter": "F"}, {"itemText": "The advantage for lower attine ants of growing a range of fungi.", "correctCategoryLetter": "G"}, {"itemText": "The discovery of the age of the attine-ant fungi.", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Two things at which leaf-cutter ants have succeeded but humans have failed. — {H}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Astoundingly, the leaf-cutter ants are accomplishing <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"65\">feats beyond the power of humans</strong>: they are growing a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"118\">monocultural crop</strong> year after year without disaster, and they are using an <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"192\">antibiotic</strong>… so wisely that… they are not provoking antibiotic resistance…” (Đoạn H)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hai việc kiến làm tốt hơn người là: canh tác độc canh bền vững và sử dụng kháng sinh mà không bị kháng thuốc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. A comparison between the nests of leaf-cutter ants and lower attine ants. — {C}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The leaf-cutters use fresh vegetation; the other groups, known as the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"82\">lower attines because their nests are smaller and their techniques more primitive</strong>…” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C so sánh trực tiếp kích thước tổ và kỹ thuật giữa hai nhóm kiến.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. An assessment of the impact leaf-cutter ants have on their environment. — {B}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Biologists believe <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"31\">15 percent of the leaf production of tropical forests disappears</strong> down the nests of leaf-cutter ants.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Con số 15% sản lượng lá rừng bị tiêu thụ chính là đánh giá về tác động môi trường của loài kiến này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. The effect Escovopsis has on ant communities. — {F}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…can <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"19\">devastate a fungus garden</strong> in a couple of days… other ants won’t go near it and the ants associated with the garden just <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"141\">starve to death</strong>.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác động của nấm Escovopsis là phá hủy vườn nấm và khiến đàn kiến chết đói.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. The advantage for lower attine ants of growing a range of fungi. — {G}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…possible reason for the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"39\">different varieties of fungus</strong> in the lower attine mushroom gardens to <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"109\">stay one step ahead of the relentless Escovopsis</strong>.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lợi thế của việc trồng nhiều loại nấm là giúp chúng luôn đi trước một bước trước sự tấn công của ký sinh trùng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. The discovery of the age of the attine-ant fungi. — {D}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…found that the leaf-cutters’ fungus was descended from a single pure strain, propagated for <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"107\">at least 23 million years</strong>.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Con số 23 triệu năm chính là tuổi thọ (age) của dòng nấm này.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('f37b3e34-018a-44f0-b149-7f63fb591e4e', '3b9d7e7e-e529-4ba0-bf1d-5e9f7c719599', 'matrix', 'Questions 20–24', '', '<p>Classify the following descriptions as relating to</p>
<p data-path-to-node="29">Write the correct letter, <strong data-path-to-node="29" data-index-in-node="26">A, B or C</strong>, in boxes 20–24 on your answer sheet.</p>
<p data-path-to-node="30,0,0"> </p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of options", "matrixItems": [{"itemText": "the use of dead vegetation to cultivate their fungus", "correctCategoryLetter": "B"}, {"itemText": "very small ants that keep the fungus free of foreign organisms", "correctCategoryLetter": "A"}, {"itemText": "the ability to safely eat harmful plants", "correctCategoryLetter": "C"}, {"itemText": "the cultivation of a single fungus", "correctCategoryLetter": "A"}, {"itemText": "a nest with a very large number of rooms for growing fungus", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Leaf-cutting ants", "categoryLetter": "A"}, {"categoryText": "Lower attines", "categoryLetter": "B"}, {"categoryText": "Both leaf-cutting ants and lower attine ants", "categoryLetter": "C"}]}', '[{"content": "<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">20. The use of dead vegetation to cultivate their fungus — {B: Lower attines}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the other groups [lower attines]… feed their gardens with <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"75\">similar leaves that have fallen on the ground and insects that lie on the forest floor</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lá rụng và côn trùng chết trên nền rừng chính là thực vật chết (dead vegetation).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">21. Very small ants that keep the fungus free of foreign organisms — {A: Leaf-cutting ants}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…<strong data-path-to-node=\"21,0,0\" data-index-in-node=\"15\">leaf-cutter worker ants come in made-to-fit sizes</strong>… and <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"72\">miniature workers</strong> to seed them with fungus and <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"119\">clean off alien growths</strong>.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chỉ nhóm Leaf-cutter mới được mô tả là có sự phân hóa kích thước thợ, trong đó kiến thợ nhỏ (miniature) làm nhiệm vụ dọn dẹp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">22. The ability to safely eat harmful plants — {C: Both}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"16\">attine ants’ achievement</strong> is remarkable because it allows them to consume… harvest of tropical forests whose <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"126\">leaves are laden with poisonous chemicals</strong>.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cả bộ tộc kiến Attine (bao gồm cả leaf-cutters và lower attines) đều có khả năng này nhờ sự tiêu hóa của nấm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">23. The cultivation of a single fungus — {A: Leaf-cutting ants}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"16\">pure strain</strong> of fungus grown by the <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"51\">leaf-cutters</strong>…” (Đoạn E) và “…the <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"88\">pure clone cultivation of the leaf-cutters</strong>…” (Đoạn D).</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">24. A nest with a very large number of rooms for growing fungus — {A: Leaf-cutting ants}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “A <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"14\">single leaf-cutter nest</strong> may contain a <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"52\">thousand such chambers</strong>…” (Đoạn A)</p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chỉ tổ của kiến leaf-cutter mới được mô tả là có quy mô khổng lồ với hàng nghìn ngăn (rooms/chambers).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('697c819f-4bdb-46de-a8b4-31a79d637416', '3b9d7e7e-e529-4ba0-bf1d-5e9f7c719599', 'radio', 'Questions 25-26', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong></p>
<p>Write the correct letter in boxes 25 and 26 on your answer sheet.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A No previous work had been done in this area."}, {"option_text": "B Earlier studies did not support his theory."}, {"option_text": "C Textbooks on this subject lacked specific detail."}, {"option_text": "D Currie''s initial theory had proven to be incorrect."}], "question": "What does the writer say about Cameron Currie''s research?"}, {"correct": 3, "options": [{"option_text": "A has a white covering"}, {"option_text": "B is covered in wax."}, {"option_text": "C is poisonous to humans."}, {"option_text": "D has a substance useful to humans."}], "question": "Using a microscope, Currie was the first to discover that the body of attine ants"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">25. What does the writer say about Cameron Currie’s research? — {B} Earlier studies did not support his theory.</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Currie felt there had to be a parasite… But <strong data-path-to-node=\"31,0,0\" data-index-in-node=\"58\">a century of ant research had provided no evidence for his idea</strong>. Textbooks describe how leaf-cutter ants scrupulously weed their gardens…” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Suốt 100 năm nghiên cứu trước đó không tìm thấy bằng chứng và sách giáo khoa cũng nói ngược lại ý của Currie, tức là các nghiên cứu trước đó không ủng hộ giả thuyết của ông.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">26. Using a microscope, Currie was the first to discover that the body of attine ants — {D} has a substance useful to humans.</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…after examining it under a <strong data-path-to-node=\"33,0,0\" data-index-in-node=\"42\">microscope</strong>, Currie discovered… a particular kind of bacterium… the <strong data-path-to-node=\"33,0,0\" data-index-in-node=\"113\">source of half the antibiotics used in medicine</strong>.” (Đoạn H)</p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Currie dùng kính hiển vi để phát hiện ra lớp phủ trên thân kiến thực chất là vi khuẩn tạo ra <strong data-path-to-node=\"33,1,0\" data-index-in-node=\"105\">kháng sinh (antibiotics)</strong> – một chất cực kỳ hữu ích cho y học loài người.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('9753ecdd-ca8b-44b0-9b02-4dd14d500d78', '9f70f12e-2b99-4bf8-b469-dd04e2a0b38c', 'matching', 'Questions 14–19', '', '<p>Write the correct number, <strong data-path-to-node="6" data-index-in-node="148">i–vii</strong>, in boxes 14–19 on your answer sheet.</p>', 'matching_paragraph_information', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "i The behaviour of a small animal expanding its territory"}, {"optionText": "ii The urban environment encouraging the spread of imported flora and fauna"}, {"optionText": "iii Insects that thrive in urban areas"}, {"optionText": "iv A creature which likes rubbish"}, {"optionText": "v Creatures which change their shape and colour"}, {"optionText": "vi Why natural scientists are interested in studying urban areas"}, {"optionText": "vii Changes in the urban built environments encourage particular species"}], "matchingItems": []}', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. Paragraph A — {vi. Why natural scientists are interested in studying urban areas}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“…a growing number [of ecologists] have <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"53\">turned their attention</strong> to the complex interactions of the wildlife that inhabits <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"134\">concrete jungles</strong>… research is <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"166\">timely</strong>… we need to understand how cities are changing the ecology…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn A giải thích lý do tại sao các nhà sinh thái học (natural scientists) lại chuyển hướng sang nghiên cứu đô thị (urban areas/concrete jungles). Đó là vì dân số thế giới đang tập trung về thành phố và nghiên cứu này mang tính cấp thiết (timely).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. Paragraph B — {iv. A creature which likes rubbish}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“…it is known as the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"34\">‘garbage turkey’</strong>. The bird’s reputation for digging through inner-city <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"105\">bins</strong> and scavenging street <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"132\">garbage</strong>…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A creature” ở đây chính là chim <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"45\">white ibis</strong>. Đặc điểm nổi bật nhất được nhắc đến là thói quen bới rác (garbage/bins) để tìm thức ăn, đúng với tiêu đề “sinh vật thích rác”.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. Paragraph C — {vii. Changes in the urban built environments encourage particular species}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“…homeowners prefer to landscape their backyards with <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"67\">tall trees and manicured lawns</strong>… Gardens filled with flowering plants and fruit trees <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"154\">favour omnivorous birds</strong> such as currawongs…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C mô tả việc thay đổi cách làm vườn của con người (từ bụi rậm sang cây cao và cỏ) đã tạo điều kiện thuận lợi (favour/encourage) cho một số loài chim cụ thể (particular species) như noisy miner, đồng thời làm suy giảm các loài chim nhỏ.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. Paragraph D — {iii. Insects that thrive in urban areas}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Many <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"17\">invertebrates</strong>, such as the golden orb-weaver <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"62\">spider</strong> and the blue triangle <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"91\">butterfly</strong>, also relish living in the city… Hochuli has also found some varieties of <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"177\">ant</strong>…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Insects” (côn trùng) ở đây đại diện cho nhóm động vật không xương sống (invertebrates) như nhện, bướm và kiến. Đoạn này tập trung giải thích lý do tại sao chúng lại phát triển mạnh (thrive/relish living) ở thành phố (như nhiệt độ ấm hơn).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. Paragraph E — {i. The behaviour of a small animal expanding its territory}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“…the rabbit-sized, long-nosed <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"44\">bandicoot</strong> has discovered the advantages of <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"87\">venturing out to grassy suburban backyards</strong>… Dr Price is trying to understand what encourages the little mammal into urban environments.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Small animal” chính là loài chuột túi bandicoot. Đoạn văn mô tả hành vi của chúng khi mạo hiểm rời khỏi các khu bụi rậm để tiến vào (expanding its territory) các khu vườn ở ngoại ô để kiếm ăn.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. Paragraph F — {ii. The urban environment encouraging the spread of imported flora and fauna}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“It’s not just native wildlife… <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"45\">Non-native species</strong> such as black rodents, cockroaches and foxes… But <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"116\">weeds</strong> are the pest that has gained the most advantage.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Imported flora and fauna” (động thực vật nhập khẩu) tương ứng với “Non-native species” (loài không bản địa) và “introduced plant life/weeds” (cỏ dại ngoại lai). Đoạn văn giải thích cách môi trường đô thị (hệ thống nước thải, bê tông) giúp những loài này xâm nhập và lấn át loài bản địa.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('1a124874-642c-4711-b8fa-4b007c923be7', '9f70f12e-2b99-4bf8-b469-dd04e2a0b38c', 'matrix', 'Questions 20–23', '', '<p data-path-to-node="11">Write the correct letter, <strong data-path-to-node="11" data-index-in-node="176">A, B, C</strong> or <strong data-path-to-node="11" data-index-in-node="187">D</strong>, in boxes 20–23 on your answer sheet<em data-path-to-node="11" data-index-in-node="150">.</em></p>
<p data-path-to-node="12"><strong data-path-to-node="12" data-index-in-node="0">NB</strong> <em data-path-to-node="12" data-index-in-node="3">You may use any letter more than once.</em></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Researchers", "matrixItems": [{"itemText": "It is not clear why one small animal is moving from its natural environment.", "correctCategoryLetter": "D"}, {"itemText": "Hot weather might positively affect the health of a species.", "correctCategoryLetter": "A"}, {"itemText": "Sydney’s residential gardens suit some species better than others.", "correctCategoryLetter": "C"}, {"itemText": "Research into the natural world’s responses to urban settings is vital.", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Dieter Hochuli", "categoryLetter": "A"}, {"categoryText": "John Martin", "categoryLetter": "B"}, {"categoryText": "Richard Major", "categoryLetter": "C"}, {"categoryText": "Catherine Price", "categoryLetter": "D"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">20. It is not clear why one small animal is moving from its natural environment. — {D. Catherine Price}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"21\">Catherine Price</strong>, a research associate… says: ‘<strong data-path-to-node=\"5,0,0\" data-index-in-node=\"69\">We don’t know</strong> if it’s an overflow from the park, or if they’ve got particular survival traits…’”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “We don’t know” (Chúng tôi không biết) đồng nghĩa với “It is not clear” (Không rõ ràng). Catherine Price đang nói về loài <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"138\">bandicoot</strong> (small animal) và lý do tại sao chúng lại rời công viên để vào khu dân cư.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">21. Hot weather might positively affect the health of a species. — {A. Dieter Hochuli}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">Professor Hochuli</strong> and his team are trying to understand why… the golden orb spiders in Sydney are <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"121\">fatter and fitter</strong> than species found elsewhere… whether it’s more food or the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"201\">urban heat</strong>…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Fatter and fitter” (béo hơn và khỏe hơn) tương ứng với “positively affect the health”. “Urban heat” (nhiệt độ đô thị – thường cao hơn 4 độ) tương ứng với “Hot weather”. Dieter Hochuli đang nghiên cứu xem liệu cái nóng có phải là lý do khiến nhện khỏe hơn không.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">22. Sydney’s residential gardens suit some species better than others. — {C. Richard Major}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"21\">Richard Major</strong> says: ‘The predominant driver in the decline of small birds is that <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"103\">we’ve made a suitable environment for native noisy miners</strong>.’”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Richard Major chỉ ra rằng cách làm vườn hiện nay (residential gardens) đã tạo ra một môi trường phù hợp (suitable environment) cho loài <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"148\">noisy miners</strong> nhưng lại khiến các loài chim nhỏ suy giảm (suit some species better than others).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">23. Research into the natural world’s responses to urban settings is vital. — {A. Dieter Hochuli}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"21\">Associate Professor Dieter Hochuli</strong>… believes that ‘<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"74\">we need to understand</strong> how cities are changing the ecology…’”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “We need to understand” (Chúng ta cần phải hiểu) thể hiện tính chất quan trọng, cấp thiết (vital). “Urban settings” chính là môi trường thành phố (cities). Dieter Hochuli nhấn mạnh tầm quan trọng của việc nghiên cứu cách các loài thích nghi với đô thị.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('203d3063-6f16-42f1-a9aa-eebbcdc8d989', '9f70f12e-2b99-4bf8-b469-dd04e2a0b38c', 'fillup', 'Questions 24–26', '<p data-path-to-node="17">Complete the summary below.</p>
<p data-path-to-node="17">Choose <strong data-path-to-node="17" data-index-in-node="35">ONE WORD ONLY</strong> from the passage for each answer.</p>
<p data-path-to-node="17">Write your answers in boxes 24–26 on your answer sheet.</p>
<p data-path-to-node="18"><span style="font-size: 12pt;"><strong data-path-to-node="18" data-index-in-node="0">Seeking comfort in city living</strong></span></p>
<p data-path-to-node="19">It’s not only native plants and animals that are adapting to city life; non-native plants and animals are also adapting. Examples of successful ‘city dwellers’ include small, non-native rats and non-native insects such as {cockroaches} However, what causes most problems in the city is weeds. Michelle Leishman, a scientist from Macquarie University, has proven that Sydney’s large areas of {concrete} and its drainage network favour the growth of weeds. Water gathers {chemicals} as it passes from gardens and streets into the city drainage network. This, in turn, creates very good soil for several varieties of rapidly growing non-native plants.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">24. cockroaches — {Examples… include small, non-native rats and non-native insects such as cockroaches}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Non-native species such as black <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"54\">rodents</strong>, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"63\">cockroaches</strong> and foxes have developed survival strategies too.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc liệt kê các loài không bản địa (non-native) bao gồm loài gặm nhấm (rodents – tương ứng với “rats”) và gián (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"128\">cockroaches</strong>). Vì câu hỏi yêu cầu ví dụ về côn trùng (insects), từ chính xác cần điền là “cockroaches”.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">25. concrete — {Sydney’s large areas of concrete and its drainage network favour the growth of weeds.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…Leishman and her colleagues have shown how Sydney’s huge stretches of impermeable <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"106\">concrete</strong>, together with the storm-water system, have helped <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"166\">weeds</strong> infiltrate…”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Michelle Leishman đã chứng minh rằng những dải bê tông (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"68\">concrete</strong>) không thấm nước cùng với hệ thống thoát nước mưa (storm-water system / drainage network) đã tạo điều kiện thuận lợi cho cỏ dại phát triển và xâm nhập.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">26. chemicals — {Water gathers chemicals as it passes from gardens and streets into the city drainage network.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“As rain washes over <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"41\">backyards and roadways</strong>, it collects <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"77\">chemicals</strong> which enter the storm-water system…”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi nước mưa chảy qua các sân sau (gardens/backyards) và đường sá (roadways/streets), nó thu gom các loại hóa chất (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"128\">chemicals</strong>) trước khi đổ vào hệ thống thoát nước. Lượng nước giàu dưỡng chất và hóa chất này sau đó tạo môi trường lý tưởng cho các loài cây ngoại lai phát triển nhanh.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('b89ce4ec-20c3-415f-bb81-aae4eb4c7eab', 'e6765018-69d3-4e49-bb43-b6ee67a9fd2d', 'matching', 'Questions 31–34', '', '<p>Complete each sentence with the correct ending, <strong>A–F</strong>, below.</p>
<p>Write the correct letter, <strong>A–F</strong>, in boxes 31–34 on your answer sheet.</p>', 'matching_sentence_endings', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "but there are concerns about this."}, {"optionText": "as systems do not need to conform to standard practices."}, {"optionText": "but they are far from perfect."}, {"optionText": "despite the noise issues."}, {"optionText": "because translation is immediate."}, {"optionText": "and have an awareness of good manners."}], "matchingItems": [{"questionPart": "Speech translation methods are developing fast in Japan", "correctAnswer": "C"}, {"questionPart": "TV interviews that use translation voiceover methods are successful", "correctAnswer": "E"}, {"questionPart": "Future translation systems should address people appropriately", "correctAnswer": "F"}, {"questionPart": "Users may be able to maintain their local customs", "correctAnswer": "B"}]}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">31. C (but they are far from perfect) — {Speech translation methods are developing fast in Japan but they are far from perfect.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Waibel highlights the significance of certain Asian nations, noting that <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"94\">voice translation has really taken off in countries such as Japan</strong> with a range of systems. <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"185\">There is still a long way to go, though</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hệ thống dịch giọng nói phát triển rất mạnh mẽ, bùng nổ (\"really taken off\" tương ứng với \"developing fast\") ở Nhật Bản. Tuy nhiên, vế sau khẳng định \"there is still a long way to go\" (vẫn còn một chặng đường dài phía trước), đồng nghĩa với việc chúng còn lâu mới hoàn hảo (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"286\">far from perfect</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">32. E (because translation is immediate) — {TV interviews that use translation voiceover methods are successful because translation is immediate.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“A translation system <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"42\">needs to be simultaneous, like the translator’s voice speaking over the foreign politician being interviewed on TV</strong>, rather than in sections that oblige speakers to pause...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả lấy ví dụ về việc dịch lồng tiếng trên TV (translation voiceover) cần phải diễn ra đồng thời, tức thời (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"124\">simultaneous</strong>), chứ không phải dịch theo từng đoạn khiến người nói phải dừng lại chờ đợi. Sự tức thời này tương ứng với vế \"because translation is <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"270\">immediate</strong>\".</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">33. F (and have an awareness of good manners) — {Future translation systems should address people appropriately and have an awareness of good manners.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Systems... will also <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"42\">need to be socially aware by addressing people in the right way</strong>. Some cultural traditions demand solemn respect for academic status, for example, and it is <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"198\">only polite to respect this</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc xưng hô, trò chuyện đúng cách với mọi người (\"addressing people in the right way\" tương ứng với \"address people appropriately\") đòi hỏi máy dịch phải có nhận thức xã hội. Hành động cư xử lịch sự (\"only polite to respect this\") chính là việc nhận thức được các chuẩn mực/phép lịch sự tối thiểu (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"311\">an awareness of good manners</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">34. B (as systems do not need to conform to standard practices) — {Users may be able to maintain their local customs as systems do not need to conform to standard practices.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Etiquette-sensitive artificial translators could <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"70\">relieve people of the need to know these differing cultural norms. At the same time, they might help to preserve local customs</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các máy dịch nhạy bén với nghi thức sẽ giúp người dùng giải phóng/không cần phải biết các chuẩn mực văn hóa khác biệt (\"relieve people of the need to know...\" tương ứng với \"do not need to conform to standard practices\"). Nhờ đó, họ có thể bảo tồn/duy trì phong tục địa phương (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"290\">maintain/preserve local customs</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('2fbdbf3d-7ec9-4f82-bbb6-519e85975d5e', 'a6870343-14eb-4b90-9abd-db97958fe03c', 'matrix', 'Questions 25–30', '', '<p><span class="citation-68677 citation-68678 citation-68679 citation-68680 citation-68681 citation-68682 citation-68683 citation-68684 citation-68685">Choose </span><strong data-path-to-node="5" data-index-in-node="7"><span class="citation-68677 citation-68678 citation-68679 citation-68680 citation-68681 citation-68682 citation-68683 citation-68684 citation-68685">SIX</span></strong><span class="citation-68677 citation-68678 citation-68679 citation-68680 citation-68681 citation-68682 citation-68683 citation-68684 citation-68685"> answers from the box and write the correct letter, </span><strong data-path-to-node="5" data-index-in-node="62"><span class="citation-68677 citation-68678 citation-68679 citation-68680 citation-68681 citation-68682 citation-68683 citation-68684 citation-68685">A–H</span></strong><span class="citation-68677 citation-68678 citation-68679 citation-68680 citation-68681 citation-68682 citation-68683 citation-68684 citation-68685 citation-end-68685">, next to Questions 25–30.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "Opinions", "matrixItems": [{"itemText": "Use of local products", "correctCategoryLetter": "D"}, {"itemText": "Reduction in unnecessary packaging", "correctCategoryLetter": "G"}, {"itemText": "Gluten-free and lactose-free food", "correctCategoryLetter": "C"}, {"itemText": "Use of branded products related to celebrity chefs", "correctCategoryLetter": "B"}, {"itemText": "Development of ''ghost kitchens'' for takeaway food", "correctCategoryLetter": "F"}, {"itemText": "Use of mushrooms for common health concerns", "correctCategoryLetter": "H"}], "matrixCategories": [{"categoryText": "This is only relevant to young people.", "categoryLetter": "A"}, {"categoryText": "This may have disappointing results.", "categoryLetter": "B"}, {"categoryText": "This already seems to be widespread.", "categoryLetter": "C"}, {"categoryText": "Retailers should do more to encourage this.", "categoryLetter": "D"}, {"categoryText": "More financial support is needed for this.", "categoryLetter": "E"}, {"categoryText": "Most people know little about this.", "categoryLetter": "F"}, {"categoryText": "There should be stricter regulations about this.", "categoryLetter": "G"}, {"categoryText": "This could be dangerous.", "categoryLetter": "H"}]}', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('ec67b6fb-d366-4de0-9ac6-4cdb1101abfe', '7b022dc0-7dcc-489a-be22-041d75014750', 'fillup', 'Questions 31–40', '<p data-path-to-node="12">Complete the notes below.</p>
<p data-path-to-node="13">Write <strong data-path-to-node="13" data-index-in-node="6">ONE WORD ONLY</strong> for each answer.</p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; border: 2px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="border-width: 2px; padding: 2px; border-color: #000000;">
<p style="text-align: left;" data-path-to-node="14,0"><span style="font-size: 14pt;"><strong>Céide Fields</strong></span></p>
<ul data-path-to-node="14,1">
<li>
<p id="p-rc_c3c52cddf277798e-560" data-path-to-node="14,1,0,0">an important N<span class="citation-68577 citation-68578 citation-68579 citation-68580 citation-68581 citation-68582 citation-68583 citation-end-68583">eolithic archaeological site in the northwest of Ireland<sup class="superscript" data-turn-source-index="121"><!----></sup></span><span class="citation-68577 citation-68578 citation-68579 citation-68580 citation-68581 citation-68582 citation-end-68582"><sup class="superscript" data-turn-source-index="122"><!----></sup></span><span class="citation-68577 citation-68578 citation-68579 citation-68580 citation-68581 citation-end-68581"><sup class="superscript" data-turn-source-index="123"><!----></sup></span><span class="citation-68577 citation-68578 citation-68579 citation-68580 citation-end-68580"><sup class="superscript" data-turn-source-index="124"><!----></sup></span><span class="citation-68577 citation-68578 citation-68579 citation-end-68579"><sup class="superscript" data-turn-source-index="125"><!----></sup></span><span class="citation-68577 citation-68578 citation-end-68578"><sup class="superscript" data-turn-source-index="126"><!----></sup></span><span class="citation-68577 citation-end-68577"><sup class="superscript" data-turn-source-index="127"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
</ul>
<p id="p-rc_c3c52cddf277798e-561" data-path-to-node="14,2"><strong data-path-to-node="14,2" data-index-in-node="0"><span class="citation-68570 citation-68571 citation-68572 citation-68573 citation-68574 citation-68575 citation-68576 citation-end-68576">Discovery<sup class="superscript" data-turn-source-index="128"><!----></sup></span><span class="citation-68570 citation-68571 citation-68572 citation-68573 citation-68574 citation-68575 citation-end-68575"><sup class="superscript" data-turn-source-index="129"><!----></sup></span><span class="citation-68570 citation-68571 citation-68572 citation-68573 citation-68574 citation-end-68574"><sup class="superscript" data-turn-source-index="130"><!----></sup></span><span class="citation-68570 citation-68571 citation-68572 citation-68573 citation-end-68573"><sup class="superscript" data-turn-source-index="131"><!----></sup></span><span class="citation-68570 citation-68571 citation-68572 citation-end-68572"><sup class="superscript" data-turn-source-index="132"><!----></sup></span><span class="citation-68570 citation-68571 citation-end-68571"><sup class="superscript" data-turn-source-index="133"><!----></sup></span><span class="citation-68570 citation-end-68570"><sup class="superscript" data-turn-source-index="134"><!----></sup></span></strong></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<ul data-path-to-node="14,3">
<li>
<p id="p-rc_c3c52cddf277798e-562" data-path-to-node="14,3,0,0"><span class="citation-68563 citation-68564 citation-68565 citation-68566 citation-68567 citation-68568 citation-68569">In the 1930s, a local teacher realised that stones beneath the bog surface were once<strong> </strong>{walls}</span><span class="citation-68563 citation-68564 citation-68565 citation-68566 citation-68567 citation-68568 citation-68569 citation-end-68569"> .<sup class="superscript" data-turn-source-index="135"><!----></sup></span><span class="citation-68563 citation-68564 citation-68565 citation-68566 citation-68567 citation-68568 citation-end-68568"><sup class="superscript" data-turn-source-index="136"><!----></sup></span><span class="citation-68563 citation-68564 citation-68565 citation-68566 citation-68567 citation-end-68567"><sup class="superscript" data-turn-source-index="137"><!----></sup></span><span class="citation-68563 citation-68564 citation-68565 citation-68566 citation-end-68566"><sup class="superscript" data-turn-source-index="138"><!----></sup></span><span class="citation-68563 citation-68564 citation-68565 citation-end-68565"><sup class="superscript" data-turn-source-index="139"><!----></sup></span><span class="citation-68563 citation-68564 citation-end-68564"><sup class="superscript" data-turn-source-index="140"><!----></sup></span><span class="citation-68563 citation-end-68563"><sup class="superscript" data-turn-source-index="141"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_c3c52cddf277798e-563" data-path-to-node="14,3,1,0"><span class="citation-68556 citation-68557 citation-68558 citation-68559 citation-68560 citation-68561 citation-68562">His {son}</span><span class="citation-68556 citation-68557 citation-68558 citation-68559 citation-68560 citation-68561 citation-68562 citation-end-68562"> became an archaeologist and undertook an investigation of the site:<sup class="superscript" data-turn-source-index="142"><!----></sup></span><span class="citation-68556 citation-68557 citation-68558 citation-68559 citation-68560 citation-68561 citation-end-68561"><sup class="superscript" data-turn-source-index="143"><!----></sup></span><span class="citation-68556 citation-68557 citation-68558 citation-68559 citation-68560 citation-end-68560"><sup class="superscript" data-turn-source-index="144"><!----></sup></span><span class="citation-68556 citation-68557 citation-68558 citation-68559 citation-end-68559"><sup class="superscript" data-turn-source-index="145"><!----></sup></span><span class="citation-68556 citation-68557 citation-68558 citation-end-68558"><sup class="superscript" data-turn-source-index="146"><!----></sup></span><span class="citation-68556 citation-68557 citation-end-68557"><sup class="superscript" data-turn-source-index="147"><!----></sup></span><span class="citation-68556 citation-end-68556"><sup class="superscript" data-turn-source-index="148"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<ul data-path-to-node="14,3,1,1">
<li>
<p id="p-rc_c3c52cddf277798e-564" data-path-to-node="14,3,1,1,0,0"><span class="citation-68549 citation-68550 citation-68551 citation-68552 citation-68553 citation-68554 citation-68555 citation-end-68555">a traditional meth<sup class="superscript" data-turn-source-index="149"><!----></sup></span><span class="citation-68549 citation-68550 citation-68551 citation-68552 citation-68553 citation-68554">od used by local people to dig for {fuel}</span><span class="citation-68549 citation-68550 citation-68551 citation-68552 citation-68553 citation-68554 citation-end-68554"> was used to identify where stones were located<sup class="superscript" data-turn-source-index="150"><!----></sup></span><span class="citation-68549 citation-68550 citation-68551 citation-68552 citation-68553 citation-end-68553"><sup class="superscript" data-turn-source-index="151"><!----></sup></span><span class="citation-68549 citation-68550 citation-68551 citation-68552 citation-end-68552"><sup class="superscript" data-turn-source-index="152"><!----></sup></span><span class="citation-68549 citation-68550 citation-68551 citation-end-68551"><sup class="superscript" data-turn-source-index="153"><!----></sup></span><span class="citation-68549 citation-68550 citation-end-68550"><sup class="superscript" data-turn-source-index="154"><!----></sup></span><span class="citation-68549 citation-end-68549"><sup class="superscript" data-turn-source-index="155"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_c3c52cddf277798e-565" data-path-to-node="14,3,1,1,1,0"><span class="citation-68543 citation-68544 citation-68545 citation-68546 citation-68547 citation-68548 citation-end-68548">carbon dating<sup class="superscript" data-turn-source-index="156"><!----></sup></span><span class="citation-68543 citation-68544 citation-68545 citation-68546 citation-68547 citation-end-68547"> later proved the site was Neolithic.<sup class="superscript" data-turn-source-index="157"><!----></sup></span><span class="citation-68543 citation-68544 citation-68545 citation-68546 citation-end-68546"><sup class="superscript" data-turn-source-index="158"><!----></sup></span><span class="citation-68543 citation-68544 citation-68545 citation-end-68545"><sup class="superscript" data-turn-source-index="159"><!----></sup></span><span class="citation-68543 citation-68544 citation-end-68544"><sup class="superscript" data-turn-source-index="160"><!----></sup></span><span class="citation-68543 citation-end-68543"><sup class="superscript" data-turn-source-index="161"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
</ul>
</li>
<li>
<p id="p-rc_c3c52cddf277798e-566" data-path-to-node="14,3,2,0"><span class="citation-68538 citation-68539 citation-68540 citation-68541 citation-68542">Items are well preserved in the bog because of a lack of {oxygen}</span><span class="citation-68538 citation-68539 citation-68540 citation-68541 citation-end-68541"> .<sup class="superscript" data-turn-source-index="163"><!----></sup></span><span class="citation-68538 citation-68539 citation-68540 citation-end-68540"><sup class="superscript" data-turn-source-index="164"><!----></sup></span><span class="citation-68538 citation-68539 citation-end-68539"><sup class="superscript" data-turn-source-index="165"><!----></sup></span><span class="citation-68538 citation-end-68538"><sup class="superscript" data-turn-source-index="166"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
</ul>
<p id="p-rc_c3c52cddf277798e-567" data-path-to-node="14,4"><strong data-path-to-node="14,4" data-index-in-node="0"><span class="citation-68534 citation-68535 citation-68536 citation-68537 citation-end-68537">Neolithic farmers<sup class="superscript" data-turn-source-index="167"><!----></sup></span><span class="citation-68534 citation-68535 citation-68536 citation-end-68536"><sup class="superscript" data-turn-source-index="168"><!----></sup></span><span class="citation-68534 citation-68535 citation-end-68535"><sup class="superscript" data-turn-source-index="169"><!----></sup></span><span class="citation-68534 citation-end-68534"><sup class="superscript" data-turn-source-index="170"><!----></sup></span></strong></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<ul data-path-to-node="14,5">
<li>
<p id="p-rc_c3c52cddf277798e-568" data-path-to-node="14,5,0,0"><span class="citation-68530 citation-68531 citation-68532 citation-68533">Houses were {rectangular}</span><span class="citation-68530 citation-68531 citation-68532 citation-end-68532"> in shape and had a hole in the roof.<sup class="superscript" data-turn-source-index="172"><!----></sup></span><span class="citation-68530 citation-68531 citation-end-68531"><sup class="superscript" data-turn-source-index="173"><!----></sup></span><span class="citation-68530 citation-end-68530"><sup class="superscript" data-turn-source-index="174"><!----></sup></span></p>
