<li>
<p id="p-rc_c3c52cddf277798e-570" data-path-to-node="14,5,1,1,0,0"><span class="citation-68522 citation-68523 citation-68524 citation-68525 citation-end-68525">cooking indoors<sup class="superscript" data-turn-source-index="179"><!----></sup></span><span class="citation-68522 citation-68523 citation-68524 citation-end-68524"><sup class="superscript" data-turn-source-index="180"><!----></sup></span><span class="citation-68522 citation-68523 citation-end-68523"><sup class="superscript" data-turn-source-index="181"><!----></sup></span><span class="citation-68522 citation-end-68522"><sup class="superscript" data-turn-source-index="182"><!----></sup></span></p>
