INSERT INTO public.questions VALUES ('a7d272e7-5498-4790-aa96-7ede953534e3', '396708a8-a509-4c2a-9a73-ef89e34f1de2', 'matrix', 'Questions 14-18', '', '<p>Reading Passage 2 has six paragraphs, <strong>A</strong>-<strong>F</strong>.</p>
<p>Which paragraph contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Similarities between studies of mammoth remains from different parts of the world.", "correctCategoryLetter": "D"}, {"itemText": "Details of the uses to which mammoth body parts were put.", "correctCategoryLetter": "B"}, {"itemText": " A theory that accounts for the damage to lyuba''s face. ", "correctCategoryLetter": "E"}, {"itemText": " An explanation of how an individual was able to identify a small corpse.", "correctCategoryLetter": "A"}, {"itemText": "A comparison between lyuba and other young mammoth corpses.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">14. Similarities between studies of mammoth remains from different parts of the world. — {D}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Most of these came from the </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"40\">Great Lakes region of North America</strong><span class=\"\">…</span><span class=\"\"> He has done limited work in </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"107\">Siberia</strong><span class=\"\">,</span><span class=\"\"> but his analysis of tusks from Wrangel Island…</span><span class=\"\"> suggests the </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"178\">same conclusion</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn D so sánh kết quả nghiên cứu của Dan Fisher tại Bắc Mỹ và Siberia,</span><span class=\"\"> cho thấy chúng đều dẫn đến cùng một kết luận (</span><em class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"130\">same conclusion</em><span class=\"\">).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">15. Details of the uses to which mammoth body parts were put. — {B}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “In addition to exploiting mammoths for </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"51\">food</strong><span class=\"\">,</span><span class=\"\"> they used their bones and tusks to make </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"97\">weapons, tools, and even dwellings</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn B liệt kê chi tiết các bộ phận của voi ma mút được con người sử dụng làm thức ăn,</span><span class=\"\"> vũ khí,</span><span class=\"\"> công cụ và nhà ở.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">16. A theory that accounts for the damage to Lyuba’s face. — {E}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">Fisher saw it as a possible explanation for the </span><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"63\">dent above her trunk</strong><span class=\"\">.</span><span class=\"\"> If she was frantically fighting for breath…</span><span class=\"\"> a partial vacuum was created…</span><span class=\"\"> which would have </span><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"180\">flattened surrounding soft tissue</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn E đưa ra giả thuyết của Fisher về việc hít phải bùn cát quá mạnh tạo ra môi trường chân không làm lõm/phẳng phần mô mềm trên mặt (vết lõm trên vòi).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">17. An explanation of how an individual was able to identify a small corpse. — {A}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Although he’d never seen such an animal before,</span><span class=\"\"> Khudi had seen </span><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"75\">many mammoth tusks</strong><span class=\"\">…</span><span class=\"\"> and this </span><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"106\">persuaded him the corpse was a baby mammoth</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn A giải thích nhờ kinh nghiệm nhìn thấy nhiều ngà voi ma mút trước đó mà Yuri Khudi có thể nhận diện được cái xác nhỏ này là voi ma mút.</span></p>\n</li>\n</ul>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">18. A comparison between Lyuba and other young mammoth corpses. — {C}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Fisher and Buigues had examined <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"44\">other specimens together, including infants</strong>, but these had been in a <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"113\">relatively poor state</strong>. Lyuba was <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"146\">another story entirely</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C so sánh Lyuba với các mẫu vật voi con khác, nhấn mạnh rằng Lyuba ở tình trạng bảo quản hoàn hảo hơn hẳn.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('6265b7ea-5ef6-41b0-9ae9-ae88f2318be0', '396708a8-a509-4c2a-9a73-ef89e34f1de2', 'matrix', 'Questions 19-23', '', '<p>Match each statement with the correct person, <strong>A-G.</strong></p>
<p><strong>NB </strong>You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "The indications are that mammoths died as a result of climate change.", "correctCategoryLetter": "C"}, {"itemText": "Teeth analysis is important in discovering why mammoths died out.", "correctCategoryLetter": "E"}, {"itemText": "The corpse of the baby mammoth is in better condition than any other that has been discovered.", "correctCategoryLetter": "D"}, {"itemText": "It would be a mistake to ignore the baby mammoth''s discovery, because of its potential importance.", "correctCategoryLetter": "A"}, {"itemText": "Mammoths often died at a time of year when they should have been in good physical condition.", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "Yuri Khudi", "categoryLetter": "A"}, {"categoryText": "Kirill Serotetto", "categoryLetter": "B"}, {"categoryText": "Adrian Lister", "categoryLetter": "C"}, {"categoryText": "Alexei Tikhonov", "categoryLetter": "D"}, {"categoryText": "Dan Fisher", "categoryLetter": "E"}, {"categoryText": "Bermard Buigues", "categoryLetter": "F"}, {"categoryText": "Naoki Suzuki", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">19. The indications are that mammoths died as a result of climate change. — {C: Adrian Lister}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “‘We have strong evidence that the <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"46\">temperature rise played a significant part in their extinction</strong>.’ says Adrian Lister…” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">20. Teeth analysis is important in discovering why mammoths died out. — {E: Dan Fisher}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…a confirmation for Fisher that <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"46\">dental research</strong> is useful for evaluating health and thus <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"103\">key to investigating the causes of mammoth extinction</strong>.” (Đoạn F)</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. The corpse of the baby mammoth is in better condition than any other… — {D: Alexei Tikhonov}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “According to Tikhonov, Khudi had rescued ‘<strong data-path-to-node=\"20,0,0\" data-index-in-node=\"54\">the best preserved mammoth</strong> to come down to us from the Ice Age’…” (Đoạn C)</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">22. It would be a mistake to ignore the baby mammoth’s discovery… — {A: Yuri Khudi}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “Khudi realised the find might be significant and <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"61\">he knew he couldn’t just return home and forget all about it</strong>.” (Đoạn A)</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">23. Mammoths often died at a time of year when they should have been in good physical condition. — {E: Dan Fisher}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “His samples frequently came from animals that had <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"62\">died in the autumn</strong>, when they <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"92\">should have been at their peak</strong> after summer grazing…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “At their peak” tương ứng với “good physical condition”.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('86983512-d8eb-423b-b77f-6042e415b057', '396708a8-a509-4c2a-9a73-ef89e34f1de2', 'fillup', 'Questions 24 - 26', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Some researchers say that a marked rise in temperature impacted on mammoths by changing the type of.</p>
<p>{vegetation} available.</p>
<p>Fisher concluded that many of the mammoth tusks he looked at displayed signs of {human hunting}</p>
<p>Not long after Lyuba’s death, the Mammuthus primigenius group she belonged to was replaced by another group that came from {North America}.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">24. …marked rise in temperature impacted on mammoths by changing the type of {vegetation} available.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…sharp rise in temperature, which dramatically altered the <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"73\">vegetation</strong>.” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">25. Fisher concluded that many of the mammoth tusks he looked at displayed signs of {human hunting}.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…to Fisher the tusks often revealed telltale evidence of <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"71\">human hunting</strong>.” (Đoạn D)</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">26. …the Mammuthus primigenius group she belonged to was replaced by another group that came from {North America}.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…another population migrating to Siberia from <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"60\">North America</strong> would take their place.” (Đoạn F)</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('e94a3215-7bfe-49b7-889a-0ed6490d7098', 'c905f154-4bd4-4dfc-9551-66e20062ece0', 'matching', 'Questions 15 – 20', NULL, '<p>What is the main theme of each of the following musicals?<br />
Choose <strong>SIX</strong> answers from the box and write the correct letter, <strong>A-H</strong></p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Musicals</strong></p>\r\n<p> </p>\r\n<p>The Climb {managing to achieve success}</p>\r\n<p> </p>\r\n<p>The Voyagers {living in a different century}</p>\r\n<p> </p>\r\n<p>Joey Brown {handling conflict}</p>\r\n<p> </p>\r\n<p>Main Street {experiencing disappointment}</p>\r\n<p> </p>\r\n<p>Millie and Mike {growing up}</p>\r\n<p> </p>\r\n<p>Windswept {living in a magical place}</p>", "answerOptions": [{"optionText": "living in a different century"}, {"optionText": "managing to achieve success"}, {"optionText": "ageing slowly"}, {"optionText": "growing up"}, {"optionText": "experiencing disappointment"}, {"optionText": "living in a magical place"}, {"optionText": "overcoming poverty"}, {"optionText": "handling conflict"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('78dcae57-5782-4c66-943a-5c27238b89ec', '78920030-364b-495e-8dd4-411aab4db460', 'checkbox', 'Questions 19 and 20', '', '<p>Choose <strong data-path-to-node="26" data-index-in-node="7">TWO</strong> letters, <strong data-path-to-node="26" data-index-in-node="20">A–E</strong>.</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A   working as part of a team"}, {"correct": true, "option_text": "B   experiences when working in winter"}, {"correct": false, "option_text": "C   being thanked by those he has helped"}, {"correct": false, "option_text": "D   the fact that it keeps him fit"}, {"correct": false, "option_text": "E   the chance to develop new equipment"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('116cecde-89dc-4e96-83d7-05c4098ab4cd', '71b5a527-8a2d-4931-9f69-8ce62cbcaa02', 'radio', 'Questions 21–26', NULL, '<p data-start="84" data-end="110">Choose the correct answer.</p>
<p data-start="112" data-end="166"><strong><span style="font-size: 14pt;">Feedback on second year of Performance Arts Course</span></strong></p>
<p data-start="168" data-end="357"> </p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "has a very good reputation"}, {"content": "has links with various theatres."}, {"content": "has an international flavour"}], "question": "Gina chose to study performance arts at this university because the course"}, {"correct": 0, "options": [{"content": "Movement Analysis"}, {"content": "Dance and Drama"}, {"content": "The Body in Dance"}], "question": "Which of the options they chose have Gina and Charlie both found useful?"}, {"correct": 0, "options": [{"content": "He worked in a costume department"}, {"content": "He performed with a ballet company."}, {"content": "He helped out at a dance school for children"}], "question": "What did Charlie do during his work experience?"}, {"correct": 1, "options": [{"content": "how to organise her time better"}, {"content": "how to work better in a team"}, {"content": "how to cope when under pressure"}], "question": "What does Gina say she learnt from her work experience?"}, {"correct": 2, "options": [{"content": "He wanted it to be different from those of other students"}, {"content": "He had already done an assignment in this area"}, {"content": "He was inspired to choose it by a performance he saw."}], "question": "What does Charlie say about his dissertation topic?"}, {"correct": 1, "options": [{"content": "finding enough to say"}, {"content": "doing the background reading"}, {"content": "presenting it in an appropriate way"}], "question": "Which aspect of writing a dissertation is Gina worried about?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: PERFORMANCE ARTS COURSE FEEDBACK</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Charlie:</strong> So Gina, we’ve got to give our tutor some feedback on how we feel about the course, now we’ve come to the end of our second year. Is it okay with you if we have a chat together before we go and see him?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Gina:</strong> Sure, Charlie.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Charlie:</strong> So, did you choose this university to do Performance Arts because it’s got such a good reputation? That’s what hooked me in.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Gina:</strong> Well, there are other good places which I also considered, but when I looked into things further,<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"6\" data-index-in-node=\"104\">(21) I was impressed by the connections this course has with a whole range of theatres of different types [Answer: B]</strong></span>. So even though I was tempted to go and study abroad, I decided to come here in the end.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Charlie:</strong> And you don’t regret it?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Gina:</strong> No, it’s been brilliant, especially the options this year. The Body and Dance option I did for this term has been particularly stimulating.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Charlie:</strong> Hmm, I’m sorry I didn’t go for that one too, but I did Dance and Drama which was brilliant too. I think <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"9\" data-index-in-node=\"113\">(22) the most valuable option I’ve done was the Movement Analysis course we did in the first year [Answer: A]</strong>.</span></p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Gina:</strong> Absolutely. It’s provided a great foundation for all our other work since then. So let’s talk about our work experience. Last summer you went to Finland, didn’t you?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Charlie:</strong> That’s right. I was at their National Ballet Theatre. I didn’t get the chance to go on stage, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"107\">(23) I helped out with sewing clothes for current productions and even with designing some for future shows [Answer: A – costume department]</strong></span>. It was brilliant. I got to know a lot of students studying at the local dance school, and I may get the chance to go back there next summer.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Gina:</strong> Hmm, I’ve been offered more work at the place where I was working in Canada.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Charlie:</strong> Great! So, what do you think you gained most from the experience? I think I’ve got much better at controlling my stress levels.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Gina:</strong> For me, it was probably<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"14\" data-index-in-node=\"30\">(24) the fact that I learned a lot about collaborating with others rather than working independently [Answer: B – work better in a team]</strong>.</span> I was lucky to be able to do that in a situation that wasn’t too stressful. Also, I had to organize my time well, but I’ve always been reasonably good at that.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Charlie:</strong> That’s good. So, we’ve got quite a few things ready to say to our tutor. It would be a good chance to ask him any questions we have too.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Gina:</strong> Of course. I also think it could be helpful to discuss our future plans, for example, what we’re planning to do our dissertations on.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Charlie:</strong> Sure. I was unsure about whether to focus on globalisation in dance or on stage design. I did an essay on globalisation in my first year and really enjoyed it, but then <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"178\">(25) I saw a spectacular production at the Royal Opera House and that settled me on stage design [Answer: C]</strong></span>. I know another student who’s planning to work on that too, so we can discuss things together a bit.</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Gina:</strong> OK, that could be useful. I’m planning to do something on current trends in contemporary dance for my dissertation.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Charlie:</strong> That sounds pretty challenging. It’s a big topic. It might not be easy to organize in a coherent way.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Gina:</strong> I’ve thought about it quite a lot and I think that’ll be OK, and I feel confident about how to write a longer piece of work. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"20\" data-index-in-node=\"131\">(26) I’m in a bit of a panic though about how I’ll get through all the literature. There seems to be so much [Answer: B – background reading]</strong></span>. Hopefully, it won’t all be relevant.</p>\n<hr data-path-to-node=\"21\" />\n<h3 data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">CAREER PLANS (Questions 27–30)</strong></h3>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Charlie:</strong> So have you made any career plans yet?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Gina:</strong> I’m still undecided. I’ve thought about <strong data-path-to-node=\"24\" data-index-in-node=\"46\">performance</strong>, of course.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Charlie:</strong> Yes, I think lots of graduates from here take that route. But it’s a hard life involving lots of tough repetitive practice as well as actually appearing on stage.</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Gina:</strong> Yes, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"26\" data-index-in-node=\"15\">(27) the performers I’ve met know that’s essential for the job and say they wouldn’t change what they do for the world [Answer: E]</strong></span>.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Charlie:</strong> I know lots of graduates go into <strong data-path-to-node=\"27\" data-index-in-node=\"42\">education</strong>, teaching at various levels.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Gina:</strong> But<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"28\" data-index-in-node=\"10\">(28) that means doing some kind of post-grad certificate [Answer: C]</strong></span>, but I think it would be interesting, rewarding work.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Charlie:</strong> I was wondering about <strong data-path-to-node=\"29\" data-index-in-node=\"31\">theatre management</strong> as a possible option. That’s what our tutor did before he got into teaching, isn’t it?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Gina:</strong> Yes, but he said he quickly realized it wasn’t for him. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"30\" data-index-in-node=\"62\">(29) He wasn’t earning enough to live on [Answer: A]</strong></span>. I can imagine his communication skills are better than his business skills as well.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Charlie:</strong> <strong data-path-to-node=\"31\" data-index-in-node=\"9\">Marketing</strong>’s a possibility, of course.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Gina:</strong> Sure. I’ve read something saying it can be an interesting career, though <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"32\" data-index-in-node=\"79\">(30) I don’t think many graduates go for this [Answer: F]</strong></span>, but that might mean there’s not so much competition as in many other fields of dance.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Charlie:</strong> Right, so now should we make a list…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('45e34f0b-3de6-48da-b6ee-bd5fdffe0b25', 'b58bb246-047d-48e5-843b-1ecc19bb07b9', 'matrix', 'Questions 1 – 7', '', '<p>Choose the correct letter, A-F, in boxes 1-7 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Spend enough with this firm and you can get something free", "correctCategoryLetter": "F"}, {"itemText": "This firm will not charge you for telling you the likely cost.", "correctCategoryLetter": "C"}, {"itemText": "It is cheaper if you can prove you are at college.", "correctCategoryLetter": "A"}, {"itemText": "This firm claims to have the lowest prices in the area. ", "correctCategoryLetter": "F"}, {"itemText": "This firm offers a 24-hour service.", "correctCategoryLetter": "A"}, {"itemText": "You cannot pay this firm in cash", "correctCategoryLetter": "B"}, {"itemText": "Charges are reduced at certain times.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. Spend enough with this firm and you can get something free. — {F}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Receive a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"22\">complimentary pen</strong> for orders over £25″</em> (Đoạn F).</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Complimentary” = Free. “Orders over £25” = Spend enough.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. This firm will not charge you for telling you the likely cost. — {C}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"12\">Estimates free</strong> – All work guaranteed”</em> (Đoạn C).</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Estimate” là việc báo giá/ước tính chi phí (likely cost). “Free” = Not charge.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. It is cheaper if you can prove you are at college. — {A}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"12\">Reduced charges for full-time students</strong> (ID required)”</em> (Đoạn A).</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thẻ sinh viên (ID) là bằng chứng bạn đang học đại học/cao đẳng (prove you are at college).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. This firm claims to have the lowest prices in the area. — {F}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Find the same item for less locally and <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"52\">we’ll refund double the difference</strong>!”</em> (Đoạn F).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là lời khẳng định về giá rẻ nhất (Incredible prices/lowest prices).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. This firm offers a 24-hour service. — {A}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“We come to you – <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"29\">day or night</strong>“</em> (Đoạn A).</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Ngày hoặc đêm” tương ứng với dịch vụ 24 giờ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. You cannot pay this firm in cash. — {B}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"15,0,0\" data-index-in-node=\"12\">Credit or debit cards only</strong>“</em> (Đoạn B).</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chỉ dùng thẻ đồng nghĩa với việc không chấp nhận tiền mặt (cannot pay in cash).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. Charges are reduced at certain times. — {B}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"17,0,0\" data-index-in-node=\"12\">Special weekend rates</strong> (min 2 days)”</em> (Đoạn B).</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Cuối tuần” là thời điểm nhất định (certain times) có mức giá đặc biệt/giảm giá.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('8ca627ad-a022-4b68-a20f-29321842054e', 'b58bb246-047d-48e5-843b-1ecc19bb07b9', 'fillup', 'Questions 8 – 14', '<p data-path-to-node="9,0,0">Membership costs less for students and people <strong data-path-to-node="9,0,0" data-index-in-node="46">{over 60}</strong>.</p>
<p>Before joining you can arrange to have a <strong data-path-to-node="9,1,0" data-index-in-node="41">{free induction}</strong>.</p>
<p data-path-to-node="9,2,0">The gym is not available to <strong data-path-to-node="9,2,0" data-index-in-node="28">{under 16s}</strong>.</p>
<p data-path-to-node="9,3,0">Studio classes are available for people of any <strong data-path-to-node="9,3,0" data-index-in-node="47">{fitness level}</strong>.</p>
<p data-path-to-node="9,4,0">On certain evenings, squash games are followed by a <strong data-path-to-node="9,4,0" data-index-in-node="52">{social event}</strong>.</p>
<p data-path-to-node="9,5,0">The best membership type for people who do not want to attend regularly is <strong data-path-to-node="9,5,0" data-index-in-node="75">{SILVER}</strong>.</p>
<p data-path-to-node="9,6,0">If you’re in Old Lane and trying to find Harry’s, look out for <strong data-path-to-node="9,6,0" data-index-in-node="63">{Deansden station}</strong>.</p>', '<p><strong>Complete the sentences below.</strong></p>', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">8. Membership costs less for students and people {over 60}.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…£29 to £55 per month – the lowest price in the area with <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"81\">special rates for students and anyone over 60</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Special rates” (mức giá đặc biệt) trong ngữ cảnh này được hiểu là mức giá ưu đãi/thấp hơn. Đối tượng được hưởng ngoài sinh viên là những người trên 60 tuổi (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"170\">over 60</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">9. Before joining you can arrange to have a {free induction}.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Fitness in the Gym):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"36\">“Still unsure? Phone and book an appointment for your <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"90\">free induction</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nếu bạn còn chưa chắc chắn (trước khi gia nhập/joining), bạn có thể gọi điện để đặt lịch cho một buổi hướng dẫn miễn phí (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"134\">free induction</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">10. The gym is not available to {under 16s}.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Ghi chú dưới mục Fitness):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"38\">“</em> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"40\">Under 16s are not permitted to use the gym</strong>.”*</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Not permitted to use” (không được phép sử dụng) đồng nghĩa với “not available to” (không dành cho). Đối tượng bị hạn chế là những người dưới 16 tuổi (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"163\">under 16s</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">11. Studio classes are available for people of any {fitness level}.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Classes in the Studio):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"39\">“No matter what your <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"60\">fitness level</strong>, we have classes to suit…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “No matter what” (bất kể là gì) tương ứng với “any” (bất kỳ) trong câu hỏi. Các lớp học tại studio phù hợp với mọi mức độ thể chất (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"144\">fitness level</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">12. On certain evenings, squash games are followed by a {social event}.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Squash):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"24\">“Join us for friendly organised squash on ‘Club Nights’ on Thursday and Friday evenings, <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"113\">with a social event afterwards</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “On certain evenings” (vào một số buổi tối nhất định) tương ứng với tối Thứ Năm và Thứ Sáu. “Afterwards” (sau đó) đồng nghĩa với “followed by”. Hoạt động diễn ra sau đó là sự kiện giao lưu (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"202\">social event</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">13. The best membership type for people who do not want to attend regularly is {SILVER}.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Membership):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"28\">“<strong data-path-to-node=\"15,0,0\" data-index-in-node=\"29\">SILVER (for occasional use)</strong>: all facilities are available at individual charges and paid for at time of use.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Occasional use” (sử dụng thỉnh thoảng/không thường xuyên) tương ứng với “do not want to attend regularly”. Loại thẻ phù hợp nhất là thẻ bạc (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"154\">SILVER</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">14. If you’re in Old Lane and trying to find Harry’s, look out for {Deansden station}.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Mục Find us):</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"25\">“Harry’s Sports and Fitness Centre / Old Lane / London / SW18 3DL / (<strong data-path-to-node=\"17,0,0\" data-index-in-node=\"94\">next to Deansden station</strong>)”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để tìm được trung tâm tại đường Old Lane, người ta cần chú ý đến mốc địa điểm nằm ngay bên cạnh là ga Deansden (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"124\">Deansden station</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('a3d2a0cf-b246-4712-aa4e-d32b2b21296a', 'ed771c0e-626b-4376-bc14-6c752d472fbb', 'fillup', 'Questions 8–13', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>THE MOREPORK</strong></p>
<p><strong>Appearance</strong></p>
<p>– approximately {29 centimeters} in length</p>
<p>– feathers with fringes to enable quiet flight</p>
<p><strong>Nesting</strong></p>
<p>– nests in trees, plants or spaces in roots and {Rocks}</p>
<p>– after about 35 days, baby morepocks are capable of leaving the nest</p>
<p><strong>Hunting</strong></p>
<p>– transports Its prey using its {Bill}</p>
<p>– can be chased away by other birds during the {Day}</p>
<p>– attacked {Plovers} that had been introduced to Motuora island</p>
<p><strong>Threats</strong></p>
<p>– may be exposed to {poison} in their prey</p>', NULL, 'short_answer', 'null', 'null', 'null', 'null', '[{"content": "<p>8. Appearance – approximately <strong>29 centimeters</strong> in length</p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án:</strong> <strong>29 centimeters</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) “…they are around <strong>29 centimeters</strong> long from head to tail…”</p>\n</li>\n</ul>\n<p>9. Nesting – nests in trees, plants or spaces in roots and <strong>rocks</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong>Đáp án:</strong> <strong>rocks</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) “Moreporks nest in tree hollows, in clumps of plants, or in cavities among <strong>rocks</strong> and roots…”</p>\n</li>\n</ul>\n<p>10. Hunting – transports Its prey using its <strong>bill</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong>Đáp án:</strong> <strong>bill</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “…which it then carries away in its <strong>bill</strong>.”</p>\n</li>\n</ul>\n<p>11. Hunting – can be chased away by other birds during the <strong>day</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong>Đáp án:</strong> <strong>day</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) “<strong>In the day</strong>, these small birds sometimes mob drowsy moreporks and chase them away from their roosts.”</p>\n</li>\n</ul>\n<p>12. Hunting – attacked <strong>plovers</strong> that had been introduced to Motuora island</p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong>Đáp án:</strong> <strong>plovers</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) “The culprits turned out to be five pairs of Moreporks that ate or chased away the new arrivals [<strong>plovers</strong>].”</p>\n</li>\n</ul>\n<p>13. Threats – may be exposed to <strong>poison</strong> in their prey</p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong>Đáp án:</strong> <strong>poison</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “…they could be affected by an accumulative <strong>poison</strong> by consuming prey that has ingested poison.”</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('e5bbd53a-818c-47a3-90ab-cf51dc45f970', 'd6144b69-2fc5-45db-8f6a-fa0eaecc6198', 'fillup', 'Questions 15–20', '<p>Complete the notes below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 15–20 on your answer sheet.</p>
<p style="text-align: center;" data-start="238" data-end="257"><span style="font-size: 12pt;" role="text"><strong data-start="240" data-end="257">Safety Policy</strong></span></p>
<p data-start="259" data-end="273"><span role="text"><strong data-start="262" data-end="273">Ladders</strong></span></p>
<p data-start="274" data-end="427">• no paint on wood as {defects} need to be visible<br data-start="328" data-end="331">• ladders need firm base<br data-start="355" data-end="358">• use guardrails if chance of falling from two-metre height or more</p>
<p data-start="434" data-end="457"><span role="text"><strong data-start="437" data-end="457">Mobile platforms</strong></span></p>
<p data-start="458" data-end="671">• to be used by {authorised} staff only<br data-start="498" data-end="501">• make sure platforms for work are stable<br data-start="542" data-end="545">• ensure there are not any cables above the platform<br data-start="597" data-end="600">• signs are required particularly in places open to the {public}</p>
<p data-start="678" data-end="689"><span role="text"><strong data-start="681" data-end="689">Roof</strong></span></p>
<p data-start="690" data-end="962">• edges must be fenced<br data-start="712" data-end="715">• if openings cannot be fenced, use {safety belts}<br data-start="764" data-end="767">• Safety Manager to be contacted immediately when roof has unusual shape, or {dangerous substances} are present in materials<br data-start="882" data-end="885">• spread out stored materials to avoid {overloading} the roof in some areas</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Câu 15: defects</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…timber should not be painted because this hides <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"63\">defects</strong>.” (Mục Ladders and Platforms).</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đề bài yêu cầu tìm lý do không sơn gỗ (timber) để các lỗi có thể nhìn thấy (visible). Trong bài, việc sơn sẽ làm che giấu (hides) các khiếm khuyết (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"160\">defects</strong>). Vì vậy, từ cần điền là <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"193\">defects</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Câu 16: authorised</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Operation of this equipment is restricted to <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"57\">authorised</strong> persons.” (Mục Mobile Elevating Work Platforms).</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “to be used by… staff only” (chỉ được dùng bởi nhân viên…) tương ứng với “restricted to… persons” (giới hạn cho những người…). Những người này được gọi là nhân viên có thẩm quyền (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"204\">authorised</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Câu 17: public</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This is especially important if work takes place where the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"71\">public</strong> have access.” (Mục Mobile Elevating Work Platforms).</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Places open to the <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"32\">public</strong>” (nơi mở cửa cho công chúng) đồng nghĩa với “where the public have access” (nơi công chúng có thể tiếp cận). Tại những nơi này, việc đặt biển báo (signs/warning signs) là cực kỳ quan trọng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Câu 18: safety belts</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…if this is not possible, then <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"45\">safety belts</strong> will be required.” (Mục Roofwork).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi giả định tình huống nếu không thể rào chắn các lỗ hổng (if openings cannot be fenced). Bài đọc chỉ rõ giải pháp thay thế bắt buộc trong trường hợp này là sử dụng dây đai an toàn (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"199\">safety belts</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Câu 19: dangerous substances</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…or materials containing <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"39\">dangerous substances</strong> are found, the Safety Manager must be notified…” (Mục Roofwork).</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Safety Manager to be contacted immediately” tương ứng với “Safety Manager must be notified at an early stage”. Khi vật liệu có chứa các chất nguy hiểm (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"165\">dangerous substances</strong>), phải báo ngay cho người quản lý.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Câu 20: overloading</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…should be distributed evenly to prevent the <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"59\">overloading</strong> of part of the roof structure.” (Mục Roofwork).</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Spread out” (trải đều vật liệu) đồng nghĩa với “distributed evenly”. Mục đích của hành động này là để tránh (avoid) hoặc ngăn chặn (prevent) tình trạng quá tải (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"174\">overloading</strong>) lên cấu trúc mái.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('c04e9a3e-52b0-43a5-b4d1-a12032c0f8d7', 'abae79a8-e023-4414-ba40-5090e823301c', 'radio', 'Questions 33–40', '', '<p data-start="5728" data-end="5770">Choose: <strong data-start="5772" data-end="5780">TRUE </strong>if the statement agrees with the information, <strong data-start="5829" data-end="5838">FALSE </strong>if the statement contradicts the information, <strong data-start="5887" data-end="5900">NOT GIVEN </strong>if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Eric Clarke discovered gold close to where he had found an old coin"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "A metal detector can locate gold up to 3 metres below the surface."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Information about the location of gold deposits can be found at the local library."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Gold fossicking by amateurs is permitted in state and national parks."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In Australia professional miners need a licence."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Gold panning is the most popular way to find gold in flowing water."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In 1823, news of a gold find caused a gold rush in Australia."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Almost all Australian gold has now been mined."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">33. Eric Clarke discovered gold close to where he had found an old coin. — {TRUE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Clarke was overjoyed to unearth an 1842 gold half-sovereign… picked up a faint signal <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"109\">within metres of his original find</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một đồng “half-sovereign” là một loại tiền xu cổ (old coin). Cục vàng được tìm thấy chỉ cách vị trí đồng xu vài mét.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">34. A metal detector can locate gold up to 3 metres below the surface. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Trong các đoạn văn, độ sâu được nhắc đến là 10cm, 20cm hoặc “shovel’s depth” (độ sâu một xẻng).</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"20\">không hề đề cập</strong> đến giới hạn tối đa mà máy dò kim loại có thể dò tới (không nhắc tới con số 3 mét).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">35. Information about the location of gold deposits can be found at the local library. — {TRUE}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“Many weekend prospectors <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"46\">start at their local library</strong> researching where gold has already been reported.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông tin hoàn toàn khớp với bài đọc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">36. Gold fossicking by amateurs is permitted in state and national parks. — {FALSE}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“Most public lands, <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"40\">apart from state and national parks</strong>, are open to recreational fossickers.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Apart from” nghĩa là ngoại trừ. Tức là việc tìm vàng trong công viên bang và quốc gia là <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"102\">không được phép</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">37. In Australia professional miners need a licence. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"20\">“In some states <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"36\">amateurs</strong> require a licence or a miner’s right.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nhắc đến việc những người <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"50\">nghiệp dư (amateurs)</strong> cần giấy phép, không có thông tin về thợ đào chuyên nghiệp (professional miners).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">38. Gold panning is the most popular way to find gold in flowing water. — {TRUE}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn H):</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"20\">“…the gold pan… remains the <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"52\">essential tool</strong> for recovering gold from <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"92\">running streams</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Running streams” = flowing water. Việc đãi vàng (panning) là phương pháp thiết yếu (cách phổ biến nhất) cho môi trường này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">39. In 1823, news of a gold find caused a gold rush in Australia. — {FALSE}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn I):</strong> <em data-path-to-node=\"21,0,0\" data-index-in-node=\"20\">“News of this first recorded find <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"54\">was suppressed</strong> at the time for <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"85\">fear of creating a gold rush</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Suppressed” nghĩa là bị giữ kín/che giấu. Do đó, nó không hề gây ra cơn sốt vàng (gold rush) vào năm đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">40. Almost all Australian gold has now been mined. — {FALSE}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn J):</strong> <em data-path-to-node=\"23,0,0\" data-index-in-node=\"20\">“…geologists estimate that a <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"51\">significant percentage of the gold in Australia is still in the ground</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một tỉ lệ đáng kể vàng vẫn còn trong lòng đất, trái ngược với ý kiến “hầu như tất cả đã được khai thác”.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('a8ad931d-6f14-4d2d-b8bb-e1fcf997ec63', '62865638-b9a5-4641-85c9-90076e4a96e7', 'fillup', 'Questions 24–26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>Producing spider silk in the lab</strong></p>
<p>Both scientists and manufacturers are interested in producing silk for many different purposes. Some researchers have tried to grow silk by introducing genetic material into {Bacteria} and some animals. But these experiments have been somewhat disappointing.</p>
<p>It is difficult to make spider silk in a lab setting because the silk comes from a liquid protein made in a {Gland} inside the spider’s body. When a spider spins silk, it causes a {transformation} that turns this liquid into solid silk. Scientists cannot replicate this yet.</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p>24.  Some researchers have tried to grow silk by introducing genetic material into <strong>Bacteria</strong> and some animals.</p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong>Đáp án:</strong> <strong>Bacteria</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “Several groups have tried inserting spider genes into <strong>bacteria</strong> or even cows and goats to produce silk…”</p>\n</li>\n</ul>\n<p>25.It is difficult to make spider silk in a lab because the silk comes from a liquid protein made in a <strong>Gland</strong> inside the spider’s body.</p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong>Đáp án:</strong> <strong>Gland</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) “…it starts out as a liquid protein that’s produced by a special <strong>gland</strong> in the spider’s abdomen.”</p>\n</li>\n</ul>\n<p>26. <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Transformation</strong></p>\n<ul data-path-to-node=\"2,2,1\">\n<li>\n<p data-path-to-node=\"2,2,1,0,0\"><strong data-path-to-node=\"2,2,1,0,0\" data-index-in-node=\"0\">Vị trí trong bài:</strong> Đoạn cuối, câu: <em data-path-to-node=\"2,2,1,0,0\" data-index-in-node=\"34\">\"...the spider applies forces to produce a <strong data-path-to-node=\"2,2,1,0,0\" data-index-in-node=\"77\">transformation</strong> from liquid to solid...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,1,1,0\"><strong data-path-to-node=\"2,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi nhện nhả tơ, nó dùng lực để tạo ra một sự biến đổi (transformation) từ dạng lỏng sang dạng rắn.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('6e53d8fb-2d5b-4291-850b-8b7d55d8697e', '2f5d39ba-28ff-4ee6-bfee-823f82b5189a', 'radio', 'Questions 27–31', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "peers."}, {"content": "patients"}, {"content": "students"}, {"content": "teachers"}], "question": "According to the writer, Ekman became interested in lying after a question from his"}, {"correct": 1, "options": [{"content": "illustrate how frequently patients lie."}, {"content": "describe the origins of Ekman’s theories."}, {"content": "compare Ekman’s research to previous studies."}, {"content": "show how patients behaviour is affected by filming."}], "question": "The writer refers to the 12-minute interviews in order to"}, {"correct": 0, "options": [{"content": "Micro-expressions are common to all people."}, {"content": "Recent research has refuted an old idea."}, {"content": "With practice we can learn to control our micro-expression."}, {"content": "Human society is too complex to allow for generalisations."}], "question": "What is the writer’s point in the third paragraph?"}, {"correct": 1, "options": [{"content": "It’s natural for people to lie"}, {"content": "Few untrained people can detect lying"}, {"content": "Most liar suffer from periods of depression."}, {"content": "All of his subjects were trained to identify micro-expressions."}], "question": "What are we told about Ekman’s conclusions from his tests?"}, {"correct": 1, "options": [{"content": "They take decades to teach"}, {"content": "They have been in great demand"}, {"content": "They have aroused the suspicions of some agencies"}, {"content": "They can be used by a limited range of occupations"}], "question": "At what point does the writer make about Ekman’s techniques in the fourth paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. According to the writer, Ekman became interested in lying after a question from his&#8230;</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> C. students</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, dòng 1–3.</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Dr Paul Ekman was addressing a group of <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"52\">young psychiatrists in training</strong> when he was asked a question&#8230;&#8221;</li>\n<li><strong data-path-to-node=\"4,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ &#8220;young psychiatrists in training&#8221; (những bác sĩ tâm thần trẻ đang trong quá trình đào tạo) tương ứng với &#8220;students&#8221; (sinh viên/học viên). Câu hỏi của họ về việc làm sao biết bệnh nhân nói thật hay không đã khơi gợi sự quan tâm của ông.</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. The writer refers to the 12-minute interviews in order to&#8230;</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. describe the origins of Ekman’s theories</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 1–6.</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;As part of his research, he had already filmed a series of <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"71\">12-minute interviews</strong>&#8230; Then he slowed it down&#8230; And suddenly&#8230; he saw it&#8230; He termed his discovery <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"174\">micro-expression</strong>.&#8221;</li>\n<li><strong data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhắc đến các cuộc phỏng vấn 12 phút này để kể lại quá trình Ekman tình cờ phát hiện ra các biểu cảm siêu nhỏ (micro-expression) khi xem chậm đoạn phim. Đây chính là nguồn gốc (origins) hình thành nên học thuyết của ông.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. What is the writer’s point in the third paragraph?</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> A. Micro-expressions are common to all people.</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 2–5.</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;the ways in which we express rage, disgust&#8230; are <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"65\">universal</strong>. The facial muscles triggered&#8230; are, he has shown, essentially <strong data-path-to-node=\"8,2,0\" data-index-in-node=\"139\">standard, regardless of language and culture</strong>&#8230;&#8221;</li>\n<li><strong data-path-to-node=\"8,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh rằng các biểu cảm khuôn mặt là &#8220;universal&#8221; (phổ quát) và &#8220;standard&#8221; (tiêu chuẩn) ở mọi nền văn hóa. Điều này đồng nghĩa với việc các biểu cảm siêu nhỏ này tồn tại giống nhau ở tất cả mọi người (common to all people).</li>\n</ul>\n<p><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. What are we told about Ekman’s conclusions from his tests?</strong></p>\n<ul data-path-to-node=\"10\">\n<li><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. Few untrained people can detect lying.</li>\n<li><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1–3.</li>\n<li><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Fortunately for liars, <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"35\">most people will fail to spot</strong> these fleeting signals&#8230; Of the 15,000 Ekman has tested, <strong data-path-to-node=\"10,2,0\" data-index-in-node=\"123\">only 50 people</strong>, whom he calls ‘naturals’, have been able to do it.&#8221;</li>\n<li><strong data-path-to-node=\"10,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Với tỉ lệ chỉ 50/15.000 người có khả năng tự nhiên để phát hiện nói dối, bài đọc khẳng định rằng rất ít người chưa qua đào tạo (untrained) có thể làm được việc này.</li>\n</ul>\n<p><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. What point does the writer make about Ekman’s techniques in the fourth paragraph?</strong></p>\n<ul data-path-to-node=\"12\">\n<li><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án:</strong> B. They have been in great demand.</li>\n<li><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 5–10.</li>\n<li><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;&#8230;he has been called in by the <strong data-path-to-node=\"12,2,0\" data-index-in-node=\"44\">FBI and CIA (among countless more law-enforcement and other agencies around the world)</strong>&#8230; workshops for <strong data-path-to-node=\"12,2,0\" data-index-in-node=\"148\">defense and prosecution lawyers, health professionals, even jealous spouses</strong>&#8230;&#8221;</li>\n<li><strong data-path-to-node=\"12,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc hàng loạt cơ quan an ninh (FBI, CIA), các luật sư, chuyên gia y tế và cả những người vợ/chồng hay ghen tìm đến ông cho thấy kỹ thuật của ông đang rất được săn đón và có nhu cầu cực lớn (in great demand).</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('fcdca61e-c410-434e-a45d-536c74135f6a', '2f5d39ba-28ff-4ee6-bfee-823f82b5189a', 'matching', 'Questions 32–36', NULL, '<p>Complete the summary using the list of words, A-I, below.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>The television series based on Ekman’s work</strong></p>\r\n<p>A new TV series based on Ekman’s work features a hero named Lightman, who detects lies. Initially, Ekman was unenthusiastic about the TV project because he feared the possibility of encouraging viewers {C false belief}. For example, he was worried that one day the programme could result in {E justice} not being carried out. Ultimately though, he has given the show his blessing because he is not aware of any other comparable programme based on a single person’s {H research}.</p>\r\n<p>The {D motives} of the show’s producer have been another pleasant surprise and, considering the genre of the programme, Ekman is happy with the show’s overall {F accuracy}</p>", "answerOptions": [{"optionText": "A consequences"}, {"optionText": "B crimes"}, {"optionText": "C false belief"}, {"optionText": "D motives"}, {"optionText": "E justice"}, {"optionText": "F accuracy"}, {"optionText": "G acting"}, {"optionText": "H research"}, {"optionText": "I ratings"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>32. Initially, Ekman was unenthusiastic about the TV project because he feared the possibility of encouraging viewers  C. false belief.</strong></p>\n<ul data-path-to-node=\"16\">\n<li><strong>Đáp án:</strong> <strong>C. false belief</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;&#8230;he was fearful that the show would exaggerate the effectiveness of his techniques and <strong>create the quite inaccurate impression</strong> among audiences that criminals could no longer hope to get away with lying.&#8221;</li>\n<li><strong>Giải thích:</strong> Ông lo sợ chương trình sẽ tạo ra ấn tượng sai lệch (false belief) về tính hiệu quả của kỹ thuật.</li>\n</ul>\n<p><strong>33. For example, he was worried that one day the programme could result in E. justice not being carried out.</strong></p>\n<ul data-path-to-node=\"18\">\n<li><strong>Đáp án:</strong> <strong>E. justice</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 5) &#8220;In the worst-case scenario, he was concerned about <strong>unfair convictions</strong>, that one day someone not properly trained in his techniques might be sitting on a jury and <strong>wrongly find someone guilty of a crime</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> Ông lo sợ việc kết án sai người vô tội (unfair convictions/wrongly find someone guilty) sẽ dẫn đến việc công lý (<strong>justice</strong>) không được thực thi.</li>\n</ul>\n<p><strong>34. Ultimately though, he has given the show his blessing because he is not aware of any other comparable programme based on a single person&#8217;s  H. research.</strong></p>\n<ul data-path-to-node=\"20\">\n<li><strong>Đáp án:</strong> <strong>H. research</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;It is the first time, as far as Ekman is aware, that a commercial TV drama has been based on the work of <strong>just one scientist</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Ông bị thuyết phục vì chương trình dựa trên công trình nghiên cứu (<strong>research</strong>) của cá nhân ông.</li>\n</ul>\n<p><strong>35. The <span class=\"math-inline\" data-math=\"rightarrow\">$rightarrow$</span> D. motives of the show&#8217;s producer have been another pleasant surprise, and considering the genre of the programme, Ekman is happy with the show&#8217;s overall  F. accuracy.</strong></p>\n<ul data-path-to-node=\"22\">\n<li><strong>Đáp án:</strong> <strong>D. motives</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;He was also impressed with the producer’s manifestly serious and <strong>well-intentioned reasons</strong> for making the programme.&#8221;</li>\n<li><strong>Giải thích:</strong> Ekman ấn tượng với lý do (motives) nghiêm túc và có ý định tốt của nhà sản xuất.</li>\n</ul>\n<p><strong>36. &#8230;Ekman is happy with the show&#8217;s overall  F. accuracy.</strong></p>\n<ul data-path-to-node=\"24\">\n<li><strong>Đáp án:</strong> <strong>F. accuracy</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) &#8220;Now that the first series has been completed, he believes probably <strong>80-90 per cent of the show is based on fact</strong> and that’s good enough for what is.&#8221;</li>\n<li><strong>Giải thích:</strong> Việc tin rằng 80-90% chương trình dựa trên sự thật thể hiện sự hài lòng về tính chính xác (<strong>accuracy</strong>) tổng thể của chương trình</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('2dabae2f-4b56-4898-ab0f-9259d6f17ccd', 'd99087c2-5edf-4d31-9c1a-e869b405820d', 'radio', 'Questions 30-34', '', '<p data-path-to-node="12,0,0">Choose<strong data-path-to-node="12,0,0" data-index-in-node="0"> YES</strong> if the statement agrees with the views of the writer,<strong data-path-to-node="12,1,0" data-index-in-node="0">NO</strong> if the statement contradicts the views of the writer,<strong data-path-to-node="12,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Children tend to make a clear distinction between print literature and electronic media."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The study of children’s literature at higher education institutions is restricted to one subject area."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Exploring children’s perceptions of reading will assist parents to choose suitable books for children."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Adults may appreciate the appeal of illustrated stories better, if they have more information on how children read."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Children should be asked what features they would like digital games to include."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">30. Children tend to make a clear distinction between print literature and electronic media.</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"3,1,0\" data-index-in-node=\"11\">“In the eyes of the child, the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"42\">boundaries</strong> between the book, the film, and the computer game are <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"107\">increasingly blurred</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói trẻ em phân biệt rõ rệt (<strong data-path-to-node=\"3,2,0\" data-index-in-node=\"49\">clear distinction</strong>), nhưng bài đọc khẳng định ranh giới trong mắt trẻ em đang ngày càng <strong data-path-to-node=\"3,2,0\" data-index-in-node=\"136\">mờ nhạt (blurred)</strong>. Hai thông tin này đối nghịch nhau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">31. The study of children’s literature at higher education institutions is restricted to one subject area.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,1,0\" data-index-in-node=\"11\">“Children’s literature is now a field of study that <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"63\">crosses traditional academic boundaries</strong>, involving departments of <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"129\">English, Education, Psychology, and Media Studies</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói việc nghiên cứu bị giới hạn trong một ngành (<strong data-path-to-node=\"5,2,0\" data-index-in-node=\"69\">restricted to one subject</strong>), nhưng bài đọc liệt kê rất nhiều ngành khác nhau cùng tham gia nghiên cứu (Tiếng Anh, Giáo dục, Tâm lý học, Truyền thông).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">32. Exploring children’s perceptions of reading will assist parents to choose suitable books for children.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc có thể nói về việc nghiên cứu nhận thức của trẻ em, nhưng <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"77\">không hề nhắc đến</strong> việc nghiên cứu này sẽ giúp ích cho <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"131\">phụ huynh (parents)</strong> trong việc chọn sách.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông tin về “lợi ích cho phụ huynh” không xuất hiện trong bài, dù ngoài đời điều này có thể đúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">33. Adults may appreciate the appeal of illustrated stories better, if they have more information on how children read.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,1,0\" data-index-in-node=\"11\">“By understanding the <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"33\">complex ways in which children decode visual and verbal texts</strong>, adults can gain a <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"114\">deeper appreciation</strong> for the sophisticated nature of picture books.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định nếu người lớn hiểu được cách trẻ em giải mã hình ảnh và văn bản (more information), họ sẽ có sự trân trọng sâu sắc hơn (<strong data-path-to-node=\"9,2,0\" data-index-in-node=\"151\">deeper appreciation</strong>) đối với sách tranh. Thông tin này khớp hoàn toàn với câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">34. Children should be asked what features they would like digital games to include.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài đọc có thể thảo luận về các đặc điểm của trò chơi kỹ thuật số.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tuy nhiên, tác giả <strong data-path-to-node=\"11,2,0\" data-index-in-node=\"31\">không đưa ra lời khuyên hoặc quan điểm</strong> rằng trẻ em “nên được hỏi” (<strong data-path-to-node=\"11,2,0\" data-index-in-node=\"98\">should be asked</strong>) về mong muốn của chúng khi thiết kế game. Đây là thông tin thiếu hụt.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('a02a5575-1b6b-4651-af59-dabb5895334e', '71b5a527-8a2d-4931-9f69-8ce62cbcaa02', 'matching', 'Questions 27–30', NULL, '<p><strong data-start="86" data-end="180">What do the students say about each of the following types of careers in performance arts?</strong><br data-start="180" data-end="183" />Choose <strong>FOUR</strong> correct answers, <strong>A</strong>–<strong>F</strong></p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Types of careers</strong></p>\r\n<p> </p>\r\n<p>Performance {People with experience feel very positive about it}</p>\r\n<p> </p>\r\n<p>Education {An additional qualification is required}</p>\r\n<p> </p>\r\n<p>Theatre management {The pay can be low}</p>\r\n<p> </p>\r\n<p>Marketing {It is a relatively unpopular choice}</p>", "answerOptions": [{"optionText": "The pay can be low"}, {"optionText": "There is a lot of competition"}, {"optionText": "An additional qualification is required"}, {"optionText": "Good communication skills are required"}, {"optionText": "People with experience feel very positive about it"}, {"optionText": "It is a relatively unpopular choice"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('dc778345-5f8d-4c7d-b8d5-97aae0b7605f', 'fff7df18-ff0a-4c1a-83c2-b85e66213af4', 'radio', 'Questions 1–6', '', '<p id="p-rc_f40516ba28055d43-424" data-path-to-node="5,0,0"><span class="citation-52054">Choose</span><strong data-path-to-node="5,0,0" data-index-in-node="0"><span class="citation-52054"> TRUE</span></strong><span class="citation-52054 citation-end-52054"> if the statement agrees with the information,<sup class="superscript" data-turn-source-index="4"><!----></sup></span><strong data-path-to-node="5,1,0" data-index-in-node="0"><span class="citation-52053">FALSE</span></strong><span class="citation-52053 citation-end-52053"> if the statement contradicts the inform<sup class="superscript" data-turn-source-index="5"><!----></sup></span>ation,<strong data-path-to-node="5,2,0" data-index-in-node="0">NOT GIVEN</strong> if there is no information on this</p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Forty years ago, there were fewer butterflies in Britain than at present."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Caterpillars are eaten by a number of different predators."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "''Phenology'' is a term used to describe a creature''s ability to alter the location of a lifecycle event."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Some species of butterfly have a reduced lifespan due to spring temperature increases."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "There is a clear reason for the adaptations that butterflies are making to climate change."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The data used in the study was taken from the work of amateur butterfly watchers."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">1. Forty years ago, there were fewer butterflies in Britain than at present. — {FALSE}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">\"According to conservationists, <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"52\">populations of around two thirds of butterfly species have declined</strong> in Britain <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"131\">over the past 40 years</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói rằng trong 40 năm qua, số lượng bướm đã <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"64\">sụt giảm</strong> (declined). Điều này có nghĩa là 40 năm trước số lượng bướm phải <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"138\">nhiều hơn</strong> hiện tại. Câu hỏi lại khẳng định 40 năm trước ít bướm hơn hiện tại (fewer... than at present) là hoàn toàn ngược lại với sự thật (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"278\">FALSE</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">2. Caterpillars are eaten by a number of different predators. — {TRUE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“...and these insects [caterpillars]... in turn <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"68\">act as prey for birds as well as bats and other small mammals</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sâu bướm đóng vai trò là con mồi (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"46\">prey</strong>) cho nhiều loài động vật khác nhau bao gồm chim, dơi và các động vật có vú nhỏ khác. Các loài động vật này chính là những kẻ săn mồi (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"185\">a number of different predators</strong>), vì vậy câu này đúng (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"240\">TRUE</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">3. ''Phenology'' is a term used to describe a creature''s ability to alter the location of a lifecycle event. — {FALSE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">\"Scientists refer to the <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"45\">timing of such lifecycle events as ''phenology''</strong>, so when an animal or plant starts to do something <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"143\">earlier in the year</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khoa học dùng từ \"Phenology\" (vốn là \"Phân kỳ học / Chu kỳ sinh học\") để nói về <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"92\">thời gian / thời điểm</strong> (timing / earlier in the year) diễn ra các sự kiện trong vòng đời sinh vật. Câu hỏi lại bẫy bằng cách đổi chữ \"timing\" thành <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"239\">\"location\"</strong> (vị trí/địa điểm). Sự sai lệch định nghĩa này khiến đáp án là <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"312\">FALSE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">4. Some species of butterfly have a reduced lifespan due to spring temperature increases. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"20\">\"In Britain, as the average spring temperature has increased by roughly 0.5 °C over the past 20 years, species have advanced by between three days and a week on average...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc nhiệt độ mùa xuân tăng 0.5 °C làm bướm xuất hiện sớm hơn. Tuy nhiên, hoàn toàn <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"116\">không có thông tin</strong> nào nói về việc vòng đời/tuổi thọ (<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"170\">lifespan</strong>) của chúng có bị giảm đi (<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"205\">reduced</strong>) hay không (<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"225\">NOT GIVEN</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">5. There is a clear reason for the adaptations that butterflies are making to climate change. — {FALSE}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">“Is this a sign that butterflies are well equipped to cope with climate change...? Or are these populations under stress...? <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"145\">The answer is still unknown</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra hai giả thuyết về lý do bướm thay đổi chu kỳ (do thích nghi tốt hay do bị áp lực áp đặt), và kết luận thẳng thắn là \"câu trả lời vẫn chưa được biết\" (The answer is still unknown). Vì vậy, nói rằng đã có một lý do rõ ràng (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"249\">clear reason</strong>) là sai (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"271\">FALSE</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">6. The data used in the study was taken from the work of amateur butterfly watchers. — {TRUE}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"20\">“...data from millions of records that had been <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"68\">submitted by butterfly enthusiasts – people who spend their free time observing the activities of different species</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nguồn dữ liệu đến từ những người đam mê bướm (butterfly enthusiasts), được định nghĩa rõ là những người dành thời gian rảnh rỗi để quan sát (spend their free time observing). Đây chính là cách giải thích cho từ người quan sát nghiệp dư (<strong data-path-to-node=\"18,1,0\" data-index-in-node=\"249\">amateur butterfly watchers</strong>). Đáp án là <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"288\">TRUE</strong>.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('0e6edfac-8df5-4fa4-902c-d78e40431d4c', 'fff7df18-ff0a-4c1a-83c2-b85e66213af4', 'fillup', 'Questions 7–13', '<p id="p-rc_f40516ba28055d43-430" data-path-to-node="14"><span class="citation-52041 citation-end-52041">Complete the notes below.<sup class="superscript" data-turn-source-index="17"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_f40516ba28055d43-431" data-path-to-node="15"><span class="citation-52040">Choose </span><strong data-path-to-node="15" data-index-in-node="7"><span class="citation-52040">ONE WORD ONLY</span></strong><span class="citation-52040 citation-end-52040"> from the passage for each answer.<sup class="superscript" data-turn-source-index="18"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_f40516ba28055d43-432" data-path-to-node="16"><span class="citation-52039 citation-end-52039">Write your answers in b<sup class="superscript" data-turn-source-index="19"><!----></sup></span>oxes 7–13 on your answer sheet.</p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; border: 2px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="border-width: 2px; padding: 2px; border-color: #000000;">
<p style="text-align: center;" data-path-to-node="17"><span style="font-size: 14pt;"><strong>Butterflies in the UK</strong></span></p>
<p data-path-to-node="18"><strong>The Small Blue</strong></p>
<ul data-path-to-node="19">
<li>
<p data-path-to-node="19,0,0">lives in large {colonies}</p>
</li>
<li>
<p data-path-to-node="19,1,0">first appears at the start of {spring}</p>
</li>
<li>
<p data-path-to-node="19,2,0">completes more than one reproductive cycle per year</p>
</li>
</ul>
<p data-path-to-node="20"><strong>The High Brown Fritillary</strong></p>
<ul data-path-to-node="21">
<li>
<p data-path-to-node="21,0,0">has one reproductive cycle</p>
</li>
<li>
<p data-path-to-node="21,1,0">is considered to be more {endangered} than other species</p>
</li>
<li>
<p data-path-to-node="21,2,0">its caterpillars occupy a limited range of {habitats}</p>
</li>
</ul>
<p data-path-to-node="22"><strong>The Silver-studded Blue</strong></p>
<ul data-path-to-node="23">
<li>
<p data-path-to-node="23,0,0">is already able to reproduce twice a year in warm areas of<strong> </strong>{Europe}</p>
</li>
</ul>
<p data-path-to-node="24"><strong>The White Admiral</strong></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<ul data-path-to-node="25">
<li>
<p data-path-to-node="25,0,0">is found in {southern} areas of England</p>
</li>
<li>
<p data-path-to-node="25,1,0">both climate change and the<strong> </strong>{diet} of the caterpillar are possible reasons for decline</p>
</li>
</ul>
</td>
</tr>
</tbody>
</table>
<p data-path-to-node="16"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">7. colonies — {lives in large colonies}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“For these species, such as Britain''s tiniest butterfly, the dainty Small Blue, <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"100\">whose colonies are up to a hundred strong</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm \"up to a hundred strong\" (mạnh đến hàng trăm cá thể) đồng nghĩa với việc chúng sống trong những bầy đàn/quần thể lớn (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"134\">large colonies</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">8. spring — {first appears at the start of spring}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“...some develop into butterflies <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"54\">early in spring</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Early in spring\" (đầu mùa xuân) tương ứng với cụm \"at the start of spring\".</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">9. endangered — {is considered to be more endangered than other species}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"20\">“The beautiful High Brown Fritillary, often described as <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"77\">Britain''s most endangered butterfly</strong>, is in this group.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Loài bướm này được mô tả là loài có nguy cơ tuyệt chủng cao nhất ở Anh (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"84\">most endangered</strong>), tương ứng với ý nguy cấp hơn các loài khác (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"146\">more endangered than other species</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">10. habitats — {its caterpillars occupy a limited range of habitats}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"20\">“...worryingly, it was found that the species in this group that specialise in <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"99\">very specific habitat types</strong>... It is found only in coppiced woodland and limestone pavement <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"191\">habitats</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc loài bướm này chỉ sống ở một vài kiểu môi trường cố định (woodland, limestone) đồng nghĩa với việc chúng chỉ chiếm một phạm vi môi trường sống hạn chế (<strong data-path-to-node=\"14,1,0\" data-index-in-node=\"169\">limited range of habitats</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">11. Europe — {is already able to reproduce twice a year in warm areas of Europe}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 8):</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"20\">“Many of Britain''s single-generation species show the capacity, in <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"87\">continental Europe</strong>, to <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"110\">add a second generation in years that are sufficiently warm</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở vùng lục địa Châu Âu (<strong data-path-to-node=\"18,1,0\" data-index-in-node=\"36\">Europe</strong>), vào những năm đủ ấm (sufficiently warm), các loài bướm thuộc nhóm này có thể sinh sản thêm một thế hệ thứ hai (add a second generation), tức là sinh sản 2 lần/năm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">12. southern — {is found in southern areas of England}</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"22,0,0\" data-index-in-node=\"20\">“The White Admiral of <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"42\">southern England</strong>, a much sought-after butterfly...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Loài bướm White Admiral được tìm thấy ở khu vực phía nam (<strong data-path-to-node=\"22,1,0\" data-index-in-node=\"70\">southern</strong>) nước Anh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">13. diet — {both climate change and the diet of the caterpillar are possible reasons for decline}</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"24,0,0\" data-index-in-node=\"20\">“This may be because the <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"45\">caterpillar exists solely on a diet of a plant called honeysuckle</strong>. But it is also <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"127\">likely to be due to climate change</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hai nguyên nhân cốt lõi dẫn đến sự sụt giảm số lượng của loài bướm này là do biến đổi khí hậu (due to climate change) và chế độ ăn của sâu bướm chỉ phụ thuộc vào cây kim ngân (<strong data-path-to-node=\"24,1,0\" data-index-in-node=\"188\">diet of the caterpillar</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('60ce46a0-8738-4ce2-93bf-b33010718f2c', 'd2af5006-9e21-4b8c-8269-8cc2dfb176eb', 'matrix', 'Questions 14–17', '', '<p><span class="citation-56035 citation-56036">Write the correct letter, </span><strong data-path-to-node="5" data-index-in-node="26"><span class="citation-56035 citation-56036">A–F</span></strong><span class="citation-56035 citation-56036 citation-end-56036">, in boxes 14–17 on your answer sheet.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "reference to the rapidly increasing need for one raw material in the transport industry", "correctCategoryLetter": "C"}, {"itemText": "a rough estimate of the area of the Earth covered by the oceans", "correctCategoryLetter": "F"}, {"itemText": "how a particular underwater habitat, where minerals and organisms co-exist, is formed", "correctCategoryLetter": "E"}, {"itemText": "reference to the fact that the countries of the world have yet to agree on rules for the exploration of the seabed", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">14. reference to the rapidly increasing need for one raw material in the transport industry — {C}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">“...and point to the fact that demand for resources such as copper, aluminium, <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"90\">cobalt for electric car batteries</strong> and other metals to power technology and smartphones, <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"178\">is soaring</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The transport industry\" (ngành vận tải) ở đây được đại diện qua \"electric car\" (xe điện). \"One raw material\" (một loại nguyên liệu thô) chính là Cobalt dùng làm pin xe điện. Nhu cầu tăng nhanh chóng (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"213\">rapidly increasing need</strong>) tương ứng với từ quặng đang tăng vọt (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"276\">soaring</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">15. a rough estimate of the area of the Earth covered by the oceans — {F}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“<strong data-path-to-node=\"10,0,0\" data-index-in-node=\"12\">The oceans occupy around 70% of the planet</strong> and are relatively unexplored, says Mike Johnston...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"A rough estimate\" (một ước tính sơ bộ/khoảng) tương ứng với cụm \"around 70%\". \"The area of the Earth covered by the oceans\" (diện tích Trái Đất được bao phủ bởi đại dương) tương ứng với \"The oceans occupy... of the planet\". Thông tin này nằm ngay đầu đoạn F.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">16. how a particular underwater habitat, where minerals and organisms co-exist, is formed — {E}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“...the deep seabed, and <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"36\">hydrothermal vents, which are created when seawater meets volcanic magma</strong>, have crucial impacts upon biodiversity... <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"152\">The mineral-rich vents and their surrounds are also home to many well-known animals</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"A particular underwater habitat\" chính là các lỗ phun thủy nhiệt (hydrothermal vents) - nơi khoáng sản giàu có (mineral-rich) và sinh vật cùng chung sống (home to many animals). Cách nó được hình thành (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"216\">how... is formed</strong>) được giải thích qua mệnh đề: \"created when seawater meets volcanic magma\" (được tạo ra khi nước biển gặp magma núi lửa).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">17. reference to the fact that the countries of the world have yet to agree on rules for the exploration of the seabed — {D}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“...and that the <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"28\">global regulatory framework is not yet drafted</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The countries of the world\" tương ứng với tính chất toàn cầu (global). \"Have yet to agree on rules\" (vẫn chưa đồng ý về các quy tắc) tương ứng với cụm \"regulatory framework is not yet drafted\" (khung quy định/pháp lý vẫn chưa được soạn thảo). Thông tin này nằm ở đoạn D.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('f8d9498e-458a-428c-983e-725845d836b4', '2f5d39ba-28ff-4ee6-bfee-823f82b5189a', 'radio', 'Questions 37–40', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Ekman regrets the lies he told as a child"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": " People who are good at lying tend to be good at detecting lies."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Ekman has worked with poker players to help them lie more convincingly."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Ekman is more interested in the types of lies with serious consequences."}]', 'null', 'null', 'null', '[{"content": "<p><strong>37. Ekman regrets the lies he told as a child.</strong></p>\n<ul data-path-to-node=\"27\">\n<li><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) &#8220;Ekman, incidentally, <strong>professes to have been a terrible liar ever since he was a small boy</strong>&#8230;&#8221;</li>\n<li><strong>Giải thích:</strong> Ông thừa nhận là một người nói dối kém từ nhỏ, nhưng <strong>không nói</strong> ông có hối hận (regrets) về những lời nói dối đó hay không.</li>\n</ul>\n<p><strong>38. People who are good at lying tend to be good at detecting lies.</strong></p>\n<ul data-path-to-node=\"29\">\n<li><strong>Đáp án:</strong> <strong>NO</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) &#8220;&#8230;and observes that <strong>ability to detect a lie and the ability to lie successfully are completely unrelated</strong>.&#8221;</li>\n<li><strong>Giải thích:</strong> Hai khả năng này hoàn toàn không liên quan đến nhau (completely unrelated).</li>\n</ul>\n<p><strong>39. Ekman has worked with poker players to help them lie more convincingly.</strong></p>\n<ul data-path-to-node=\"31\">\n<li><strong>Đáp án:</strong> <strong>NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) Ông nói poker players không phải là người nói dối thực sự, nhưng <strong>không có thông tin</strong> về việc ông có làm việc với họ để cải thiện khả năng lừa dối hay không.</li>\n</ul>\n<p><strong>40. Ekman is more interested in the types of lies with serious consequences.</strong></p>\n<ul data-path-to-node=\"33\">\n<li><strong>Đáp án:</strong> <strong>YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) &#8220;He prefers to focus on the kinds of lies where <strong>the liar would be on grave trouble if they were found out</strong>, and where the target would feel properly aggrieved if they knew.&#8221;</li>\n<li><strong>Giải thích:</strong> Ông tập trung vào những lời nói dối gây ra hậu quả nghiêm trọng (&#8220;grave trouble&#8221; / &#8220;serious consequences&#8221;).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('6eda99a5-b3ca-4e9a-97c1-b3d2ae83c205', 'ba5e460b-3837-4355-b923-f06c9b93f981', 'fillup', 'Questions 31-40', '<p>Complete the notes below</p>
<p>Write <strong>ONE WORD ONLY </strong>for each answer.</p>
<p><span style="font-size: 14pt;"><strong>Food Safety Standards</strong></span></p>
<p><strong>Risk assessment</strong></p>
<p>Scientists have to consider potential problems with:</p>
<ul>
<li>
<p>the products {ingredients} (could they attract harmful bacteria?)</p>
</li>
<li>
<p>method of preparation (will it eliminate harmful micro-organisms?)</p>
</li>
<li>
<p>how products are {stored} and distributed</p>
</li>
<li>
<p>supermarkets (e.g. changes in {temperature} affecting the condition of frozen food)</p>
</li>
<li>
<p>end-users (how is food usually handled in the home?)</p>
</li>
</ul>
<p><strong>Factors affecting food consumption</strong></p>
<p><strong>Legislation</strong></p>
<p>Consumer attitudes</p>
<ul>
<li>e.g. dislike of additives → growth of the {organic} food market in Australia</li>
</ul>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>The food industry</strong></p>
<ul>
<li>supermarkets may use price or {image} as their selling strategy (but the main concern is profitability)</li>
</ul>
<p><strong>The mass media</strong></p>
<ul>
<li>
<p>now the main source of {information} for many</p>
</li>
<li>
<p>negative effect because not objective:</p>
<ul>
<li>
<p>concern for {sales}</p>
</li>
<li>
<p>news is now a form of {entertainment}, which can mislead the public</p>
</li>
</ul>
</li>
</ul>
<p><strong>Personal opinion</strong></p>
<ul>
<li>
<p>few programmes deal with food safety or {nutrition}</p>
</li>
<li>
<p>Importance of education: as with benefits of exercise, many children can influence their {parents}</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text "> </div>
</div>
</div>
</div>
</div>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 4: FOOD SAFETY STANDARDS</strong></h3>\n<p id=\"p-rc_a8cb76ec0e49ec8f-161\" data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> <span class=\"citation-3391 citation-3392 citation-3393 citation-3394 citation-3395 citation-end-3395\">Good morning everyone. In today’s lecture, I’m going to talk about food safety and the factors involved in setting standards for the food industry, with particular reference to the situation here in Australia</span><span class=\"citation-3391 citation-3392 citation-3393 citation-3394 citation-end-3394\">.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_a8cb76ec0e49ec8f-162\" data-path-to-node=\"4\"><span class=\"citation-3387 citation-3388 citation-3389 citation-3390 citation-end-3390\">Now, before anyone can decid</span><span class=\"citation-3387 citation-3388 citation-3389 citation-end-3389\">e what kind of standards need to be s</span><span class=\"citation-3387 citation-3388 citation-end-3388\">et for ensuring that any specific food product is safe, scientists have to carry out a risk assessment. And in doing this, they have to consider several potential problems.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_a8cb76ec0e49ec8f-163\" data-path-to-node=\"5\"><span class=\"citation-3385 citation-3386 citation-end-3386\">Firstl</span><span class=\"citation-3385 citation-end-3385\">y, they have to consider t</span>he <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"35\">(31) <span class=\"citation-3383 citation-3384\">ingredients</span></strong></span><span class=\"citation-3383 citation-3384 citation-end-3384\"> of the product. They have to decide whether any of these might make the finished product more susceptible to harmful bacteria. Then they have to consider the process used in the preparation of the food, and whether or not it includes a step designed to eliminate unwanted microor</span><span class=\"citation-3383 citation-end-3383\">ganisms.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_a8cb76ec0e49ec8f-164\" data-path-to-node=\"6\"><span class=\"citation-3382 citation-end-3382\">After that, they’ve got to consider the way products are</span> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"57\">(32) <span class=\"citation-3380 citation-3381\">stored</span></strong></span><span class=\"citation-3380 citation-3381 citation-end-3381\">, for instance in warehouses or cold stores, and distributed to retailers. And it doesn’t end there—the analysts even have to be aware of problems that might occur after the food has reached the supermarket, thi</span><span class=\"citation-3380\">ngs like frozen foods being defrosted and then refrozen because the </span><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"347\"><span class=\"citation-3380 citation-end-3380\">(</span>33) <span class=\"citation-3379\">temperature</span></strong></span><span class=\"citation-3379 citation-end-3379\"> fluctuated, or foods being kept past their expiry date.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_a8cb76ec0e49ec8f-165\" data-path-to-node=\"7\"><span class=\"citation-3378 citation-end-3378\">And finally, any assessment of the overall risk has to take into account the way the end users—consumers—normally handle food at home. So as you see, the risk assessment is quite complica</span>ted.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<hr data-path-to-node=\"8\" />\n<h3 data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">FACTORS AFFECTING FOOD CONSUMPTION</strong></h3>\n<p id=\"p-rc_a8cb76ec0e49ec8f-166\" data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Lecturer:</strong> <span class=\"citation-3377 citation-end-3377\">Now, there are several factors affecting what kind of food we eat. Only one of which is legislation. Another is the attitudes of consumers. A good example of this is the dislike that many Australians have for additives in their food, even when these additives are considered safe</span>. This has led to the phenomenal expansion of the market for <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"350\">(34) organic</strong></span> food in Australia.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"11\">Another important influence on what we eat is the food industry itself. In some large supermarkets, low prices are the main strategy for attracting customers, while for more upscale marketers, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"193\">(35) image</strong></span> is more important. But we should bear in mind for all of them, the key consideration is profitability.</p>\n<p data-path-to-node=\"12\">Finally, there is the influence of the mass media, which is the most important source of <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"89\">(36) information</strong></span> for most people. Unfortunately, this has a rather negative effect because, in general, they are not very objective. For one thing, the prime motivation of the media, as with the food industry, is <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"302\">(37) sales</strong></span>, and this has a major influence on the way in which the topic is dealt with.</p>\n<p data-path-to-node=\"13\">A further problem is that news is regarded as a type of <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"56\">(38) entertainment</strong>.</span> Often the issues that get top billing are those that are sensational or controversial, so it’s not at all surprising if the public ends up with a rather distorted understanding of food and food safety.</p>\n<hr data-path-to-node=\"14\" />\n<h3 data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">PERSONAL OPINION AND EDUCATION</strong></h3>\n<p id=\"p-rc_a8cb76ec0e49ec8f-167\" data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Lecturer:</strong> On top of that, up till now, food safety and <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"55\">(39) nutrition</strong></span> have never been considered a really int<span class=\"citation-3376 citation-end-3376\">eresting topic for the public. Very few TV or radio shows address the issues, and even those shows that are devoted to cooking or eating generally ignore them.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_a8cb76ec0e49ec8f-168\" data-path-to-node=\"17\"><span class=\"citation-3375 citation-end-3375\">At this point, I’ll just offer a personal opinion on this subject. I firmly believe in food safety education starting </span>at primary schools. We know that many children who have been taught about the benefits of exercise come home and lecture their <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"245\">(40) parents</strong> </span>about it. So the same could be done for food and food preparation.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"18\">And at the same time, the countless educational television shows…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('249c5991-640c-4daa-8ffc-0bfa9a904385', '6c315ac3-abf2-44a8-98e3-4264baafd507', 'radio', 'Questions 27–31', '', '<p>Choose <strong data-start="157" data-end="164">YES</strong> – if the statement agrees with the claims of the writer, <strong data-start="223" data-end="229">NO</strong> – if the statement contradicts the claims of the writer, <strong data-start="288" data-end="301">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The Onge language has a particularly poor chance of survival"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Most linguists oppose the idea of a single global language"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Many citizens of the Roman Empire chose to become Latin speakers"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Majority languages such as Spanish and English are now spreading faster within smaller communities than larger ones"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "There is a greater proportion of English used on the internet nowadays than in the 1990s"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. NO</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“Consequently, it would be considered less threatened than a language such as Chipweyan in Canada...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định tiếng Onge có cơ hội sống sót đặc biệt thấp (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"76\">particularly poor chance of survival</em>). Tuy nhiên, bài đọc chỉ ra rằng vì tiếng Onge là bản ngữ của toàn bộ trẻ em trên đảo nên nó được đánh giá là ít bị đe dọa hơn (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"241\">less threatened</strong>) so với tiếng Chipweyan ở Canada. Thông tin mâu thuẫn trực tiếp nên đáp án là <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"335\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. YES</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“The majority of linguists argue, however, that when it comes to language, diversity matters.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói phần lớn các nhà ngôn ngữ học phản đối ý tưởng về một ngôn ngữ toàn cầu duy nhất (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"106\">oppose the idea of a single global language</em>). Điều này trùng khớp với lập luận của bài: phần lớn các nhà ngôn ngữ học cho rằng sự đa dạng mới là điều quan trọng (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"268\">diversity matters</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. YES</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“There was some prestige associated with the language – it was the medium of trade and administration – and people who wanted to get on in life tended to learn it.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói nhiều công dân của Đế quốc La Mã đã tự lựa chọn học tiếng La-tinh (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"91\">chose to become Latin speakers</em>). Bài đọc xác nhận vì tiếng La-tinh mang lại vị thế và là công cụ giao thương, những người muốn tiến thân trong cuộc sống có xu hướng tự học nó (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"267\">tended to learn it</strong>). Đáp án là <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"298\">YES</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“In recent decades, the mass media have reinforced this process further and extended the penetration of metropolitan languages like English and Spanish beyond urban centres into smaller communities.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu thông tin các ngôn ngữ lớn đang mở rộng tầm ảnh hưởng vượt ra ngoài các trung tâm đô thị để thâm nhập vào các cộng đồng nhỏ hơn, chứ <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"161\">hoàn toàn không có sự so sánh</strong> xem tốc độ lan rộng ở cộng đồng nhỏ có nhanh hơn (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"241\">spreading faster</em>) cộng đồng lớn hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. NO</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"13,0,0\" data-index-in-node=\"26\">“However, these fears proved to be unfounded, as the diversity of languages on the web increased rapidly in the years that followed.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định tỷ lệ tiếng Anh được sử dụng trên Internet ngày nay lớn hơn so với những năm 1990 (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"114\">greater proportion... than in the 1990s</em>). Ngược lại, bài đọc chỉ ra rằng nỗi sợ tiếng Anh độc bá đã không diễn ra, vì sự đa dạng của các ngôn ngữ khác trên mạng đã tăng trưởng nhanh chóng (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"303\">diversity of languages on the web increased rapidly</em>), đồng nghĩa với việc tỷ lệ tiếng Anh đã bị giảm đi chứ không tăng lên. Do đó đáp án là <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"443\">NO</strong>.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('52552744-a92e-45ec-b2da-31aa0c44dc3f', 'd2af5006-9e21-4b8c-8269-8cc2dfb176eb', 'matrix', 'Questions 18–23', '', '<p data-path-to-node="14">Write the correct letter, <strong data-path-to-node="14" data-index-in-node="26">A–E</strong>, in boxes 18–23 on your answer sheet.</p>
<p data-path-to-node="15"><strong data-path-to-node="15" data-index-in-node="0">NB</strong> You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of People", "matrixItems": [{"itemText": "A move away from the exploration of heavily mined reserves on land is a good idea.", "correctCategoryLetter": "D"}, {"itemText": "The negative effects of undersea exploration on local areas and their inhabitants are being ignored.", "correctCategoryLetter": "B"}, {"itemText": "There are more worthwhile things to extract from the sea than minerals.", "correctCategoryLetter": "A"}, {"itemText": "No other form of human exploration will have such a destructive impact on marine life as deep-sea mining.", "correctCategoryLetter": "E"}, {"itemText": "More is known about outer space than about what lies beneath the oceans.", "correctCategoryLetter": "B"}, {"itemText": "There is one marine life habitat where experts agree mining should not take place.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Professor Mat Upton", "categoryLetter": "A"}, {"categoryText": "Julie Hunter, Julian Aguon and Pradeep Singh", "categoryLetter": "B"}, {"categoryText": "Dr Jon Copley", "categoryLetter": "C"}, {"categoryText": "Mike Johnston", "categoryLetter": "D"}, {"categoryText": "Verena Tunnicliffe", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">18. D (Mike Johnston) — {A move away from the exploration of heavily mined reserves on land is a good idea.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“It makes sense to explore this untapped potential in an environmentally sustainable way, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"110\">instead of continually looking at the fast depleting land resources of the planet</strong> to meet society’s rising needs,” says Mike Johnston.</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"It makes sense\" (Nó là hợp lý/ý kiến hay) tương ứng với \"is a good idea\". Cụm \"instead of continually looking at the fast depleting land resources\" (thay vì liên tục khai thác nguồn tài nguyên đang cạn kiệt nhanh trên cạn) tương ứng với vế \"a move away from the exploration of heavily mined reserves on land\". Đây là lập luận của <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"343\">Mike Johnston</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">19. B (Julie Hunter, Julian Aguon and Pradeep Singh) — {The negative effects of undersea exploration on local areas and their inhabitants are being ignored.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“...deep-sea mining shares many features with past resource scrambles – including <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"102\">a general disregard for environmental and social impacts</strong>, and the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"168\">marginalisation of indigenous peoples and their rights</strong>,” a paper, written by Julie Hunter and Julian Aguon... and Pradeep Singh... argues.</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"A general disregard\" (sự thờ ơ/coi thường nói chung) tương ứng với việc đang bị ngó lơ (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"101\">being ignored</strong>). \"Environmental and social impacts\" cùng với \"indigenous peoples\" (người bản địa) tương ứng với tác động tiêu cực lên vùng địa phương và cư dân nơi đó (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"268\">local areas and their inhabitants</strong>). Do đó đáp án là <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"320\">B</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">20. A (Professor Mat Upton) — {There are more worthwhile things to extract from the sea than minerals.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“In sustainability terms, <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"46\">this [bioactive potential/medicines] could be a better way of exploiting the economic potential of the deep sea</strong>,” he [Upton] argues... fear such potential will be lost in the rush to exploit the deep sea’s equally rich metal and mineral resources.</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> GS Upton cho rằng việc khai thác tiềm năng sinh học để làm thuốc chữa bệnh là một cách khai thác \"tốt hơn\" (better way / <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"133\">more worthwhile</strong> - đáng giá hơn) so với việc vội vã khai thác tài nguyên kim loại và khoáng sản (minerals). Đáp án chính xác là <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"260\">A</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">21. E (Verena Tunnicliffe) — {No other form of human exploration will have such a destructive impact on marine life as deep-sea mining.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"21\">Mining will be the greatest assault on deep-sea ecosystems ever inflicted by humans</strong>,” according to hydrothermal vent expert Verena Tunnicliffe...</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The greatest assault... ever inflicted by humans\" (cuộc tấn công lớn nhất lịch sử do con người gây ra) đồng nghĩa với việc không có hình thức khai thác nào khác có tác động hủy hoại lớn đến thế (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"208\">No other form... will have such a destructive impact</strong>). Quan điểm cực kỳ mạnh mẽ này là của bà <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"302\">Verena Tunnicliffe</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">22. B (Julie Hunter, Julian Aguon and Pradeep Singh) — {More is known about outer space than about what lies beneath the oceans.}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p id=\"p-rc_fb600a4e390d6b47-23\" data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"13,0,0\" data-index-in-node=\"21\"><span class=\"citation-99\">The surface of the Moon, Mars and even Venus have all been mapped and studied in much greater detail</span></strong><span class=\"citation-99 citation-end-99\">, leading marine scientists to commonly remark that, with respect to the deep sea, ''We don’t yet know what we need to <sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span>know''.” [Written by Julie Hunter, Julian Aguon and Pradeep Singh].</em></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!---->\n<p> </p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặt Trăng, Sao Hỏa và Sao Kim (outer space) đều đã được nghiên cứu chi tiết hơn nhiều (in much greater detail / <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"124\">More is known</strong>) so với biển sâu dưới đại dương. Thông tin này nằm trong bài báo cáo của nhóm chuyên gia thuộc đáp án <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"240\">B</strong>. (Lưu ý: Đáp án B được sử dụng 2 lần).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">23. C (Dr Jon Copley) — {There is one marine life habitat where experts agree mining should not take place.}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"15,0,0\" data-index-in-node=\"21\">On deep sea vents</strong>, scientists are clear,” says Dr Jon Copley... “<strong data-path-to-node=\"15,0,0\" data-index-in-node=\"86\">we don’t want mining on them</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"One marine life habitat\" được chỉ đích danh là các lỗ phun thủy nhiệt dưới biển sâu (deep sea vents). Chuyên gia khẳng định rõ ràng là họ không muốn việc khai thác diễn ra tại đây (should not take place). Đây là tuyên bố của <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"238\">Dr Jon Copley</strong>.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('c29cddb5-f81a-4718-8140-1dcba01f1107', 'e674a859-fea5-4fa4-b005-35d527afb782', 'matrix', 'Questions 19–21', '', '<p>Choose the correct business person, <strong>A</strong>–<strong>E</strong>, for each statement.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "Employees should be kept informed about business developments and performance", "correctCategoryLetter": "B"}, {"itemText": "Work output increases when employees have a good balance between company and family responsibilities", "correctCategoryLetter": "D"}, {"itemText": "It is critical to business success that all company members recognise that they matter", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "Jennifer West", "categoryLetter": "A"}, {"categoryText": "Stephen Harper", "categoryLetter": "B"}, {"categoryText": "Margaret Mills", "categoryLetter": "C"}, {"categoryText": "Victor Davies", "categoryLetter": "D"}, {"categoryText": "Hazel Gibbs", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">19. Employees should be kept informed about business developments and performance — {B: Stephen Harper}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…when his employees receive their salary, they also get an <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"73\">update about the company</strong>, including who their new customers are, what successes they’ve had…” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">20. Work output increases when employees have a good balance… — {D: Victor Davies}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “We enable employees to maintain equilibrium between work and home, a policy which ultimately results in a <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"118\">more productive</strong> and stable workforce.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Productive” tương ứng với “work output increases”, và “equilibrium” tương ứng với “balance”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. It is critical to business success that all company members recognise that they matter — {E: Hazel Gibbs}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…she works hard to ensure that everyone… <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"57\">realizes that they count</strong>.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “They count” (họ có giá trị/quan trọng) đồng nghĩa với “they matter”.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('06083f92-588a-47f3-a7de-7df6f4a45686', '618a0771-05ed-4629-a435-693019173a38', 'matching', 'Questions 14-19', NULL, '<p>Reading passage 2 has six paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of heading below.</p>
<p>Choose the correct number, i-ix, in boxes <strong>14-19</strong>.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. Experimenting with an old idea"}, {"optionText": "ii. Life cycle of Madagascar spiders"}, {"optionText": "iii. Advances in the textile industry"}, {"optionText": "iv. Resources needed to meet the project’s demands"}, {"optionText": "v. The physical properties of spider silk"}, {"optionText": "vi. A scientific analysis of spider silk"}, {"optionText": "vii. A unique work of art"}, {"optionText": "viii. Importance of the silk textile market"}, {"optionText": "ix. Difficulties of raising spiders in captivity"}], "matchingItems": null}', 'null', '[{"content": "<p>14. Paragraph 1</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>vii. A unique work of art</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 1) Văn bản mô tả một loại vải dệt hiếm (<em>rare textile</em>) làm từ lụa nhện, là <strong>tác phẩm duy nhất và lớn nhất</strong> (<em>“the only large piece of cloth made from natural spider silk existing in the world today”</em>) được trưng bày tại bảo tàng New York.</p>\n</li>\n</ul>\n<p>15. Paragraph 2</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong>Đáp án:</strong> <strong>v. The physical properties of spider silk</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 2) Đoạn này liệt kê các thuộc tính vật lý đặc biệt của tơ nhện: <strong>độ đàn hồi cao</strong> (<em>“very elastic”</em>), <strong>sức bền kéo</strong> (<em>“tensile strength”</em>) lớn hơn Kevlar và thép, <strong>siêu nhẹ</strong> (<em>“extremely lightweight”</em>), và <strong>dẻo</strong> (<em>“ductile”</em>).</p>\n</li>\n</ul>\n<p>16.Paragraph 3</p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong>Đáp án:</strong> <strong>ix. Difficulties of raising spiders in captivity</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) Đoạn này giải thích tại sao tơ nhện khó sản xuất hàng loạt: <strong>“spiders have a habit of chomping off each other’s heads when housed together”</strong> (nhện ăn thịt lẫn nhau khi bị nuôi nhốt).</p>\n</li>\n</ul>\n<p>17. Paragraph 4</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>i. Experimenting with an old idea</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) Peers nảy ra ý tưởng dệt tơ nhện sau khi biết về nhà truyền giáo Pháp Jacob Paul Camboue, người đã sử dụng nhện ở Madagascar vào những năm <strong>1880-1890</strong>. Peers đã <strong>xây dựng một bản sao</strong> (<em>“build a replica”</em>) của chiếc máy kéo tơ 24 nhện của Camboue.</p>\n</li>\n</ul>\n<p>18. Paragraph 5</p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong>Đáp án:</strong> <strong>iv. Resources needed to meet the project’s demands</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 5) Để sản xuất lượng tơ cần thiết, các chuyên gia phải <strong>thuê hàng tá người bắt nhện</strong> (<em>“hiring dozens of spider handlers”</em>) và cuối cùng đã sử dụng <strong>hơn 1 triệu con nhện</strong> (<em>“more than 1 million female golden orb spiders”</em>).</p>\n</li>\n</ul>\n<p>19. Paragraph 6</p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong>Đáp án:</strong> <strong>vi. A scientific analysis of spider silk</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 6) Đoạn này thảo luận về các nỗ lực khoa học để sản xuất tơ nhện trong phòng thí nghiệm (chèn gen vào vi khuẩn/động vật) và vai trò của các chuyên gia như Todd Blackledge trong việc <strong>phân tích cách nhện áp dụng lực</strong> (<em>“apply force to rearrange the protein’s molecular structure”</em>) để biến protein lỏng thành tơ rắn.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('36aee50d-2350-4d26-973b-29d36ebf9a74', 'e674a859-fea5-4fa4-b005-35d527afb782', 'fillup', 'Questions 22–26', '<div class="flex max-w-full flex-col grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1" dir="auto" data-message-author-role="assistant" data-message-id="8b1078ca-a7b2-4a64-9205-47843c3b6faf" data-message-model-slug="gpt-5-2">
<div class="flex w-full flex-col gap-1 empty:hidden first:pt-[1px]">
<div class="markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling">
<p data-start="1210" data-end="1286">Complete the summary. Write <strong data-start="1238" data-end="1255">ONE WORD ONLY</strong> from the text for each answer.</p>
<p style="text-align: center;" data-start="1288" data-end="1377"><strong data-start="1292" data-end="1377">Family-friendly practices at Plastic Solutions and the Margaret Mills Corporation</strong></p>
<p data-start="1379" data-end="1786">At Plastic Solutions, a bi-weekly update is issued to workers at the same time as their pay. This includes a section dealing with problems such as {gossip} in communal areas of the workplace. The CEO also arranges a regular {seminar} for selected employees for workplace skills which are in great demand. Finally, employees’ families are invited to company open days, when they are allowed to try out the {machines}.</p>
<p data-start="1788" data-end="2122" data-is-last-node="" data-is-only-node="">The Margaret Mills Corporation allows employees a degree of flexibility with their children, who can be brought to the office once {school} has finished. Mills likes to reward employees for company performance with a party or even a {trip} for families. There is considerable evidence that these practices are having the desired effect.</p>
</div>
</div>
</div>
</div>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">22. …dealing with problems such as {gossip} in communal areas…</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “This addresses issues like <strong data-path-to-node=\"24,0,0\" data-index-in-node=\"39\">gossip</strong>, which employees sometimes indulge in around the water cooler…” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">23. The CEO also arranges a regular {seminar} for selected employees…</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “His employees line up to attend his monthly invitation-only Business Pragmatics <strong data-path-to-node=\"26,0,0\" data-index-in-node=\"92\">seminar</strong>…” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">24. …they are allowed to try out the {machines}.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…kids can experiment with the company’s <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"54\">machines</strong> that manufacture their products…” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Experiment with” tương ứng với “try out”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">25. …who can be brought to the office once {school} has finished.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…allows workers to have their children dropped off when <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"70\">school</strong> is over…” (Đoạn C)</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">26. …reward employees for company performance with a party or even a {trip} for families.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…the company took all employees and their families on a 2-day <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"76\">trip</strong> to Montreal, Canada.” (Đoạn C)</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('99d94cea-b033-4c78-ac89-ada12e3a482b', '6c315ac3-abf2-44a8-98e3-4264baafd507', 'matching', 'Questions 32–35', '', '<p data-start="827" data-end="888">Complete the summary using the list of words, <strong data-start="873" data-end="880">A–I</strong>, below.</p>
<p data-start="890" data-end="965">Write the correct letter, <strong data-start="916" data-end="923">A–I</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-section-id=\"1dr7tvv\" data-start=\"967\" data-end=\"1020\"><span style=\"font-size: 14pt;\"><strong>Disappearing languages in today''s globalised world</strong></span></p>\n<p data-start=\"1022\" data-end=\"1255\">If everybody spoke the same language, whether Spanish, English or Chinese, there would certainly be less chance of {I misunderstandings} between people. But would society suffer if there were one global language? Experts agree that it would.</p>\n<p data-start=\"1257\" data-end=\"1547\">According to Marcus Colchester, people''s use of native languages is key to how they relate to their {D surroundings}. He also emphasises the link between indigenous people''s traditional {F occupations} and the recounting of the myths and folk tales which are integral to their sense of identity.</p>\n<p data-start=\"1549\" data-end=\"1734\">Louisa Maffi describes how loss of language diversity leads to a loss of collective human knowledge, so there could be fewer {A ideas} available to help solve problems in the world.</p>", "optionsTitle": "List of Words", "answerOptions": [{"optionText": "A ideas"}, {"optionText": "B speakers"}, {"optionText": "C connections"}, {"optionText": "D surroundings"}, {"optionText": "E families"}, {"optionText": "F occupations"}, {"optionText": "G relationship"}, {"optionText": "H words"}, {"optionText": "I misunderstandings"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">32. I (misunderstandings)</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"17,0,0\" data-index-in-node=\"26\">“It might bring us closer together, and we would certainly be more likely to make our ideas comprehensible.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nếu tất cả mọi người nói cùng một ngôn ngữ, chúng ta sẽ dễ dàng làm cho ý tưởng của mình trở nên dễ hiểu hơn (<em data-path-to-node=\"17,1,0\" data-index-in-node=\"122\">make our ideas comprehensible</em>). Điều này đồng nghĩa với việc sẽ giảm thiểu được khả năng xảy ra sự hiểu lầm giữa người với người (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"252\">less chance of misunderstandings</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. D (surroundings)</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"19,0,0\" data-index-in-node=\"26\">“People''s understanding of themselves, and their relationship with their environment are all framed in terms of concepts expressed in their own languages...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ khóa \"environment\" (môi trường sống xung quanh) trong bài đọc được thay thế bằng từ đồng nghĩa trong bảng từ là <strong data-path-to-node=\"19,1,0\" data-index-in-node=\"127\">surroundings</strong> (vùng không gian xung quanh).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. F (occupations)</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“Day-to-day activities such as hunting, fishing and farming are directly connected to spirits and mythic beings whose stories make these people who they are.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các hoạt động hằng ngày được bài đọc liệt kê bao gồm săn bắn, đánh cá và làm ruộng (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"96\">hunting, fishing and farming</em>). Tất cả những hoạt động này được khái quát hóa bằng danh từ chỉ nghề nghiệp, công việc mưu sinh (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"223\">occupations</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. A (ideas)</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“As we lose each language, we lose a repository of knowledge, values and beliefs that, in many cases, provide alternative solutions to human problems; we diminish that pool of creativity and inventiveness...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc mất đi một ngôn ngữ làm mất đi kho tàng tri thức và sự sáng tạo, khiến con người có ít các giải pháp (<em data-path-to-node=\"23,1,0\" data-index-in-node=\"119\">solutions</em>), phương án hoặc ý tưởng (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"155\">ideas</strong>) hơn để giải quyết các vấn đề toàn cầu.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('c8e30fe6-1d9e-4e57-b10e-dabd1744bb5c', '6c315ac3-abf2-44a8-98e3-4264baafd507', 'radio', 'Questions 37–40', '', '<p data-start="21" data-end="65">Choose the correct letter, <strong data-start="48" data-end="64">A, B, C or D</strong>.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A. a key factor in determining how endangered a language is"}, {"option_text": "B. alternative methods of interpreting data about languages at risk"}, {"option_text": "C. different reasons why a minority language might be under threat"}, {"option_text": "D. difficulties involved in assessing a language''s survival prospects"}], "question": "In the first paragraph, the writer mentions two particular languages in order to indicate"}, {"correct": 1, "options": [{"option_text": "A. the growth of international trade"}, {"option_text": "B. the shift towards living in more extended social groups"}, {"option_text": "C. the attitude of governments towards minority languages"}, {"option_text": "D. the speed with which minority languages fall out of use"}], "question": "What similarity between the Roman Empire and the present day does Nicholas Ostler mention?"}, {"correct": 3, "options": [{"option_text": "A. it is more difficult for minority-language speakers to access education"}, {"option_text": "B. majority-language speakers can participate better in national life"}, {"option_text": "C. their national government is opposed to the use of minority languages"}, {"option_text": "D. they need to choose between being a minority- or majority-language speaker"}], "question": "According to Louisa Maffi, many people wrongly believe that"}, {"correct": 0, "options": [{"option_text": "A. younger people''s perceptions of their mother tongue"}, {"option_text": "B. breakdown of communication between the generations"}, {"option_text": "C. older people''s attitudes to their children''s language use"}, {"option_text": "D. generational differences in ability to access the mass media"}], "question": "What problem among minority-language speakers is mentioned in the eighth paragraph?"}, {"correct": 1, "options": [{"option_text": "A. the variety of media it can use"}, {"option_text": "B. the freedom its users can have"}, {"option_text": "C. the wide geographical area it can reach"}, {"option_text": "D. the range of people it can be accessed by"}], "question": "What does Peter Austin see as the main advantage of the internet for minority language groups?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">36. A — a key factor in determining how endangered a language is.</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"27,0,0\" data-index-in-node=\"26\">“However, the total number of speakers is not always a clear indication of the health of a language.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả mượn ví dụ về tiếng Onge (ít người nói nhưng trẻ em vẫn dùng) và tiếng Chipweyan (nhiều người thuộc nhóm dân tộc đó nhưng thế hệ trẻ không dùng) để làm nổi bật luận điểm: tổng số lượng người nói không phải là thước đo duy nhất, mà việc thế hệ trẻ có kế thừa ngôn ngữ đó hay không mới là yếu tố mấu chốt (<strong data-path-to-node=\"27,1,0\" data-index-in-node=\"324\">a key factor</strong>) để xác định mức độ nguy cấp của một ngôn ngữ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">37. B — the shift towards living in more extended social groups</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\">“The Romans succeeded in making people live in larger communities, what we now call urbanisation.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nicholas Ostler chỉ ra điểm tương đồng giữa thời La Mã và thời hiện đại là xu hướng dịch chuyển từ nông thôn ra thành thị, khiến con người sống trong các cộng đồng lớn hơn (<strong data-path-to-node=\"29,1,0\" data-index-in-node=\"185\">live in larger communities / shift towards living in more extended social groups</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">38. D — they need to choose between being a minority- or majority-language speaker.</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“There is essentially a misconceived either/or ideology: either you maintain your mother tongue... or you forget your mother tongue and learn the majority language.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Louisa Maffi cho rằng mọi người đang bị áp đặt một tư tưởng sai lầm \"hoặc/hoặc\" (<em data-path-to-node=\"31,1,0\" data-index-in-node=\"93\">misconceived either/or ideology</em>): hoặc giữ tiếng mẹ đẻ, hoặc quên nó đi để học ngôn ngữ phổ thông. Tư tưởng sai lầm này khiến họ lầm tưởng rằng mình bắt buộc phải chọn lựa giữa việc trở thành người nói tiếng thiểu số hay tiếng phổ thông (<strong data-path-to-node=\"31,1,0\" data-index-in-node=\"331\">need to choose between...</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">39. A — younger people''s perceptions of their mother tongue</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"33,0,0\" data-index-in-node=\"26\">“All of the images children see in the media are of the glamorised lifestyle of the majority... So it becomes very difficult for them to find a reason to value their own language.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn số 8 đề cập đến vấn đề truyền thông đại chúng vẽ ra lối sống hào nhoáng của nhóm đa số, khiến trẻ em và người trẻ tuổi không còn tìm được lý do để trân trọng ngôn ngữ truyền thống của dân tộc mình. Đây chính là góc nhìn, nhận thức của người trẻ về tiếng mẹ đẻ (<strong data-path-to-node=\"33,1,0\" data-index-in-node=\"278\">younger people''s perceptions of their mother tongue</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">40. B — the freedom its users can have</strong></p>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong data-path-to-node=\"35,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"35,0,0\" data-index-in-node=\"26\">“Unlike most TV or radio, the web isn''t in the hands of big media corporations... Minority groups around the world... are now taking advantage of this autonomy to document their language...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong data-path-to-node=\"35,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Peter Austin nhận định lợi thế lớn nhất của Internet là nó không bị kiểm soát bởi các tập đoàn truyền thông lớn. Bất kỳ ai cũng có thể tự tạo tài khoản và sản xuất nội dung. Sự tự trị, tự chủ này (<em data-path-to-node=\"35,1,0\" data-index-in-node=\"209\">autonomy</em>) mang lại quyền tự do hành động rất lớn cho người dùng (<strong data-path-to-node=\"35,1,0\" data-index-in-node=\"274\">the freedom its users can have</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('65d0aa60-325d-4c9d-9a10-1bea5bd64d51', 'd2af5006-9e21-4b8c-8269-8cc2dfb176eb', 'fillup', 'Questions 24–26', '<p id="p-rc_dfc462fbf3824578-464" data-path-to-node="26">Complete the summary <span class="citation-55988 citation-55989 citation-55990 citation-55991 citation-55992 citation-end-55992">below.<sup class="superscript" data-turn-source-index="49"><!----></sup></span><span class="citation-55988 citation-55989 citation-55990 citation-55991 citation-end-55991"><sup class="superscript" data-turn-source-index="50"><!----></sup></span><span class="citation-55988 citation-55989 citation-55990 citation-end-55990"><sup class="superscript" data-turn-source-index="51"><!----></sup></span><span class="citation-55988 citation-55989 citation-end-55989"><sup class="superscript" data-turn-source-index="52"><!----></sup></span><span class="citation-55988 citation-end-55988"><sup class="superscript" data-turn-source-index="53"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_dfc462fbf3824578-465" data-path-to-node="27"><span class="citation-55983 citation-55984 citation-55985 citation-55986 citation-55987">Choose </span><strong data-path-to-node="27" data-index-in-node="7"><span class="citation-55983 citation-55984 citation-55985 citation-55986 citation-55987">ONE WORD ONLY</span></strong><span class="citation-55983 citation-55984 citation-55985 citation-55986 citation-55987 citation-end-55987"> from the passage for each answer.<sup class="superscript" data-turn-source-index="54"><!----></sup></span><span class="citation-55983 citation-55984 citation-55985 citation-55986 citation-end-55986"><sup class="superscript" data-turn-source-index="55"><!----></sup></span><span class="citation-55983 citation-55984 citation-55985 citation-end-55985"><sup class="superscript" data-turn-source-index="56"><!----></sup></span><span class="citation-55983 citation-55984 citation-end-55984"><sup class="superscript" data-turn-source-index="57"><!----></sup></span><span class="citation-55983 citation-end-55983"><sup class="superscript" data-turn-source-index="58"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_dfc462fbf3824578-466" data-path-to-node="28"><span class="citation-55978 citation-55979 citation-55980 citation-55981 citation-55982 citation-end-55982">Write your answers in boxes 24–26 on your answer sheet.</span></p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; border: 2px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr style="height: 205.771px;">
<td style="border-width: 2px; padding: 2px; border-color: #000000;">
<p style="text-align: center;" data-path-to-node="29"><span class="citation-55973 citation-55974 citation-55975 citation-55976 citation-55977 citation-end-55977"><span style="font-size: 12pt;"><strong>Mining the sea floor</strong></span><sup class="superscript" data-turn-source-index="64"><!----></sup></span><span class="citation-55973 citation-55974 citation-55975 citation-55976 citation-end-55976"><sup class="superscript" data-turn-source-index="65"><!----></sup></span><span class="citation-55973 citation-55974 citation-55975 citation-end-55975"><sup class="superscript" data-turn-source-index="66"><!----></sup></span><span class="citation-55973 citation-55974 citation-end-55974"><sup class="superscript" data-turn-source-index="67"><!----></sup></span><span class="citation-55973 citation-end-55973"><sup class="superscript" data-turn-source-index="68"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_dfc462fbf3824578-467" data-path-to-node="30"><span class="citation-55968 citation-55969 citation-55970 citation-55971 citation-55972 citation-end-55972">Mining corporations believe that the mineral resources lying under the sea may be superior to those found in the earth. They also say that these can <sup class="superscript" data-turn-source-index="69"><!----></sup></span><span class="citation-55968 citation-55969 citation-55970 citation-55971">be removed without producing much<strong> </strong>{waste}</span><span class="citation-55968 citation-55969 citation-55970 citation-55971 citation-end-55971"> .<sup class="superscript" data-turn-source-index="70"><!----></sup></span><span class="citation-55968 citation-55969 citation-55970 citation-end-55970"><sup class="superscript" data-turn-source-index="71"><!----></sup></span><span class="citation-55968 citation-55969 citation-end-55969"><sup class="superscript" data-turn-source-index="72"><!----></sup></span><span class="citation-55968 citation-end-55968"><sup class="superscript" data-turn-source-index="73"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_dfc462fbf3824578-468" data-path-to-node="31"><span class="citation-55964 citation-55965 citation-55966 citation-55967 citation-end-55967">The extraction is often done by adapting the<sup class="superscript" data-turn-source-index="74"><!----></sup></span> {machinery}<span class="citation-55964 citation-55965 citation-55966 citation-end-55966"> that has already been used to work on land. The method of excavation involves removing the seawat<sup class="superscript" data-turn-source-index="75"><!----></sup></span><span class="citation-55964 citation-55965 citation-end-55965">er from the slurry that is brought up to ships and returning it to the seabed. However, concerned groups strongly believe tha<sup class="superscript" data-turn-source-index="76"><!----></sup></span><span class="citation-55964">t {caution}</span><span class="citation-55964 citation-end-55964"> is necessary due to the possible number of unidentified consequ<sup class="superscript" data-turn-source-index="77"><!----></sup></span>ences.</p>
</td>
</tr>
</tbody>
</table>
<p data-path-to-node="28"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">24. waste — {They also say that these can be removed without producing much waste.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“They say that deep-sea mining could yield far superior ore to land mining with <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"100\">little, if any, waste</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Without producing much\" (không tạo ra nhiều) tương ứng với cụm từ \"little, if any\" (rất ít, nếu có). Từ cần điền ở đây là chất thải (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"146\">waste</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">25. machinery — {The extraction is often done by adapting the machinery that has already been used to work on land.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Different methods of extraction exist, but most involve employing some form of <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"100\">converted machinery previously used in terrestrial mining</strong> to excavate materials from the sea floor...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Terrestrial mining\" chính là khai thác trên cạn (work on land). \"Converted\" (được chuyển đổi mục đích) tương ứng với từ \"adapting\" (cải tiến/thích nghi). Thiết bị được cải tiến ở đây chính là máy móc (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"214\">machinery</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">26. caution — {However, concerned groups strongly believe that caution is necessary due to the possible number of unidentified consequences.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“But environmental and legal groups <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"56\">have urged caution</strong>, arguing there are <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"94\">potentially massive and unknown ramifications</strong> for the environment...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Concerned groups\" (các nhóm lo ngại) chính là các tổ chức về môi trường và pháp lý (environmental and legal groups). \"Unidentified consequences\" (những hậu quả chưa được xác định) tương ứng với \"unknown ramifications\" (những hệ lụy chưa biết tới). Các nhóm này đã thúc giục/kêu gọi sự cẩn trọng (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"309\">caution</strong>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('53d2978b-ed9b-4971-ab6e-90233f904235', '9b361a9e-dca1-4d35-9f5e-8b48bc7c4bf8', 'fillup', 'Questions 1-10', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Complete the notes below</p>
<p>Write<strong> NO MORE THAN TWO WORDS AND/OR A NUMBER </strong>for each answer.</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><span style="font-size: 12pt;"><strong>International Student Travel Agency Enquiry Form</strong></span></p>
<p><strong>Name:</strong> Sarah Brown</p>
<p><strong>Date of birth:</strong> {30th March 1988|March 30th 1988|March 30 1988}</p>
<p><strong>Address:</strong> 21 Waverley Road, Radstone, RD4 6WV</p>
<p><strong>Contact tel. no.:</strong> {0903775115}</p>
<p><strong>Notes:</strong></p>
<ul>
<li>
<p>wants to travel in {Northern} Europe</p>
</li>
<li>
<p>hopes to travel by {train}</p>
</li>
<li>
<p>interested in working in a {hotel}</p>
</li>
<li>
<p>recommended to consider an alternative e.g.</p>
</li>
<li>
<p>{farm} work</p>
</li>
<li>
<p>advised to buy a European {pass} for travelling</p>
</li>
<li>
<p>given a {booklet} with accommodation details</p>
</li>
<li>
<p>agreed to take out {insurance} from the Agency</p>
</li>
<li>
<p>told to use an {internet cafe} for contacting people</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 1: INTERNATIONAL STUDENT TRAVEL AGENCY ENQUIRY</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Agent:</strong> Hello, how can I help you?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Sarah:</strong> Um, I’m taking a year off and I’m hoping to travel abroad and to find work as well for part of the time. I know you specialize in student travel and work placements.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Agent:</strong> That’s right. We can help you arrange your travel and set up a job for you. But first of all, I need some personal details and then we’ll match your details against our database to see what’s available work-wise.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Sarah:</strong> Great, OK.</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Agent:</strong> Your full name?</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Sarah:</strong> Sarah Brown.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Agent:</strong> Date of birth?</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Sarah:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"7\">(1) March the 30th</strong></span>, oh I’m the 31st haha, <strong data-path-to-node=\"10\" data-index-in-node=\"49\">1988</strong>.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Agent:</strong> And your address?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Sarah:</strong> 21 Waverly Road, Radstone, RD4 6WV.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Agent:</strong> And a contact telephone number please?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Sarah:</strong> Um, I can give you my mobile number… <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"46\">(2) 0903775115</strong>.</span></p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Agent:</strong> Fine. Now tell me where you plan to travel to and I’ll see how I can help.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Sarah:</strong> Well, I’d like to go to <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"31\">(3) Northern</strong></span> Europe.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Agent:</strong> Have you been there before?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Sarah:</strong> No, I know Southern Europe quite well as I’ve been there with my family. We always went by plane but now I can choose, I’d like to go by <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"144\">(4) train</strong></span> so I can stop off whenever I want.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Agent:</strong> OK, now just as important, what sort of work have you got in mind?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Sarah:</strong> Well, I thought about<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"20\" data-index-in-node=\"29\">(5) hotel</strong></span> work, because then I might get accommodation with the job, and I’d like to work for about half the year.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Agent:</strong> Hmm, that sort of work is usually quite competitive. Perhaps you should consider an alternative just in case, such as… well, lots of students like to work on a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"169\">(6) farm</strong></span>. We have lots of requests from people looking for student workers for a few weeks at a time throughout the year. You can generally earn quite good money if you’re willing to work fairly long hours.</p>\n<hr data-path-to-node=\"22\">\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Agent:</strong> Now travel… buying single tickets would be expensive, so the best option would be to have a European <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"110\">(7) pass</strong></span>, which would give you unlimited rail travel at off-peak times. To start off with, we could issue one for up to three months to cover the countries you’re intending to visit.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Sarah:</strong> Sounds good. Do you have any information about youth hostels which I could use to plan my route?</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Agent:</strong> Yes, I’ll give you a <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"28\">(8) booklet</strong></span> now, but it’s down to you to book your accommodation. At certain times of the year, especially during public holiday periods, such places fill up fast.</p>\n<p data-path-to-node=\"26\">And remember, if we are going to arrange work for you in the countryside, you won’t be able to go out easily in the evenings, although you’d probably be too tired anyway.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Sarah:</strong> I won’t mind that. And you’re going to be travelling alone?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Sarah:</strong> Yes.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Agent:</strong> Well, before I make any arrangements for you, you need to have <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"29\" data-index-in-node=\"70\">(9) insurance</strong></span> for your entire trip. We can arrange that for you if you like.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Sarah:</strong> What does it cover?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Agent:</strong> Any valuable items, jewellery for example, your money, your mobile, your health… and if you needed to get back home quickly, you’d be covered so you could buy a plane ticket, right?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Sarah:</strong> I’ll do that. I thought I’d take my laptop so I can email and keep in touch with people at home.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Agent:</strong> Hmm, not a good idea to lug your computer around with you. It’s much more sensible to rely on an <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"33\" data-index-in-node=\"104\">(10) internet cafe</strong></span>. That’s what we tell people to do.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Sarah:</strong> Oh, okay.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Agent:</strong> Right, so I’ve entered all your details. Let’s see what the database comes up with…</p>"}]', 0);
INSERT INTO public.questions VALUES ('8fbc6016-412d-448e-82ad-5b9e6c577362', '3d353081-66fb-4f73-a006-c0a6ae3bb3a4', 'radio', 'Question 11-15', NULL, '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Choose the correct letter, A,B or C</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Driving license in UK</strong></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A a medical report"}, {"content": "B a valid licence from another country"}, {"content": "C Current residency in the UK"}], "question": "What is the basic requirement for applying for a UK driving licence?"}, {"correct": 0, "options": [{"content": "A Applicants need to go to a recognised organisation"}, {"content": "B It is not always necessary for foreigners when applying for a UK licence"}, {"content": "C Applicants need to pay an extra fee for translation services"}], "question": "What is true about the translation of original licences?"}, {"correct": 1, "options": [{"content": "A Photos in which the applicant is wearing glasses"}, {"content": "B Photos with a cream background"}, {"content": "C Photos that are undersized"}], "question": "When applying for a UK licence, which type of photos will NOT be approved?"}, {"correct": 0, "options": [{"content": "A The process is too slow"}, {"content": "B The application form is confusing"}, {"content": "C Some of the steps are unnecessary"}], "question": "What does the speaker think of the licence checking service?"}, {"correct": 2, "options": [{"content": "A Choosing a quiet location"}, {"content": "B Visiting the nearest branch"}, {"content": "C Completing the forms online"}], "question": "What does the speaker recommend about making an application?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 2: DRIVING LICENCES AND TRAFFIC CONDITIONS</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Edward:</strong> Hello, I’m Edward and I’m here to tell you about road conditions in various areas of the UK. I am also going to tell you about driver’s licenses in the UK.</p>\n<p id=\"p-rc_1255320846f8b4f5-142\" data-path-to-node=\"4\">If you have never had a driver’s licence or you have one from another country and you want to get a UK licence, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"112\">(11) you must be a UK resident [Answer: C]</strong></span>. <span class=\"citation-2373 citation-end-2373\">You will need to show a medical report when your UK licence needs to be renewed.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_1255320846f8b4f5-143\" data-path-to-node=\"5\"><span class=\"citation-2372 citation-end-2372\">If you are trying to translate your original foreign driving licence to apply for a UK licence, which is a must if you want to be able to driv</span>e here, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"150\">(12) you will need to visit an official agency [Answer: A – recognized organisation]</strong></span>. These are scattered throughout the London area and are well equipped to assist you with any questions you might have, and any services they offer are included in your license <span class=\"citation-2370 citation-2371 citation-end-2371\">fee. If you already have a translated licence but need some personal information updating, you do not need to pay for the update; they’ll do it for free.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_1255320846f8b4f5-144\" data-path-to-node=\"6\"><span class=\"citation-2368 citation-2369 citation-end-2369\">When you are getting a new driving licence, you may need to have a new photo taken as some photos </span><span class=\"citation-2368\">are rejected. It’s actually okay if your photo is too small since we can get it enlarged with our printer. </span><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"205\"><span class=\"citation-2368 citation-end-2368\">(</span>13) The majority of rejected photos are the ones that were taken with a cream backdrop [Answer: B]</strong></span>, instead of a monotone grey background. <span class=\"citation-2366 citation-2367 citation-end-2367\">We’ve now found that photos with the latter allow us to identify the licence holder much more easily. If you were wearing glasses on the previous photo, you don’t need to worry about it since it is still allowed.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_1255320846f8b4f5-145\" data-path-to-node=\"7\"><span class=\"citation-2364 citation-2365 citation-end-2365\">If you are not sure whether your previous licence is still valid then the licence checking service is for you. The procedures are qu</span><span class=\"citation-2364 citation-end-2364\">ite clear and you just have to follow them</span>. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"176\">(14) Ideally I would like to see the process going faster, since it can take hours to finish [Answer: A – too slow]</strong></span>. <span class=\"citation-2362 citation-2363 citation-end-2363\">From my standpoint, it will help if all the applicants bring the necessary identification with them, then all they have to do is just fill in the forms accordingly step by step.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_1255320846f8b4f5-146\" data-path-to-node=\"8\"><span class=\"citation-2360 citation-2361 citation-end-2361\">I’m often asked whether I have a personal recommendation about the fastest or cheapest place to</span><span class=\"citation-2360 citation-end-2360\"> get all this done, but I think it really depends on where you are. They can all get busy at some point. A</span>ll I would say is that there is absolutely no difference in price. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"268\">(15) The quickest way to complete an application is to fill out the form on the internet [Answer: C]</strong></span>, and then bring a print copy with you to the agency location of your choice.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<hr data-path-to-node=\"9\" />\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">TRAFFIC MANAGEMENT IN UK CITIES (Questions 16–20)</strong></h3>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Edward:</strong> Next, people frequently ask me what I think of the road conditions in some of our cities.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">London</strong> is obviously the biggest, and there are lots of parking restrictions, one-way systems and so on. But on the whole, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"122\">(16) I find the traffic signs are very clear [Answer: A – Good signage]</strong>.</span></p>\n<p id=\"p-rc_1255320846f8b4f5-147\" data-path-to-node=\"13\">In <strong data-path-to-node=\"13\" data-index-in-node=\"3\">Edinburgh</strong>, most people use digital maps to get to know local traffic and road conditions. It is a city of lights—traffic lights—but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"135\">(17) they’re extremely efficient as they’re timed perfectly to get the traffic flowing smoothly [Answer: F – Effective traffic lights]</strong>.</span> <span class=\"citation-2359 citation-end-2359\">That’s important because pedestrian areas and crossings are always packed with people on foot which needs strong regulation.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p id=\"p-rc_1255320846f8b4f5-148\" data-path-to-node=\"14\"><span class=\"citation-2358\">The City of </span><strong data-path-to-node=\"14\" data-index-in-node=\"12\"><span class=\"citation-2358\">Cardiff</span></strong><span class=\"citation-2358 citation-end-2358\"> has tackled traffic flow in a different way. It recently completed a road expansion scheme</span> and <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"115\">(18) the extra lanes of the dual carriageway are easing congestion [Answer: G – Additional lanes]</strong>.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p>&nbsp;</p>\n<p data-path-to-node=\"15\">It’s a similar story in <strong data-path-to-node=\"15\" data-index-in-node=\"24\">Manchester</strong>. Instead of going through the town centre, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"78\">(19) most vehicles choose ring roads so as to avoid the downtown congestion [Answer: D – Ring roads]</strong></span>. It can still happen though, so there’s a possibility that the city will introduce checkpoints where the police can intervene.</p>\n<p data-path-to-node=\"16\">And finally, they say all roads lead to Rome, and you could say that about <strong data-path-to-node=\"16\" data-index-in-node=\"75\">Oxford</strong>. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"83\">(20) I like the many options for getting in and out of the city because drivers can always find alternative routes [Answer: B – Multiple access roads]</strong>.</span></p>\n"}]', 0);
INSERT INTO public.questions VALUES ('2e866985-41e0-4682-a23e-7ddc8c4507d5', '3d353081-66fb-4f73-a006-c0a6ae3bb3a4', 'matching', 'Question 16-20', NULL, '<p>What is the current feature of traffic management in each of the following cities<br>Write the correct letter, <strong>A-H</strong></p>', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Cities</strong></p>\n<p> </p>\n<p>London {good signage}</p>\n<p> </p>\n<p>Edinburgh {Effective traffic lights}</p>\n<p> </p>\n<p>Cardiff {Additional lanes}</p>\n<p> </p>\n<p>manchester {ring roads}</p>\n<p> </p>\n<p>oxford {multiple access roads}</p>", "optionsTitle": "Features", "answerOptions": [{"optionText": "good signage"}, {"optionText": "multiple access roads"}, {"optionText": "police control points"}, {"optionText": "ring roads"}, {"optionText": "one- way streets"}, {"optionText": "Effective traffic lights"}, {"optionText": "Additional lanes"}, {"optionText": "Pedestrianised areas"}], "matchingItems": null}', 'null', '[{"content": ""}]', 1);
INSERT INTO public.questions VALUES ('eed498b5-945f-458d-b269-8e5a4040e43c', '3efd3c46-8e10-415a-b836-b30d805fa715', 'radio', 'Questions 21–25', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "give both sides of an argument."}, {"option_text": "express personal opinions."}, {"option_text": "present a range of views."}], "question": "Katy thinks it might be inappropriate for academic essays to"}, {"correct": 2, "options": [{"option_text": "withhold their own views."}, {"option_text": "avoid too much repetition."}, {"option_text": "refer to the title."}], "question": "The tutor says that in one type of conclusion students should"}, {"correct": 0, "options": [{"option_text": "There is a standard format for references."}, {"option_text": "Presentation is not assessed at this level."}, {"option_text": "Book titles should be underlined."}], "question": "What does the tutor say about the bibliography?"}, {"correct": 1, "options": [{"option_text": "They provide evidence of how widely a student has read."}, {"option_text": "They are useful for defining difficult concepts."}, {"option_text": "There is a tendency to use too few of them."}], "question": "What advice does the tutor give about quotations?"}, {"correct": 0, "options": [{"option_text": "done more thorough research."}, {"option_text": "analysed his data more carefully."}, {"option_text": "given his views more clearly."}], "question": "John suggests that the writer of the first essay should have"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 3: ACADEMIC ESSAY WRITING</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Tutor:</strong> Morning Katie. Morning John. I want to talk about essays today and what the requirements are for this university—what kinds of things we look for when we''re grading them, okay? So let''s look at those two sample essays I gave you last week. I asked you to read them and to think about their strong and weak points. Do either of you have any general comments or questions about the first one, Katie?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Katie:</strong> Um, well, the writer''s made it quite clear what his own views are about this subject. <span style=\"text-decoration: underline;\"><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"93\">(Q21) But I thought in academic essays you weren''t supposed to do that. I thought you were meant to present all the different arguments and just appear to be neutral</strong></span></span> about which one you think is best.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Tutor:</strong> Students do sometimes come down quite firmly on one particular side, and that''s okay, as long as they can show that they''ve given balanced consideration to all the issues. Do you see what I mean? John, you''re looking a bit uncertain. Did you want to say something?</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">John:</strong> Well, what if you don''t feel as sure about the debate as this student?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Tutor:</strong> There''s another type of conclusion that''s valid when you''re writing at this level. People don''t have to come down strongly on a particular side. They can say in the essay that the process of researching a particular topic has identified the importance of a range of studies that support different viewpoints. <strong data-path-to-node=\"7\" data-index-in-node=\"316\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q22) And then they return to the title of the assignment</span>.</strong> I''d say that it''s a good idea to use some of the actual words that are in the title; it shows the reader that you''re still on track.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">John:</strong> Can I just ask you something about the bibliography?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Tutor:</strong> Of course, um...</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">John:</strong> This person''s used italics when he refers to book titles in the reference section, but I thought we had to underline them.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Tutor:</strong> <strong data-path-to-node=\"11\" data-index-in-node=\"7\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q23) Actually, he''s done it in the way we set out in the university study guide. That is the appropriate convention for titles</span>.</strong> You might think it''s trivial, but presenting references appropriately is one of the requirements of a degree at this level.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Katie:</strong> I looked in the study guide to see what it said about quotations. The essay''s got a lot of quite long ones, and I was a bit surprised by that.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Tutor:</strong> Using a range of quotations is a way of showing that you have actually read quite widely, isn''t it? Well, not really, unfortunately. Some students just pick out extracts to quote without actually reading the whole thing. It''s really a matter of using quotations appropriately. <strong data-path-to-node=\"13\" data-index-in-node=\"284\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q24) So when exactly should we use quotes? Particularly where there are definitions involved... terms that need defining for instance</span>.</strong> Why not cite someone else''s definition rather than dream one up yourself?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">John:</strong> What about the way the writer discusses research findings? <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"65\">(Q25) One thing that struck me was the approach of the student to some of the things he''d read... I''ve always felt that it''s just up to me to go to the primary sources and find out.</strong></span></p>\n<hr data-path-to-node=\"15\">\n<h3 data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">THE SECOND ESSAY (Questions 26–30)</strong></h3>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Tutor:</strong> Now let''s look at the second essay then. Did you think this student answered the question?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Katie/John:</strong> Yes.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Tutor:</strong> Good, because really that''s the bottom line. The minimum criterion for an assignment is relevance. Secondly, what about the overall structure?</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Katie:</strong> Sometimes writers mix different subtopics up, so it''s quite difficult to follow the logic of the essay. <strong data-path-to-node=\"20\" data-index-in-node=\"111\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q26) But here I think they''re separated very clearly (sub-topics)</span>.</strong></p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">John:</strong> Yes, I mean it is very clear, but is it okay to use subheadings and bullet points like this? I mean, <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"107\">(Q27) in things like reports they can be very useful I know, but is it alright to use them in academic essays?</strong></span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Tutor:</strong> Well, my general feeling is that it''s best just to use paragraphs to signal changes of topic.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">John:</strong><span style=\"text-decoration: underline;\"> </span><strong data-path-to-node=\"23\" data-index-in-node=\"6\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q28) One thing I thought was really good about this essay was the way the writer always gives examples to support statements</span>.</strong> He never just assumes that explanations are enough.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Tutor:</strong> Yes, I''m glad you brought that up. It''s very helpful for the reader.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Katie:</strong> Another thing that helps the reader is the way he uses words and phrases to <strong data-path-to-node=\"25\" data-index-in-node=\"83\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q29) connect (link) his ideas</span>.</strong> You mean things like \"however\" and \"on the other hand\"?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Tutor:</strong> Yes, that really is one of the hallmarks of a good essay. Now, you may feel at this early stage that your writing skills are rusty, but <strong data-path-to-node=\"26\" data-index-in-node=\"143\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q30) reading is the key I think</span>.</strong> As you read more and more extensively, you''ll find that your own use of academic language will improve.</p>"}]', 0);
INSERT INTO public.questions VALUES ('fd078f0f-b91c-4734-954a-39d48081c5ee', '3efd3c46-8e10-415a-b836-b30d805fa715', 'fillup', 'Questions 26–30', '<p>Complete the sentences below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<ul>
<li>
<p>The tutor says that the most basic requirement of an essay is relevance.</p>
</li>
<li>
<p>Katy thinks the writer separates different {subtopics|sub-topics} very clearly.</p>
</li>
<li>
<p>John feels that bullet points and sub-headings might be more appropriate for {reports} than for essays.</p>
</li>
<li>
<p>The tutor thinks that paragraphs should be used to structure essays.</p>
</li>
<li>
<p>John particularly admires the way the writer backs up his statements with {examples}</p>
</li>
<li>
<p>Katy likes the writer''s use of language to link his {ideas}</p>
</li>
<li>
<p>The tutor thinks that wide {reading} helps to develop writing ability</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": ""}]', 1);
INSERT INTO public.questions VALUES ('56de983d-0a61-4134-9881-4e8b0c81dd61', 'bcd0cc46-d16d-489c-8e59-12a478fdf10a', 'fillup', 'Questions 1-10', '<p>Complete the notes below</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p style="text-align: left;"><span style="font-size: 12pt;"><strong>Rooms to hire for parties</strong></span></p>
<p><strong>The Exchange Hotel</strong></p>
<ul>
<li>
<p>Number of seated guests possible: 45</p>
</li>
<li>
<p>Room on the {fifth} floor large, bright room with a good {view}</p>
</li>
<li>
<p>Cost £32 with buffet per person (minimum number of people: {35} )</p>
</li>
<li>
<p>Available any {Saturday} In April</p>
</li>
</ul>
<p><strong>The {Limerick} Hotel</strong></p>
<ul>
<li>
<p>Large room (seats 75)</p>
</li>
<li>
<p>In the {business} area of the city</p>
</li>
<li>
<p>Room on ground floor with a small {garden} for guests to use</p>
</li>
<li>
<p>cost : £36 with buffet per person</p>
</li>
<li>
<p>Available: 13th and 20th April</p>
</li>
</ul>
<p><strong>Booking information</strong></p>
<ul>
<li>
<p>Bookings held for a {week}</p>
</li>
<li>
<p>Final payment of {65} %required 10 days before booking</p>
</li>
<li>
<p>Need to confirm guests and menu 5 days in advance</p>
</li>
<li>
<p>To book, phone {044298611} On Monday</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">PART 1: ROOMS TO HIRE FOR PARTIES</strong></h3>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Manager:</strong> Good morning, The Function Company. Can I help you?</p>\n<p data-path-to-node=\"5\"><strong>Woman:</strong> Hi. A friend told me that you can arrange rooms for hire for parties and things like that.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Manager:</strong> That''s right. We have about ten hotels on our list and we hire out function rooms on their behalf. Are you having a party?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong>Yes, it''s for my birthday—my 21st.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Manager:</strong> Okay. First of all, can you tell me how many people you''re inviting?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong> I''m not sure yet. It depends on the cost.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Manager:</strong> Okay. Well, the Exchange Hotel might be a good choice for you. They have a room which will seat up to 45 and will take 65 people standing. Are you going to have a meal or just a buffet?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong> Uh, I think a buffet. It doesn''t have to be a sit-down meal. I don''t know the Exchange Hotel. Can you tell me a bit more about it?</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Manager:</strong> Well, it was built about 150 years ago. We regularly arrange parties there. They have a room for hire on the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"118\">(Q1) fifth</strong></span> floor. It''s not the most central hotel, but it''s very easy for people to find. It''s very popular for wedding parties, so I''ll have to check if it''s available.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong> Okay. Is the room nice? Have you seen it?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Manager:</strong> I have. It''s quite big and very light, but the best thing is that it has a wonderful <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"94\">(Q2) view</strong></span>. On a fine evening, you can see for miles.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong> Oh, sounds good. How much is it?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Manager:</strong> It''s £32 a head. That includes the hire of the room and the standard buffet, but not drinks. And you have to have at least <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"132\">(Q3) 35</strong></span> guests.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong>Well, that won''t be a problem. We''re likely to be more than that. Can you tell me when it''s available?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Manager:</strong> I can check that for you. Which dates are you looking at?</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong>Uh, ideally the middle to end of April, weekends.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Manager:</strong> Let me see... um, they can do any <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"20\" data-index-in-node=\"43\">(Q4) Saturday</strong></span> in April, but not Fridays or Sundays.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong> Okay. But if I want something bigger, what would you recommend?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Manager:</strong> There''s the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"22\" data-index-in-node=\"21\">(Q5) Limerick</strong></span> Hotel.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong>How do you spell that? Oh, I''m taking notes.</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Manager:</strong> It''s L-I-M-E-R-I-C-K. There''s a large room there which seats up to 75 people, or there''s room for 125 standing.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong> Oh, I expect we''ll be standing. Where is it?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Manager:</strong> It''s in the <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"26\" data-index-in-node=\"21\">(Q6) business</strong></span> district, so public transport''s good. It''s got a large car park too. Though the room''s on the ground floor and it''s recently been refurbished.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman: </strong>Is there a garden we could use if we''re on the ground floor?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Manager:</strong> There''s a small <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"28\" data-index-in-node=\"25\">(Q7) garden</strong></span> that would be available.</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman: </strong>Oh, sounds nice, especially if it''s a warm evening. And the cost?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Manager:</strong> The buffet is £36 per person. Shall I check availability in April for you?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong>Yes, please.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Manager:</strong> Okay, you said weekends, didn''t you? Yes... No Fridays again. And it''s not free on the first Saturday, that''s the 6th, but it''s free on the 13th and 20th.</p>\n<hr data-path-to-node=\"33\">\n<h3 data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">BOOKING INFORMATION (Questions 8–10)</strong></h3>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong>I think the first hotel looks best for me, but I need two or three days to think about it.</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Manager:</strong> Okay. Well, if I take your booking today, I can hold it for a <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"36\" data-index-in-node=\"71\">(Q8) week</strong></span>. So if you want to change your mind or have a look at other possible hotels, we can do that. To confirm the booking, I then need a deposit of 35%. You pay the other <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"36\" data-index-in-node=\"246\">(Q9) 65%</strong></span> 10 days before the party.</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong>Okay. And when do I have to confirm numbers?</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Manager:</strong> The number of guests needs to be confirmed five days before the party, and you also have to decide which menu you want then.</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong> That sounds okay. I''ll ring you on Monday. Is this your direct line? 368207.</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Manager:</strong> I''ll be out of the office on Monday, but you can call me on my <strong><span style=\"background-color: #ffffff;\"> mobile phone </span></strong>on <span style=\"background-color: #f1c40f;\"><strong>(Q10) </strong><strong><span style=\"background-color: #f1c40f;\">044</span>29 8611.</strong></span></p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"3\" data-index-in-node=\"91\">Woman:</strong>Alright, I''ve got all that. I''ll ring you back later. Thanks</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Manager: </strong>bye then.</p>"}]', 0);
INSERT INTO public.questions VALUES ('53e680de-f120-4a8a-b183-b8ae39ea29ce', '30cc5ddf-20e1-41e7-af22-e96be223faaf', 'matching', 'Questions 37–40', NULL, '<p>Complete each sentence with the correct ending below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A is dependent on adapting to unfamiliar interaction formats."}, {"optionText": "B is key in determining whether a student has a sense of belonging in a course."}, {"optionText": "C is a subject that the writer believes will require more study."}, {"optionText": "D is essential to excel in study and scholarship."}, {"optionText": "E is key in determining whether a student feels they have learned something from a course."}, {"optionText": "F is important for determining their validity."}], "matchingItems": [{"questionPart": "The ability to succeed in an online course", "correctAnswer": "A is dependent on adapting to unfamiliar interaction formats.", "sectionContent": null}, {"questionPart": "The need to be mindful of the source of comments in an online discussion ", "correctAnswer": "F is important for determining their validity.", "sectionContent": null}, {"questionPart": "In online courses, it is presence, rather than interaction, that ", "correctAnswer": "B is key in determining whether a student has a sense of belonging in a course.", "sectionContent": null}, {"questionPart": "The relationship between interaction and learning achievement ", "correctAnswer": "C is a subject that the writer believes will require more study.", "sectionContent": null}]}', 'null', '[{"content": "<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Câu 37</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"8\">A (is dependent on adapting to unfamiliar interaction formats.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…effective web-based learning requires adjustments on the part of students and teachers for successful interactions to occur…”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong data-path-to-node=\"28,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Để thành công/hiệu quả, người học cần sự “adjustment” (điều chỉnh/thích nghi) với các hình thức tương tác trực tuyến.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Câu 38</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"8\">F (is important for determining their validity.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…students need to have the experience and knowledge base to sift through the discussion for misinformation.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong data-path-to-node=\"30,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc chú ý đến nguồn gốc ý kiến giúp sinh viên lọc bỏ thông tin sai lệch (misinformation) để xác định tính đúng đắn/hợp lệ (validity) của nội dung.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Câu 39</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"8\">B (is key in determining whether a student has a sense of belonging in a course.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The simplest definition of presence… refers to a student’s sense of being registered and belonging in a course…”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong data-path-to-node=\"32,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả định nghĩa “presence” gắn liền với cảm giác thuộc về (belonging), và phân biệt nó với hành động tương tác thuần túy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Câu 40</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"34,0,0\" data-index-in-node=\"8\">C (is a subject that the writer believes will require more study.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…how interaction affects learning outcomes and what the relationships between the two are, is in need of further study.”</p>\n</li>\n<li>\n<p data-path-to-node=\"34,2,0\"><strong data-path-to-node=\"34,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả kết luận mối quan hệ giữa tương tác và kết quả học tập “cần được nghiên cứu thêm” (in need of further study).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('4f5c06cb-b4e7-4a98-b9cf-d5934da948bf', 'b6dd2bbc-c2e9-4b68-ba67-2bea2a277e62', 'checkbox', 'Questions 38-40', NULL, '<p>Choose <strong>THREE </strong>correct answers.</p>
<p>According to the writer, which <strong>THREE </strong>of the following areas have not been studied enough in order to understand the origin of language?</p>
', 'multiple_choice_many', 'null', '[{"option": "Evidence from prehistoric times", "correct": true}, {"option": "Intelligence", "correct": false}, {"option": "Individual sounds", "correct": false}, {"option": "Music", "correct": true}, {"option": "Emotions", "correct": true}, {"option": "Human intellect", "correct": false}, {"option": "Children’s language", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\">Câu 38: Evidence from prehistoric times</p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 1-3.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The first is an <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"28\">insufficient concern with the archaeological and fossil proof</strong> of the brains and behaviour of our human ancestors.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả chỉ ra rằng các nhà nghiên cứu chưa chú trọng đúng mức đến các bằng chứng khảo cổ và hóa thạch từ thời tiền sử (prehistoric times) của tổ tiên loài người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\">Câu 39: Music</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 1-3.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"15\">insufficient concern</strong> with the other major aural and vocal communication system of modern humans: <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"112\">music</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là lý do thứ hai khiến tiến độ nghiên cứu bị hạn chế. Tác giả cho rằng âm nhạc thường bị ngó lơ hoặc bị tách rời khỏi các cuộc thảo luận về ngôn ngữ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\">Câu 40: Emotions</p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 1-3.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a third reason for our lack of progress… an <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"61\">insufficient concern with emotion</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định đời sống cảm xúc của tổ tiên đã bị “bỏ rơi” (neglected) trong khi các nhà khoa học lại quá tập trung vào khả năng trí tuệ, điều này làm cản trở việc hiểu về nguồn gốc ngôn ngữ.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('3df31321-19b7-4f09-b5fa-f7205018ea08', 'b2554d64-629e-4aa2-8c14-2da421d2141b', 'checkbox', 'Questions 22-23', NULL, '<p>Choose <strong>TWO</strong> correct answers.</p>
<p>The list below goes some possible results of the 1960s parenting style.</p>
<p>Which <strong>TWO </strong>of these results are mentioned by Franklin Foer in the excerpt from How Soccer Explains the World?</p>
', 'multiple_choice_many', 'null', '[{"option": "Participation in youth soccer became much more expensive.", "correct": false}, {"option": "Some youth soccer leagues adopted more restrictive rules of play.", "correct": true}, {"option": "Fewer young people joined youth soccer teams.", "correct": false}, {"option": "Youth soccer players were sometimes rewarded for simply playing in games.", "correct": true}, {"option": "Soccer equipment manufacturers directed advertising towards parents.", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"19\"><strong>22-23. Which TWO of these results are mentioned by Franklin Foer in the excerpt from <em>How Soccer Explains the World</em>?</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong>Đáp án: B (Some youth soccer leagues adopted more restrictive rules of play.) và D (Youth soccer players were sometimes rewarded for simply playing in games.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong>Dẫn chứng cho B:</strong> (Đoạn C) “…<strong>some youth leagues prohibited heading the ball altogether</strong>.” (Cấm đánh đầu là một luật lệ hạn chế hơn/restrictive rules).</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong>Dẫn chứng cho D:</strong> (Đoạn C) “Soccer leagues like the one I played in as a child handed out <strong>‘participation’ prizes to every player</strong>, no matter how few games his (or her) team won…” (Thưởng cho việc tham gia).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('10b47ccb-0776-453a-bd71-2a1be63453b2', 'b2554d64-629e-4aa2-8c14-2da421d2141b', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>Winners and losers</strong></span></p>
<p>For youth soccer players, a key {Principle} is that they should always come away from the game with a positive attitude. In this respect, regardless of the effort the players make, they get some kind of {Reward} at the end of a game.</p>
<p>In street soccer, however, players gain resilience because they have to learn to cope with failure. But the outcome of a match isn’t remembered for long. In fact, no-one ever keeps a {record} of the results of games.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"22\"><strong>24. For youth soccer players, a key principle is that they should always come away from the game with a positive attitude.</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án:</strong> <strong class=\"animating\">principle</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “<strong>‘Everyone’s a winner; no one’s a loser’ is a guiding principle of youth soccer</strong>.” (Nguyên tắc hướng dẫn).</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong>25. In this respect, regardless of the effort the players make, they get some kind of reward at the end of a game.</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong>Đáp án:</strong> <strong>reward</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G) “<strong>Since giving less than your best receives the same reward as giving your best</strong> why go to any extra effort?” (Việc nhận được phần thưởng bất kể nỗ lực).</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong>26. In fact, no-one ever keeps a record of the results of games.</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong>Đáp án:</strong> <strong>record</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong>Dẫn chứng:</strong> (Đoạn G – cuối) “In street soccer a formal <strong>record</strong> is not kept.”</p>\n</li>\n</ul>\n"}]', 3);
SET session_replication_role = DEFAULT;
